const AnnualSalesChart = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const props = item.props || {};

  const title = props.title || 'ROASTERY GROWTH';
  const subtitle = props.subtitle || 'Revenue Overview 2020-2025 (in 10M)';
  const bgStart = props.bgStart || '#061025';
  const bgEnd = props.bgEnd || '#28354c';
  const accentColor = props.accentColor || '#f6dfc6';
  const barColor = props.barColor || '#d29400';

  const dataPoints = [
    { label: props.label1 || '2019', value: Number(props.val1) || 42 },
    { label: props.label2 || '2020', value: Number(props.val2) || 58 },
    { label: props.label3 || '2021', value: Number(props.val3) || 71 },
    { label: props.label4 || '2022', value: Number(props.val4) || 65 },
    { label: props.label5 || '2023', value: Number(props.val5) || 89 },
    { label: props.label6 || '2024', value: Number(props.val6) || 103 },
  ];

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);
  const safeFps = fps || 30;

  const CHART_W = 1300;
  const CHART_H = 560;
  const CHART_LEFT = (DESIGN_WIDTH - CHART_W) / 2;
  const CHART_TOP = 320;
  const BAR_W = 120;
  const gap = (CHART_W - dataPoints.length * BAR_W) / (dataPoints.length - 1);
  const maxVal = 120;
  const gridVals = [0, 30, 60, 90, 120];

  const titleSpring = spring({ frame, fps: safeFps, config: { damping: 22, stiffness: 90 } });
  const titleOpacity = interpolate(titleSpring, [0, 1], [0, 1]);
  const titleY = interpolate(titleSpring, [0, 1], [-40, 0]);

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      background: `linear-gradient(135deg, ${bgStart} 0%, ${bgEnd} 100%)`,
      transform: `scale(${scale})`, transformOrigin: 'top left',
      overflow: 'hidden', fontFamily: "'Inter', sans-serif", color: accentColor,
    }}>
      <div style={{
        position: 'absolute', top: 0, left: 0, right: 0, height: 3,
        background: `linear-gradient(90deg, transparent, ${barColor}, transparent)`,
        opacity: titleOpacity,
      }} />

      <div style={{
        position: 'absolute', top: 80, width: '100%', textAlign: 'center',
        opacity: titleOpacity, transform: `translateY(${titleY}px)`,
      }}>
        <div style={{ fontSize: 76, fontWeight: 900, letterSpacing: '0.08em', textTransform: 'uppercase',
          textShadow: `0 0 40px ${barColor}99` }}>{title}</div>
        <div style={{ fontSize: 28, fontWeight: 300, marginTop: 14, opacity: 0.7, letterSpacing: '0.12em' }}>{subtitle}</div>
      </div>

      <div style={{ position: 'absolute', top: CHART_TOP, left: CHART_LEFT, width: CHART_W, height: CHART_H }}>
        {gridVals.map((val, i) => {
          const y = CHART_H - (val / maxVal) * CHART_H;
          const op = interpolate(frame, [10 + i * 4, 30 + i * 4], [0, 1], { extrapolateRight: 'clamp' });
          return (
            <div key={val} style={{ position: 'absolute', top: y, left: -60, right: 0 }}>
              <div style={{ height: 1, background: `rgba(210,148,0,${val === 0 ? 0.4 : 0.15})`, opacity: op }} />
              <span style={{ position: 'absolute', left: -10, top: -12, fontSize: 18,
                fontFamily: "'IBM Plex Mono', monospace", opacity: op * 0.6, textAlign: 'right' }}>{val}</span>
            </div>
          );
        })}

        {dataPoints.map((pt, i) => {
          const delay = 20 + i * 6;
          const prog = spring({ frame: Math.max(0, frame - delay), fps: safeFps,
            config: { mass: 1, damping: 16, stiffness: 85 } });
          const barH = (pt.value / maxVal) * CHART_H;
          const xPos = i * (BAR_W + gap);
          const labelOp = interpolate(frame - delay - 8, [0, 12], [0, 1], { extrapolateRight: 'clamp', extrapolateLeft: 'clamp' });

          return (
            <div key={i} style={{ position: 'absolute', left: xPos, bottom: 0, width: BAR_W, height: CHART_H }}>
              <div style={{
                position: 'absolute', bottom: 0, width: '100%', height: '100%',
                background: 'rgba(210,148,0,0.06)', borderRadius: '6px 6px 0 0',
              }} />
              <div style={{
                position: 'absolute', bottom: 0, width: '100%', height: barH,
                background: `linear-gradient(to top, ${barColor}, ${barColor}cc)`,
                transform: `scaleY(${prog})`, transformOrigin: 'bottom',
                borderRadius: '6px 6px 0 0',
                boxShadow: `0 0 20px ${barColor}66`,
              }} />
              <div style={{
                position: 'absolute', bottom: barH * prog + 14, width: '100%',
                textAlign: 'center', fontSize: 26, fontWeight: 700,
                opacity: labelOp, fontFamily: "'IBM Plex Mono', monospace",
                color: barColor, textShadow: `0 0 12px ${barColor}`,
              }}>{pt.value}</div>
              <div style={{
                position: 'absolute', bottom: -48, width: '100%', textAlign: 'center',
                fontSize: 22, fontWeight: 600, opacity: labelOp * 0.85,
                letterSpacing: '0.05em',
              }}>{pt.label}</div>
            </div>
          );
        })}
      </div>

      <div style={{
        position: 'absolute', bottom: 0, left: 0, right: 0, height: 2,
        background: `linear-gradient(90deg, transparent, ${barColor}88, transparent)`,
        opacity: titleOpacity,
      }} />
    </div>
  );
};

const CategoryBarChart = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  const props = item.props || {};
  const titleText = props.titleText || 'Membership Signups';
  const bgColor = props.bgColor || '#212038';
  const unit = props.unit || 'K';

  const barColor1 = props.barColor1 || '#ce63ba';
  const barColor2 = props.barColor2 || '#a594eb';
  const barColor3 = props.barColor3 || '#0093cc';
  const barColor4 = props.barColor4 || '#efa200';
  const barColor5 = props.barColor5 || '#00b6a0';

  const cat1 = props.cat1 || 'Yoga'; const val1 = Number(props.val1 ?? 890);
  const cat2 = props.cat2 || 'Cycling';     const val2 = Number(props.val2 ?? 560);
  const cat3 = props.cat3 || 'Nutrition';     const val3 = Number(props.val3 ?? 430);
  const cat4 = props.cat4 || 'Recovery';     const val4 = Number(props.val4 ?? 320);
  const cat5 = props.cat5 || 'Strength';     const val5 = Number(props.val5 ?? 250);

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const safeFps = fps || 30;
  const safeSpring = (delay = 0, config = { damping: 15 }) => {
    return Math.min(1, spring({ frame: Math.max(0, frame - delay), fps: safeFps, config }));
  };

  const titleSpring = safeSpring(0, { damping: 14 });
  const gridSpring = safeSpring(10, { damping: 20 });

  const chartTop = 320;
  const chartHeight = 580;
  const chartLeft = 200;
  const chartWidth = 1520;

  const actualMax = Math.max(val1, val2, val3, val4, val5, 10);
  const computedMax = Math.ceil(actualMax / 200) * 200;

  const gridSteps = 5;
  const gridItems = [];
  for (let i = 0; i <= gridSteps; i++) {
    const val = (computedMax / gridSteps) * i;
    const yPos = chartTop + chartHeight - (val / computedMax) * chartHeight;
    gridItems.push({ val, yPos });
  }

  const data = [
    { label: cat1, value: val1, color: barColor1 },
    { label: cat2, value: val2, color: barColor2 },
    { label: cat3, value: val3, color: barColor3 },
    { label: cat4, value: val4, color: barColor4 },
    { label: cat5, value: val5, color: barColor5 },
  ];

  const barWidth = 130;
  const barSpacing = chartWidth / data.length;

  const rootStyle = {
    position: 'absolute', top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`, transformOrigin: 'top left',
    backgroundColor: bgColor,
    overflow: 'hidden',
    fontFamily: '"Noto Sans SC", sans-serif',
    color: 'white'
  };

  const gridLines = gridItems.map((item, i) => {
    const lineOpacity = gridSpring * 0.15;
    const lineStyle = {
      position: 'absolute',
      left: chartLeft,
      top: item.yPos,
      width: chartWidth,
      height: 2,
      backgroundColor: `rgba(255,255,255,${lineOpacity})`,
      transform: `scaleX(${gridSpring})`,
      transformOrigin: 'left center'
    };

    const labelStyle = {
      position: 'absolute',
      left: chartLeft - 30,
      top: item.yPos - 14,
      width: 100,
      textAlign: 'right',
      transform: 'translateX(-100%)',
      fontSize: 22,
      color: `rgba(255,255,255,${gridSpring * 0.6})`,
      fontFamily: '"IBM Plex Mono", monospace'
    };

    return (
      <div key={`grid-${i}`}>
        <div style={lineStyle} />
        <div style={labelStyle}>{item.val}</div>
      </div>
    );
  });

  const bars = data.map((d, i) => {
    const barSpring = safeSpring(20 + i * 5, { damping: 14, mass: 0.8 });
    const targetHeight = (d.value / computedMax) * chartHeight;
    const currentHeight = targetHeight * barSpring;
    const currentY = chartTop + chartHeight - currentHeight;
    const currentVal = Math.round(d.value * barSpring);

    const barCenterX = chartLeft + (barSpacing * i) + (barSpacing / 2);

    const barContainerStyle = {
      position: 'absolute',
      left: barCenterX - (barWidth / 2),
      top: currentY,
      width: barWidth,
      height: Math.max(0, currentHeight),
      borderRadius: '16px 16px 0 0',
      background: `linear-gradient(180deg, ${d.color} 0%, rgba(0,0,0,0.3) 100%)`,
      backgroundColor: d.color,
      boxShadow: '0 8px 24px rgba(0,0,0,0.4)',
      opacity: barSpring
    };

    const innerHighlightStyle = {
      position: 'absolute', top: 0, left: 0, right: 0, bottom: 0,
      borderRadius: '16px 16px 0 0',
      background: 'linear-gradient(180deg, rgba(255,255,255,0.25) 0%, rgba(255,255,255,0) 25%)',
    };

    const labelStyle = {
      position: 'absolute',
      left: barCenterX - 150,
      top: currentY - 56 - (barSpring * 10),
      width: 300,
      textAlign: 'center',
      fontSize: 36,
      fontWeight: 700,
      color: 'white',
      opacity: barSpring,
      fontFamily: '"IBM Plex Mono", monospace',
      textShadow: '0px 4px 12px rgba(0,0,0,0.4)'
    };

    const unitStyle = {
      fontSize: 22,
      fontFamily: '"Noto Sans SC", sans-serif',
      marginLeft: 6,
      fontWeight: 400,
      opacity: 0.8
    };

    const categoryStyle = {
      position: 'absolute',
      left: barCenterX - 150,
      top: chartTop + chartHeight + 24,
      width: 300,
      textAlign: 'center',
      fontSize: 28,
      fontWeight: 500,
      color: `rgba(255,255,255,${barSpring * 0.95})`,
      transform: `translateY(${interpolate(barSpring, [0, 1], [20, 0])}px)`
    };

    return (
      <div key={`bar-${i}`}>
        <div style={barContainerStyle}>
            <div style={innerHighlightStyle} />
        </div>
        <div style={labelStyle}>
          {currentVal}
          <span style={unitStyle}>{unit}</span>
        </div>
        <div style={categoryStyle}>{d.label}</div>
      </div>
    );
  });

  const xAxisStyle = {
    position: 'absolute',
    left: chartLeft,
    top: chartTop + chartHeight,
    width: chartWidth,
    height: 3,
    backgroundColor: `rgba(255,255,255,${gridSpring * 0.4})`,
    transform: `scaleX(${gridSpring})`,
    transformOrigin: 'left center'
  };

  return (
    <div style={rootStyle}>
       {gridLines}
       <div style={xAxisStyle} />
       {bars}
       <div style={{
         position: 'absolute',
         left: chartLeft,
         top: 100,
         opacity: titleSpring,
         transform: `translateX(${interpolate(titleSpring, [0, 1], [-40, 0])}px)`
       }}>
         <h1 style={{
             margin: 0,
             fontSize: 64,
             fontWeight: 700,
             letterSpacing: 2,
             color: 'white',
             textShadow: '0 4px 16px rgba(0,0,0,0.3)'
         }}>{titleText}</h1>
         <div style={{
             marginTop: 16,
             width: 120,
             height: 8,
             backgroundColor: barColor1,
             borderRadius: 4,
             transform: `scaleX(${titleSpring})`,
             transformOrigin: 'left center'
         }} />
       </div>
    </div>
  );
};

const RegionalBarChart = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  const props = item.props || {};
  const titleText = props.titleText || 'WISHLISTS BY PLATFORM';
  const subtitleText = props.subtitleText || 'Launch Week Totals (in K)';
  const bgGradientStart = props.bgGradientStart || '#3b4860';
  const bgGradientEnd = props.bgGradientEnd || '#4d5768';
  const barColor = props.barColor || '#ffffff';
  const trackColor = props.trackColor || 'rgba(255, 255, 255, 0.1)';
  const gridColor = props.gridColor || 'rgba(255, 255, 255, 0.15)';
  const textColor = props.textColor || '#ffffff';
  const fontFamily = props.fontFamily || 'Inter, sans-serif';
  const monoFont = '"IBM Plex Mono", monospace';

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    background: `linear-gradient(135deg, ${bgGradientStart}, ${bgGradientEnd})`,
    fontFamily: fontFamily,
    color: textColor,
    overflow: 'hidden'
  };

  const titleSpring = spring({ frame, fps, config: { damping: 16 } });
  const titleOpacity = interpolate(titleSpring, [0, 1], [0, 1]);
  const titleY = interpolate(titleSpring, [0, 1], [-30, 0]);

  const subSpring = spring({ frame: Math.max(0, frame - 5), fps, config: { damping: 16 } });
  const subOpacity = interpolate(subSpring, [0, 1], [0, 0.8]);
  const subY = interpolate(subSpring, [0, 1], [-20, 0]);

  const gridSpring = spring({ frame: Math.max(0, frame - 15), fps, config: { damping: 20 } });
  const gridOpacity = interpolate(gridSpring, [0, 1], [0, 1]);

  const data = [
    { label: 'North America', value: 82 },
    { label: 'Europe', value: 67 },
    { label: 'Asia Pacific', value: 91 },
    { label: 'Latin America', value: 43 },
    { label: 'Middle East', value: 28 },
  ];

  const gridLines = [0, 25, 50, 75, 100].map(val => ({
    val,
    bottom: `${val}%`,
  }));

  const bars = data.map((d, i) => {
    const barSpring = spring({ 
      frame: Math.max(0, frame - 25 - i * 6), 
      fps, 
      config: { damping: 15, mass: 0.9 } 
    });
    const valOpacity = interpolate(barSpring, [0.7, 1], [0, 1], { 
      extrapolateRight: 'clamp', 
      extrapolateLeft: 'clamp' 
    });
    const valOffset = interpolate(barSpring, [0.7, 1], [15, 0], { 
      extrapolateRight: 'clamp', 
      extrapolateLeft: 'clamp' 
    });

    return {
      ...d,
      heightPct: d.value,
      currentHeight: d.value * barSpring,
      displayValue: Math.round(d.value * barSpring),
      valOpacity,
      valOffset
    };
  });

  return (
    <div style={rootStyle}>
      {/* Header */}
      <div style={{ position: 'absolute', top: 120, width: '100%', textAlign: 'center' }}>
        <h1 style={{
          margin: 0,
          fontSize: 56,
          fontWeight: 600,
          letterSpacing: '4px',
          opacity: titleOpacity,
          transform: `translateY(${titleY}px)`,
          textTransform: 'uppercase'
        }}>{titleText}</h1>
        <h2 style={{
          margin: '12px 0 0 0',
          fontSize: 24,
          fontWeight: 300,
          letterSpacing: '1px',
          opacity: subOpacity,
          transform: `translateY(${subY}px)`
        }}>{subtitleText}</h2>
      </div>

      {/* Chart Area */}
      <div style={{
        position: 'absolute',
        top: 360,
        left: 260,
        width: 1400,
        height: 520,
        opacity: gridOpacity
      }}>
        {/* Grid Lines */}
        {gridLines.map(line => (
          <div key={line.val} style={{
            position: 'absolute',
            bottom: line.bottom,
            left: 0,
            width: '100%',
            borderBottom: `1px solid ${gridColor}`,
            display: 'flex',
            alignItems: 'center'
          }}>
            <span style={{
              position: 'absolute',
              left: -60,
              fontSize: 18,
              fontWeight: 400,
              fontFamily: monoFont,
              opacity: 0.7
            }}>{line.val}</span>
          </div>
        ))}

        {/* Bars Container */}
        <div style={{
          position: 'absolute',
          top: 0, left: 0, width: '100%', height: '100%',
          display: 'flex',
          justifyContent: 'space-around',
          alignItems: 'flex-end',
          paddingLeft: 40,
          paddingRight: 40,
          boxSizing: 'border-box'
        }}>
          {bars.map((bar) => (
            <div key={bar.label} style={{
              position: 'relative',
              width: 100,
              height: '100%'
            }}>
              {/* Track */}
              <div style={{
                position: 'absolute',
                bottom: 0, left: 0,
                width: '100%', height: '100%',
                backgroundColor: trackColor
              }} />

              {/* Filled Bar */}
              <div style={{
                position: 'absolute',
                bottom: 0, left: 0,
                width: '100%',
                height: `${bar.currentHeight}%`,
                backgroundColor: barColor,
                transformOrigin: 'bottom'
              }} />

              {/* Value Label */}
              <div style={{
                position: 'absolute',
                bottom: `${bar.currentHeight}%`,
                left: 0, width: '100%',
                textAlign: 'center',
                marginBottom: 20,
                transform: `translateY(-${bar.valOffset}px)`,
                opacity: bar.valOpacity,
                fontSize: 28,
                fontWeight: 500,
                fontFamily: monoFont,
              }}>
                {bar.displayValue}
              </div>

              {/* X Axis Label */}
              <div style={{
                position: 'absolute',
                top: '100%',
                left: '50%',
                transform: 'translateX(-50%)',
                marginTop: 24,
                width: 160,
                textAlign: 'center',
                fontSize: 18,
                fontWeight: 300,
                opacity: 0.9,
                lineHeight: 1.3
              }}>
                {bar.label}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

