          <div style={titleStyle}>{titleText}</div>
          <div style={kpiContainerStyle}>
            <div style={kpiValueStyle}>{kpiValue}</div>
            <div style={kpiLabelStyle}>{kpiLabel}</div>
          </div>
        </div>

        {/* Chart */}
        <div style={chartContainerStyle}>
          {/* Y Axis Labels */}
          <div style={yAxisStyle}>
            {yAxisLabels.map((label, i) => (
              <div key={i} style={gridLineLabelStyle}>
                {label}
              </div>
            ))}
          </div>

          {/* Grid Lines */}
          <div style={gridLinesContainerStyle}>
            {yAxisLabels.map((_, i) => (
              <div key={i} style={gridLineStyle} />
            ))}
          </div>

          {/* Bars */}
          <div style={barsAreaStyle}>
            {dataPoints.map((dp, i) => {
              // Stagger delay: 5 frames per bar
              const progress = growthSpring(i * 5);
              // Current display value
              const currentVal = Math.round(progress * dp.value);
              // Bar height calculation
              const barHeightPercent = (dp.value / maxVal) * 100 * progress;
              const color = i % 2 === 0 ? accentColor1 : accentColor2;

              return (
                <div
                  key={i}
                  style={{
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'flex-end',
                    height: '100%',
                    width: '10%',
                  }}
                >
                  {/* Number Label above bar */}
                  <div
                    style={{
                      marginBottom: 12,
                      fontSize: 24,
                      fontWeight: 700,
                      color: '#585465',
                      opacity: progress, // Fade in label
                      transform: `translateY(${10 - progress * 10}px)`,
                    }}
                  >
                    {currentVal}
                  </div>

                  {/* The Bar */}
                  <div
                    style={{
                      width: '60%',
                      height: `${barHeightPercent}%`,
                      backgroundColor: color,
                      borderRadius: '8px 8px 0 0',
                      boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
                    }}
                  />

                  {/* X Axis Label */}
                  <div
                    style={{
                      marginTop: 16,
                      height: 40,
                      fontSize: 20,
                      fontWeight: 600,
                      color: '#9c98a9',
                    }}
                  >
                    {dp.label}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

const GroupedBarChart = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  const props = item.props || {};
  const titleText = props.titleText || 'GROOMING BOOKINGS';
  const subtitleText = props.subtitleText || 'Booked vs Goal Volume (sessions)';
  const bgGradientStart = props.bgGradientStart || '#3b4860';
  const bgGradientEnd = props.bgGradientEnd || '#4d5768';
  const actualColor = props.actualColor || '#FFFFFF';
  const targetColor = props.targetColor || 'rgba(255, 255, 255, 0.2)';
  const textColor = props.textColor || '#FFFFFF';
  const gridColor = props.gridColor || 'rgba(255, 255, 255, 0.1)';
  const fontFamily = props.fontFamily || 'Inter, sans-serif';
  const monoFont = '"IBM Plex Mono", monospace';

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const safeFps = fps || 30;
  const safeSpring = (delay = 0, config = { damping: 15 }) => {
    return spring({ frame: Math.max(0, frame - delay), fps: safeFps, config });
  };

  const data = [
    { label: 'Jan', actual: 55, target: 60 },
    { label: 'Feb', actual: 68, target: 70 },
    { label: 'Mar', actual: 72, target: 75 },
    { label: 'Apr', actual: 61, target: 65 },
    { label: 'May', actual: 84, target: 80 },
    { label: 'Jun', actual: 90, target: 85 },
  ];

  const chartWidth = 1400;
  const chartHeight = 550;
  const chartLeft = 260;
  const chartTop = 320;
  const yMax = 100;
  const yStep = 25;
  const pxPerUnit = chartHeight / yMax;

  const groupWidth = chartWidth / data.length;
  const barWidth = 40;
  const barGap = 12;

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    background: `linear-gradient(135deg, ${bgGradientStart}, ${bgGradientEnd})`,
    fontFamily,
    color: textColor,
    overflow: 'hidden'
  };

  const titleOpacity = safeSpring(0, { damping: 20 });
  const titleY = interpolate(safeSpring(0, { damping: 20 }), [0, 1], [30, 0]);
  const titleTransform = `translateY(${titleY}px)`;

  const legendOpacity = safeSpring(15, { damping: 20 });

  const gridLines = [];
  for (let i = 0; i <= yMax; i += yStep) {
    gridLines.push(i);
  }

  const gridElements = gridLines.map((val, i) => {
    const yPos = chartHeight - (val * pxPerUnit);
    const gridSpring = safeSpring(10 + i * 2, {damping: 20});
    const gridScaleX = `scaleX(${gridSpring})`;

    return (
      <div key={`grid-${val}`} style={{
        position: 'absolute',
        top: yPos,
        left: -60,
        width: chartWidth + 60,
        height: 1,
        display: 'flex',
        alignItems: 'center',
        opacity: gridSpring
      }}>
        <div style={{ width: 40, textAlign: 'right', fontSize: 18, fontWeight: 400, fontFamily: monoFont, opacity: 0.6, marginRight: 20 }}>
          {val}
        </div>
        <div style={{ flex: 1, height: 1, backgroundColor: gridColor, transformOrigin: 'left', transform: gridScaleX }} />
      </div>
    );
  });

  const barElements = data.map((d, i) => {
    const groupLeft = i * groupWidth;
    const delay = 25 + i * 5;

    const targetProgress = safeSpring(delay, { damping: 18, stiffness: 80 });
    const actualProgress = safeSpring(delay + 4, { damping: 18, stiffness: 80 });

    const targetH = Math.max(0, targetProgress * (d.target * pxPerUnit));
    const actualH = Math.max(0, actualProgress * (d.actual * pxPerUnit));

    const groupCenter = groupWidth / 2;
    const totalBarsWidth = (barWidth * 2) + barGap;
    const startX = groupCenter - (totalBarsWidth / 2);

    const labelSpring = safeSpring(20 + i * 3, { damping: 20 });
    const labelY = interpolate(labelSpring, [0, 1], [10, 0]);
    const labelTransform = `translateY(${labelY}px)`;

    return (
      <div key={d.label} style={{
        position: 'absolute',
        top: 0,
        left: groupLeft,
        width: groupWidth,
        height: chartHeight + 60,
      }}>
        <div style={{
          position: 'absolute',
          bottom: 60,
          left: startX,
          width: barWidth,
          height: targetH,
          backgroundColor: targetColor,
          transformOrigin: 'bottom',
        }} />
        <div style={{
          position: 'absolute',
          bottom: 60,
          left: startX + barWidth + barGap,
          width: barWidth,
          height: actualH,
          backgroundColor: actualColor,
          transformOrigin: 'bottom',
        }} />
        <div style={{
          position: 'absolute',
          bottom: 0,
          left: 0,
          width: '100%',
          textAlign: 'center',
          fontSize: 18,
          fontWeight: 300,
          opacity: labelSpring,
          transform: labelTransform
        }}>
          {d.label}
        </div>
      </div>
    );
  });

  return (
    <div style={rootStyle}>
      <div style={{
        position: 'absolute',
        top: 120,
        left: chartLeft,
        opacity: titleOpacity,
        transform: titleTransform,
      }}>
        <h1 style={{ margin: 0, fontSize: 56, fontWeight: 600, letterSpacing: '4px' }}>{titleText}</h1>
        <h2 style={{ margin: '12px 0 0 0', fontSize: 24, fontWeight: 300, opacity: 0.7, letterSpacing: '1px' }}>{subtitleText}</h2>
      </div>

      <div style={{
        position: 'absolute',
        top: 140,
        left: chartLeft + chartWidth - 300,
        display: 'flex',
        gap: '32px',
        opacity: legendOpacity,
        justifyContent: 'flex-end',
        width: 300
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <div style={{ width: 16, height: 16, backgroundColor: actualColor }} />
          <span style={{ fontSize: 20, fontWeight: 300, opacity: 0.9 }}>Booked</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <div style={{ width: 16, height: 16, backgroundColor: targetColor }} />
          <span style={{ fontSize: 20, fontWeight: 300, opacity: 0.9 }}>Goal</span>
        </div>
      </div>

      <div style={{
        position: 'absolute',
        top: chartTop,
        left: chartLeft,
        width: chartWidth,
        height: chartHeight,
      }}>
        {gridElements}
        {barElements}
      </div>
    </div>
  );
};

const ChartComponent = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
  const props = item.props || {};

  // Editable properties
  const titleText = props.titleText || 'Monthly Learner Signups';
  const bgColor = props.bgColor || '#212038';
  const barColorStart = props.barColorStart || '#bd53aa';
  const barColorEnd = props.barColorEnd || '#a191e6';
  const xLabelsStr = props.xLabels || 'Jan, Feb, Mar, Apr, May, Jun';
  const dataValuesStr = props.dataValues || '1.2, 1.8, 2.4, 3.1, 4.2, 5.8';
  const yMax = parseFloat(props.yMax || '7');
  const yAxisSteps = parseInt(props.yAxisSteps || '7', 10);
  const valueSuffix = props.valueSuffix || 'K';
  const fontFamily = props.fontFamily || '"Noto Sans SC", sans-serif';

  // Responsive scaling
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  // Data parsing
  const labels = xLabelsStr.split(',').map((s) => s.trim());
  const values = dataValuesStr.split(',').map((s) => {
    const val = parseFloat(s.trim());
    return isNaN(val) ? 0 : val;
  });

  // Layout configuration
  const chartWidth = 1400;
  const chartHeight = 600;
  const chartLeft = 280;
  const chartTop = 320;

  // Safe spring helper
  const safeFps = fps || 30;
  const safeSpring = (delay = 0, config = {damping: 15}) => {
    return spring({frame: Math.max(0, frame - delay), fps: safeFps, config});
  };

  // Global Animations
  const titleSpring = safeSpring(5, {damping: 16});
  const titleOp = titleSpring;
  const titleY = interpolate(titleSpring, [0, 1], [40, 0]);

  const gridFade = safeSpring(15, {damping: 20});

  // Grid lines generation
  const stepsCount = yAxisSteps > 0 ? yAxisSteps : 7;
  const gridLines = Array.from({length: stepsCount + 1}).map((_, i) => {
    const percent = i / stepsCount;
    const yVal = yMax * percent;
    const isBase = i === 0;
    return {percent, yVal, isBase, key: `grid-${i}`};
  });

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: bgColor,
    fontFamily: fontFamily,
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
  };

  const titleStyle = {
    position: 'absolute',
    left: chartLeft - 60,
    top: 120,
    fontSize: 64,
    fontWeight: 800,
    color: '#FFFFFF',
    letterSpacing: '2px',
    opacity: titleOp,
    transform: `translateY(${titleY}px)`,
  };

  const chartContainerStyle = {
    position: 'absolute',
    left: chartLeft,
    top: chartTop,
    width: chartWidth,
    height: chartHeight,
  };

  return (
    <div style={rootStyle}>
      <div style={titleStyle}>{titleText}</div>

      <div style={chartContainerStyle}>
        {/* Grid and Y-Axis */}
        {gridLines.map((line) => (
          <div
            key={line.key}
            style={{
              position: 'absolute',
              bottom: `${line.percent * 100}%`,
              width: '100%',
              height: 1,
              backgroundColor: line.isBase
                ? 'rgba(255, 255, 255, 0.4)'
                : 'rgba(255, 255, 255, 0.08)',
              opacity: gridFade,
            }}
          >
            <div
              style={{
                position: 'absolute',
                left: -120,
                top: -16,
                width: 100,
                textAlign: 'right',
                color: 'rgba(255, 255, 255, 0.6)',
                fontSize: 22,
                fontWeight: 500,
              }}
            >
              {line.yVal % 1 === 0 ? line.yVal : line.yVal.toFixed(1)}
              {valueSuffix}
            </div>
          </div>
        ))}

        {/* Bars and X-Axis */}
        <div
          style={{
            display: 'flex',
            justifyContent: 'space-around',
            alignItems: 'flex-end',
            width: '100%',
            height: '100%',
            position: 'absolute',
            top: 0,
            left: 0,
            padding: '0 40px',
            boxSizing: 'border-box',
          }}
        >
          {values.map((v, i) => {
            const delay = 20 + i * 8;
            const barSpring = safeSpring(delay, {damping: 14, mass: 0.8});
            const animatedHeight = barSpring * (v / Math.max(yMax, 0.1)) * chartHeight;

            const textOp = interpolate(barSpring, [0.6, 1], [0, 1], {
              extrapolateRight: 'clamp',
              extrapolateLeft: 'clamp',
            });
            const textY = interpolate(barSpring, [0.6, 1], [15, 0], {
              extrapolateRight: 'clamp',
              extrapolateLeft: 'clamp',
            });

            return (
              <div
                key={`bar-${i}`}
                style={{
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'flex-end',
                  height: '100%',
                  position: 'relative',
                  width: 120,
                }}
              >
                {/* Value Label Above Bar */}
                <div
                  style={{
                    opacity: textOp,
                    transform: `translateY(${textY}px)`,
                    marginBottom: 16,
                    fontSize: 34,
                    fontWeight: 'bold',
                    color: '#FFFFFF',
                  }}
                >
                  {v}
                  <span style={{fontSize: 20, opacity: 0.8, marginLeft: 2}}>{valueSuffix}</span>
                </div>

                {/* Bar */}
                <div
                  style={{
                    width: 80,
                    height: Math.max(animatedHeight, 0),
                    background: `linear-gradient(to top, ${barColorStart}, ${barColorEnd})`,
                    borderTopLeftRadius: 20,
                    borderTopRightRadius: 20,
                    boxShadow: '0 10px 30px -10px rgba(161,145,230, 0.3)',
                  }}
                />

                {/* X-Axis Label */}
                <div
                  style={{
                    position: 'absolute',
                    bottom: -60,
                    textAlign: 'center',
                    width: '100%',
                    fontSize: 26,
                    fontWeight: 600,
                    color: 'rgba(255, 255, 255, 0.8)',
                    opacity: gridFade,
                  }}
                >
                  {labels[i] || ''}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

