};

const ChartComponent = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
  const safeFps = fps || 30;

  const props = item.props || {};
  const titleText = props.titleText || 'Weekly Taste Score';
  const kpi1Value = props.kpi1Value || '5%';
  const kpi1Label = props.kpi1Label || 'more variety';
  const kpi2Value = props.kpi2Value || '-3%';
  const kpi2Label = props.kpi2Label || 'more variety';
  const posColor = props.posColor || '#ff8572';
  const negColor = props.negColor || '#8fd6ff';
  const bgColor = props.bgColor || '#E8E6F0';
  const cardColor = props.cardColor || '#FFFFFF';

  const data = [
    { day: 'Sun', value: props.valSun !== undefined ? Number(props.valSun) : 24 },
    { day: 'Mon', value: props.valMon !== undefined ? Number(props.valMon) : 14 },
    { day: 'Tue', value: props.valTue !== undefined ? Number(props.valTue) : -10 },
    { day: 'Wed', value: props.valWed !== undefined ? Number(props.valWed) : -17 },
    { day: 'Thu', value: props.valThu !== undefined ? Number(props.valThu) : -5 },
    { day: 'Fri', value: props.valFri !== undefined ? Number(props.valFri) : 18 },
    { day: 'Sat', value: props.valSat !== undefined ? Number(props.valSat) : 24 },
  ];

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const safeSpring = (delay = 0, config = { damping: 15, mass: 0.8 }) => {
    return spring({ frame: Math.max(0, frame - delay), fps: safeFps, config });
  };

  const cardProgress = safeSpring(5, { damping: 16 });
  const cardOpacity = interpolate(frame, [5, 15], [0, 1], { extrapolateRight: 'clamp' });
  const headerOpacity = interpolate(frame, [15, 25], [0, 1], { extrapolateRight: 'clamp' });
  const headerY = interpolate(frame, [15, 25], [20, 0], { extrapolateRight: 'clamp' });

  // Chart dimensions
  // chartHeight: total height of the chart plotting area (above + below zero line)
  // zeroY: pixel position of the zero baseline from the top of the chart container
  const chartHeight = 420;
  const zeroY = chartHeight / 2; // 210px — zero line is exactly in the middle
  const valueMultiplier = zeroY / 100; // pixels per 1% value

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: bgColor,
    fontFamily: 'Inter, sans-serif',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    overflow: 'hidden',
  };

  const cardStyle = {
    width: 1400,
    height: 800,
    backgroundColor: cardColor,
    borderRadius: 40,
    boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.08)',
    padding: '60px 80px 60px 80px',
    boxSizing: 'border-box',
    position: 'relative',
    transform: `translateY(${(1 - cardProgress) * 50}px)`,
    opacity: cardOpacity,
    overflow: 'hidden',
  };

  const watermarkStyle = {
    position: 'absolute',
    top: '50%',
    left: '50%',
    transform: 'translate(-50%, -50%)',
    fontSize: '500px',
    fontWeight: 800,
    color: 'rgba(0, 0, 0, 0.03)',
    pointerEvents: 'none',
    zIndex: 0,
  };

  return (
    <div style={rootStyle}>
      <div style={cardStyle}>
        <div style={watermarkStyle}>₿</div>

        {/* Header */}
        <div style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          opacity: headerOpacity,
          transform: `translateY(${headerY}px)`,
          zIndex: 10,
          position: 'relative',
        }}>
          <h1 style={{ margin: 0, fontSize: '56px', color: '#0f2e2f', fontWeight: 800, letterSpacing: '-1px' }}>
            {titleText}
          </h1>
          <div style={{ display: 'flex', gap: '60px' }}>
            <div>
              <div style={{ fontSize: '56px', fontWeight: 800, color: posColor, lineHeight: 1 }}>{kpi1Value}</div>
              <div style={{ fontSize: '20px', fontWeight: 500, color: '#577b7a', marginTop: '8px', textTransform: 'uppercase', letterSpacing: '1px' }}>{kpi1Label}</div>
            </div>
            <div>
              <div style={{ fontSize: '56px', fontWeight: 800, color: negColor, lineHeight: 1 }}>{kpi2Value}</div>
              <div style={{ fontSize: '20px', fontWeight: 500, color: '#577b7a', marginTop: '8px', textTransform: 'uppercase', letterSpacing: '1px' }}>{kpi2Label}</div>
            </div>
          </div>
        </div>

        {/* Chart wrapper: chartHeight (bars) + 40px (day labels below zero line) */}
        <div style={{
          marginTop: '60px',
          position: 'relative',
          height: chartHeight + 40,
          zIndex: 10,
          overflow: 'visible',
        }}>
          {/* Y-axis grid lines — all positioned relative to this wrapper using zeroY */}
          {[100, 50, 0, -50, -100].map((tick, i) => {
            // top of this tick line = zeroY - (tick * valueMultiplier)
            const topPos = zeroY - tick * valueMultiplier;
            const isZero = tick === 0;
            const gridOpacity = interpolate(frame, [20 + i * 3, 30 + i * 3], [0, 1], { extrapolateRight: 'clamp' });

            return (
              <div key={tick} style={{
                position: 'absolute',
                top: topPos,
                left: 0,
                right: 0,
                display: 'flex',
                alignItems: 'center',
                transform: 'translateY(-50%)',
                opacity: gridOpacity,
              }}>
                <div style={{
                  width: '60px',
                  textAlign: 'right',
                  paddingRight: '20px',
                  fontSize: '18px',
                  color: '#89a9a8',
                  fontWeight: 600,
                }}>
                  {tick}%
                </div>
                <div style={{
                  flex: 1,
                  height: isZero ? '2px' : '1px',
                  backgroundColor: isZero ? '#89a9a8' : 'transparent',
                  borderTop: isZero ? 'none' : '2px dashed #E2E8F0',
                }} />
              </div>
            );
          })}

          {/* Bars row — same coordinate system as grid, left offset for Y-axis labels */}
          <div style={{
            position: 'absolute',
            top: 0,
            left: '80px',
            right: 0,
            height: chartHeight,
            display: 'flex',
            overflow: 'visible',
          }}>
            {data.map((d, i) => {
              const isPositive = d.value >= 0;
              const barHeight = Math.abs(d.value) * valueMultiplier;
              const barScale = safeSpring(30 + i * 4);
              const labelOpacity = interpolate(frame, [40 + i * 4, 50 + i * 4], [0, 1], { extrapolateRight: 'clamp' });

              // Bar top position (from top of chart container):
              // Positive bar: grows upward from zeroY → top = zeroY - barHeight
              // Negative bar: grows downward from zeroY → top = zeroY
              const barTop = isPositive ? zeroY - barHeight : zeroY;

              return (
                <div key={d.day} style={{ flex: 1, position: 'relative', display: 'flex', justifyContent: 'center', overflow: 'visible' }}>
                  {/* Bar */}
                  <div style={{
                    position: 'absolute',
                    top: barTop,
                    width: '64px',
                    height: Math.max(barHeight, 2),
                    backgroundColor: isPositive ? posColor : negColor,
                    borderRadius: isPositive ? '12px 12px 0 0' : '0 0 12px 12px',
                    transformOrigin: isPositive ? 'bottom center' : 'top center',
                    transform: `scaleY(${barScale})`,
                  }} />

                  {/* Day label — below zero line for positive bars, below bar bottom for negative bars */}
                  <div style={{
                    position: 'absolute',
                    top: isPositive ? zeroY + 12 : barTop + barHeight + 12,
                    fontSize: '20px',
                    fontWeight: 600,
                    color: '#577b7a',
                    opacity: labelOpacity,
                    whiteSpace: 'nowrap',
                  }}>
                    {d.day}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

const WarmthChart = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const props = item.props || {};

  const titleText = props.titleText;
  const fontFamily = props.fontFamily;
  const textColor = props.textColor;
  const subtextColor = props.subtextColor;
  const backgroundColor = props.backgroundColor;
  const transparentBackground = props.transparentBackground;

  const g1Phone = props.g1Phone;
  const g1Chip = props.g1Chip;
  const g2Phone = props.g2Phone;
  const g2Chip = props.g2Chip;
  const g3Phone = props.g3Phone;
  const g3Chip = props.g3Chip;

  const singleColorStart = props.singleColorStart;
  const singleColorEnd = props.singleColorEnd;
  const multiColorStart = props.multiColorStart;
  const multiColorEnd = props.multiColorEnd;

  const g1Single = props.g1Single;
  const g1Multi  = props.g1Multi;
  const g2Single = props.g2Single;
  const g2Multi  = props.g2Multi;
  const g3Single = props.g3Single;
  const g3Multi  = props.g3Multi;

  const BAR_MAX_PX = 1066;
  const BAR_MIN_PX = 140;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const bgColor = transparentBackground
    ? 'transparent'
    : interpolateColors(Math.min(frame, 15), [0, 15], ['#000000', backgroundColor]);

  const rootStyle = {
    position: 'absolute',
    top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: bgColor,
    fontFamily: fontFamily,
    overflow: 'hidden',
  };

  const titleSpring = spring({ frame: Math.max(0, frame - 9), fps, config: { damping: 28, stiffness: 200, mass: 1 }, overshootClamping: true });
  const titleOpacity = Math.min(1, titleSpring / 0.4);
  const titleTranslateY = (1 - titleSpring) * 20;

  const SAFE_H = 192;
  const SAFE_V = 108;
  const CONTENT_LEFT = SAFE_H;
  const CONTENT_RIGHT = DESIGN_WIDTH - SAFE_H;
  const CONTENT_TOP = SAFE_V;
  const CONTENT_BOTTOM = DESIGN_HEIGHT - SAFE_V;
  const CONTENT_W = CONTENT_RIGHT - CONTENT_LEFT;
  const PHONE_COL_W = 360;
  const LABEL_COL_W = 110;
  const MAX_SCORE = Math.max(g1Single, g1Multi, g2Single, g2Multi, g3Single, g3Multi);

  const TITLE_TOP = CONTENT_TOP + 10;
  const GROUPS_TOP = CONTENT_TOP + 100;
  const GROUP_H = Math.floor((CONTENT_BOTTOM - GROUPS_TOP) / 3);
  const GROUP_Y = [
    GROUPS_TOP,
    GROUPS_TOP + GROUP_H,
    GROUPS_TOP + GROUP_H * 2,
  ];

  const BAR_HEIGHT = 58;
  const NUM_FONTSIZE = 36;
  const LABEL_FONTSIZE = 21;

  const groups = [
    {
      id: 1, phone: g1Phone, chip: g1Chip,
      single: g1Single, multi: g1Multi,
      textStart: 24, singleStart: 30, multiStart: 54,
      y: GROUP_Y[0],
    },
    {
      id: 2, phone: g2Phone, chip: g2Chip,
      single: g2Single, multi: g2Multi,
      textStart: 84, singleStart: 90, multiStart: 114,
      y: GROUP_Y[1],
    },
    {
      id: 3, phone: g3Phone, chip: g3Chip,
      single: g3Single, multi: g3Multi,
      textStart: 144, singleStart: 150, multiStart: 174,
      y: GROUP_Y[2],
    },
  ];

  return (
    <div style={rootStyle}>
      {!transparentBackground && (
        <>
          <div style={{
            position: 'absolute', top: GROUP_Y[1] - 4, left: CONTENT_LEFT, width: CONTENT_W,
            height: 1, backgroundColor: '#cccccc', opacity: titleOpacity,
          }} />
          <div style={{
            position: 'absolute', top: GROUP_Y[2] - 4, left: CONTENT_LEFT, width: CONTENT_W,
            height: 1, backgroundColor: '#cccccc', opacity: titleOpacity,
          }} />
        </>
      )}

      <h1 style={{
        position: 'absolute', top: TITLE_TOP, left: CONTENT_LEFT, width: CONTENT_W,
        textAlign: 'center', fontSize: 52, fontWeight: 800, color: textColor,
        margin: 0, opacity: titleOpacity,
        transform: `translateY(${titleTranslateY}px)`,
        letterSpacing: '-1px',
      }}>
        {titleText}
      </h1>

      {groups.map((g) => {
        const textSpring = spring({ frame: Math.max(0, frame - g.textStart), fps, config: { damping: 28, stiffness: 200, mass: 1 }, overshootClamping: true });
        const textOpacity = Math.min(1, textSpring / 0.4);
        const textX = (1 - textSpring) * -24;

        const chipFrame = Math.max(0, frame - (g.textStart + 8));
        const chipRaw = Math.min(1, chipFrame / 12);
        const chipEased = 1 - Math.pow(1 - chipRaw, 3);
        const chipOpacity = chipEased;
        const chipBlur = Math.max(0, (1 - chipEased) * 4);
        const chipY = (1 - chipEased) * 10;

        const singleSpring = spring({ frame: Math.max(0, frame - g.singleStart), fps, config: { damping: 20, stiffness: 90, mass: 1 }, overshootClamping: true });
        const multiSpring = spring({ frame: Math.max(0, frame - g.multiStart), fps, config: { damping: 20, stiffness: 90, mass: 1 }, overshootClamping: true });

        const singleTargetW = Math.min(BAR_MAX_PX, Math.max(BAR_MIN_PX, (g.single / MAX_SCORE) * BAR_MAX_PX));
        const multiTargetW  = Math.min(BAR_MAX_PX, Math.max(BAR_MIN_PX, (g.multi  / MAX_SCORE) * BAR_MAX_PX));

        const singleWidth = singleSpring * singleTargetW;
        const multiWidth = multiSpring * multiTargetW;

        const singleNumRaw = interpolate(singleSpring, [0.7, 1], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
        const singleEased = 1 - Math.pow(1 - singleNumRaw, 3);
        const singleCurrent = Math.round(singleEased * g.single);

        const multiNumRaw = interpolate(multiSpring, [0.7, 1], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
        const multiEased = 1 - Math.pow(1 - multiNumRaw, 3);
        const multiCurrent = Math.round(multiEased * g.multi);

        const labelOpacity = textOpacity;

        const renderBar = (label, width, gradStart, gradEnd, numProgress, current) => (
          <div style={{ display: 'flex', alignItems: 'center', height: BAR_HEIGHT }}>
            <div style={{
              width: LABEL_COL_W,
              textAlign: 'right',
              paddingRight: 12,
              boxSizing: 'border-box',
              fontSize: LABEL_FONTSIZE,
              fontWeight: 700,
              color: gradStart,
              opacity: labelOpacity,
              flexShrink: 0,
            }}>
              {label}
            </div>

            <div style={{
              height: BAR_HEIGHT,
              width: Math.max(0, width),
              background: `linear-gradient(90deg, ${gradStart}, ${gradEnd})`,
              borderRadius: BAR_HEIGHT / 2,
              position: 'relative',
              overflow: 'hidden',
              flexShrink: 0,
            }}>
              {numProgress > 0 && (
                <div style={{
                  position: 'absolute',
                  left: 20,
                  top: 0,
                  height: '100%',
                  display: 'flex',
                  alignItems: 'center',
                }}>
                  <span style={{
                    color: '#fff',
                    fontWeight: 800,
                    fontSize: NUM_FONTSIZE,
                    textShadow: '0 1px 4px rgba(0,0,0,0.25)',
                    letterSpacing: '-0.5px',
                  }}>
                    {current.toLocaleString()}
                  </span>
                </div>
              )}
            </div>
          </div>
        );

        return (
          <div key={g.id} style={{
            position: 'absolute',
            top: g.y,
            left: CONTENT_LEFT,
            width: CONTENT_W,
            height: GROUP_H,
            display: 'flex',
            alignItems: 'center',
          }}>
            <div style={{ width: PHONE_COL_W, flexShrink: 0, display: 'flex', flexDirection: 'column', gap: 6 }}>
              <div style={{
                opacity: textOpacity,
                transform: `translateX(${textX}px)`,
                fontSize: 34, fontWeight: 800, color: textColor, lineHeight: 1, whiteSpace: 'nowrap',
              }}>{g.phone}</div>
              <div style={{
                opacity: chipOpacity,
                transform: `translateY(${chipY}px) translateZ(0)`,
                filter: `blur(${chipBlur}px)`,
                willChange: 'transform, opacity, filter',
                fontSize: 18, fontWeight: 500, color: subtextColor, whiteSpace: 'nowrap',
              }}>{g.chip}</div>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: 18 }}>
              {renderBar('Price', singleWidth, singleColorStart, singleColorEnd, singleNumRaw, singleCurrent)}
              {renderBar('Ambiance', multiWidth, multiColorStart, multiColorEnd, multiNumRaw, multiCurrent)}
            </div>
          </div>
        );
      })}
    </div>
  );
};

