  const titleOpacity = Math.min(1, titleSpring / 0.4);
  const titleTranslateY = (1 - titleSpring) * 20;

  // Layout — 10% safe zone on all sides: left/right 192px, top/bottom 108px
  const SAFE_H = 192;  // horizontal margin
  const SAFE_V = 108;  // vertical margin
  const CONTENT_LEFT = SAFE_H;        // 192px from left
  const CONTENT_RIGHT = DESIGN_WIDTH - SAFE_H;  // 1728px
  const CONTENT_TOP = SAFE_V;         // 108px from top
  const CONTENT_BOTTOM = DESIGN_HEIGHT - SAFE_V; // 972px
  const CONTENT_W = CONTENT_RIGHT - CONTENT_LEFT; // 1536px
  const PHONE_COL_W = 360;  // wider to accommodate longer names
  const LABEL_COL_W = 110;
  // Reference score: the highest possible value maps to BAR_MAX_PX
  const MAX_SCORE = Math.max(g1Single, g1Multi, g2Single, g2Multi, g3Single, g3Multi);

  // Vertical layout: title + 3 groups evenly distributed within safe zone
  // Title area ~80px, remaining ~784px split into 3 groups of ~240px each with 32px gaps
  const TITLE_TOP = CONTENT_TOP + 10;
  const GROUPS_TOP = CONTENT_TOP + 100;
  const GROUP_H = Math.floor((CONTENT_BOTTOM - GROUPS_TOP) / 3); // ~257px each
  const GROUP_Y = [
    GROUPS_TOP,
    GROUPS_TOP + GROUP_H,
    GROUPS_TOP + GROUP_H * 2,
  ];

  const BAR_HEIGHT = 58;
  const NUM_FONTSIZE = 36;          // large bold number inside bar
  const LABEL_FONTSIZE = 21;        // bar label outside bar

  const groups = [
    {
      id: 1, phone: g1Phone, chip: g1Chip,
      single: g1Single, multi: g1Multi,
      textStart: 24, singleStart: 30, multiStart: 54,
      y: GROUP_Y[0],
    },
    {
      id: 2, phone: g2Phone, chip: g2Chip,
      single: g2Single, multi: g2Multi,
      textStart: 84, singleStart: 90, multiStart: 114,
      y: GROUP_Y[1],
    },
    {
      id: 3, phone: g3Phone, chip: g3Chip,
      single: g3Single, multi: g3Multi,
      textStart: 144, singleStart: 150, multiStart: 174,
      y: GROUP_Y[2],
    },
  ];

  return (
    <div style={rootStyle}>
      {/* Divider lines */}
      {!transparentBackground && (
        <>
          <div style={{
            position: 'absolute', top: GROUP_Y[1] - 4, left: CONTENT_LEFT, width: CONTENT_W,
            height: 1, backgroundColor: '#cccccc', opacity: titleOpacity,
          }} />
          <div style={{
            position: 'absolute', top: GROUP_Y[2] - 4, left: CONTENT_LEFT, width: CONTENT_W,
            height: 1, backgroundColor: '#cccccc', opacity: titleOpacity,
          }} />
        </>
      )}

      {/* Title */}
      <h1 style={{
        position: 'absolute', top: TITLE_TOP, left: CONTENT_LEFT, width: CONTENT_W,
        textAlign: 'center', fontSize: 52, fontWeight: 800, color: textColor,
        margin: 0, opacity: titleOpacity,
        transform: `translateY(${titleTranslateY}px)`,
        letterSpacing: '-1px',
      }}>
        {titleText}
      </h1>

      {groups.map((g) => {
        // Phone name: slide in from left — direct spring math, no interpolate mapping
        const textSpring = spring({ frame: Math.max(0, frame - g.textStart), fps, config: { damping: 28, stiffness: 200, mass: 1 }, overshootClamping: true });
        const textOpacity = Math.min(1, textSpring / 0.4);
        const textX = (1 - textSpring) * -24;

        // Chip subtitle: slide up + fade in
        // Using interpolate with easing instead of spring to avoid oscillation artifacts
        const chipFrame = Math.max(0, frame - (g.textStart + 8));
        const chipRaw = Math.min(1, chipFrame / 12); // 12 frames = 0.4s, linear 0→1
        const chipEased = 1 - Math.pow(1 - chipRaw, 3); // easeOutCubic — no oscillation possible
        const chipOpacity = chipEased;
        const chipBlur = Math.max(0, (1 - chipEased) * 4);
        const chipY = (1 - chipEased) * 10;

        const singleSpring = spring({ frame: Math.max(0, frame - g.singleStart), fps, config: { damping: 20, stiffness: 90, mass: 1 }, overshootClamping: true });
        const multiSpring = spring({ frame: Math.max(0, frame - g.multiStart), fps, config: { damping: 20, stiffness: 90, mass: 1 }, overshootClamping: true });

        // Target widths proportional to score, hard-clamped so bars never overflow or get too thin
        const singleTargetW = Math.min(BAR_MAX_PX, Math.max(BAR_MIN_PX, (g.single / MAX_SCORE) * BAR_MAX_PX));
        const multiTargetW  = Math.min(BAR_MAX_PX, Math.max(BAR_MIN_PX, (g.multi  / MAX_SCORE) * BAR_MAX_PX));

        const singleWidth = singleSpring * singleTargetW;
        const multiWidth = multiSpring * multiTargetW;

        // Number roll: easeOut curve — fast start, slow finish
        // t goes 0→1 linearly, easeOut(t) = 1 - (1-t)^3 accelerates early, decelerates at end
        const singleNumRaw = interpolate(singleSpring, [0.7, 1], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
        const singleEased = 1 - Math.pow(1 - singleNumRaw, 3);
        const singleCurrent = Math.round(singleEased * g.single);

        const multiNumRaw = interpolate(multiSpring, [0.7, 1], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
        const multiEased = 1 - Math.pow(1 - multiNumRaw, 3);
        const multiCurrent = Math.round(multiEased * g.multi);

        const labelOpacity = textOpacity; // labels fade in with the group text

        const renderBar = (label, width, gradStart, gradEnd, numProgress, current) => (
          <div style={{ display: 'flex', alignItems: 'center', height: BAR_HEIGHT }}>
            {/* Label OUTSIDE bar, fixed width column */}
            <div style={{
              width: LABEL_COL_W,
              textAlign: 'right',
              paddingRight: 12,
              boxSizing: 'border-box',
              fontSize: LABEL_FONTSIZE,
              fontWeight: 700,
              color: gradStart,
              opacity: labelOpacity,
              flexShrink: 0,
            }}>
              {label}
            </div>

            {/* Bar with number inside */}
            <div style={{
              height: BAR_HEIGHT,
              width: Math.max(0, width),
              background: `linear-gradient(90deg, ${gradStart}, ${gradEnd})`,
              borderRadius: BAR_HEIGHT / 2,
              position: 'relative',
              overflow: 'hidden',
              flexShrink: 0,
            }}>
              {/* Number inside bar, left-aligned */}
              {numProgress > 0 && (
                <div style={{
                  position: 'absolute',
                  left: 20,
                  top: 0,
                  height: '100%',
                  display: 'flex',
                  alignItems: 'center',
                }}>
                  <span style={{
                    color: '#fff',
                    fontWeight: 800,
                    fontSize: NUM_FONTSIZE,
                    textShadow: '0 1px 4px rgba(0,0,0,0.25)',
                    letterSpacing: '-0.5px',
                  }}>
                    {current.toLocaleString()}
                  </span>
                </div>
              )}
            </div>
          </div>
        );

        return (
          <div key={g.id} style={{
            position: 'absolute',
            top: g.y,
            left: CONTENT_LEFT,
            width: CONTENT_W,
            height: GROUP_H,
            display: 'flex',
            alignItems: 'center',
          }}>
            {/* Phone name + chip — animated independently */}
            <div style={{ width: PHONE_COL_W, flexShrink: 0, display: 'flex', flexDirection: 'column', gap: 6 }}>
              {/* Phone name: slides in from left */}
              <div style={{
                opacity: textOpacity,
                transform: `translateX(${textX}px)`,
                fontSize: 34, fontWeight: 800, color: textColor, lineHeight: 1, whiteSpace: 'nowrap',
              }}>{g.phone}</div>
              {/* Chip subtitle: slides up after phone name, with blur+fade pre-reveal */}
              <div style={{
                opacity: chipOpacity,
                transform: `translateY(${chipY}px) translateZ(0)`,
                filter: `blur(${chipBlur}px)`,
                willChange: 'transform, opacity, filter',
                fontSize: 18, fontWeight: 500, color: subtextColor, whiteSpace: 'nowrap',
              }}>{g.chip}</div>
            </div>

            {/* Bar rows */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: 18 }}>
              {renderBar('Price', singleWidth, singleColorStart, singleColorEnd, singleNumRaw, singleCurrent)}
              {renderBar('Ambiance', multiWidth, multiColorStart, multiColorEnd, multiNumRaw, multiCurrent)}
            </div>
          </div>
        );
      })}
    </div>
  );
};

const WeatherDataBoard = ({item}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const props = item.props || {};

  // Properties
  const tempValue = props.tempValue || '-12.5°';
  const pressureValue = props.pressureValue || '1008.6 hPa';
  const labelText = props.labelText || 'FIELD SENSOR';
  const readingText = props.readingText || 'READING: 0083';
  const accentColor = props.accentColor || '#ffd4f5';
  const primaryFont = props.primaryFont || 'IBM Plex Mono, monospace';
  const labelFont = props.labelFont || 'Inter, sans-serif';
  const logoUrl = props.logoUrl || '';
  const showGrid = props.showGrid !== false;

  // Canvas Config
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // Animation Helpers
  const safeSpring = (delay) => spring({
    frame: frame - delay,
    fps,
    config: { damping: 15, stiffness: 120, mass: 0.8 }
  });

  // Staggered Character Reveal Component
  const RollingText = ({ text, delayOffset = 0, style, fontSize, item }) => {
    return (
      <div style={{ display: 'flex', flexDirection: 'row', overflow: 'hidden', ...style }}>
        {text.split('').map((char, i) => {
          const delay = delayOffset + (i * 3);
          const progress = safeSpring(delay);

          const translateY = interpolate(progress, [0, 1], [100, 0]);
          const opacity = interpolate(progress, [0, 1], [0, 1]);

          return (
            <span 
              key={i} 
              style={{ 
                display: 'inline-block', 
                transform: `translateY(${translateY}%)`, 
                opacity,
                fontSize,
                whiteSpace: 'pre',
                lineHeight: 1
              }}
            >
              {char}
            </span>
          );
        })}
      </div>
    );
  };

  // Entrance for static elements
  const opacitySpring = spring({ frame, fps, config: { damping: 20 } });
  const lineProgress = spring({ frame: frame - 10, fps, config: { damping: 200, mass: 5 } }); // Slow draw

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    backgroundColor: '#080808',
    color: 'white',
    fontFamily: labelFont,
    overflow: 'hidden',
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
  };

  // Topographic Lines (Simulated with SVG)
  const pathStyle = {
    fill: 'none',
    stroke: '#FFFFFF',
    strokeWidth: 1.5,
    opacity: 0.08,
    strokeDasharray: 3000,
    strokeDashoffset: interpolate(lineProgress, [0, 1], [3000, 0]),
  };

  return (
    <div style={rootStyle}>
      {/* Background Texture: Topographic Lines */}
      <svg width={DESIGN_WIDTH} height={DESIGN_HEIGHT} style={{ position: 'absolute', top: 0, left: 0 }}>
        <path d="M-100,400 C400,200 800,600 1200,500 S1800,200 2100,400" style={pathStyle} />
        <path d="M-100,600 C500,400 900,800 1300,700 S1900,400 2100,600" style={{...pathStyle, strokeDashoffset: interpolate(lineProgress, [0, 1], [3000, 500])}} />
        <path d="M-100,800 C600,700 1000,950 1400,850 S2000,600 2100,800" style={{...pathStyle, strokeDashoffset: interpolate(lineProgress, [0, 1], [3000, 1000])}} />
        <path d="M-100,200 C300,100 700,300 1100,200 S1700,50 2100,150" style={{...pathStyle, strokeDashoffset: interpolate(lineProgress, [0, 1], [3000, 200])}} />
        <path d="M500,0 C600,300 400,600 600,1080" style={{...pathStyle, opacity: 0.05}} />
        <path d="M1500,0 C1400,300 1600,600 1400,1080" style={{...pathStyle, opacity: 0.05}} />
      </svg>

      {/* Crosshair Grid */}
      {showGrid && (
        <div style={{ position: 'absolute', inset: 0, opacity: 0.15 }}>
          <div style={{ position: 'absolute', top: '50%', left: 0, right: 0, height: 1, backgroundColor: 'white' }} />
          <div style={{ position: 'absolute', left: '33%', top: 0, bottom: 0, width: 1, backgroundColor: 'white' }} />
          <div style={{ position: 'absolute', left: '66%', top: 0, bottom: 0, width: 1, backgroundColor: 'white' }} />
          {/* Crosses */}
          {[33, 66].map(x => (
             <div key={x} style={{ position: 'absolute', left: `${x}%`, top: '50%', width: 40, height: 40, transform: 'translate(-50%, -50%)' }}>
               <div style={{ position: 'absolute', top: 19, left: 0, right: 0, height: 2, backgroundColor: 'white' }} />
               <div style={{ position: 'absolute', left: 19, top: 0, bottom: 0, width: 2, backgroundColor: 'white' }} />
             </div>
          ))}
        </div>
      )}

      {/* Logo Area */}
      <div style={{ position: 'absolute', top: 60, right: 80, opacity: opacitySpring }}>
        {logoUrl ? (
          <Img src={logoUrl} style={{ height: 60, width: 'auto', objectFit: 'contain' }} />
        ) : (
          <div style={{ 
            width: 60, height: 60, border: '2px solid white', borderRadius: '50%', 
            display: 'flex', alignItems: 'center', justifyContent: 'center' 
          }}>
            <div style={{ width: 10, height: 10, backgroundColor: accentColor, borderRadius: '50%' }} />
