        {/* Label 1 */}
        <div style={{ 
          fontSize: 24, 
          letterSpacing: '0.15em', 
          fontWeight: 500, 
          marginBottom: 10, 
          opacity: opacitySpring,
          display: 'flex', alignItems: 'center', gap: 15
        }}>
           <div style={{ width: 40, height: 2, backgroundColor: accentColor }} />
           {labelText}
        </div>

        {/* Temperature */}
        <RollingText 
          text={tempValue} 
          fontSize={180} 
          delayOffset={10} 
          style={{ 
            fontFamily: primaryFont, 
            fontWeight: 700, 
            color: accentColor,
            marginBottom: -20
          }} 
        />

        {/* Pressure */}
        <RollingText 
          text={pressureValue} 
