      </div>

    </div>
  );
};

const BudgetPieChart = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // --- Editable Properties ---
  const props = item.props || {};
  const titleText = props.titleText || 'Content Budget Mix';
  const mainFont = props.mainFont || 'Inter, sans-serif';
  const accentFont = props.accentFont || 'Inter, sans-serif';
  const bgColor = props.bgColor || '#E8E6F0';
  const cardColor = props.cardColor || '#ffffff';
  const textColor = props.textColor || '#2D3436';

  // Segment Data (5 Segments)
  const segments = [
    {
      label: props.seg1Label || 'Licensing',
      value: props.seg1Value !== undefined ? Number(props.seg1Value) : 24,
      color: props.seg1Color || '#2eeacf', // Cyan — matches 柱状图1/3, 饼状图1
    },
    {
      label: props.seg2Label || 'Promotion',
      value: props.seg2Value !== undefined ? Number(props.seg2Value) : 20,
      color: props.seg2Color || '#009c47', // Blue — matches 柱状图1, 饼状图1
    },
    {
      label: props.seg3Label || 'Tech',
      value: props.seg3Value !== undefined ? Number(props.seg3Value) : 7,
      color: props.seg3Color || '#d4a800', // Orange — matches 柱状图2/3, 折线图2
    },
    {
      label: props.seg4Label || 'Payouts',
      value: props.seg4Value !== undefined ? Number(props.seg4Value) : 3,
      color: props.seg4Color || '#009dd9', // Pink-Red — matches 折线图3
    },
    {
      label: props.seg5Label || 'Support',
      value: props.seg5Value !== undefined ? Number(props.seg5Value) : 27,
      color: props.seg5Color || '#bf5cb8', // Purple — matches 折线图2
    },
  ];

  // --- Layout Constants ---
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  // --- Helpers ---
  const totalValue = segments.reduce((acc, seg) => acc + seg.value, 0);

  // Prepare Slice Data
  let accumulatedAngle = 0;
  const radius = 175;
  const center = { x: 240, y: 240 }; // Center of SVG viewport for pie
  const circumference = 2 * Math.PI * radius;

  const sliceData = segments.map((seg) => {
    const percent = seg.value / totalValue;
    const angle = percent * 360;
    const startAngle = accumulatedAngle;
    accumulatedAngle += angle;
    return {
      ...seg,
      percent,
      angle,
      startAngle,
      strokeLength: circumference * percent,
    };
  });

  // --- Animations ---
  // Entrance spring
  const entrance = spring({
    frame,
    fps,
    config: { damping: 20, stiffness: 90 },
  });

  // Staggered KPI Text
  const kpiOpacity = (index) =>
    spring({
      frame: frame - index * 5,
      fps,
      config: { damping: 20 },
    });

  // Pie Rotation / Draw
  // We animate the 'progress' of the pie drawing from 0 to 1
  const pieProgress = spring({
    frame: frame - 10,
    fps,
    config: { mass: 1, damping: 25, stiffness: 80 },
  });

  // (virus rotation removed — replaced with static dot grid)

  // --- Styles ---
  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    backgroundColor: bgColor,
    fontFamily: mainFont,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    overflow: 'hidden',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
  };

  const cardStyle = {
    position: 'relative',
    width: 1400,
    height: 800,
    backgroundColor: cardColor,
    borderRadius: 40,
    boxShadow: '0 20px 60px rgba(0,0,0,0.08)',
    display: 'flex',
    flexDirection: 'column',
    padding: '60px 80px',
    opacity: entrance,
    transform: `translateY(${interpolate(entrance, [0, 1], [50, 0])}px)`,
    overflow: 'hidden',
    zIndex: 2,
  };

  const headerStyle = {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'flex-start',
    marginBottom: 24,
    zIndex: 5,
  };

  const titleStyle = {
    fontSize: 56,
    fontWeight: 700,
    color: textColor,
    margin: 0,
    letterSpacing: '-0.02em',
  };

  const kpiContainerStyle = {
    display: 'flex',
    gap: 40,
  };

  const contentRowStyle = {
    display: 'flex',
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
    gap: 60,
    position: 'relative',
    zIndex: 5,
  };

  // --- Watermark Component --- dot grid, consistent with 折线图3 style
  const DotGridWatermark = () => {
    const cols = 6, rows = 6, spacing = 22;
    const dots = [];
    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        dots.push(<circle key={`${r}-${c}`} cx={c * spacing} cy={r * spacing} r={3} fill={textColor} />);
      }
    }
    return (
      <svg
        width={cols * spacing}
        height={rows * spacing}
        viewBox={`0 0 ${cols * spacing} ${rows * spacing}`}
        style={{
          position: 'absolute',
          right: 40,
          bottom: 40,
          opacity: 0.07,
          zIndex: 1,
        }}
      >
        {dots}
      </svg>
    );
  };

  // --- Triangle Icon Component ---
  const ArrowIcon = ({ color, item }) => (
    <svg width="16" height="16" viewBox="0 0 24 24" style={{ display: 'inline-block', marginLeft: 6, marginBottom: 2 }}>
      <path d="M12 4l-8 12h16z" fill={color} />
    </svg>
  );

  return (
    <div style={rootStyle}>
      {/* Background Watermark Pattern inside Card Context if needed, or global. Prompt says "Virus icon watermark background light". Put inside card for cleaner look. */}

      <div style={cardStyle}>
        <DotGridWatermark />

        {/* Header Section: Title & KPI Row */}
        <div style={headerStyle}>
          <div>
            <h1 style={titleStyle}>{titleText}</h1>
            <div style={{ fontSize: 24, color: '#888', marginTop: 10 }}>Global Streaming Q3</div>
          </div>

          {/* KPI summary removed — info already in right-side legend */}
        </div>

        {/* Main Chart Area */}
        <div style={contentRowStyle}>
          {/* Pie Chart SVG */}
          <svg width="480" height="480" viewBox="0 0 480 480">
            {/* Base Circle (Track) */}
            <circle cx="240" cy="240" r={radius} fill="none" stroke="#f0f0f0" strokeWidth="60" />

            {/* Animated Segments */}
            {sliceData.map((seg, i) => {
              // Calculate DASH ARRAY for animation
              // We want to simulate "drawing" the circle. 
              // The stroke-dasharray will be [length, circumference]. 
              // The rotation places it correctly.

              // To animate drawing from 0: interpolate dasharray or use a mask.
              // Simplest approach with stroke-dasharray: 
              // The segment length is `seg.strokeLength`. 
              // We animate the rendered length from 0 to seg.strokeLength * pieProgress.

              const currentLength = seg.strokeLength * pieProgress;
              const gapLength = circumference - currentLength;

              return (
                <circle
                  key={i}
                  cx="240"
                  cy="240"
                  r={radius}
                  fill="none"
                  stroke={seg.color}
                  strokeWidth="60"
                  strokeDasharray={`${currentLength} ${gapLength}`}
                  strokeDashoffset={0} // We rotate the element instead of offsetting the dash for start position
                  transform={`rotate(${-90 + seg.startAngle} 240 240)`}
                  style={{ opacity: pieProgress > 0.05 ? 1 : 0 }}
                />
              );
            })}

            {/* Center Text/Icon inside Donut */}
            <g opacity={Math.max(0, pieProgress - 0.2)}>
                <text
                    x="240" y="228"
                    textAnchor="middle"
                    fill="#333"
                    fontSize="20"
                    fontWeight="600"
                    fontFamily={mainFont}
                >
                    TOTAL
                </text>
                <text
                    x="240" y="270"
                    textAnchor="middle"
                    fill="#333"
                    fontSize="40"
                    fontWeight="800"
                    fontFamily={accentFont}
                >
                    {totalValue}%
                </text>
            </g>
          </svg>

          {/* Legend / Detailed Labels */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: 24, minWidth: 300 }}>
            {sliceData.map((seg, i) => {
                const labelEntrance = spring({ frame: frame - 15 - (i * 3), fps, config: { damping: 20 } });
                return (
                  <div 
                    key={i} 
                    style={{ 
                        display: 'flex', 
                        alignItems: 'center', 
                        gap: 15,
                        opacity: labelEntrance,
                        transform: `translateX(${interpolate(labelEntrance, [0, 1], [30, 0])}px)`
                    }}
                  >
                    {/* Color indicator dot */}
                    <div style={{ width: 16, height: 16, borderRadius: '50%', backgroundColor: seg.color }} />

                    {/* Text content */}
                    <div>
                        <div style={{ fontSize: 18, color: '#555', fontWeight: 600 }}>{seg.label}</div>
                        <div style={{ display: 'flex', alignItems: 'center' }}>
