};

const DonutChartInfographic = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const props = item.props || {};
  const titleText = props.titleText || 'Booking Mix';
  const centerMainText = props.centerMainText || '12%';
  const centerSubText = props.centerSubText || 'YoY Bookings';

  const appBgColor = props.appBgColor || '#E8E6F0';
  const cardBgColor = props.cardBgColor || '#FFFFFF';
  const titleColor = props.titleColor || '#2D3436';

  const segments = [
    { value: props.seg1Value ?? 30, label: props.seg1Label || 'Film Studio',   color: props.seg1Color || '#2eeacf' },
    { value: props.seg2Value ?? 54, label: props.seg2Label || 'Photo Studio',   color: props.seg2Color || '#348b12' },
    { value: props.seg3Value ?? 65, label: props.seg3Label || 'Print Studio',    color: props.seg3Color || '#aa8700' },
    { value: props.seg4Value ?? 40, label: props.seg4Label || 'Event Studio', color: props.seg4Color || '#36beff' },
  ];

  const totalValue = segments.reduce((acc, s) => acc + s.value, 0);
  // ViewBox matches container exactly (640×640), no scaling distortion
  const centerXY = 320;
  const radius = 200;
  const strokeWidth = 52;
  const circumference = 2 * Math.PI * radius;
  // Gap must be wider than strokeWidth arc-equivalent to prevent round-cap overlap
  // strokeWidth=52, radius=200 → cap extends 26px → ~7.5° per side → need >15° total
  const gapDeg = 16;
  const gapArcLength = (gapDeg / 360) * circumference;

  const entranceSpring = spring({ frame, fps, config: { damping: 20, stiffness: 100 } });

  const chartProgress = spring({
    frame: Math.max(0, frame - 10),
    fps,
    config: { damping: 30, stiffness: 80 },
  });

  const textReveal = spring({
    frame: Math.max(0, frame - 20),
    fps,
    config: { damping: 20, stiffness: 100 },
  });

  // DNA Helix watermark — restored as original
  const helixDots = new Array(20).fill(0).map((_, i) => {
    const y = i * 40;
    const norm = i / 20;
    const xOffset = Math.sin(norm * Math.PI * 4) * 60;
    return { y, x1: 100 + xOffset, x2: 100 - xOffset, opacity: 0.1 + (1 - norm) * 0.2 };
  });

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    backgroundColor: appBgColor,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontFamily: 'Inter, sans-serif',
    overflow: 'hidden',
  };

  const cardStyle = {
    width: 1400,
    height: 800,
    backgroundColor: cardBgColor,
    borderRadius: 50,
    boxShadow: '0 20px 60px rgba(0,0,0,0.05)',
    position: 'relative',
    display: 'flex',
    flexDirection: 'row',
    padding: '60px 80px',
    boxSizing: 'border-box',
    opacity: entranceSpring,
    transform: `translateY(${(1 - entranceSpring) * 50}px)`,
    overflow: 'hidden',
  };

  const leftColStyle = {
    flex: 1,
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    paddingLeft: 150,
    paddingRight: 20,
    zIndex: 2,
  };

  const rightColStyle = {
    flex: 1,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    position: 'relative',
    zIndex: 2,
  };

  const titleStyle = {
    fontSize: 56,
    fontWeight: 800,
    color: titleColor,
    marginBottom: 60,
    letterSpacing: '-0.02em',
  };

  let accumulatedRotation = -90;

  return (
    <div style={rootStyle}>
      <div style={cardStyle}>

        {/* DNA Watermark — original style, opacity lowered slightly */}
        <div style={{ position: 'absolute', right: 50, top: '50%', transform: 'translateY(-50%)', opacity: 0.08, zIndex: 0 }}>
          <svg width="200" height="800" viewBox="0 0 200 800">
            {helixDots.map((dot, i) => (
              <React.Fragment key={i}>
                <circle cx={dot.x1} cy={dot.y} r={8} fill="#a6b6ad" opacity={dot.opacity} />
                <circle cx={dot.x2} cy={dot.y} r={8} fill="#a6b6ad" opacity={dot.opacity} />
                <line x1={dot.x1} y1={dot.y} x2={dot.x2} y2={dot.y} stroke="#a6b6ad" strokeWidth="2" opacity={dot.opacity * 0.5} />
              </React.Fragment>
            ))}
          </svg>
        </div>

        {/* Left Column: Title & Legend */}
        <div style={leftColStyle}>
          <h1 style={titleStyle}>{titleText}</h1>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 30 }}>
            {segments.map((seg, i) => {
              const percentage = Math.round((seg.value / totalValue) * 100);
              const delay = i * 5 + 10;
              const itemSpring = spring({ frame: Math.max(0, frame - delay), fps, config: { damping: 15 } });
              return (
                <div key={i} style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 20,
                  opacity: itemSpring,
                  transform: `translateX(${(1 - itemSpring) * -30}px)`,
                }}>
                  <div style={{
                    width: 24, height: 24, borderRadius: '50%',
                    backgroundColor: seg.color, flexShrink: 0,
                    boxShadow: `0 4px 10px ${seg.color}66`,
                  }} />
                  <span style={{ fontSize: 32, fontWeight: 700, color: titleColor, minWidth: 90 }}>{percentage}%</span>
                  <span style={{ fontSize: 28, fontWeight: 500, color: '#636e72' }}>{seg.label}</span>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Column: Donut Chart */}
        <div style={rightColStyle}>
          <div style={{ position: 'relative', width: 640, height: 640 }}>

            {/* Center Text */}
            <div style={{
              position: 'absolute', top: 0, left: 0,
              width: '100%', height: '100%',
              display: 'flex', flexDirection: 'column',
              alignItems: 'center', justifyContent: 'center',
              textAlign: 'center', zIndex: 10, pointerEvents: 'none',
            }}>
              <div style={{
                fontSize: 80, fontWeight: 800, color: titleColor,
                lineHeight: 1,
                opacity: textReveal,
                transform: `scale(${0.8 + 0.2 * textReveal})`,
              }}>{centerMainText}</div>
              <div style={{
                fontSize: 18, fontWeight: 500, color: '#636e72',
                marginTop: 8, maxWidth: 140, lineHeight: 1.3,
                opacity: textReveal,
                transform: `translateY(${(1 - textReveal) * 20}px)`,
              }}>{centerSubText}</div>
            </div>

            {/* SVG Donut
                Animation: strokeDashoffset goes from segmentLength → 0
                This draws the arc from its start point forward — no shrink, no disappear.
                strokeDasharray is fixed at [segmentLength, circumference] so only this
                segment's arc is ever visible regardless of offset. */}
            <svg width="640" height="640" viewBox="0 0 640 640">
              {segments.map((seg, i) => {
                // Fixed 4° gap — all gaps look the same width regardless of segment size
                const segmentLength = Math.max(0, (seg.value / totalValue) * circumference - gapArcLength);
                const rotation = accumulatedRotation;
                accumulatedRotation += (seg.value / totalValue) * 360;

                const dashOffset = segmentLength * (1 - chartProgress);

                return (
                  <circle
                    key={i}
                    cx={centerXY} cy={centerXY} r={radius}
                    fill="transparent"
                    stroke={seg.color}
                    strokeWidth={strokeWidth}
                    strokeDasharray={`${segmentLength} ${circumference}`}
                    strokeDashoffset={dashOffset}
                    strokeLinecap="round"
                    transform={`rotate(${rotation} ${centerXY} ${centerXY})`}
                  />
                );
              })}
            </svg>
          </div>
        </div>

      </div>
    </div>
  );
};

