  const sourceText = props.sourceText || 'Source: EU Agricultural Statistics Office';

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  // ── Zone layout ──────────────────────────────────────
  // Title zone:  0   → 200
  // Chart zone:  200 → 880  (chartTop=200, chartH=620)
  // Legend zone: 880 → 1080
  const TITLE_ZONE_H = 200;
  const LEGEND_ZONE_TOP = 880;

  const chartLeft = 384;       // 20% of 1920
  const chartWidth = 1152;     // 60% of 1920
  const chartTop = TITLE_ZONE_H + 20;
  const chartHeight = LEGEND_ZONE_TOP - chartTop - 60; // ~600px

  // Chart data
  const labels = ['2015', '2017', '2019', '2021', '2023'];
  const line1Data = [15, 22, 35, 48, 65];  // Organic
  const line2Data = [80, 72, 60, 45, 25];  // Conventional
  const line3Data = [5,  6,  5,  7,  10];  // Local/Farm
  const yTicks = [0, 25, 50, 75, 100];

  const getX = (i) => (i / (labels.length - 1)) * chartWidth;
  const getY = (v) => chartHeight - (v / 100) * chartHeight;

  const makePath = (data) =>
    data.map((d, i) => `${i === 0 ? 'M' : 'L'}${getX(i).toFixed(1)},${getY(d).toFixed(1)}`).join(' ');

  // Calculate actual path length for correct dash animation
  const calcPathLen = (data) => {
    let len = 0;
    for (let i = 1; i < data.length; i++) {
      const dx = getX(i) - getX(i - 1);
      const dy = getY(data[i]) - getY(data[i - 1]);
      len += Math.sqrt(dx * dx + dy * dy);
    }
    return Math.ceil(len) + 20; // +20px buffer for roughpaper filter jitter
  };

  const len1 = calcPathLen(line1Data);
  const len2 = calcPathLen(line2Data);
  const len3 = calcPathLen(line3Data);

  // lineDrawProgress: frame [20,210] → 0~1, spans ~6.3s of the 8s clip
  const lineDrawProgress = interpolate(frame, [20, 210], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.bezier(0.1, 0.6, 0.2, 1),
  });

  // Animations
