  const chartWidth = DESIGN_WIDTH - chartMargin.left - chartMargin.right;
  const chartHeight = DESIGN_HEIGHT - chartMargin.top - chartMargin.bottom;
  const barWidth = 120;
  const barGap = 60;

  // Baseline animation
