        <defs>
          <filter id="paperTex" x="0%" y="0%" width="100%" height="100%">
            <feTurbulence type="fractalNoise" baseFrequency="0.02" numOctaves="5" result="noise"/>
            <feColorMatrix type="saturate" values="0"/>
          </filter>
        </defs>
        <rect width="100%" height="100%" filter="url(#paperTex)"/>
      </svg>

      {/* Title Section */}
      <div style={{
        position: 'absolute',
        top: 100,
        width: '100%',
        textAlign: 'center',
        opacity: titleEntrance,
        transform: `translateY(${interpolate(titleEntrance, [0, 1], [-20, 0])}px)`
      }}>
        <h1 style={{ 
          fontSize: 64, 
          fontWeight: 700, 
          margin: 0, 
          marginBottom: 10,
          color: '#222'
        }}>
          {title}
        </h1>
      </div>

      {/* Legend - Centered above chart */}
      <div style={{
        position: 'absolute',
        top: 220,
        width: '100%',
        display: 'flex',
        justifyContent: 'center',
        gap: 40,
        opacity: spring({ frame: frame - 10, fps, config: springConfig }),
        transform: `translateY(${interpolate(spring({ frame: frame - 10, fps }), [0, 1], [-10, 0])}px)`
      }}>
        {legendLabels.map((label, i) => (
          <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <div style={{ 
              width: 24, height: 24, 
              backgroundColor: colors[i], 
              borderRadius: 2,
              filter: 'url(#roughEdges)'
            }} />
            <span style={{ fontSize: 28, fontWeight: 600, color: '#444' }}>{label}</span>
          </div>
        ))}
      </div>

      {/* Chart Area */}
      <div style={{
        position: 'absolute',
        top: chartMargin.top,
        left: chartMargin.left,
        width: chartWidth,
        height: chartHeight,
      }}>

        {/* Grid Lines */}
        {[0, 0.25, 0.5, 0.75, 1].map((tick, i) => {
          const gridDelay = 5 + i * 2;
          const gridProgress = spring({ frame: frame - gridDelay, fps, config: { damping: 18 } });
          return (
            <div key={i} style={{
              position: 'absolute',
              left: -20,
              right: 0,
              top: `${(1 - tick) * 100}%`,
              borderTop: '2px solid rgba(0,0,0,0.1)',
              display: 'flex',
              alignItems: 'center',
              transform: `scaleX(${gridProgress})`,
              transformOrigin: 'left'
            }}>
              <span style={{
                position: 'absolute',
                left: -70,
                top: -12,
                fontSize: 24,
                fontFamily: '"Comic Sans MS", cursive',
                color: '#666',
                opacity: gridProgress
              }}>
                {Math.round(tick * 100)}%
              </span>
            </div>
          );
        })}

        {/* Bars */}
        <div style={{
          display: 'flex',
          alignItems: 'flex-end',
          justifyContent: 'center',
          height: '100%',
          width: '100%',
          gap: barGap
        }}>
          {data.map((item, colIndex) => {
            const barDelay = barsStartFrame + (colIndex * 5);
            const segmentDuration = 8;
            const total = item.values.reduce((a, b) => a + b, 0);

            // Calculate cumulative heights for layered fill effect
            // values: [blue, red, pink] = [45, 40, 15]
            // pink fills to 100%, red fills to blue+red (85%), blue fills to blue (45%)
            const blueHeight = (item.values[0] / total) * 100;
            const redHeight = ((item.values[0] + item.values[1]) / total) * 100;
            const pinkHeight = 100;

            // Animation timing: pink first, then red, then blue
            const pinkProgress = spring({ frame: frame - barDelay, fps, config: { damping: 16 } });
            const redProgress = spring({ frame: frame - barDelay - segmentDuration, fps, config: { damping: 16 } });
            const blueProgress = spring({ frame: frame - barDelay - segmentDuration * 2, fps, config: { damping: 16 } });

            return (
              <div key={colIndex} style={{
                width: barWidth,
                height: '100%',
                position: 'relative',
                filter: 'url(#roughEdges)',
                overflow: 'hidden'
              }}>
                {/* Pink layer - fills to 100% */}
                <div style={{
                  position: 'absolute',
                  bottom: 0,
                  left: 0,
                  width: '100%',
                  height: `${pinkHeight * pinkProgress}%`,
                  backgroundColor: colors[2],
                  backgroundImage: 'linear-gradient(45deg, rgba(255,255,255,0.1) 25%, transparent 25%, transparent 50%, rgba(255,255,255,0.1) 50%, rgba(255,255,255,0.1) 75%, transparent 75%, transparent)',
                  backgroundSize: '10px 10px'
                }} />

                {/* Red layer - fills to blue+red height */}
                <div style={{
                  position: 'absolute',
                  bottom: 0,
                  left: 0,
                  width: '100%',
                  height: `${redHeight * redProgress}%`,
                  backgroundColor: colors[1],
                  backgroundImage: 'linear-gradient(45deg, rgba(255,255,255,0.1) 25%, transparent 25%, transparent 50%, rgba(255,255,255,0.1) 50%, rgba(255,255,255,0.1) 75%, transparent 75%, transparent)',
                  backgroundSize: '10px 10px'
                }} />

                {/* Blue layer - fills to blue height */}
                <div style={{
                  position: 'absolute',
                  bottom: 0,
                  left: 0,
                  width: '100%',
                  height: `${blueHeight * blueProgress}%`,
                  backgroundColor: colors[0],
                  backgroundImage: 'linear-gradient(45deg, rgba(255,255,255,0.1) 25%, transparent 25%, transparent 50%, rgba(255,255,255,0.1) 50%, rgba(255,255,255,0.1) 75%, transparent 75%, transparent)',
                  backgroundSize: '10px 10px'
                }} />

                {/* X-Axis Label */}
                <div style={{
                  position: 'absolute',
                  bottom: -50,
                  left: 0,
                  width: '100%',
                  textAlign: 'center',
                  fontSize: 28,
                  fontWeight: 'bold',
                  fontFamily: '"Courier New", monospace',
                  color: '#444',
                  opacity: spring({ frame: frame - barDelay - 5, fps, config: { damping: 20 } })
                }}>
                  {item.year}
                </div>
              </div>
            );
          })}
        </div>

        {/* X-Axis baseline with animation */}
        <div style={{
          position: 'absolute',
          bottom: 0,
          left: '50%',
          width: interpolate(baselineProgress, [0, 1], [0, chartWidth + 40]),
          height: 2,
          backgroundColor: '#333',
          opacity: interpolate(baselineProgress, [0, 0.3], [0, 0.7]),
          transform: 'translateX(-50%)'
        }} />
      </div>

      {/* Source - Bottom Right */}
      <div style={{
        position: 'absolute',
        bottom: 50,
        right: 80,
        fontFamily: 'sans-serif',
        fontSize: 24,
        fontWeight: 600,
        color: '#666',
        opacity: spring({ frame: frame - legendStartFrame, fps }),
      }}>
        {sourceText}
      </div>
    </div>
  );
};

const ChartAnimation = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
  const safeFps = fps || 30;

  const props = item.props || {};
  const titleText = props.titleText || 'SHOW GROWTH';
  const subtitleText = props.subtitleText || 'Downloads vs Weekly Listeners by Quarter';
  const descText = props.descText || 'Steady quarter-over-quarter gains across both key metrics, signaling wider audience reach and strong listener loyalty since the relaunch.';
  const bgGradientStart = props.bgGradientStart || '#364a5f';
  const bgGradientEnd = props.bgGradientEnd || '#4a5867';
  const elementColor = props.elementColor || '#ffffff';
  const accentColor = props.accentColor || 'rgba(255,255,255,0.55)';
  const fontFamily = props.fontFamily || 'Inter, sans-serif';
  const monoFont = '"IBM Plex Mono", monospace';

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const rootStyle = {
    position: 'absolute',
    top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundImage: `linear-gradient(135deg, ${bgGradientStart} 0%, ${bgGradientEnd} 100%)`,
    fontFamily,
    color: elementColor,
    display: 'flex',
    flexDirection: 'column',
    padding: '80px 120px 100px',
    boxSizing: 'border-box',
    overflow: 'hidden'
  };

  const downloads = [1.2, 1.8, 2.4, 3.1, 3.8, 4.5, 5.2, 6.1];
  const users = [0.8, 1.1, 1.6, 2.0, 2.6, 3.2, 3.9, 4.7];
  const quarters = ['Q1 22', 'Q2 22', 'Q3 22', 'Q4 22', 'Q1 23', 'Q2 23', 'Q3 23', 'Q4 23'];
  const yTicks = [0, 2, 4, 6, 8];
  const maxY = 8;

  const chartWidth = 1100;
  const chartHeight = 620;
  const margin = { top: 40, right: 40, bottom: 60, left: 60 };
  const innerWidth = chartWidth - margin.left - margin.right;
  const innerHeight = chartHeight - margin.top - margin.bottom;

  const buildPath = (dataArr) => {
    return dataArr.map((val, i) => {
      const x = margin.left + (i / (dataArr.length - 1)) * innerWidth;
      const y = margin.top + innerHeight - (val / maxY) * innerHeight;
      return `${i === 0 ? 'M' : 'L'} ${x},${y}`;
    }).join(' ');
  };

  const computePathLength = (dataArr) => {
    let len = 0;
    for (let i = 1; i < dataArr.length; i++) {
      const x1 = margin.left + ((i - 1) / (dataArr.length - 1)) * innerWidth;
      const y1 = margin.top + innerHeight - (dataArr[i - 1] / maxY) * innerHeight;
      const x2 = margin.left + (i / (dataArr.length - 1)) * innerWidth;
      const y2 = margin.top + innerHeight - (dataArr[i] / maxY) * innerHeight;
      len += Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2);
    }
    return len;
  };

  const pathDownloads = buildPath(downloads);
  const pathUsers = buildPath(users);
  const lengthDownloads = computePathLength(downloads);
  const lengthUsers = computePathLength(users);

  const titleAnim = spring({ frame: Math.max(0, frame - 5), fps: safeFps, config: { damping: 15 } });
  const panelAnim = spring({ frame: Math.max(0, frame - 15), fps: safeFps, config: { damping: 16 } });

  const drawProgress = interpolate(frame, [20, 110], [0, 1], {
    extrapolateRight: 'clamp',
    extrapolateLeft: 'clamp',
    easing: Easing.out(Easing.cubic)
  });

  const dashOffsetDownloads = lengthDownloads * (1 - drawProgress);
  const dashOffsetUsers = lengthUsers * (1 - drawProgress);

  const hexToRgba = (hex, alpha) => {
    const r = parseInt(hex.slice(1, 3), 16) || 255;
    const g = parseInt(hex.slice(3, 5), 16) || 255;
    const b = parseInt(hex.slice(5, 7), 16) || 255;
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  };

  const gridColor = hexToRgba(elementColor, 0.15);
  const textMuted = hexToRgba(elementColor, 0.6);
  const textSemi = hexToRgba(elementColor, 0.8);

  return (
    <div style={rootStyle}>

      {/* Top Header — full width, centered */}
      <div style={{
        textAlign: 'center',
        marginBottom: 50,
        opacity: titleAnim,
        transform: `translateY(${(1 - titleAnim) * 20}px)`
      }}>
        <h1 style={{
          margin: 0, fontSize: 56, fontWeight: 600,
          letterSpacing: '4px', textTransform: 'uppercase'
        }}>
          {titleText}
        </h1>
        <h2 style={{
          margin: '12px 0 0 0', fontSize: 24, fontWeight: 300,
          color: textSemi, letterSpacing: '1px'
        }}>
          {subtitleText}
        </h2>
      </div>

      {/* Bottom Row: Chart + Panel */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'row', alignItems: 'center' }}>

        {/* Left: Chart */}
        <div style={{ flex: 1, display: 'flex', alignItems: 'center' }}>
          <div style={{ position: 'relative', width: chartWidth, height: chartHeight }}>
            <svg width={chartWidth} height={chartHeight} style={{ position: 'absolute', top: 0, left: 0, overflow: 'visible' }}>

              {/* Y-Axis Grid & Labels */}
              {yTicks.map((tick, i) => {
                const yPos = margin.top + innerHeight - (tick / maxY) * innerHeight;
                const tickAnim = spring({ frame: Math.max(0, frame - 10 - i * 5), fps: safeFps, config: { damping: 14 } });
                return (
                  <g key={`y-${tick}`} style={{ opacity: tickAnim }}>
                    <line
                      x1={margin.left} x2={margin.left + innerWidth}
                      y1={yPos} y2={yPos}
                      stroke={gridColor} strokeWidth={1}
                      strokeDasharray={tick === 0 ? "none" : "4, 4"}
                    />
                    <text
                      x={margin.left - 20} y={yPos + 6}
                      textAnchor="end" fill={textMuted}
                      fontSize={18} fontFamily={monoFont} fontWeight={400}
                    >
                      {tick}M
                    </text>
                  </g>
                );
              })}

              {/* X-Axis Labels */}
              {quarters.map((label, i) => {
                const xPos = margin.left + (i / (quarters.length - 1)) * innerWidth;
                const labelAnim = spring({ frame: Math.max(0, frame - 20 - i * 5), fps: safeFps, config: { damping: 14 } });
                return (
                  <text
                    key={`x-${i}`}
                    x={xPos} y={margin.top + innerHeight + 40}
                    textAnchor="middle" fill={textMuted}
                    fontSize={18} fontWeight={500}
                    style={{ opacity: labelAnim }}
                  >
                    {label}
                  </text>
                );
              })}

              {/* Downloads Line */}
              <path
                d={pathDownloads}
                fill="none"
                stroke={elementColor}
                strokeWidth={5}
                strokeLinejoin="round"
                strokeLinecap="round"
                strokeDasharray={lengthDownloads}
                strokeDashoffset={dashOffsetDownloads}
              />

              {/* Active Users Line */}
              <path
                d={pathUsers}
                fill="none"
                stroke={accentColor}
                strokeWidth={5}
                strokeLinejoin="round"
                strokeLinecap="round"
                strokeDasharray={`${lengthUsers} ${lengthUsers}`}
                strokeDashoffset={dashOffsetUsers}
              />

              {/* Data Points */}
              {quarters.map((_, i) => {
                const xPos = margin.left + (i / (quarters.length - 1)) * innerWidth;
                const yDown = margin.top + innerHeight - (downloads[i] / maxY) * innerHeight;
                const yUser = margin.top + innerHeight - (users[i] / maxY) * innerHeight;

                const lineReachFraction = i / (quarters.length - 1);
                const delay = 20 + lineReachFraction * 90 + 5;
                const dotScale = spring({ frame: Math.max(0, frame - delay), fps: safeFps, config: { damping: 12, mass: 0.8 } });

                return (
                  <g key={`dots-${i}`}>
                    <circle cx={xPos} cy={yDown} r={8 * dotScale} fill={elementColor} />
                    <circle
                      cx={xPos} cy={yUser}
                      r={8 * dotScale}
                      fill="transparent"
                      stroke={accentColor}
                      strokeWidth={4 * dotScale}
                    />
                  </g>
                );
              })}
            </svg>
          </div>
        </div>

        {/* Right: Legend Panel */}
        <div style={{
          width: 480,
          marginLeft: 60,
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          opacity: panelAnim,
          transform: `translateX(${(1 - panelAnim) * 40}px)`
        }}>
          <div style={{
            backgroundColor: 'rgba(0, 0, 0, 0.2)',
            border: `1px solid ${hexToRgba(elementColor, 0.1)}`,
            borderRadius: 24,
            padding: '60px 50px',
            backdropFilter: 'blur(12px)'
          }}>
            <h3 style={{
              margin: '0 0 40px 0', fontSize: 18, fontWeight: 300,
              letterSpacing: '0.1em', color: textMuted, textTransform: 'uppercase'
            }}>
              Key Metrics
            </h3>

            <div style={{ display: 'flex', flexDirection: 'column', gap: 30 }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
                <svg width={40} height={16} viewBox="0 0 40 16">
                  <line x1={0} y1={8} x2={40} y2={8} stroke={elementColor} strokeWidth={4} />
                  <circle cx={20} cy={8} r={6} fill={elementColor} />
                </svg>
                <span style={{ fontSize: 20, fontWeight: 300 }}>Downloads</span>
              </div>

              <div style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
                <svg width={40} height={16} viewBox="0 0 40 16">
                  <line x1={0} y1={8} x2={40} y2={8} stroke={accentColor} strokeWidth={4} strokeDasharray="8 4" />
                  <circle cx={20} cy={8} r={6} fill="transparent" stroke={accentColor} strokeWidth={3} />
                </svg>
                <span style={{ fontSize: 20, fontWeight: 300 }}>Weekly Listeners</span>
              </div>
            </div>

            <div style={{ height: 1, backgroundColor: gridColor, margin: '40px 0' }} />

            <p style={{
              margin: 0, fontSize: 20, lineHeight: 1.7,
              color: textSemi, fontWeight: 400
            }}>
              {descText}
            </p>
          </div>
        </div>

      </div>
    </div>
  );
};

const GrowthTrendChart = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const props = item.props || {};

  const title = props.title || 'TASTE TREND';
  const subtitle = props.subtitle || 'H1 Recap - Viewers & Recipes (in 10K)';
  const bgStart = props.bgStart || '#061025';
  const bgEnd = props.bgEnd || '#28354c';
  const color1 = props.color1 || '#d08600';
  const color2 = props.color2 || '#fc913e';
  const legend1 = props.legend1 || 'Viewer Growth';
  const legend2 = props.legend2 || 'Recipe Saves';
  const data1 = (props.data1 || '12,19,28,35,41,53').split(',').map(Number);
  const data2 = (props.data2 || '8,14,22,31,38,47').split(',').map(Number);
  const months = ['JAN', 'FEB', 'MAR', 'APR', 'MAY', 'JUN'];

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);
  const safeFps = fps || 30;

  const ML = 220, MR = 180, MT = 320, MB = 200;
  const CW = DESIGN_WIDTH - ML - MR;
  const CH = DESIGN_HEIGHT - MT - MB;
  const maxVal = 60;
  const gridVals = [0, 15, 30, 45, 60];

  const getX = (i, len) => (i / (len - 1)) * CW;
  const getY = (v) => CH - (v / maxVal) * CH;

  const makePath = (data) => data.map((v, i) =>
    `${i === 0 ? 'M' : 'L'} ${getX(i, data.length)} ${getY(v)}`).join(' ');

  const pathLen = (data) => {
    let l = 0;
    for (let i = 0; i < data.length - 1; i++) {
      const dx = getX(i + 1, data.length) - getX(i, data.length);
      const dy = getY(data[i + 1]) - getY(data[i]);
      l += Math.sqrt(dx * dx + dy * dy);
    }
    return l;
  };

  const len1 = pathLen(data1);
  const len2 = pathLen(data2);

  const mainProg = spring({ frame: Math.max(0, frame - 15), fps: safeFps,
    config: { stiffness: 38, damping: 20, mass: 1.5 } });

  const titleSpring = spring({ frame, fps: safeFps, config: { damping: 22, stiffness: 90 } });
  const titleOpacity = interpolate(titleSpring, [0, 1], [0, 1]);
  const titleY = interpolate(titleSpring, [0, 1], [-40, 0]);
  const legendOp = interpolate(frame, [10, 30], [0, 1], { extrapolateRight: 'clamp' });

  const dashOff1 = interpolate(mainProg, [0, 1], [len1, 0]);
  const dashOff2 = interpolate(mainProg, [0, 1], [len2, 0]);

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      background: `linear-gradient(135deg, ${bgStart} 0%, ${bgEnd} 100%)`,
      transform: `scale(${scale})`, transformOrigin: 'top left',
      overflow: 'hidden', fontFamily: "'Inter', sans-serif", color: props.textColor || '#f3e1c5',
    }}>
      <div style={{
        position: 'absolute', top: 0, left: 0, right: 0, height: 3,
        background: `linear-gradient(90deg, transparent, ${color1}, ${color2}, transparent)`,
        opacity: titleOpacity,
      }} />

      <div style={{
        position: 'absolute', top: 80, left: ML,
        opacity: titleOpacity, transform: `translateY(${titleY}px)`,
      }}>
        <div style={{ fontSize: 76, fontWeight: 900, letterSpacing: '0.08em', textTransform: 'uppercase' }}>{title}</div>
        <div style={{ fontSize: 28, fontWeight: 300, marginTop: 14, opacity: 0.7, letterSpacing: '0.1em' }}>{subtitle}</div>
      </div>

      {/* Legend */}
      <div style={{
        position: 'absolute', top: 95, right: MR,
        display: 'flex', flexDirection: 'column', gap: 16, opacity: legendOp,
      }}>
        {[{ color: color1, label: legend1, dashed: false }, { color: color2, label: legend2, dashed: true }].map((l, i) => (
          <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
            <svg width={40} height={4}>
              <line x1={0} y1={2} x2={40} y2={2} stroke={l.color} strokeWidth={3}
                strokeDasharray={l.dashed ? '8,4' : 'none'} />
            </svg>
            <span style={{ fontSize: 22, fontWeight: 500, color: l.color }}>{l.label}</span>
          </div>
        ))}
      </div>

      {/* Chart SVG */}
      <svg style={{ position: 'absolute', top: MT, left: ML }}
        width={CW} height={CH} overflow="visible">
        <defs>
          <filter id="glow1">
            <feGaussianBlur stdDeviation="3" result="blur" />
            <feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge>
          </filter>
        </defs>

        {/* Grid */}
        {gridVals.map((val, i) => {
          const y = getY(val);
          const op = interpolate(frame, [8 + i * 3, 24 + i * 3], [0, 0.3], { extrapolateRight: 'clamp' });
          return (
            <g key={val} opacity={op}>
              <line x1={0} y1={y} x2={CW} y2={y} stroke={props.gridColor || '#f3e1c5'} strokeWidth={1} />
              <text x={-16} y={y + 6} fill={props.textColor || '#f3e1c5'} fontSize={20}
                fontFamily="'IBM Plex Mono', monospace" textAnchor="end" opacity={2}>{val}</text>
            </g>
          );
        })}

        {/* X labels */}
        {months.map((m, i) => {
          const x = getX(i, months.length);
          const op = interpolate(frame, [20 + i * 3, 36 + i * 3], [0, 0.7], { extrapolateRight: 'clamp' });
          return (
            <text key={m} x={x} y={CH + 48} fill={props.textColor || '#f3e1c5'} fontSize={22}
              fontFamily="'IBM Plex Mono', monospace" textAnchor="middle" opacity={op}>{m}</text>
          );
        })}

        {/* Line 2 */}
        <path d={makePath(data2)} fill="none" stroke={color2} strokeWidth={4}
          strokeDasharray={len2} strokeDashoffset={dashOff2} strokeLinecap="round"
          strokeDasharray2="none" opacity={0.85} />

        {/* Line 1 */}
        <path d={makePath(data1)} fill="none" stroke={color1} strokeWidth={6}
          strokeDasharray={len1} strokeDashoffset={dashOff1} strokeLinecap="round"
          filter="url(#glow1)" />

        {/* Dots line 1 */}
        {data1.map((v, i) => {
          const tp = i / (data1.length - 1);
          const vis = mainProg >= tp - 0.05;
          const s = spring({ frame: Math.max(0, frame - 15 - tp * 30), fps: safeFps,
            config: { stiffness: 120, damping: 12 } });
          return vis ? (
            <circle key={i} cx={getX(i, data1.length)} cy={getY(v)} r={8} fill={color1}
              style={{ transformOrigin: `${getX(i, data1.length)}px ${getY(v)}px`, transform: `scale(${s})` }}
              filter="url(#glow1)" />
          ) : null;
        })}

        {/* Dots line 2 */}
        {data2.map((v, i) => {
          const tp = i / (data2.length - 1);
          const vis = mainProg >= tp - 0.05;
          const s = spring({ frame: Math.max(0, frame - 15 - tp * 30), fps: safeFps,
            config: { stiffness: 120, damping: 12 } });
          return vis ? (
            <circle key={i} cx={getX(i, data2.length)} cy={getY(v)} r={6}
              fill={bgEnd} stroke={color2} strokeWidth={3}
              style={{ transformOrigin: `${getX(i, data2.length)}px ${getY(v)}px`, transform: `scale(${s})` }} />
          ) : null;
        })}
      </svg>

      <div style={{
        position: 'absolute', bottom: 0, left: 0, right: 0, height: 2,
        background: `linear-gradient(90deg, transparent, ${color1}88, ${color2}88, transparent)`,
        opacity: titleOpacity,
      }} />
    </div>
  );
};

