const StockChart = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // Editable Properties
  const props = item.props || {};
  const titleText = props.titleText || 'Share Price Momentum';
  const bgColor = props.bgColor || '#212038';
  const lineColorStart = props.lineColorStart || '#f174b7';
  const lineColorEnd = props.lineColorEnd || '#c26cd2';
  const textColor = props.textColor || '#FFFFFF';
  const gridColor = props.gridColor || 'rgba(255, 255, 255, 0.1)';
  const fontFamily = props.fontFamily || 'Inter, sans-serif';

  // Responsive Scaling
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  // Chart Configuration
  const data = [128, 142, 135, 156, 171, 163, 189, 204, 198, 221, 235, 248];
  const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  const yMin = 100;
  const yMax = 260;
  const margin = { top: 220, right: 120, bottom: 180, left: 180 };
  const graphWidth = DESIGN_WIDTH - margin.left - margin.right;
  const graphHeight = DESIGN_HEIGHT - margin.top - margin.bottom;

  // Helper Functions
  const getX = (index) => margin.left + (index / (data.length - 1)) * graphWidth;
  const getY = (val) => margin.top + graphHeight - ((val - yMin) / (yMax - yMin)) * graphHeight;

  // Generate Path Strings
  const points = data.map((val, i) => `${getX(i)},${getY(val)}`);
  const linePath = `M ${points.join(' L ')}`;
  const areaPath = `M ${getX(0)},${margin.top + graphHeight} L ${points.join(' L ')} L ${getX(data.length - 1)},${margin.top + graphHeight} Z`;

  // Animation Logic
  // 1. Title Entrance
  const titleProgress = spring({ frame, fps, config: { damping: 15 } });
  const titleY = interpolate(titleProgress, [0, 1], [-40, 0]);
  const titleOpacity = interpolate(titleProgress, [0, 1], [0, 1]);

  // 2. Grid Fade In
  const gridOpacity = interpolate(frame, [10, 30], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  // 3. Line Drawing (Reveal via Mask)
  const drawT = interpolate(frame, [15, 75], [0, 1], {
    easing: Easing.bezier(0.25, 0.1, 0.25, 1),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  // 4. Staggered Dots Pop-in — delay synced with line draw progress
  // Line draws from frame 15 to 75 (60 frames), each dot appears when line reaches it
  const getDotScale = (index) => {
    const lineDrawStart = 15;
    const lineDrawDuration = 60;
    const delay = lineDrawStart + (index / (data.length - 1)) * lineDrawDuration;
    if (frame < delay) return 0;
    return Math.min(1, spring({
      frame: frame - delay,
      fps,
      config: { stiffness: 150, damping: 12 }
    }));
  };

  // Styles
  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    backgroundColor: bgColor,
    fontFamily: fontFamily,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    overflow: 'hidden',
    color: textColor,
  };

  const titleStyle = {
    position: 'absolute',
    left: margin.left,
    top: 80,
    fontSize: '80px',
    fontWeight: 700,
    opacity: titleOpacity,
    transform: `translateY(${titleY}px)`,
    margin: 0,
  };

  return (
    <div style={rootStyle}>
      <h1 style={titleStyle}>{titleText}</h1>

      <svg width={DESIGN_WIDTH} height={DESIGN_HEIGHT} style={{ position: 'absolute', top: 0, left: 0 }}>
        <defs>
          <linearGradient id="lineGradient" x1="0" y1="0" x2="1" y2="0">
            <stop offset="0%" stopColor={lineColorStart} />
            <stop offset="100%" stopColor={lineColorEnd} />
          </linearGradient>

          <linearGradient id="areaGradient" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={lineColorStart} stopOpacity="0.4" />
            <stop offset="100%" stopColor={lineColorEnd} stopOpacity="0" />
          </linearGradient>

          <clipPath id="drawClip">
            <rect
              x={margin.left}
              y={0}
              width={graphWidth * drawT}
              height={DESIGN_HEIGHT}
            />
          </clipPath>
        </defs>

        {/* Grid Lines & Y-Axis Labels */}
        <g style={{ opacity: gridOpacity }}>
          {[100, 140, 180, 220, 260].map((val) => (
            <g key={val}>
              <line
                x1={margin.left}
                y1={getY(val)}
                x2={margin.left + graphWidth}
                y2={getY(val)}
                stroke={gridColor}
                strokeWidth="2"
              />
              <text
                x={margin.left - 30}
                y={getY(val) + 12}
                fill={textColor}
                fillOpacity="0.6"
                fontSize="32"
                textAnchor="end"
                fontWeight="500"
              >
                {val}
              </text>
            </g>
          ))}

          {/* X-Axis Labels */}
          {months.map((m, i) => (
            <text
              key={i}
              x={getX(i)}
              y={margin.top + graphHeight + 60}
              fill={textColor}
              fillOpacity="0.6"
              fontSize="32"
              textAnchor="middle"
              fontWeight="500"
            >
              {m}
            </text>
          ))}
        </g>

        {/* Data Chart (Clipped for animation) */}
        <g clipPath="url(#drawClip)">
          <path d={areaPath} fill="url(#areaGradient)" />
          <path
            d={linePath}
            fill="none"
            stroke="url(#lineGradient)"
            strokeWidth="6"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </g>

        {/* Data Points (Staggered Pop) */}
        {data.map((val, i) => {
          const s = getDotScale(i);
          return (
            <g key={i} transform={`translate(${getX(i)}, ${getY(val)}) scale(${s})`}>
              <circle
                r="10"
                fill={bgColor}
                stroke={lineColorEnd}
                strokeWidth="4"
              />
            </g>
          );
        })}
      </svg>
    </div>
  );
};

const TemperatureChart = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const props = item.props || {};

  const title = props.title || 'RAINFALL TRENDS';
  const subtitle = props.subtitle || 'Monthly Average Rainfall (mm)';
  const bgStart = props.bgStart || '#001518';
  const bgEnd = props.bgEnd || '#133b40';
  const lineColor = props.lineColor || '#00c1a9';
  const dataValues = [-3, 1, 9, 18, 24, 29, 32, 31, 24, 15, 6, -1];
  const months = ['JAN', 'FEB', 'MAR', 'APR', 'MAY', 'JUN', 'JUL', 'AUG', 'SEP', 'OCT', 'NOV', 'DEC'];

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);
  const safeFps = fps || 30;

  const ML = 220, MR = 180, MT = 340, MB = 220;
  const CW = DESIGN_WIDTH - ML - MR;
  const CH = DESIGN_HEIGHT - MT - MB;
  const Y_MIN = -10, Y_MAX = 40;

  const getX = (i) => (i / (dataValues.length - 1)) * CW;
  const getY = (v) => CH - ((v - Y_MIN) / (Y_MAX - Y_MIN)) * CH;

  const generatePath = (pts) => {
    let d = `M ${getX(0)} ${getY(pts[0])}`;
    for (let i = 0; i < pts.length - 1; i++) {
      const x1 = getX(i), y1 = getY(pts[i]);
      const x2 = getX(i + 1), y2 = getY(pts[i + 1]);
      const cp1x = x1 + (x2 - x1) / 3;
      const cp2x = x2 - (x2 - x1) / 3;
      d += ` C ${cp1x} ${y1}, ${cp2x} ${y2}, ${x2} ${y2}`;
    }
    return d;
  };

  const pathD = generatePath(dataValues);

  const lineProgress = spring({ frame, fps: safeFps,
    config: { damping: 22, stiffness: 50, mass: 1.5 } });

  const titleSpring = spring({ frame, fps: safeFps, config: { damping: 22, stiffness: 90 } });
  const titleOpacity = interpolate(titleSpring, [0, 1], [0, 1]);
  const titleY = interpolate(titleSpring, [0, 1], [-40, 0]);

  const gridVals = [-10, 0, 10, 20, 30, 40];
  const maxVal = Math.max(...dataValues);
  const minVal = Math.min(...dataValues);

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      background: `linear-gradient(135deg, ${bgStart} 0%, ${bgEnd} 100%)`,
      transform: `scale(${scale})`, transformOrigin: 'top left',
      overflow: 'hidden', fontFamily: "'Inter', sans-serif", color: '#cfecd7',
    }}>
      <div style={{
        position: 'absolute', top: 0, left: 0, right: 0, height: 3,
        background: `linear-gradient(90deg, transparent, ${lineColor}, transparent)`,
        opacity: titleOpacity,
      }} />

      <div style={{
        position: 'absolute', top: 80, width: '100%', textAlign: 'center',
        opacity: titleOpacity, transform: `translateY(${titleY}px)`,
      }}>
        <div style={{ fontSize: 72, fontWeight: 900, letterSpacing: '0.08em', textTransform: 'uppercase',
          textShadow: `0 0 40px ${lineColor}88` }}>{title}</div>
        <div style={{ fontSize: 28, fontWeight: 300, marginTop: 14, opacity: 0.7, letterSpacing: '0.12em' }}>{subtitle}</div>
      </div>

      <svg style={{ position: 'absolute', top: MT, left: ML }}
        width={CW} height={CH} overflow="visible">
        <defs>
          <linearGradient id="lineGrad" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="#4cb158" />
            <stop offset="50%" stopColor={lineColor} />
            <stop offset="100%" stopColor="#c39a00" />
          </linearGradient>
          <filter id="glowTemp">
            <feGaussianBlur stdDeviation="4" result="blur" />
            <feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge>
          </filter>
          <clipPath id="lineClip">
            <rect x={0} y={-60} width={CW * lineProgress} height={CH + 120} />
          </clipPath>
        </defs>

        {/* Grid lines */}
        {gridVals.map((val, i) => {
          const y = getY(val);
          const op = interpolate(frame, [8 + i * 3, 26 + i * 3], [0, 0.28], { extrapolateRight: 'clamp' });
          return (
            <g key={val} opacity={op}>
              <line x1={0} y1={y} x2={CW} y2={y} stroke="#cfecd7" strokeWidth={val === 0 ? 1.5 : 1} />
              <text x={-16} y={y + 6} fill="#cfecd7" fontSize={20}
                fontFamily="'IBM Plex Mono', monospace" textAnchor="end" opacity={3}>{val}°</text>
            </g>
          );
        })}

        {/* X labels */}
        {months.map((m, i) => {
          const x = getX(i);
          const op = interpolate(frame, [20 + i * 2, 36 + i * 2], [0, 0.65], { extrapolateRight: 'clamp' });
          return (
            <text key={m} x={x} y={CH + 48} fill="#cfecd7" fontSize={18}
              fontFamily="'IBM Plex Mono', monospace" textAnchor="middle" opacity={op}>{m}</text>
          );
        })}

        {/* Area fill */}
        <path
          d={pathD + ` L ${getX(dataValues.length - 1)} ${CH} L ${getX(0)} ${CH} Z`}
          fill={`url(#lineGrad)`} opacity={0.07}
          clipPath="url(#lineClip)"
        />

        {/* Main line */}
        <path d={pathD} fill="none" stroke="url(#lineGrad)" strokeWidth={6}
          strokeLinecap="round" clipPath="url(#lineClip)"
          filter="url(#glowTemp)" />

        {/* Data points */}
        {dataValues.map((v, i) => {
          const tp = i / (dataValues.length - 1);
          const vis = lineProgress >= tp - 0.04;
          const s = spring({ frame: Math.max(0, frame - tp * 45), fps: safeFps,
            config: { stiffness: 140, damping: 12 } });
          const isExtrema = v === maxVal || v === minVal;

          return vis ? (
            <g key={i} transform={`translate(${getX(i)}, ${getY(v)})`}>
              <circle r={isExtrema ? 10 : 6} fill={lineColor}
                style={{ transform: `scale(${s})`, transformOrigin: '0px 0px' }}
                filter="url(#glowTemp)" />
              {isExtrema && (
                <text y={v < 0 ? 38 : -22} fill="#fff" fontSize={28} fontWeight={700}
                  textAnchor="middle" fontFamily="'IBM Plex Mono', monospace"
                  opacity={s}>{v}°C</text>
              )}
            </g>
          ) : null;
        })}
      </svg>

      <div style={{
        position: 'absolute', bottom: 0, left: 0, right: 0, height: 2,
        background: `linear-gradient(90deg, transparent, ${lineColor}88, transparent)`,
        opacity: titleOpacity,
      }} />
    </div>
  );
};

const MultiLineChart = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // Props with defaults
  const props = item.props || {};
  const titleText = props.titleText || 'Workspace Growth';
  const kpi1Label = props.kpi1Label || 'Live Sessions';
  const kpi1Value = props.kpi1Value || 12;
  const kpi2Label = props.kpi2Label || 'Trial Starts';
  const kpi2Value = props.kpi2Value || 9;
  const xAxisLabelsStr = props.xAxisLabels || 'Sunday, Monday, Tuesday, Wednesday, Thursday, Friday, Saturday';
  const line1DataStr = props.line1Data || '20, 35, 28, 45, 38, 55, 62';
  const line2DataStr = props.line2Data || '30, 28, 42, 35, 50, 45, 58';

  const line1Color = props.line1Color || '#24bbff';
  const line2Color = props.line2Color || '#009c9c';
  const bgColor = props.bgColor || '#E8E6F0';
  const cardColor = props.cardColor || '#FFFFFF';
  const titleColor = props.titleColor || '#2D2D35';
  const gridColor = props.gridColor || '#EAE7F2';

  // Parsing data safely
  const labels = xAxisLabelsStr.split(',').map(s => s.trim());
  const line1Data = line1DataStr.split(',').map(s => parseFloat(s.trim()) || 0);
  const line2Data = line2DataStr.split(',').map(s => parseFloat(s.trim()) || 0);
  const numPoints = Math.max(labels.length, line1Data.length, line2Data.length);

  // Responsive scaling
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // Root style with transform
  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: bgColor,
    fontFamily: 'Inter, sans-serif',
    overflow: 'hidden'
  };

  // Chart Dimensions
  const chartWidth = 1160;
  const chartHeight = 400;
  const xStep = numPoints > 1 ? chartWidth / (numPoints - 1) : chartWidth;

  // Pre-calculate paths and lengths for lines
  const { d1, len1 } = React.useMemo(() => {
    let d = '';
    let len = 0;
    for (let i = 0; i < line1Data.length; i++) {
      const x = i * xStep;
      const y = chartHeight - Math.min(100, Math.max(0, line1Data[i])) / 100 * chartHeight;
      if (i === 0) d += `M ${x},${y}`;
      else d += ` L ${x},${y}`;

      if (i > 0) {
        const prevX = (i - 1) * xStep;
        const prevY = chartHeight - Math.min(100, Math.max(0, line1Data[i - 1])) / 100 * chartHeight;
        len += Math.sqrt(Math.pow(x - prevX, 2) + Math.pow(y - prevY, 2));
      }
    }
    return { d1: d, len1: len };
  }, [line1Data, xStep]);

  const { d2, len2 } = React.useMemo(() => {
    let d = '';
    let len = 0;
    for (let i = 0; i < line2Data.length; i++) {
      const x = i * xStep;
      const y = chartHeight - Math.min(100, Math.max(0, line2Data[i])) / 100 * chartHeight;
      if (i === 0) d += `M ${x},${y}`;
      else d += ` L ${x},${y}`;

      if (i > 0) {
        const prevX = (i - 1) * xStep;
        const prevY = chartHeight - Math.min(100, Math.max(0, line2Data[i - 1])) / 100 * chartHeight;
        len += Math.sqrt(Math.pow(x - prevX, 2) + Math.pow(y - prevY, 2));
      }
    }
    return { d2: d, len2: len };
  }, [line2Data, xStep]);

  // Animations
  const cardY = interpolate(frame, [0, 20], [80, 0], { extrapolateRight: 'clamp', easing: Easing.out(Easing.cubic) });
  const cardOpacity = interpolate(frame, [0, 20], [0, 1], { extrapolateRight: 'clamp' });
  const contentOpacity = interpolate(frame, [10, 30], [0, 1], { extrapolateRight: 'clamp' });

  const animatedKpi1 = Math.floor(interpolate(frame, [20, 70], [0, kpi1Value], { extrapolateRight: 'clamp', extrapolateLeft: 'clamp' }));
  const animatedKpi2 = Math.floor(interpolate(frame, [25, 75], [0, kpi2Value], { extrapolateRight: 'clamp', extrapolateLeft: 'clamp' }));

  // Line animations drawing from left
  const lineProgress = Easing.inOut(Easing.ease)(interpolate(frame, [30, 100], [0, 1], { extrapolateRight: 'clamp', extrapolateLeft: 'clamp' }));
  const line1Offset = len1 * (1 - lineProgress);
  const line2Offset = len2 * (1 - lineProgress);

  return (
    <div style={rootStyle}>
      {/* Main White Card */}
      <div style={{
        position: 'absolute',
        width: 1400,
        height: 800,
        left: 260,
        top: 140,
        backgroundColor: cardColor,
        borderRadius: 40,
        boxShadow: `0 30px 60px rgba(0,0,0,0.06)`,
        transform: `translateY(${cardY}px)`,
        opacity: cardOpacity,
        overflow: 'hidden'
      }}>
        {/* Watermark Logo/Silhouette */}
        <svg style={{ position: 'absolute', right: -50, bottom: -50, width: 600, height: 600, opacity: 0.03, fill: titleColor }} viewBox="0 0 24 24">
          <path d="M16 11c1.66 0 2.99-1.34 2.99-3S17.66 5 16 5c-1.66 0-3 1.34-3 3s1.34 3 3 3zm-8 0c1.66 0 2.99-1.34 2.99-3S9.66 5 8 5C6.34 5 5 6.34 5 8s1.34 3 3 3zm0 2c-2.33 0-7 1.17-7 3.5V19h14v-2.5c0-2.33-4.67-3.5-7-3.5zm8 0c-.29 0-.62.02-.97.05 1.16.84 1.97 1.97 1.97 3.45V19h6v-2.5c0-2.33-4.67-3.5-7-3.5z" />
        </svg>

        <div style={{ opacity: contentOpacity }}>
          {/* Header Area */}
          <div style={{ position: 'absolute', left: 80, top: 60, right: 80, display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <h1 style={{ margin: 0, fontSize: 56, fontWeight: 800, color: titleColor, letterSpacing: '-0.5px' }}>{titleText}</h1>
            <div style={{ display: 'flex', gap: 70 }}>
              <div style={{ textAlign: 'right' }}>
                <div style={{ fontSize: 22, fontWeight: 600, color: '#888', marginBottom: 6 }}>{kpi1Label}</div>
                <div style={{ fontSize: 60, fontWeight: 800, color: line1Color, lineHeight: 1 }}>{animatedKpi1}%</div>
              </div>
              <div style={{ textAlign: 'right' }}>
                <div style={{ fontSize: 22, fontWeight: 600, color: '#888', marginBottom: 6 }}>{kpi2Label}</div>
                <div style={{ fontSize: 60, fontWeight: 800, color: line2Color, lineHeight: 1 }}>{animatedKpi2}%</div>
              </div>
            </div>
          </div>

          {/* Chart Grid & Y Axis */}
          <div style={{ position: 'absolute', left: 80, top: 240, width: 1240, height: 460 }}>
            {[100, 75, 50, 25, 0].map((val, i) => {
              const isZero = val === 0;
              return (
                <div key={`y-${val}`} style={{ position: 'absolute', top: i * (chartHeight / 4), left: 0, width: '100%', display: 'flex', alignItems: 'center' }}>
                  <div style={{ width: 60, textAlign: 'right', fontSize: 18, color: '#888', paddingRight: 20, fontWeight: 600 }}>{val}%</div>
                  <div style={{ flex: 1, height: isZero ? 2 : 1.5, backgroundColor: gridColor, opacity: isZero ? 1 : 0.7 }} />
                </div>
              );
            })}

            {/* X Axis Labels */}
            {labels.map((day, i) => {
              const xOpacity = interpolate(frame, [20 + i * 5, 40 + i * 5], [0, 1], { extrapolateRight: 'clamp' });
              return (
                <div key={`x-${i}`} style={{ 
                  position: 'absolute', 
                  top: chartHeight + 20, 
                  left: 80 + i * xStep - 75, 
                  width: 150, 
                  textAlign: 'center', 
                  fontSize: 18, 
                  color: '#888', 
                  fontWeight: 600, 
                  opacity: xOpacity 
                }}>
                  {day}
                </div>
              );
            })}

            {/* SVG Lines and Dots */}
            <svg style={{ position: 'absolute', left: 80, top: 0, width: chartWidth, height: chartHeight, overflow: 'visible' }}>
              {/* Line 2 (Purple) */}
              <path 
                d={d2} 
                fill="none" 
                stroke={line2Color} 
                strokeWidth={6} 
                strokeDasharray={len2} 
                strokeDashoffset={Math.max(0, line2Offset)} 
                strokeLinecap="round" 
                strokeLinejoin="round" 
              />
              {line2Data.map((val, i) => {
                const dotDelay = 30 + (i / Math.max(1, line2Data.length - 1)) * 70;
                const dotScale = spring({ frame: frame - dotDelay, fps, config: { damping: 14 } });
                const cy = chartHeight - Math.min(100, Math.max(0, val)) / 100 * chartHeight;
                return (
                  <circle 
                    key={`dot2-${i}`} 
                    cx={i * xStep} 
                    cy={cy} 
                    r={8} 
                    fill={cardColor} 
                    stroke={line2Color} 
                    strokeWidth={5} 
                    style={{ 
                      transform: `scale(${dotScale})`, 
                      transformOrigin: `${i * xStep}px ${cy}px` 
                    }} 
                  />
                );
              })}

              {/* Line 1 (Orange) */}
              <path 
                d={d1} 
                fill="none" 
                stroke={line1Color} 
                strokeWidth={6} 
                strokeDasharray={len1} 
                strokeDashoffset={Math.max(0, line1Offset)} 
                strokeLinecap="round" 
                strokeLinejoin="round" 
              />
              {line1Data.map((val, i) => {
                const dotDelay = 30 + (i / Math.max(1, line1Data.length - 1)) * 70;
                const dotScale = spring({ frame: frame - dotDelay, fps, config: { damping: 14 } });
                const cy = chartHeight - Math.min(100, Math.max(0, val)) / 100 * chartHeight;
                return (
                  <circle 
                    key={`dot1-${i}`} 
                    cx={i * xStep} 
                    cy={cy} 
                    r={8} 
                    fill={cardColor} 
                    stroke={line1Color} 
                    strokeWidth={5} 
                    style={{ 
                      transform: `scale(${dotScale})`, 
                      transformOrigin: `${i * xStep}px ${cy}px` 
                    }} 
                  />
                );
              })}
            </svg>
          </div>
        </div>
      </div>
    </div>
  );
};

