          </filter>
        </defs>

        {/* Left grid */}
        {gridL.map((v, i) => {
          const y = getYL(v);
          const op = interpolate(frame, [6 + i * 3, 22 + i * 3], [0, 0.25], { extrapolateRight: 'clamp' });
          return (
            <g key={`l${v}`} opacity={op}>
              <line x1={0} y1={y} x2={CW} y2={y} stroke={props.gridColor || '#cbe8fd'} strokeWidth={1} />
              <text x={-14} y={y + 6} fill={color1} fontSize={18}
                fontFamily="'IBM Plex Mono', monospace" textAnchor="end" opacity={3}>{v}M</text>
            </g>
          );
        })}

        {/* Right grid labels */}
        {gridR.map((v, i) => {
          const y = getYR(v);
          const op = interpolate(frame, [6 + i * 3, 22 + i * 3], [0, 0.7], { extrapolateRight: 'clamp' });
          return (
            <text key={`r${v}`} x={CW + 14} y={y + 6} fill={color3} fontSize={18}
              fontFamily="'IBM Plex Mono', monospace" textAnchor="start" opacity={op}>{v}%</text>
          );
        })}

        {/* X labels */}
        {weeks.map((w, i) => {
          const op = interpolate(frame, [18 + i * 3, 32 + i * 3], [0, 0.65], { extrapolateRight: 'clamp' });
          return (
            <text key={w} x={getX(i)} y={CH + 46} fill={props.textColor || '#cbe8fd'} fontSize={20}
              fontFamily="'IBM Plex Mono', monospace" textAnchor="middle" opacity={op}>{w}</text>
          );
        })}

        {/* Line 3 - conv rate */}
        <path d={makePath(convRate, getYR)} fill="none" stroke={color3} strokeWidth={4}
          strokeDasharray={`${len3} ${len3}`} strokeDashoffset={interpolate(prog3, [0, 1], [len3, 0])}
          strokeLinecap="round" strokeDasharray2="3,6" opacity={0.9} />

        {/* Line 2 - new users */}
        <path d={makePath(newUsers, getYL)} fill="none" stroke={color2} strokeWidth={4}
          strokeDasharray={`${len2} ${len2}`} strokeDashoffset={interpolate(prog2, [0, 1], [len2, 0])}
          strokeLinecap="round" opacity={0.9} />

        {/* Line 1 - visits */}
        <path d={makePath(visits, getYL)} fill="none" stroke={color1} strokeWidth={6}
          strokeDasharray={`${len1} ${len1}`} strokeDashoffset={interpolate(prog1, [0, 1], [len1, 0])}
          strokeLinecap="round" filter="url(#glow3)" />

        {/* Dots visits */}
        {visits.map((v, i) => {
          const tp = i / (visits.length - 1);
          const s = spring({ frame: Math.max(0, frame - 10 - tp * 28), fps: safeFps, config: { stiffness: 120, damping: 12 } });
          return prog1 >= tp - 0.05 ? (
            <circle key={i} cx={getX(i)} cy={getYL(v)} r={8} fill={color1}
              style={{ transformOrigin: `${getX(i)}px ${getYL(v)}px`, transform: `scale(${s})` }}
              filter="url(#glow3)" />
          ) : null;
        })}

        {/* Dots new users */}
        {newUsers.map((v, i) => {
          const tp = i / (newUsers.length - 1);
          const s = spring({ frame: Math.max(0, frame - 22 - tp * 28), fps: safeFps, config: { stiffness: 120, damping: 12 } });
          return prog2 >= tp - 0.05 ? (
            <circle key={i} cx={getX(i)} cy={getYL(v)} r={6} fill={bgEnd} stroke={color2} strokeWidth={3}
              style={{ transformOrigin: `${getX(i)}px ${getYL(v)}px`, transform: `scale(${s})` }} />
          ) : null;
        })}

        {/* Dots conv rate */}
        {convRate.map((v, i) => {
          const tp = i / (convRate.length - 1);
          const s = spring({ frame: Math.max(0, frame - 34 - tp * 28), fps: safeFps, config: { stiffness: 120, damping: 12 } });
          return prog3 >= tp - 0.05 ? (
            <circle key={i} cx={getX(i)} cy={getYR(v)} r={5} fill={color3}
              style={{ transformOrigin: `${getX(i)}px ${getYR(v)}px`, transform: `scale(${s})` }} />
          ) : null;
        })}
      </svg>

      <div style={{
        position: 'absolute', bottom: 0, left: 0, right: 0, height: 2,
        background: `linear-gradient(90deg, transparent, ${color1}88, ${color2}88, transparent)`,
        opacity: titleOpacity,
      }} />
    </div>
  );
};

const PieChart = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  const props = item?.props || {};
  const titleText = props.titleText || 'INSTALLER FEEDBACK';
  const subtitleText = props.subtitleText || 'Review Results by Rating Tier';
  const bgStart = props.bgGradientStart || '#3b4860';
  const bgEnd = props.bgGradientEnd || '#4d5768';
  const titleFontFamily = props.titleFontFamily || 'Inter, sans-serif';
  const monoFont = '"IBM Plex Mono", monospace';

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const rootStyle = {
    position: 'absolute', top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`, transformOrigin: 'top left',
    background: `linear-gradient(135deg, ${bgStart}, ${bgEnd})`,
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center'
  };

  const rawData = React.useMemo(() => [
    { label: props.label1 || 'Excellent', value: Number(props.val1 ?? 48), opacity: 1.0 },
    { label: props.label2 || 'Good', value: Number(props.val2 ?? 31), opacity: 0.7 },
    { label: props.label3 || 'Fair', value: Number(props.val3 ?? 14), opacity: 0.45 },
    { label: props.label4 || 'Weak', value: Number(props.val4 ?? 7), opacity: 0.25 },
  ], [props.label1, props.val1, props.label2, props.val2, props.label3, props.val3, props.label4, props.val4]);

  const data = React.useMemo(() => {
    const totalVal = rawData.reduce((acc, curr) => acc + curr.value, 0) || 1;
    let currentPercent = 0;
    return rawData.map(d => {
      const pct = (d.value / totalVal) * 100;
      const startPercent = currentPercent;
      currentPercent += pct;
      return { ...d, pct, startPercent, endPercent: currentPercent };
    });
  }, [rawData]);

  const safeFps = fps || 30;

  const sweepProgress = interpolate(frame, [15, 75], [0, 100], {
    easing: Easing.out(Easing.cubic),
    extrapolateRight: 'clamp',
    extrapolateLeft: 'clamp'
  });

  // Pie ring dimensions — strokeWidth must be much less than radius
  const cx = 960;
  const cy = 580;
  const radius = 210;
  const ringStrokeWidth = 90;
  const circumference = 2 * Math.PI * radius;

  const titleOpacity = spring({ frame: Math.max(0, frame - 5), fps: safeFps, config: { damping: 20 } });
  const titleY = interpolate(titleOpacity, [0, 1], [-20, 0]);

  return (
    <div style={rootStyle}>
      {/* Header */}
      <div style={{
        position: 'absolute', top: 100, left: 0, width: '100%', textAlign: 'center',
        opacity: titleOpacity, transform: `translateY(${titleY}px)`
      }}>
        <div style={{ fontFamily: titleFontFamily, fontWeight: 600, fontSize: 56, color: props.titleColor || '#fff', letterSpacing: '4px', textTransform: 'uppercase' }}>
          {titleText}
        </div>
        <div style={{ fontFamily: titleFontFamily, fontWeight: 300, fontSize: 24, color: props.textColor || 'rgba(255,255,255,0.7)', letterSpacing: '1px', marginTop: 10 }}>
          {subtitleText}
        </div>
      </div>

      {/* Pie Chart SVG */}
      <svg width={DESIGN_WIDTH} height={DESIGN_HEIGHT} style={{ position: 'absolute', top: 0, left: 0, overflow: 'visible' }}>
        <g transform={`rotate(-90 ${cx} ${cy})`}>
          {data.map((slice, i) => {
            const animatedValue = Math.max(0, Math.min(slice.pct, sweepProgress - slice.startPercent));
            if (animatedValue <= 0) return null;

            // Use a small gap (2px) between segments for clean separation
            const gapAngle = (2 / circumference) * 100;
            const length = Math.max(0, (Math.max(0, animatedValue - gapAngle) / 100) * circumference);
            const offset = -(slice.startPercent / 100) * circumference;

            return (
              <circle
                key={`slice-${i}`}
                cx={cx}
                cy={cy}
                r={radius}
                fill="none"
                stroke={`rgba(${props.ringRgb || '255, 255, 255'}, ${slice.opacity})`}
                strokeWidth={ringStrokeWidth}
                strokeDasharray={`${length} ${circumference}`}
                strokeDashoffset={offset}
                strokeLinecap="butt"
              />
            );
          })}
        </g>

        {/* Callout Lines — solid, not dashed */}
        {data.map((slice, i) => {
          if (slice.pct === 0) return null;
          const centerPercent = slice.startPercent + slice.pct / 2;
          const triggerFrame = 15 + (centerPercent / 100) * 45;
          const calloutPop = spring({ frame: Math.max(0, frame - triggerFrame), fps: safeFps, config: { damping: 14, stiffness: 80 } });

          if (calloutPop === 0) return null;

          // Angle from the center percent of this slice
          const theta = (centerPercent / 100) * 2 * Math.PI;
          const isRight = Math.sin(theta) >= 0;

          const lineR1 = radius + ringStrokeWidth / 2 + 20;
          const lineR2 = lineR1 + 60;

          const lineX1 = cx + lineR1 * Math.sin(theta);
          const lineY1 = cy - lineR1 * Math.cos(theta);
          const lineX2 = cx + lineR2 * Math.sin(theta);
          const lineY2 = cy - lineR2 * Math.cos(theta);
          const lineX3 = isRight ? lineX2 + 50 : lineX2 - 50;
          const lineY3 = lineY2;

          const animX2 = interpolate(calloutPop, [0, 0.5, 1], [lineX1, lineX2, lineX2], { extrapolateRight: 'clamp' });
          const animY2 = interpolate(calloutPop, [0, 0.5, 1], [lineY1, lineY2, lineY2], { extrapolateRight: 'clamp' });
          const animX3 = interpolate(calloutPop, [0.5, 1], [lineX2, lineX3], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

          return (
            <path
              key={`line-${i}`}
              d={`M ${lineX1} ${lineY1} L ${animX2} ${animY2} L ${animX3} ${lineY3}`}
              stroke={props.lineColor || 'rgba(255,255,255,0.8)'}
              strokeWidth="2"
              fill="none"
              opacity={calloutPop}
            />
          );
        })}
      </svg>

      {/* Callout Text */}
      {data.map((slice, i) => {
        if (slice.pct === 0) return null;
        const centerPercent = slice.startPercent + slice.pct / 2;
        const triggerFrame = 15 + (centerPercent / 100) * 45;
        const calloutPop = spring({ frame: Math.max(0, frame - triggerFrame - 5), fps: safeFps, config: { damping: 14 } });

        if (calloutPop === 0) return null;

        const theta = (centerPercent / 100) * 2 * Math.PI;
        const isRight = Math.sin(theta) >= 0;
        const lineR2 = radius + ringStrokeWidth / 2 + 80;
        const lineX2 = cx + lineR2 * Math.sin(theta);
        const lineX3 = isRight ? lineX2 + 50 : lineX2 - 50;
        const lineY3 = cy - lineR2 * Math.cos(theta);

        const divStyle = {
          position: 'absolute',
          top: lineY3,
          left: isRight ? lineX3 + 15 : lineX3 - 15,
          transform: `translate(${isRight ? 0 : '-100%'}, -50%) translateY(${10 - 10 * calloutPop}px)`,
          opacity: calloutPop,
          display: 'flex',
          flexDirection: 'column',
          alignItems: isRight ? 'flex-start' : 'flex-end'
        };

        return (
          <div key={`text-${i}`} style={divStyle}>
            <div style={{ fontFamily: monoFont, fontWeight: 500, fontSize: 48, color: props.titleColor || '#fff', lineHeight: 1 }}>
              {Math.round(slice.pct)}%
            </div>
            <div style={{ fontFamily: titleFontFamily, fontWeight: 300, fontSize: 20, color: props.textColor || 'rgba(255,255,255,0.7)', textTransform: 'uppercase', letterSpacing: '2px', marginTop: 4 }}>
              {slice.label}
            </div>
          </div>
        );
      })}
    </div>
  );
};

