const ConcentricRings = ({item}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const props = item.props || {};

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const titleText = props.titleText || 'CLUB BUDGET SPLIT';
  const subtitleText = props.subtitleText || 'Funding Share by Program Team';
  const bgStart = props.bgGradientStart || '#294f53';
  const bgEnd = props.bgGradientEnd || '#435c5e';
  const ringColor = props.ringColor || '#FFFFFF';
  const trackColor = props.trackColor || 'rgba(255, 255, 255, 0.15)';
  const lineColor = props.lineColor || 'rgba(255, 255, 255, 0.4)';
  const titleFont = props.titleFont || 'Inter, sans-serif';
  const numberFont = props.numberFont || '"IBM Plex Mono", monospace';

  const data = [
    { label: props.label1 || 'Route Planning', value: Number(props.val1 ?? 84), radius: 320 },
    { label: props.label2 || 'Gear & Kit', value: Number(props.val2 ?? 71), radius: 250 },
    { label: props.label3 || 'Safety Checks', value: Number(props.val3 ?? 58), radius: 180 },
    { label: props.label4 || 'Coordination', value: Number(props.val4 ?? 39), radius: 110 },
  ];

  // Layout: center the chart vertically, title at top center
  const cx = 500;
  const cy = 600;
  const midX1 = 1050;
  const midX2 = 1250;
  const lineEndX = 1360;
  const textStartX = 1390;
  const strokeWidth = 40;
  const labelYs = [360, 510, 660, 810];

  const safeFps = fps || 30;

  // Title/subtitle: delay by at least 1 frame so frame=0 is fully hidden
  const titleOpacity = spring({ frame: Math.max(0, frame - 1), fps: safeFps, config: { damping: 20 } });
  const subtitleOpacity = spring({ frame: Math.max(0, frame - 12), fps: safeFps, config: { damping: 20 } });

  const rootStyle = {
    position: 'absolute',
    top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    background: `linear-gradient(135deg, ${bgStart} 0%, ${bgEnd} 100%)`,
    overflow: 'hidden',
    fontFamily: titleFont,
  };

  return (
    <div style={rootStyle}>

      {/* Title — top center */}
      <div style={{
        position: 'absolute', top: 80, left: 0, width: '100%',
        textAlign: 'center',
        opacity: titleOpacity,
        transform: `translateY(${(1 - titleOpacity) * 20}px)`
      }}>
        <h1 style={{ margin: 0, fontSize: 56, fontWeight: 600, color: props.titleColor || '#FFF', letterSpacing: '4px', textTransform: 'uppercase' }}>
          {titleText}
        </h1>
        <h2 style={{
          margin: '12px 0 0 0', fontSize: 28, fontWeight: 300,
          color: props.textColor || 'rgba(255,255,255,0.6)', letterSpacing: '1px',
          opacity: subtitleOpacity,
          transform: `translateY(${(1 - subtitleOpacity) * 16}px)`
        }}>
          {subtitleText}
        </h2>
      </div>

      <svg width={DESIGN_WIDTH} height={DESIGN_HEIGHT} style={{ position: 'absolute', top: 0, left: 0 }}>

        {/* Leader Lines:
            Frame timeline (all frame-based for precise timing):
            - Frame 5–35: track rings fade in inner→outer (accompaniment)
            - Frame 20–55: trunk grows from innermost ring rightward to forkX (35 frames)
            - Dots appear as trunk passes each ring edge
            - Frame 55–95: 4 branches grow simultaneously from forkX to labels (40 frames)
        */}
        {(() => {
          const sortedByRadius = [...data].sort((a, b) => a.radius - b.radius);
          const innermost = sortedByRadius[0];

          const trunkStartX = cx + innermost.radius;
          const trunkY = cy;
          const forkX = midX1;
          const trunkLen = forkX - trunkStartX;

          // Trunk: frames 20→55
          const trunkStartFrame = 20;
          const trunkEndFrame = 55;
          const trunkProgress = interpolate(frame, [trunkStartFrame, trunkEndFrame], [0, 1], {
            extrapolateLeft: 'clamp', extrapolateRight: 'clamp',
            easing: Easing.out(Easing.cubic)
          });

          // Branches: frames 55→85, linear easing so growth is visible from frame 1
          const branchStartFrame = 55;
          const branchEndFrame = 85;
          const branchProgress = interpolate(frame, [branchStartFrame, branchEndFrame], [0, 1], {
            extrapolateLeft: 'clamp', extrapolateRight: 'clamp',
            easing: Easing.out(Easing.quad)
          });

          const trunkTipX = interpolate(trunkProgress, [0, 1], [trunkStartX, forkX], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

          return (
            <g>
              {/* Trunk */}
              {trunkProgress > 0 && (
                <line x1={trunkStartX} y1={trunkY} x2={trunkTipX} y2={trunkY}
                  stroke={lineColor} strokeWidth={2} />
              )}

              {/* White dot at each ring's right edge — fades in as trunk passes */}
              {sortedByRadius.map((d, i) => {
                const dotX = cx + d.radius;
                const fraction = (dotX - trunkStartX) / trunkLen;
                // dot appears when trunk tip reaches this x
                const dotFrame = trunkStartFrame + fraction * (trunkEndFrame - trunkStartFrame);
                const dotOpacity = interpolate(frame, [dotFrame, dotFrame + 6], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
                if (dotOpacity <= 0) return null;
                return (
                  <circle key={`dot-ring-${i}`} cx={dotX} cy={trunkY} r={5}
                    fill={ringColor} opacity={dotOpacity} />
                );
              })}

              {/* 4 Branches — strokeDashoffset growth from forkX outward */}
              {branchProgress > 0 && data.map((d, i) => {
                const labelY = labelYs[i];
                // Fixed full path: forkX,trunkY → midX2,labelY → lineEndX,labelY
                const diagLen = Math.sqrt(Math.pow(midX2 - forkX, 2) + Math.pow(labelY - trunkY, 2));
                const horizLen = lineEndX - midX2;
                const totalLen = diagLen + horizLen;
                const dashOffset = totalLen * (1 - branchProgress);

                // End dot appears when branch fully drawn
                const endDotOpacity = interpolate(frame, [branchEndFrame - 2, branchEndFrame + 4], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

                return (
                  <g key={`branch-${i}`}>
                    <path
                      d={`M ${forkX},${trunkY} L ${midX2},${labelY} L ${lineEndX},${labelY}`}
                      stroke={lineColor} strokeWidth={2} fill="none"
                      strokeDasharray={totalLen}
                      strokeDashoffset={dashOffset}
                    />
                    {endDotOpacity > 0 && (
                      <circle cx={lineEndX} cy={labelY} r={4} fill={ringColor} opacity={endDotOpacity} />
                    )}
                  </g>
                );
              })}
            </g>
          );
        })()}

        {/* Concentric Ring Tracks + Animated Value Rings */}
        <g transform={`rotate(-90 ${cx} ${cy})`}>
          {data.map((d, i) => {
            // innerToOuterIndex: 0 = innermost (r=110), 3 = outermost (r=320)
            // data array is [r=320, r=250, r=180, r=110], so i=3 is innermost
            const innerToOuterIndex = data.length - 1 - i;

            // Track ring: fades in early (frames 5→17 per ring, inner first)
            // This accompanies the trunk/dot animation starting at frame 20
            const trackDelay = innerToOuterIndex * 10 + 5;
            const trackOpacity = interpolate(frame, [trackDelay, trackDelay + 12], [0, 1], {
              extrapolateLeft: 'clamp', extrapolateRight: 'clamp',
              easing: Easing.out(Easing.cubic)
            });

            // Fill arc: starts later (frame 30+, inner first), soft spring
            const delay = innerToOuterIndex * 14 + 30;
            const progress = spring({ frame: Math.max(0, frame - delay), fps: safeFps, config: { damping: 28, mass: 2.0, stiffness: 60 } });
            const circumference = 2 * Math.PI * d.radius;
            const offset = circumference * (1 - (progress * (d.value / 100)));
            // Fill arc fades in by frame range (not spring progress) — guaranteed smooth
            const fillOpacity = interpolate(frame, [delay, delay + 10], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: Easing.out(Easing.cubic) });

            return (
              <g key={`ring-${i}`}>
                {/* Track — fades in early as accompaniment to trunk/dots */}
                <circle
                  cx={cx} cy={cy} r={d.radius}
                  stroke={trackColor} strokeWidth={strokeWidth} fill="none"
                  opacity={trackOpacity}
                />
                {/* Value Ring — fades in + grows after tracks are visible */}
                <circle
                  cx={cx} cy={cy} r={d.radius}
                  stroke={ringColor} strokeWidth={strokeWidth} fill="none"
                  strokeLinecap="round"
                  strokeDasharray={circumference}
                  strokeDashoffset={offset}
                  opacity={fillOpacity}
                />
              </g>
            );
          })}
        </g>
      </svg>

      {/* Data Labels — also innermost first */}
      {data.map((d, i) => {
        const innerToOuterIndex = data.length - 1 - i;
        const delay = innerToOuterIndex * 14 + 90; // after rings + lines settle
        const textOpacity = spring({ frame: Math.max(0, frame - delay), fps: safeFps, config: { damping: 24, mass: 1.5 } });
        const slideX = interpolate(textOpacity, [0, 1], [-30, 0]);
        const ringDelay = innerToOuterIndex * 14 + 30;
        const progress = spring({ frame: Math.max(0, frame - ringDelay), fps: safeFps, config: { damping: 28, mass: 2.0, stiffness: 60 } });
        const currentVal = Math.round(progress * d.value);

        return (
          <div
            key={`text-${i}`}
            style={{
              position: 'absolute',
              top: labelYs[i] - 48,
              left: textStartX,
              opacity: textOpacity,
              transform: `translateX(${slideX}px)`,
              display: 'flex',
              flexDirection: 'column',
              justifyContent: 'center',
              height: 96
            }}
          >
            <div style={{ fontFamily: numberFont, fontSize: 56, fontWeight: 500, color: ringColor, lineHeight: 1 }}>
              {currentVal}%
            </div>
            <div style={{
              fontFamily: titleFont, fontSize: 22, fontWeight: 400,
              color: props.textColor || 'rgba(255,255,255,0.7)', textTransform: 'uppercase',
              letterSpacing: '2px', marginTop: 6
            }}>
              {d.label}
            </div>
          </div>
        );
      })}
    </div>
  );
};

const UserDemographicsChart = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const props = item.props || {};

  const title = props.title || 'LISTENER DEMOGRAPHICS';
  const subtitle = props.subtitle || 'Age Group Breakdown';
  const bgStart = props.bgStart || '#100e24';
  const bgEnd = props.bgEnd || '#32314b';
  const baseColor = props.baseColor || '#ce70c5';

  const slices = [
    { label: props.label1 || 'Age 16-24', value: Number(props.val1) || 42, opacity: 1.0 },
    { label: props.label2 || 'Age 25-34', value: Number(props.val2) || 31, opacity: 0.75 },
    { label: props.label3 || 'Age 35-44', value: Number(props.val3) || 17, opacity: 0.5 },
    { label: props.label4 || 'Age 45+',   value: Number(props.val4) || 10, opacity: 0.28 },
  ];

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);
  const safeFps = fps || 30;

  const CX = DESIGN_WIDTH / 2;
  const CY = DESIGN_HEIGHT / 2 + 60;
  const RADIUS = 300;
  const LABEL_R = RADIUS + 90;

  const total = slices.reduce((a, b) => a + b.value, 0) || 1;
  let accumulated = 0;
  const processed = slices.map((s) => {
    const pct = s.value / total;
    const startP = accumulated;
    accumulated += pct;
    const midAngle = (startP + pct / 2) * 2 * Math.PI - Math.PI / 2;
    return { ...s, pct, startP, endP: accumulated, midAngle };
  });

  const getCoords = (p, r) => {
    const x = Math.cos(2 * Math.PI * p - Math.PI / 2) * r;
    const y = Math.sin(2 * Math.PI * p - Math.PI / 2) * r;
    return [x, y];
  };

  const makeSlicePath = (startP, endP, r) => {
    const [sx, sy] = getCoords(startP, r);
    const [ex, ey] = getCoords(endP, r);
    const large = endP - startP > 0.5 ? 1 : 0;
    return `M 0 0 L ${sx} ${sy} A ${r} ${r} 0 ${large} 1 ${ex} ${ey} Z`;
  };

  const titleSpring = spring({ frame, fps: safeFps, config: { damping: 22, stiffness: 90 } });
  const titleOpacity = interpolate(titleSpring, [0, 1], [0, 1]);
  const titleY = interpolate(titleSpring, [0, 1], [-40, 0]);

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      background: `linear-gradient(135deg, ${bgStart} 0%, ${bgEnd} 100%)`,
      transform: `scale(${scale})`, transformOrigin: 'top left',
      overflow: 'hidden', fontFamily: "'Inter', sans-serif", color: props.textColor || '#f7d9ed',
    }}>
      <div style={{
        position: 'absolute', top: 0, left: 0, right: 0, height: 3,
        background: `linear-gradient(90deg, transparent, ${baseColor}, transparent)`,
        opacity: titleOpacity,
      }} />

      <div style={{
        position: 'absolute', top: 80, width: '100%', textAlign: 'center',
        opacity: titleOpacity, transform: `translateY(${titleY}px)`,
      }}>
        <div style={{ fontSize: 76, fontWeight: 900, letterSpacing: '0.08em', textTransform: 'uppercase',
          textShadow: `0 0 40px ${baseColor}88` }}>{title}</div>
        <div style={{ fontSize: 28, fontWeight: 300, marginTop: 14, opacity: 0.7, letterSpacing: '0.12em' }}>{subtitle}</div>
      </div>

      {/* Pie chart */}
      <div style={{
        position: 'absolute',
        left: CX - RADIUS, top: CY - RADIUS,
        width: RADIUS * 2, height: RADIUS * 2,
      }}>
        <svg width={RADIUS * 2} height={RADIUS * 2}
          viewBox={`${-RADIUS} ${-RADIUS} ${RADIUS * 2} ${RADIUS * 2}`}
          style={{ overflow: 'visible' }}>

          {processed.map((sl, i) => {
            const delay = 18 + i * 10;
            const entrance = spring({ frame: Math.max(0, frame - delay), fps: safeFps,
              config: { stiffness: 70, damping: 16 } });
            const animEnd = interpolate(entrance, [0, 1], [sl.startP, sl.endP]);
            const scaleV = interpolate(entrance, [0, 1], [0, 1]);
            if (frame < delay) return null;

            return (
              <g key={i} transform={`scale(${scaleV})`}>
                <path
                  d={makeSlicePath(sl.startP, animEnd, RADIUS)}
                  fill={`rgba(206,112,197,${sl.opacity})`}
                  stroke={props.sliceStrokeColor || 'rgba(16,14,36,0.8)'} strokeWidth={3}
                />
              </g>
            );
          })}
        </svg>

        {/* Labels */}
        {processed.map((sl, i) => {
          const delay = 30 + i * 10;
          const lEntrance = spring({ frame: Math.max(0, frame - delay), fps: safeFps, config: { damping: 20 } });
          if (frame < delay) return null;

          const lx = Math.cos(sl.midAngle) * LABEL_R;
          const ly = Math.sin(sl.midAngle) * LABEL_R;
          const isLeft = lx < 0;

          return (
            <div key={`lbl-${i}`} style={{
              position: 'absolute',
              left: RADIUS + lx, top: RADIUS + ly,
              opacity: lEntrance,
              transform: `translate(${isLeft ? '-100%' : '0'}, -50%)`,
              padding: isLeft ? '0 0 0 0' : '0',
            }}>
              <div style={{ fontSize: 44, fontWeight: 800,
                fontFamily: "'IBM Plex Mono', monospace", lineHeight: 1,
                color: baseColor, textShadow: `0 0 12px ${baseColor}` }}>
                {sl.value}%
              </div>
              <div style={{ fontSize: 22, opacity: 0.85, marginTop: 4, whiteSpace: 'nowrap' }}>
                {sl.label}
              </div>
            </div>
          );
        })}
      </div>

      <div style={{
        position: 'absolute', bottom: 0, left: 0, right: 0, height: 2,
        background: `linear-gradient(90deg, transparent, ${baseColor}88, transparent)`,
        opacity: titleOpacity,
      }} />
    </div>
  );
};

const DonutChartInfographic = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // --- Editable Properties ---
  const props = item.props || {};
  const titleText = props.titleText || 'Client Acquisition Breakdown';
  const centerText = props.centerText || 'Client Source';
  const subTitleText = props.subTitleText || 'Client Acquisition Breakdown';
  const bgColor = props.bgColor || '#00292d';
  const accentColor = props.accentColor || '#ffffff';
  const titleFont = props.titleFont || 'Noto Sans SC, sans-serif';

  // Data definition with fallbacks
  const rawData = [
    {
      label: props.label1 || 'Search Engine',
      value: parseFloat(props.val1 || '42'),
      c1: props.color1Start || '#18d7d5',
      c2: props.color1End || '#00bab9'
    },
    {
      label: props.label2 || 'Social Media',
      value: parseFloat(props.val2 || '25'),
      c1: props.color2Start || '#57c15d',
      c2: props.color2End || '#009656'
    },
    {
      label: props.label3 || 'Walk-In',
      value: parseFloat(props.val3 || '18'),
      c1: props.color3Start || '#c49c00',
      c2: props.color3End || '#886b00'
    },
    {
      label: props.label4 || 'Referral',
      value: parseFloat(props.val4 || '10'),
      c1: props.color4Start || '#53d3a5',
      c2: props.color4End || '#339472'
    },
    {
      label: props.label5 || 'Newsletter',
      value: parseFloat(props.val5 || '5'),
      c1: props.color5Start || '#57baff',
      c2: props.color5End || '#009cc9'
    }
  ];

  // Filter out zero/negative values to avoid drawing errors
  const data = rawData.filter(d => d.value > 0);
  const totalValue = data.reduce((acc, cur) => acc + cur.value, 0);

  // --- Layout Constants ---
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const cx = DESIGN_WIDTH / 2;
  const cy = DESIGN_HEIGHT / 2 + 50;
  const outerRadius = 320;
  const innerRadius = 180;
  const labelRadius = outerRadius + 60;

  // --- Animation ---
  // Main chart sweep
  const chartEntrance = spring({
    frame,
    fps,
    config: { damping: 20, stiffness: 90, mass: 1 }
  });

  // Labels fade in after chart starts settling
  const labelsEntrance = spring({
    frame: Math.max(0, frame - 25),
    fps,
    config: { damping: 20 }
  });

  // --- Geometry Helpers ---
  const polarToCartesian = (centerX, centerY, radius, angleInDegrees) => {
    const angleInRadians = ((angleInDegrees - 90) * Math.PI) / 180.0;
    return {
      x: centerX + radius * Math.cos(angleInRadians),
      y: centerY + radius * Math.sin(angleInRadians),
    };
  };

  const describeArc = (x, y, innerR, outerR, startAngle, endAngle) => {
    // Avoid 360 collision which causes drawing glitches in some engines
    const isFullCircle = endAngle - startAngle >= 359.9;
    const safeEndAngle = isFullCircle ? startAngle + 359.99 : endAngle;

    const startOuter = polarToCartesian(x, y, outerR, startAngle);
    const endOuter = polarToCartesian(x, y, outerR, safeEndAngle);
    const startInner = polarToCartesian(x, y, innerR, startAngle);
    const endInner = polarToCartesian(x, y, innerR, safeEndAngle);

    const largeArcFlag = safeEndAngle - startAngle <= 180 ? '0' : '1';

    return [
      'M', startOuter.x, startOuter.y,
      'A', outerR, outerR, 0, largeArcFlag, 1, endOuter.x, endOuter.y,
      'L', endInner.x, endInner.y,
      'A', innerR, innerR, 0, largeArcFlag, 0, startInner.x, startInner.y,
      'Z'
    ].join(' ');
  };

  // --- Calculate Slices ---
  let cumulativeAngle = 0;
  const slices = data.map((slice, i) => {
    const percentage = slice.value / totalValue;
    const angleSize = percentage * 360;

    // Animate the sweep: The total chart unfolds from 0 to 360 based on chartEntrance
    // But also each slice grows. 
    // "Fan out" effect: multiply all angles by progress
    const currentTotalAngle = 360 * chartEntrance;
    const startAngle = cumulativeAngle * chartEntrance;
    const endAngle = (cumulativeAngle + angleSize) * chartEntrance;

    const midAngle = startAngle + (endAngle - startAngle) / 2;
    cumulativeAngle += angleSize;

    return {
      ...slice,
      startAngle,
      endAngle,
      midAngle,
      percentage,
      index: i
    };
  });

  // --- Render ---
  const rootStyle = {
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    backgroundColor: bgColor,
    fontFamily: titleFont,
    color: 'white',
    position: 'absolute',
    top: 0,
    left: 0,
    overflow: 'hidden',
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
  };

  const titleStyle = {
    position: 'absolute',
    top: 80,
    left: 100,
    zIndex: 10,
  };

  return (
    <div style={rootStyle}>
      {/* Background Gradient Effect */}
      <div style={{
        position: 'absolute',
        width: '100%', height: '100%',
        background: 'radial-gradient(circle at 50% 50%, rgba(255,255,255,0.03) 0%, rgba(0,0,0,0) 60%)'
      }} />

      {/* Title Block */}
      <div style={titleStyle}>
        <h1 style={{
          margin: 0,
          fontSize: '64px',
          fontWeight: 700,
          letterSpacing: '-0.02em',
          opacity: Math.min(1, frame / 30),
          transform: `translateY(${(1 - Math.min(1, frame/30)) * 20}px)`
        }}>
          {titleText}
        </h1>
        <p style={{
          margin: '10px 0 0 0',
          fontSize: '28px',
          color: 'rgba(255,255,255,0.6)',
          fontWeight: 400,
          opacity: Math.min(1, Math.max(0, frame - 10) / 30),
          transform: `translateY(${(1 - Math.min(1, Math.max(0, frame - 10)/30)) * 20}px)`
        }}>
          {subTitleText}
        </p>
      </div>

      {/* Chart Container */}
      <svg 
        width={DESIGN_WIDTH} 
        height={DESIGN_HEIGHT} 
        viewBox={`0 0 ${DESIGN_WIDTH} ${DESIGN_HEIGHT}`}
        style={{ position: 'absolute', top: 0, left: 0 }}
      >
        <defs>
          {data.map((slice, i) => (
            <linearGradient 
              key={`grad-${i}`} 
              id={`grad-${i}`} 
              x1="0%" y1="0%" x2="100%" y2="100%"
            >
              <stop offset="0%" stopColor={slice.c1} />
              <stop offset="100%" stopColor={slice.c2} />
            </linearGradient>
          ))}
          {/* Shadow filter for depth */}
          <filter id="dropShadow" x="-20%" y="-20%" width="140%" height="140%">
            <feGaussianBlur in="SourceAlpha" stdDeviation="4" />
            <feOffset dx="2" dy="4" result="offsetblur" />
            <feComponentTransfer>
              <feFuncA type="linear" slope="0.3" />
            </feComponentTransfer>
            <feMerge>
              <feMergeNode />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
        </defs>

        {/* Donut Slices */}
        <g filter="url(#dropShadow)">
          {slices.map((slice, i) => (
            <path
              key={`slice-${i}`}
              d={describeArc(cx, cy, innerRadius, outerRadius, slice.startAngle, slice.endAngle)}
              fill={`url(#grad-${i})`}
              stroke={bgColor}
              strokeWidth="4"
            />
          ))}
        </g>

        {/* Labels & Connectors */}
        {slices.map((slice, i) => {
          // Only show labels if slice is large enough and animation is ready
          if (slice.percentage < 0.02) return null;

          const normalizedAngle = (slice.midAngle % 360 + 360) % 360;
          const isRightSide = normalizedAngle < 180;

          // Calculate connector points
          // Start at edge of donut
          const p1 = polarToCartesian(cx, cy, outerRadius, slice.midAngle);
          // Elbow point
          const p2 = polarToCartesian(cx, cy, labelRadius, slice.midAngle);
          // Text anchor point (push out horizontally)
          const p3 = {
            x: isRightSide ? p2.x + 80 : p2.x - 80,
            y: p2.y
          };

          return (
            <g 
              key={`label-${i}`} 
              style={{ opacity: labelsEntrance }}
            >
              {/* Connector Polyline */}
              <polyline
                points={`${p1.x},${p1.y} ${p2.x},${p2.y} ${p3.x},${p3.y}`}
                fill="none"
                stroke="rgba(255,255,255,0.4)"
                strokeWidth="2"
              />
              {/* Dot at start */}
              <circle cx={p1.x} cy={p1.y} r="4" fill={slice.c2} />

              {/* Text Group */}
              <g transform={`translate(${p3.x + (isRightSide ? 10 : -10)}, ${p3.y})`}>
                <text
                  x={0}
                  y={-5}
                  textAnchor={isRightSide ? 'start' : 'end'}
                  fill="white"
                  fontSize="24"
                  fontWeight="bold"
                  fontFamily={titleFont}
                  alignmentBaseline="baseline"
                >
                  {slice.label}
                </text>
                <text
                  x={0}
                  y={22}
                  textAnchor={isRightSide ? 'start' : 'end'}
                  fill={slice.c1}
                  fontSize="32"
                  fontWeight="bold"
                  fontFamily="'IBM Plex Mono', monospace"
                  alignmentBaseline="baseline"
                >
                  {Math.round(slice.value / totalValue * 100)}%
                </text>
              </g>
            </g>
          );
        })}
      </svg>

      {/* Center Content */}
      <div style={{
        position: 'absolute',
        left: cx - innerRadius + 20,
        top: cy - innerRadius + 20,
        width: (innerRadius - 20) * 2,
        height: (innerRadius - 20) * 2,
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center',
        borderRadius: '50%',
        textAlign: 'center',
        opacity: labelsEntrance,
        transform: `scale(${labelsEntrance})`
      }}>
         <div style={{ 
           fontSize: '20px', 
           color: 'rgba(255,255,255,0.6)', 
           marginBottom: '10px',
           textTransform: 'uppercase',
           letterSpacing: '0.1em'
         }}>
           Total
         </div>
         <div style={{ 
           fontSize: '42px', 
           fontWeight: 800, 
           color: '#ffffff' 
         }}>
           {centerText}
         </div>
      </div>
    </div>
  );
};

const withAlphaRG = (color, alpha) => {
  const m = String(color).match(/rgba?\(\s*(\d+),\s*(\d+),\s*(\d+)(?:,\s*([\d.]+))?\s*\)/);
  if (m) {
    const a = parseFloat(m[4] || '1') * alpha;
    return 'rgba(' + m[1] + ',' + m[2] + ',' + m[3] + ',' + a.toFixed(4) + ')';
  }
  return color;
};

const evalBezierRG = (seg, t) => {
  const mt = 1 - t;
  return [
    mt * mt * mt * seg[0][0] + 3 * mt * mt * t * seg[1][0] + 3 * mt * t * t * seg[2][0] + t * t * t * seg[3][0],
    mt * mt * mt * seg[0][1] + 3 * mt * mt * t * seg[1][1] + 3 * mt * t * t * seg[2][1] + t * t * t * seg[3][1],
  ];
};

const getSegLenRG = (seg) => {
  let length = 0;
  let prev = evalBezierRG(seg, 0);
  for (let i = 1; i <= 48; i++) {
    const cur = evalBezierRG(seg, i / 48);
    const dx = cur[0] - prev[0];
    const dy = cur[1] - prev[1];
    length += Math.sqrt(dx * dx + dy * dy);
    prev = cur;
  }
  return length;
};

const RetentionGraphWhite = ({ item }) => {
  const frame = useCurrentFrame();
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const SEGS = [
    [[0, 160], [30, 160], [50, 90], [80, 90]],
    [[80, 90], [120, 90], [150, 265], [200, 265]],
    [[200, 265], [240, 265], [260, 220], [300, 220]],
    [[300, 220], [350, 220], [378, 295], [420, 295]],
    [[420, 295], [452, 295], [470, 278], [500, 278]],
    [[500, 278], [548, 278], [575, 345], [645, 382]],
    [[645, 382], [740, 408], [848, 400], [950, 400]],
  ];

  const PATH_D =
    'M 0 160 C 30 160, 50 90, 80 90 ' +
    'C 120 90, 150 265, 200 265 ' +
    'C 240 265, 260 220, 300 220 ' +
    'C 350 220, 378 295, 420 295 ' +
    'C 452 295, 470 278, 500 278 ' +
    'C 548 278, 575 345, 645 382 ' +
    'C 740 408, 848 400, 950 400';

  const props = item.props || {};
  const titleText = props.titleText;
  const fontFamily = props.fontFamily;
  const lineColor = props.lineColor;
  const fillColorStart = props.fillColorStart;
  const fillColorEnd = props.fillColorEnd;
  const bgColorOuter = props.bgColorOuter;
  const transparentBackground = props.transparentBackground;

  const SEG_LENS = React.useMemo(() => SEGS.map(getSegLenRG), []);
  const TOTAL_LEN = React.useMemo(() => SEG_LENS.reduce((s, l) => s + l, 0), [SEG_LENS]);

  const buildAreaPath = (progress) => {
    if (progress <= 0) return null;
    const targetLen = progress * TOTAL_LEN;
    const points = [[0, 100]];
    let accumulated = 0;
    let done = false;
    for (let si = 0; si < SEGS.length && !done; si++) {
      const seg = SEGS[si];
      const segLen = SEG_LENS[si];
      let prevPoint = evalBezierRG(seg, 0);
      let cumulativeInSegment = 0;
      for (let i = 1; i <= 32 && !done; i++) {
        const t = i / 32;
        const cur = evalBezierRG(seg, t);
        const dx = cur[0] - prevPoint[0];
        const dy = cur[1] - prevPoint[1];
        const stepLen = Math.sqrt(dx * dx + dy * dy);
        cumulativeInSegment += stepLen;
        if (accumulated + cumulativeInSegment >= targetLen) {
          const overshoot = accumulated + cumulativeInSegment - targetLen;
          const ratio = stepLen === 0 ? 0 : 1 - overshoot / stepLen;
          points.push([
            prevPoint[0] + (cur[0] - prevPoint[0]) * ratio,
            prevPoint[1] + (cur[1] - prevPoint[1]) * ratio,
          ]);
          done = true;
        } else {
          points.push([cur[0], cur[1]]);
          prevPoint = cur;
        }
      }
      if (!done) accumulated += segLen;
    }
    if (points.length < 2) return null;
    const tip = points[points.length - 1];
    return (
      'M ' + points.map((p) => p[0].toFixed(2) + ' ' + p[1].toFixed(2)).join(' L ') +
      ' L ' + tip[0].toFixed(2) + ' 460 L 0 460 Z'
    );
  };

