const RevenueOverlay = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const titleText = props.titleText;
  const prefix = props.prefix;
  const targetValue = props.targetValue;
  const titleColor = props.titleColor;
  const numberColor = props.numberColor;
  const transparentBackground = props.transparentBackground;
  const fontFamily = props.fontFamily;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // Timings: 0-24 (Title fade), 30-54 (Number fade), 30-105 (Number roll)
  const titleOpacity = interpolate(frame, [0, 24], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const titleBlur = interpolate(frame, [0, 24], [24, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  const numberOpacity = interpolate(frame, [30, 54], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const numberBlur = interpolate(frame, [30, 54], [40, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  const countProgress = interpolate(frame, [30, 105], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.bezier(0.1, 1, 0.2, 1) // Decelerates smoothly near the target
  });
  const currentValue = Math.floor(countProgress * Number(targetValue));
  const formattedValue = `${prefix}${currentValue.toLocaleString('en-US')}`;

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: transparentBackground ? 'transparent' : '#000708',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    fontFamily: fontFamily
  };

  const titleStyle = {
    fontSize: '72px',
    fontWeight: 600,
    color: titleColor,
    opacity: titleOpacity,
    filter: `blur(${titleBlur}px)`,
    textShadow: `0 0 15px ${titleColor}80, 0 0 30px ${titleColor}40`,
    margin: 0,
    marginBottom: '20px',
    lineHeight: 1,
    letterSpacing: '1px',
    textAlign: 'center'
  };

  const numberStyle = {
    fontSize: '300px',
    fontWeight: 800,
    color: numberColor,
    opacity: numberOpacity,
    filter: `blur(${numberBlur}px)`,
    textShadow: `0 0 40px ${numberColor}, 0 0 80px ${numberColor}B3, 0 0 140px ${numberColor}80`,
    margin: 0,
    lineHeight: 1,
    letterSpacing: '-6px',
    textAlign: 'center',
    marginTop: '-20px'
  };

  return (
    <div style={rootStyle}>
      <div style={titleStyle}>{titleText}</div>
      <div style={numberStyle}>{formattedValue}</div>
    </div>
  );
};

