const FruitChecklist = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  // CONFIGURATION
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // EDITABLE PROPERTIES
  const po = item?.propertyOverrides || {};
  const item1Text = po.item1Text ?? "CARBON FRAME";
  const item2Text = po.item2Text ?? "DISC BRAKES";
  const item3Text = po.item3Text ?? "URBAN RIDING GEAR";
  const textColor = po.textColor ?? "#FFFFFF";
  const checkColor = po.checkColor ?? "#de72c9";
  const boxBorderColor = po.boxBorderColor ?? "#FFFFFF";
  const listX = po.listX ?? 150;
  const listY = po.listY ?? 650;
  const rowSpacing = po.rowSpacing ?? 120;
  const fontSize = po.fontSize ?? 60;

  // CONTENT
  const items = [
    { id: 1, text: item1Text, startFrame: 10 },
    { id: 2, text: item2Text, startFrame: 40 },
    { id: 3, text: item3Text, startFrame: 70 }
  ];

  const CHECK_DELAY = 15;
  const EXIT_START_FRAME = 105;

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    backgroundColor: 'transparent',
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    fontFamily: 'Inter, Roboto, sans-serif',
    fontWeight: 900,
    overflow: 'hidden'
  };

  return (
    <div style={rootStyle}>
      {items.map((listItem, i) => {
        const slideProgress = spring({
          frame: frame - listItem.startFrame,
          fps,
          config: { damping: 16, stiffness: 120, mass: 0.8 }
        });

        const checkStartFrame = listItem.startFrame + CHECK_DELAY;
        const checkProgress = spring({
          frame: frame - checkStartFrame,
          fps,
          config: { damping: 14, stiffness: 100 }
        });

        const isVisible = frame >= listItem.startFrame;
        const checkVisible = frame >= checkStartFrame;

        const boxRotationProgress = spring({
          frame: frame - listItem.startFrame,
          fps,
          config: { damping: 8, stiffness: 150, mass: 0.6 }
        });

        const exitFrames = frame - EXIT_START_FRAME;
        const exitDuration = 18;
        const isExiting = frame >= EXIT_START_FRAME;
        const exitRaw = Math.min(Math.max(exitFrames / exitDuration, 0), 1);
        const exitEased = 1 - Math.pow(1 - exitRaw, 3);

        const enterY = interpolate(slideProgress, [0, 1], [60, 0]);
        const translateY = enterY;
        const enterOpacity = isVisible ? interpolate(slideProgress, [0, 1], [0, 1]) : 0;
        const exitOpacity = isExiting ? interpolate(exitEased, [0, 1], [1, 0]) : 1;
        const opacity = enterOpacity * exitOpacity;
        const boxRotation = isVisible ? interpolate(boxRotationProgress, [0, 1], [25, 0]) : 25;
        const checkOpacity = checkVisible ? 1 : 0;

        const rowStyle = {
          position: 'absolute',
          left: listX,
          top: listY + (i * rowSpacing),
          display: 'flex',
          alignItems: 'center',
          gap: '30px',
          transform: `translateY(${translateY}px)`,
          opacity,
        };

        const boxStyle = {
          width: '60px',
          height: '60px',
          backgroundColor: 'transparent',
          border: `5px solid ${boxBorderColor}`,
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          position: 'relative',
          transform: `rotate(${boxRotation}deg)`,
        };

        const textStyle = {
          fontSize: `${fontSize}px`,
          color: textColor,
          textTransform: 'uppercase',
          margin: 0,
          lineHeight: 1,
          textShadow: '2px 2px 0px #000000, 0 8px 20px rgba(0,0,0,0.6)',
          letterSpacing: '-1px'
        };

        return (
          <div key={listItem.id} style={rowStyle}>
            <div style={boxStyle}>
              <svg
                width="85"
                height="85"
                viewBox="0 0 100 100"
                style={{ overflow: 'visible', opacity: checkOpacity, position: 'absolute', top: '-15px', left: '-15px' }}
              >
                <path
                  d="M 8 50 Q 22 68 32 80"
                  fill="none"
                  stroke={checkColor}
                  strokeWidth="18"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeDasharray="80"
                  strokeDashoffset={interpolate(checkProgress, [0, 0.4], [80, 0], {extrapolateRight: 'clamp'})}
                />
                <polygon
                  points="24,72 40,88 98,-8 88,-2"
                  fill={checkColor}
                  style={{
                    clipPath: `inset(${interpolate(checkProgress, [0.3, 1], [100, 0], {extrapolateLeft: 'clamp', extrapolateRight: 'clamp'})}% 0 0 0)`
                  }}
                />
              </svg>
            </div>
            <h1 style={textStyle}>{listItem.text}</h1>
          </div>
        );
      })}
    </div>
  );
};

