const SpecCardOverlay = ({item}) => {
  const frame = useCurrentFrame();
  const { durationInFrames } = useVideoConfig();
  const props = item.props || {};

  const transparentBackground = props.transparentBackground;
  const panelColor = props.panelColor;
  const accentColor = props.accentColor;
  const textColor = props.textColor;
  const brandColor = props.brandColor;
  const fontFamily = props.fontFamily;
  const textOffsetX = props.textOffsetX !== undefined ? props.textOffsetX : 0;

  const brandText = props.brandText;
  const titleText = props.titleText;
  const priceText = props.priceText;

  const specsArray = [
    props.spec1, props.spec2, props.spec3, props.spec4,
    props.spec5, props.spec6, props.spec7, props.spec8,
    props.spec9, props.spec10, props.spec11
  ].filter(s => s && s.trim() !== '');

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const introDuration = 25;
  const outroDuration = 25;
  const outroStart = durationInFrames - outroDuration;
  const OFFSCREEN = -1100;

  const panelX = (() => {
    if (frame <= introDuration) {
      return interpolate(frame, [0, introDuration], [OFFSCREEN, 0], {
        easing: Easing.out(Easing.cubic),
        extrapolateLeft: 'clamp',
        extrapolateRight: 'clamp'
      });
    }
    if (frame >= outroStart) {
      return interpolate(frame, [outroStart, durationInFrames], [0, OFFSCREEN], {
        easing: Easing.in(Easing.cubic),
        extrapolateLeft: 'clamp',
        extrapolateRight: 'clamp'
      });
    }
    return 0;
  })();

  const getAnimStyle = (index) => {
    const startFrame = 20 + index * 2;
    const opacity = interpolate(frame, [startFrame, startFrame + 12], [0, 1], { extrapolateRight: 'clamp', extrapolateLeft: 'clamp' });
    const y = interpolate(frame, [startFrame, startFrame + 15], [18, 0], {
      easing: Easing.out(Easing.cubic),
      extrapolateRight: 'clamp',
      extrapolateLeft: 'clamp'
    });
    return { opacity, transform: `translateY(${y}px)` };
  };

  const actualAccentColor = transparentBackground ? 'transparent' : accentColor;
  const panelGradient = transparentBackground
    ? 'transparent'
    : `linear-gradient(to right, ${panelColor} 0%, #130900 100%)`;

  const SKEW_DEG = 5;
  const PANEL_W = 860;
  const PANEL_TOTAL_W = PANEL_W + 120;
  // Text area: centered inside the visible panel, with symmetric padding
  // skew compensation: at PANEL_W width, skewX(-5deg) shifts right edge by ~75px

  return (
    <div style={{
      position: 'absolute',
      top: 0,
      left: 0,
      width: DESIGN_WIDTH,
      height: DESIGN_HEIGHT,
      transform: `scale(${scale})`,
      transformOrigin: 'top left',
      backgroundColor: 'transparent',
      overflow: 'hidden',
      fontFamily: fontFamily
    }}>
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        width: PANEL_TOTAL_W,
        height: DESIGN_HEIGHT,
        transform: `translateX(${panelX}px)`
      }}>
        {/* Accent strip */}
        {!transparentBackground && (
          <div style={{
            position: 'absolute',
            top: 0,
            left: PANEL_W - 4,
            width: 12,
            height: DESIGN_HEIGHT,
            backgroundColor: actualAccentColor,
            transform: `skewX(-${SKEW_DEG}deg)`,
            transformOrigin: 'top left'
          }} />
        )}
        {/* Main panel with gradient */}
        <div style={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: PANEL_W,
          height: DESIGN_HEIGHT,
          background: panelGradient,
          transform: `skewX(-${SKEW_DEG}deg)`,
          transformOrigin: 'top left'
        }} />
        {/* Text content — centered in panel, adjustable via textOffsetX */}
        <div style={{
          position: 'absolute',
          top: 0,
          left: 60 + textOffsetX,
          width: 700,
          height: DESIGN_HEIGHT,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'flex-start'
        }}>
          <div style={{
            width: '100%',
            display: 'flex',
            flexDirection: 'column'
          }}>
            <div style={{
              ...getAnimStyle(0),
              fontSize: '20px',
              fontWeight: 800,
              color: brandColor,
              letterSpacing: '3px',
              textTransform: 'uppercase',
              marginBottom: '8px'
            }}>
              {brandText}
            </div>
            <div style={{
              ...getAnimStyle(1),
              fontSize: '54px',
              fontWeight: 800,
              marginTop: '20px',
              marginBottom: '8px',
              color: textColor,
              lineHeight: 1.1
            }}>
              {titleText}
            </div>
            <div style={{
              ...getAnimStyle(2),
              fontSize: '24px',
              fontWeight: 500,
              marginBottom: '32px',
              color: textColor,
              opacity: getAnimStyle(2).opacity * 0.85
            }}>
              {priceText}
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '13px' }}>
              {specsArray.map((spec, index) => (
                <div key={index} style={{
                  ...getAnimStyle(3 + index),
                  fontSize: '22px',
                  fontWeight: 700,
                  color: textColor,
                  lineHeight: 1.3
                }}>
                  {spec}
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

