const SavingsCalculator = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
  const props = item.props || {};

  const titleText    = props.titleText;
  const card1Amount  = props.card1Amount;
  const card1Label   = props.card1Label;
  const card2Amount  = props.card2Amount;
  const card2Label   = props.card2Label;
  const card3Amount  = props.card3Amount;
  const card3Label   = props.card3Label;
  const primaryColor = props.primaryColor;
  const bgColor      = props.bgColor;
  const cardBgColor  = props.cardBgColor;
  const fontFamily   = props.fontFamily;

  const DESIGN_WIDTH  = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width  || DESIGN_WIDTH)  / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const MARGIN  = 50;
  const PANEL_X = MARGIN;
  const PANEL_Y = MARGIN;
  const PANEL_W = 1380;
  const PANEL_H = DESIGN_HEIGHT - MARGIN * 2;

  const TH_W = 380;
  const TH_H = 500;
  const TH_X = 1490;
  const TH_Y = (DESIGN_HEIGHT - TH_H) / 2;
  const TH_R = 28;

  // ── Easing helpers ───────────────────────────────────────────────
  const easeOut = (t) => 1 - (1 - t) * (1 - t);
  const lerpE = (start, end, f0, f1) => {
    if (frame <= f0) return start;
    if (frame >= f1) return end;
    return start + (end - start) * easeOut((frame - f0) / (f1 - f0));
  };
  const fadeIn = (f0, f1) => {
    if (frame < f0) return 0;
    if (frame >= f1) return 1;
    return (frame - f0) / (f1 - f0);
  };

  // ── Animation values ─────────────────────────────────────────────
  const panelWipeW    = lerpE(0, PANEL_W, 0, 20);
  const panelClipPath = `inset(0 ${PANEL_W - panelWipeW}px 0 0 round 48px)`;

  const titleOpacity    = fadeIn(18, 34);
  const titleTranslateY = lerpE(24, 0, 18, 34);

  const cards12Scale   = lerpE(0.82, 1, 32, 48);
  const cards12Opacity = fadeIn(32, 48);

  const c12PillOpacity  = fadeIn(32, 42);
  const c12PillY        = lerpE(12, 0, 32, 42);
  const c12IconOpacity  = fadeIn(42, 54);
  const c12IconY        = lerpE(14, 0, 42, 54);
  const c12LabelOpacity = fadeIn(54, 64);
  const c12LabelY       = lerpE(10, 0, 54, 64);

  const opOpacity = fadeIn(58, 70);

  const card3ShellScale   = lerpE(0.82, 1, 66, 80);
  const card3ShellOpacity = fadeIn(66, 80);

  const c3PillOpacity  = fadeIn(80, 94);
  const c3PillY        = lerpE(12, 0, 80, 94);
  const c3IconOpacity  = fadeIn(94, 108);
  const c3IconY        = lerpE(14, 0, 94, 108);
  const c3LabelOpacity = fadeIn(108, 122);
  const c3LabelY       = lerpE(10, 0, 108, 122);

  // ── SVG cutout path ──────────────────────────────────────────────
  const cutoutPath =
    `M 0 0 L ${DESIGN_WIDTH} 0 L ${DESIGN_WIDTH} ${DESIGN_HEIGHT} L 0 ${DESIGN_HEIGHT} Z ` +
    `M ${TH_X+TH_R} ${TH_Y} L ${TH_X+TH_W-TH_R} ${TH_Y} ` +
    `Q ${TH_X+TH_W} ${TH_Y} ${TH_X+TH_W} ${TH_Y+TH_R} ` +
    `L ${TH_X+TH_W} ${TH_Y+TH_H-TH_R} ` +
    `Q ${TH_X+TH_W} ${TH_Y+TH_H} ${TH_X+TH_W-TH_R} ${TH_Y+TH_H} ` +
    `L ${TH_X+TH_R} ${TH_Y+TH_H} ` +
    `Q ${TH_X} ${TH_Y+TH_H} ${TH_X} ${TH_Y+TH_H-TH_R} ` +
    `L ${TH_X} ${TH_Y+TH_R} ` +
    `Q ${TH_X} ${TH_Y} ${TH_X+TH_R} ${TH_Y} Z`;

  // ── Static styles ────────────────────────────────────────────────
  const rootStyle = {
    position: 'absolute', top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`, transformOrigin: 'top left',
    backgroundColor: 'transparent',
    fontFamily: fontFamily,
    overflow: 'hidden',
  };

  const panelStyle = {
    position: 'absolute',
    top: PANEL_Y, left: PANEL_X,
    width: PANEL_W, height: PANEL_H,
    backgroundColor: bgColor,
    borderRadius: 48,
    clipPath: panelClipPath,
    display: 'flex', flexDirection: 'column',
    alignItems: 'center', justifyContent: 'center',
    gap: 52, padding: '52px 56px',
    boxSizing: 'border-box',
    overflow: 'hidden',
  };

  const titleStyle = {
    fontSize: 48, fontWeight: 800, color: '#0a1a26',
    textAlign: 'center', letterSpacing: '-0.02em', lineHeight: 1.15,
    margin: 0,
    opacity: titleOpacity,
    transform: `translateY(${titleTranslateY}px)`,
  };

  const rowStyle = {
    display: 'flex', flexDirection: 'row',
    alignItems: 'center', justifyContent: 'center',
    gap: 20,
  };

  // Card wrapper: pill on top, square card in middle, label below
  const cardWrapBase = {
    display: 'flex', flexDirection: 'column',
    alignItems: 'center', gap: 14,
  };

  const card12WrapStyle = {
    ...cardWrapBase,
    opacity: cards12Opacity,
    transform: `scale(${cards12Scale})`,
  };

  const card3WrapStyle = {
    ...cardWrapBase,
    opacity: card3ShellOpacity,
    transform: `scale(${card3ShellScale})`,
  };

  // The square card itself — only holds the icon
  const squareCardStyle = {
    width: 260, height: 260,
    backgroundColor: cardBgColor,
    borderRadius: 36,
    border: '7px solid #FFFFFF',
    boxShadow: '0 14px 32px rgba(0,0,0,0.10)',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    overflow: 'hidden',
  };

  const pillStyle = (opacity, ty) => ({
    backgroundColor: primaryColor,
    padding: '8px 22px', borderRadius: 26,
    color: '#FFFFFF', fontSize: 26, fontWeight: 700,
    letterSpacing: '-0.01em',
    opacity, transform: `translateY(${ty}px)`,
    flexShrink: 0,
  });

  const iconWrap = (opacity, ty) => ({
    opacity, transform: `translateY(${ty}px)`,
  });

  const labelStyle = (opacity, ty) => ({
    fontSize: 23, fontWeight: 700, color: '#192b35',
