    flexShrink: 0,
    opacity: opOpacity,
    alignSelf: 'center',
    marginTop: 14 + 14 + 8, // roughly align operator to card center (pill h + gap)
  };

  const thBorderStyle = {
    position: 'absolute',
    top: TH_Y, left: TH_X, width: TH_W, height: TH_H,
    borderRadius: TH_R,
    border: `6px solid ${primaryColor}`,
    backgroundColor: 'transparent',
    boxSizing: 'border-box',
    pointerEvents: 'none',
  };

  // ── Icons (larger: 130px render size) ───────────────────────────
  const BankIcon = () => (
    <svg width="130" height="130" viewBox="0 0 100 100">
      <rect x="12" y="78" width="76" height="8" rx="3" fill="#CBD5E1" />
      <rect x="20" y="68" width="60" height="10" rx="2" fill="#8da6b5" />
      <rect x="24" y="40" width="9" height="28" fill="#5c7788" />
      <rect x="40" y="40" width="9" height="28" fill="#5c7788" />
      <rect x="56" y="40" width="9" height="28" fill="#5c7788" />
      <rect x="72" y="40" width="9" height="28" fill="#5c7788" />
