const FruitShoppingTips = ({item, props}) => {
  // Hooks
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  // Editable props with defaults
  const titleLine1 = props?.titleLine1 ?? "The 4 Rules for";
  const titleLine2 = props?.titleLine2 ?? '"Throw Pillow Shopping"';
  const subtitle = props?.subtitle ?? "How to pick the coziest accents";
  const tip1 = props?.tip1 ?? "Fabric";
  const tip2 = props?.tip2 ?? "Fill";
  const tip3 = props?.tip3 ?? "Stitching";
  const tip4 = props?.tip4 ?? "Seasonal";
  const tips = [tip1, tip2, tip3, tip4];

  const cardBgColor = props?.cardBgColor ?? "rgba(255, 255, 255, 0.95)";
  const titleColor = props?.titleColor ?? "#1a1a1a";
  const subtitleColor = props?.subtitleColor ?? "#666";
  const tip1Color = props?.tip1Color ?? "rgba(255,135,116, 0.55)";
  const tip2Color = props?.tip2Color ?? "rgba(128,209,255, 0.55)";
  const tip3Color = props?.tip3Color ?? "rgba(0,210,210, 0.55)";
  const tip4Color = props?.tip4Color ?? "rgba(176,157,252, 0.55)";
  const tipColors = [tip1Color, tip2Color, tip3Color, tip4Color];

  // Responsive scaling
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // Safe spring helper
  const safeFps = fps || 30;
  const safeSpring = (delay = 0, config = { damping: 15 }) => {
    return spring({ frame: Math.max(0, frame - delay), fps: safeFps, config });
  };

  // Animation timing
  const cardSlideIn = safeSpring(0, { damping: 18 });
  const titleFadeIn = safeSpring(10, { damping: 15 });

  // Card slide from right
  const cardX = interpolate(cardSlideIn, [0, 1], [900, 0]);

  // Title animation
  const titleOpacity = interpolate(titleFadeIn, [0, 1], [0, 1]);
  const titleY = interpolate(titleFadeIn, [0, 1], [10, 0]);

  const rootStyle = {
    position: 'absolute', top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`, transformOrigin: 'top left',
    backgroundColor: 'transparent',
  };

  const cardContainerStyle = {
    position: 'absolute',
    right: 0,
    top: 0,
    width: '45%',
    height: '100%',
    transform: `translateX(${cardX}px)`,
  };

  const cardStyle = {
    backgroundColor: cardBgColor,
    backdropFilter: 'blur(20px)',
    width: '100%',
    height: '100%',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    boxShadow: '-8px 0 48px rgba(0, 0, 0, 0.12)',
  };

  const contentWrapperStyle = {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    width: '100%',
    padding: '60px',
  };

  const titleLine1Style = {
    fontSize: 42,
    fontWeight: 500,
    color: titleColor,
    fontFamily: 'Inter, sans-serif',
    marginBottom: 8,
    opacity: titleOpacity,
    transform: `translateY(${titleY}px)`,
  };

  const titleLine2Style = {
    fontSize: 72,
    fontWeight: 800,
    color: titleColor,
    fontFamily: 'Inter, Montserrat, sans-serif',
    letterSpacing: '-0.02em',
    marginBottom: 20,
    opacity: titleOpacity,
    transform: `translateY(${titleY}px)`,
  };

  const subtitleStyle = {
    fontSize: 24,
    fontWeight: 400,
    fontStyle: 'italic',
    color: subtitleColor,
    fontFamily: 'Inter, sans-serif',
    marginBottom: 56,
    opacity: titleOpacity,
    transform: `translateY(${titleY}px)`,
  };

  const listStyle = {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    gap: 28,
  };

  return (
    <div style={rootStyle}>
      <div style={cardContainerStyle}>
        <div style={cardStyle}>
          <div style={contentWrapperStyle}>
            <div style={titleLine1Style}>{titleLine1}</div>
            <div style={titleLine2Style}>{titleLine2}</div>
            <div style={subtitleStyle}>{subtitle}</div>

            <div style={listStyle}>
              {tips.map((tip, index) => {
                const tipDelay = 20 + index * 12;
                const tipSpring = safeSpring(tipDelay, { damping: 14 });
                const tipOpacity = interpolate(tipSpring, [0, 1], [0, 1]);
                const tipY = interpolate(tipSpring, [0, 1], [20, 0]);

                const underlineDelay = tipDelay + 6;
                const underlineProgress = interpolate(frame - underlineDelay * safeFps / 30, [0, 12], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
                const underlineScale = Easing.out(Easing.cubic)(underlineProgress);

                const tipRowStyle = {
                  display: 'flex',
                  justifyContent: 'center',
                  opacity: tipOpacity,
                  transform: `translateY(${tipY}px)`,
                };

                const textWrapperStyle = {
                  position: 'relative',
                  display: 'inline-block',
                  textAlign: 'center',
                };

                const tipTextStyle = {
                  fontSize: 40,
                  color: titleColor,
                  fontFamily: 'Inter, sans-serif',
                  fontWeight: 700,
                  position: 'relative',
                  zIndex: 1,
                };

                const highlightStyle = {
                  position: 'absolute',
                  bottom: 4,
                  left: '50%',
                  transform: `translateX(-50%) scaleX(${underlineScale})`,
                  height: 14,
                  width: '100%',
                  backgroundColor: tipColors[index % tipColors.length],
                  borderRadius: 4,
                  zIndex: 0,
                };

                return (
                  <div key={index} style={tipRowStyle}>
                    <div style={textWrapperStyle}>
                      <span style={tipTextStyle}>{tip}</span>
                      <div style={highlightStyle} />
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

