const CinematicTimeline = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  const props = item.props || {};
  const label1 = props.label1;
  const label2 = props.label2;
  const label3 = props.label3;
  const color = props.color;
  const fontFam = props.fontFamily;
  const transparentBg = props.transparentBackground;

  const DESIGN_WIDTH = 1400;
  const DESIGN_HEIGHT = 260;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const safeFps = fps || 30;
  const safeSpring = (delay = 0, config = { damping: 14 }) => {
    return spring({ frame: Math.max(0, frame - delay), fps: safeFps, config });
  };

  // Line draws linearly from frame 15 to 65
  const lineProgress = interpolate(frame, [15, 65], [0, 100], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp'
  });

  // Nodes pop in sequentially matched with the line progress
  const node1Scale = safeSpring(15);
  const node2Scale = safeSpring(40);
  const node3Scale = safeSpring(65);

  // Labels fade in at the SAME time as their respective nodes
  const getLabelAnim = (startFrame) => {
    const opacity = interpolate(frame, [startFrame, startFrame + 8], [0, 1], {extrapolateLeft: 'clamp', extrapolateRight: 'clamp'});
    const y = interpolate(frame, [startFrame, startFrame + 8], [12, 0], {extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: Easing.out(Easing.quad)});
    return { opacity, y };
  };

  const l1Anim = getLabelAnim(15);
  const l2Anim = getLabelAnim(40);
  const l3Anim = getLabelAnim(65);

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: transparentBg ? 'transparent' : 'rgba(0,1,9,0.85)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center'
  };

  // Line sits at top of container, text lives strictly below
  const LINE_Y = 20;
  const NODE_SIZE = 22;

  const barContainerStyle = {
    position: 'relative',
    width: 1100,
    height: 180
  };

  const lineStyle = {
    position: 'absolute',
    top: LINE_Y,
    left: 0,
    width: `${lineProgress}%`,
    height: 4,
    backgroundColor: color,
    transform: 'translateY(-50%)',
    boxShadow: '0 2px 8px rgba(0,1,9,0.4)',
    borderRadius: 2
  };

  const renderNode = (leftPercent, scaleAnim, label, lAnim, keyIndex) => {
    // Circle is centered on the line
    const circleTop = LINE_Y - NODE_SIZE / 2;

    const circleWrapStyle = {
      position: 'absolute',
      left: `${leftPercent}%`,
      top: circleTop,
      transform: 'translateX(-50%)',
      width: NODE_SIZE,
      height: NODE_SIZE
    };

    const circleStyle = {
      width: NODE_SIZE,
      height: NODE_SIZE,
      backgroundColor: color,
      borderRadius: '50%',
      transform: `scale(${scaleAnim})`,
      boxShadow: '0 0 12px rgba(0,1,9,0.5)'
    };

    // Text starts below the circle with a clear gap, never touching the line
    const labelWrapStyle = {
      position: 'absolute',
      left: `${leftPercent}%`,
      top: LINE_Y + NODE_SIZE + 18,
      transform: 'translateX(-50%)',
      width: 320,
      textAlign: 'center'
    };

    const labelStyle = {
      color: color,
      fontFamily: fontFam,
      fontWeight: 800,
      fontSize: 22,
      letterSpacing: '0.06em',
      textAlign: 'center',
      textTransform: 'uppercase',
      opacity: lAnim.opacity,
      transform: `translateY(${lAnim.y}px)`,
      textShadow: '0 3px 6px rgba(0,1,9,0.6)',
      lineHeight: 1.35,
      whiteSpace: 'pre-line',
      display: 'inline-block'
    };

    return (
      <React.Fragment key={keyIndex}>
        <div style={circleWrapStyle}>
          <div style={circleStyle} />
        </div>
        <div style={labelWrapStyle}>
          <span style={labelStyle}>{label}</span>
        </div>
      </React.Fragment>
    );
  };

  return (
    <div style={rootStyle}>
      <div style={barContainerStyle}>
        <div style={lineStyle} />
        {renderNode(0, node1Scale, label1, l1Anim, 1)}
        {renderNode(50, node2Scale, label2, l2Anim, 2)}
        {renderNode(100, node3Scale, label3, l3Anim, 3)}
      </div>
    </div>
  );
};

