const LifestyleLowerThird = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  // Editable properties
  const props = item.props || {};
  const nameText = props.nameText || 'Marco Ferreira';
  const roleText = props.roleText || 'Street Food Guide';
  const cardColor = props.cardColor || '#edf4ff';
  const textColor = props.textColor || '#1f2633';
  const lineColor = props.lineColor || '#848d9c';
  const accentColor = props.accentColor || '#2d3340';
  const yOffset = props.yOffset !== undefined ? props.yOffset : 120;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // ── ADAPTIVE TIMING ──
  // Use item.durationInFrames (actual timeline clip length) so exit always plays
  // regardless of where the user trims the clip. Falls back to asset duration.
  const totalFrames = item?.durationInFrames || Math.round((item?.durationInSeconds || 12) * fps);

  // Exit window: 40 frames ideal, but never more than 35% of total clip length
  // This ensures even a very short clip still has a visible exit
  const EXIT_FRAMES = Math.min(40, Math.floor(totalFrames * 0.35));
  const exitStart = totalFrames - EXIT_FRAMES;

  // Entrance delays scale with clip length too — cap at what fits before exit begins
  // For very short clips, compress entrance sequence proportionally
  const entranceWindow = Math.max(1, exitStart - 5); // leave 5 frames of hold before exit
  const delayScale = Math.min(1, entranceWindow / 50); // 50 frames = full speed reference
  const nameDelay  = Math.round(12 * delayScale);
  const lineDelay  = Math.round(22 * delayScale);
  const roleDelay  = Math.round(30 * delayScale);

  // Overdamped spring config — smooth ease-in, zero bounce
  const cfg = { damping: 30, stiffness: 85 };

  // ── ENTRANCE (card slides in from left) ──
  const entranceSpring = spring({ frame, fps, config: cfg });
  const cardEnterX = interpolate(entranceSpring, [0, 1], [-1600, 0], { extrapolateRight: 'clamp' });

  const nameSpring = spring({ frame: Math.max(0, frame - nameDelay), fps, config: cfg });
  const lineSpring = spring({ frame: Math.max(0, frame - lineDelay), fps, config: cfg });
  const roleSpring = spring({ frame: Math.max(0, frame - roleDelay), fps, config: cfg });

  // ── EXIT (original path: card slides back LEFT — mirror of entrance) ──
  const exitProgress = interpolate(frame, [exitStart, totalFrames], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.bezier(0.4, 0, 0.8, 1), // ease-in: starts slow, accelerates out
  });

  // Card returns to where it came from (left, off-screen)
  const cardExitX = interpolate(exitProgress, [0, 1], [0, -1600]);

  // Inner elements fade out slightly ahead of card exit (exit feels layered not flat)
  const innerExitOp = interpolate(exitProgress, [0, 0.6], [1, 0], { extrapolateRight: 'clamp' });

  // Combined card X: entrance moves it in, exit moves it back out left
  // During entrance: cardExitX is 0 (exitProgress=0), so only cardEnterX drives position
  // During exit: cardEnterX is already settled at 0, cardExitX takes over
  const cardX = cardEnterX + cardExitX;

  // Styles
  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'flex-end',
    paddingLeft: '120px',
    paddingBottom: `${yOffset}px`,
  };

  const cardStyle = {
    backgroundColor: cardColor,
    padding: '35px 60px',
    borderRadius: '4px',
    boxShadow: '0 12px 35px rgba(0,1,9,0.12)',
    display: 'flex',
    flexDirection: 'row',
    alignItems: 'center',
    minWidth: '850px',
    maxWidth: '1400px',
    width: 'fit-content',
    transform: `translateX(${cardX}px)`,
    overflow: 'hidden',
    position: 'relative',
  };

  const textGroupStyle = {
    display: 'flex',
    flexDirection: 'row',
    alignItems: 'center',
    zIndex: 2,
    flex: 1,
    position: 'relative',
    opacity: innerExitOp,
  };

  const nameStyle = {
    fontFamily: 'Georgia, serif',
    fontWeight: 'bold',
    fontSize: '52px',
    color: textColor,
    opacity: interpolate(nameSpring, [0, 1], [0, 1], { extrapolateRight: 'clamp' }),
    transform: `translateX(${interpolate(nameSpring, [0, 1], [-20, 0], { extrapolateRight: 'clamp' })}px)`,
    whiteSpace: 'nowrap',
    letterSpacing: '-0.5px',
  };

  const lineStyle = {
    height: '2px',
    backgroundColor: lineColor,
    width: '60px',
    margin: '0 30px',
    transform: `scaleX(${interpolate(lineSpring, [0, 1], [0, 1], { extrapolateRight: 'clamp' })})`,
    transformOrigin: 'left',
    opacity: interpolate(lineSpring, [0, 1], [0, 1], { extrapolateRight: 'clamp' }),
  };

  const roleStyle = {
    fontFamily: '"Helvetica Neue", Helvetica, Arial, sans-serif',
    fontSize: '24px',
    fontWeight: '600',
    letterSpacing: '1.5px',
    textTransform: 'uppercase',
    color: textColor,
    opacity: interpolate(roleSpring, [0, 1], [0, 1], { extrapolateRight: 'clamp' }),
    transform: `translateX(${interpolate(roleSpring, [0, 1], [-10, 0], { extrapolateRight: 'clamp' })}px)`,
    whiteSpace: 'nowrap',
  };

  const silhouetteStyle = {
    position: 'absolute',
    right: '-50px',
    top: '50%',
    transform: `translateY(-45%) scale(${interpolate(entranceSpring, [0, 1], [0.8, 1], { extrapolateRight: 'clamp' })})`,
    opacity: 0.08 * innerExitOp,
    color: accentColor,
    pointerEvents: 'none',
    zIndex: 1,
  };

  return (
    <div style={rootStyle}>
      <div style={cardStyle}>
        <div style={textGroupStyle}>
          <div style={nameStyle}>{nameText}</div>
          <div style={lineStyle} />
          <div style={roleStyle}>{roleText}</div>
        </div>
        <div style={silhouetteStyle}>
          <svg width="420" height="420" viewBox="0 0 24 24" fill="currentColor">
            <path d="M12 12c2.21 0 4-1.79 4-4s-1.79-4-4-4-4 1.79-4 4 1.79 4 4 4zm0 2c-2.67 0-8 1.34-8 4v2h16v-2c0-2.66-5.33-4-8-4z" />
          </svg>
        </div>
      </div>
    </div>
  );
};

const EditorialNameCard = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps, durationInFrames } = useVideoConfig();

  const props = item.props || {};
  const firstName = props.firstName;
  const lastName = props.lastName;
  const role = props.role;
  const bgColor = props.bgColor;
  const textColor = props.textColor;
  const lineColor = props.lineColor;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const safeFps = fps || 30;
  const cardHeight = 380;

  // ── Exit ──────────────────────────────────────────────────────────────
  const exitDuration = 24;
  const exitStart = durationInFrames - exitDuration;
  const isExiting = frame >= exitStart;
  const exitT = isExiting
    ? interpolate(frame, [exitStart, durationInFrames - 1], [0, 1], { extrapolateRight: 'clamp' })
    : 0;
  const exitEased = Easing.in(Easing.cubic)(exitT);
  const exitSlide = interpolate(exitEased, [0, 1], [0, cardHeight + 20]);

  // ── Entrance: card slides up ──────────────────────────────────────────
  const cardEnter = spring({
    frame,
    fps: safeFps,
    config: { damping: 22, stiffness: 100, mass: 0.8 },
  });
  const cardSlideIn = interpolate(cardEnter, [0, 1], [cardHeight, 0]);
  const cardTranslateY = isExiting ? exitSlide : cardSlideIn;

  // ── Text: fade only, no translateY ────────────────────────────────────
  const fadeIn = (delay) =>
    interpolate(frame, [delay, delay + 10], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  const name1Op   = isExiting ? interpolate(exitEased, [0, 0.4], [1, 0]) : fadeIn(14);
  const name2Op   = isExiting ? interpolate(exitEased, [0, 0.4], [1, 0]) : fadeIn(20);
