    frame,
    fps: safeFps,
    config: { damping: 20, stiffness: 100, mass: 1 },
    from: -500,
    to: 40,
  });

  const outProgress = interpolate(
    frame,
    [outStartFrame, outStartFrame + outDuration],
    [0, 1],
