  // Intro line: 0s to 0.4s (0 to 12 frames at 30fps)
  const lineProgress = interpolate(frame, [0, 12], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp'
  });

  // Intro name: 0.4s to 0.8s (12 to 24 frames at 30fps)
