const ModernLowerThird = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const nameText = props.nameText || 'MARCUS VOSS';
  const subtitleText = props.subtitleText || 'GAME DIRECTOR';
  const barColor = props.barColor || '#56cdb9';
  const textColor = props.textColor || '#FFFFFF';
  const fontFamily = props.fontFamily || 'Inter, sans-serif';

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  // Timings based on prompt: 
  // Bar drop: 0s
  // Name slide: 0.3s
  // Subtitle slide: 0.5s
  const barDelay = 0;
  const nameDelay = Math.round(fps * 0.3);
  const subDelay = Math.round(fps * 0.5);

  // Entrance Springs
  const barEntrance = spring({ 
    frame: Math.max(0, frame - barDelay), 
    fps, 
    config: { damping: 14, stiffness: 120 } 
  });
  const nameEntrance = spring({ 
    frame: Math.max(0, frame - nameDelay), 
    fps, 
    config: { damping: 15, stiffness: 120 } 
  });
  const subEntrance = spring({ 
    frame: Math.max(0, frame - subDelay), 
    fps, 
    config: { damping: 15, stiffness: 120 } 
  });

  // Outro 
  // Slide left out + fade at the end
  const outroDuration = Math.round(fps * 0.6);
  const outroStart = durationInFrames - outroDuration;
  const outroProgress = interpolate(
    frame,
    [outroStart, durationInFrames - 5],
    [0, 1],
    { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );

  // Pre-calculated animation values
  const groupOpacity = interpolate(outroProgress, [0, 1], [1, 0]);
  const groupTranslateX = interpolate(outroProgress, [0, 1], [0, -60]);

  const barTranslateY = interpolate(barEntrance, [0, 1], [-60, 0]);
  const nameTranslateX = interpolate(nameEntrance, [0, 1], [-40, 0]);
  const subTranslateX = interpolate(subEntrance, [0, 1], [-40, 0]);

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: 'transparent',
    fontFamily,
  };

  const containerStyle = {
    position: 'absolute',
    left: 80,
    top: 870,
    display: 'flex',
    flexDirection: 'row',
    alignItems: 'center',
    opacity: groupOpacity,
    transform: `translateX(${groupTranslateX}px)`,
  };

  const barStyle = {
    width: 6,
    height: 60,
    backgroundColor: barColor,
    marginRight: 20,
    transform: `translateY(${barTranslateY}px)`,
    opacity: barEntrance,
  };

  const textContainerStyle = {
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
  };

  const nameStyle = {
    fontSize: 44,
    fontWeight: 800,
    textTransform: 'uppercase',
    color: textColor,
    margin: 0,
    lineHeight: 1,
    transform: `translateX(${nameTranslateX}px)`,
    opacity: nameEntrance,
    textShadow: '0px 2px 8px rgba(0,0,0,0.4)',
  };

  const subStyle = {
    fontSize: 20,
    fontWeight: 500,
    textTransform: 'uppercase',
    color: textColor,
    margin: 0,
    marginTop: 6,
    letterSpacing: '0.15em',
    transform: `translateX(${subTranslateX}px)`,
    opacity: subEntrance,
    textShadow: '0px 2px 8px rgba(0,0,0,0.4)',
  };

  return (
    <div style={rootStyle}>
      <div style={containerStyle}>
        <div style={barStyle} />
        <div style={textContainerStyle}>
          <h1 style={nameStyle}>{nameText}</h1>
          <h2 style={subStyle}>{subtitleText}</h2>
        </div>
      </div>
    </div>
  );
};

