const EditorialIntro = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // Editable Properties
  const props = item.props || {};
  const firstName = props.firstName || 'Marcus';
  const lastName = props.lastName || 'Alvarado';
  const roleText = props.role || 'Indie Studio Founder';
  const backgroundColor = props.backgroundColor || '#daeff2';
  const textColor = props.textColor || '#1F1F1F';
  const photoUrl = props.photoUrl || 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?ixlib=rb-1.2.1&auto=format&fit=crop&w=1200&q=80';
  const imageOpacity = props.imageOpacity !== undefined ? props.imageOpacity : 0.4;

  // Responsive Scaling
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // Timing
  const durationFrames = Math.round((item?.durationInSeconds || 12) * fps);
  const outStart = durationFrames - 45; // 45 frames = 1.5s exit window — enough to complete

  // Overdamped spring — smooth ease-in, zero bounce
  const springCfg = { damping: 30, stiffness: 85 };

  // ── ENTRANCE SEQUENCE (left→right visual flow) ──
  // Step 1: First name slides in from left (frame 0)
  const fn = spring({ frame, fps, config: springCfg });
  const firstNameX  = interpolate(fn, [0, 1], [-180, 0], { extrapolateRight: 'clamp' });
  const firstNameOp = interpolate(fn, [0, 1], [0, 1],    { extrapolateRight: 'clamp' });

  // Step 2: Last name follows slightly after (frame 8)
  const ln = spring({ frame: Math.max(0, frame - 8), fps, config: springCfg });
  const lastNameX  = interpolate(ln, [0, 1], [-180, 0], { extrapolateRight: 'clamp' });
  const lastNameOp = interpolate(ln, [0, 1], [0, 1],    { extrapolateRight: 'clamp' });

  // Step 3: Role line after last name (frame 18)
  const rl = spring({ frame: Math.max(0, frame - 18), fps, config: springCfg });
  const roleOp = interpolate(rl, [0, 1], [0, 1], { extrapolateRight: 'clamp' });
  const roleX  = interpolate(rl, [0, 1], [-20, 0], { extrapolateRight: 'clamp' });

  // Step 4: Portrait enters from right AFTER text is settled (frame 30–70, linear fade)
  // Viewer's eye has been anchored left by text; portrait slides in from right side
  const imgFadeIn = interpolate(frame, [30, 70], [0, imageOpacity], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.bezier(0.25, 0, 0.5, 1),
  });
  const imgSlideIn = interpolate(frame, [30, 70], [80, 0], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.bezier(0.25, 0, 0.5, 1),
  });

  // ── EXIT SEQUENCE — all elements slide RIGHT and fade out together ──
  const exitP = interpolate(frame, [outStart, durationFrames], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.bezier(0.4, 0, 0.8, 1),
  });
  const exitOp = interpolate(exitP, [0, 1], [1, 0]);
  const exitX  = interpolate(exitP, [0, 1], [0, 120]);   // slide right on exit

  // Styles
  const rootStyle = {
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    backgroundColor,
    position: 'relative',
    overflow: 'hidden',
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    fontFamily: '"Cormorant Garamond", "Times New Roman", serif',
  };

  // Portrait — right side, slides in from right after text
  const imageContainerStyle = {
    position: 'absolute',
    top: 0,
    right: 0,
    bottom: 0,
    width: '55%',
    opacity: imgFadeIn * exitOp,
    transform: `translateX(${imgSlideIn + exitX}px)`,
    mixBlendMode: 'multiply',
    filter: 'grayscale(100%) contrast(108%)',
  };

  const imgStyle = {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
    objectPosition: 'center 15%',
    maskImage: 'linear-gradient(to right, transparent 0%, black 55%)',
    WebkitMaskImage: 'linear-gradient(to right, transparent 0%, black 55%)',
  };

  // Text block — left side, exits right
  const contentStyle = {
    position: 'absolute',
    top: '50%',
    left: 180,
    transform: `translateY(-50%) translateX(${exitX}px)`,
    opacity: exitOp,
    zIndex: 10,
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
  };

  const lineBase = {
    color: textColor,
    fontSize: 250,
    lineHeight: 0.88,
    fontWeight: 400,
    letterSpacing: '-0.05em',
    overflow: 'hidden',
    whiteSpace: 'nowrap',
  };

  const detailRowStyle = {
    display: 'flex',
    alignItems: 'center',
    marginTop: 48,
    marginLeft: 8,
    opacity: roleOp,
    transform: `translateX(${roleX}px)`,
  };

  const dashStyle = {
    width: 72,
    height: 2,
    backgroundColor: textColor,
    marginRight: 24,
    opacity: 0.6,
  };

  const roleTextStyle = {
    color: textColor,
    fontSize: 34,
    fontWeight: 400,
    fontStyle: 'italic',
    letterSpacing: '0.03em',
    fontFamily: '"Cormorant Garamond", "Georgia", serif',
  };

  return (
    <div style={rootStyle}>
      {/* Portrait — enters after text, from right */}
      <div style={imageContainerStyle}>
        <Img src={photoUrl} style={imgStyle} />
      </div>

      {/* Typography — enters first, from left */}
      <div style={contentStyle}>
        {/* First name */}
        <div style={{ overflow: 'hidden', paddingBottom: 12 }}>
          <div style={{ ...lineBase, transform: `translateX(${firstNameX}px)`, opacity: firstNameOp }}>
            {firstName}
          </div>
        </div>
        {/* Last name — offset right for staggered indent */}
        <div style={{ overflow: 'hidden', paddingBottom: 12 }}>
          <div style={{ ...lineBase, transform: `translateX(${lastNameX}px)`, opacity: lastNameOp, marginLeft: 56 }}>
            {lastName}
          </div>
        </div>
        {/* Role line */}
        <div style={detailRowStyle}>
          <div style={dashStyle} />
          <span style={roleTextStyle}>{roleText}</span>
        </div>
      </div>
    </div>
  );
};

const TweetQuoteCard = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps, durationInFrames } = useVideoConfig();

  // Editable props
  const props = item.props || {};
  const authorName = props.authorName || 'Elena Rossi';
  const authorRole = props.authorRole || 'Founder, Cielo Coffee';
  const avatarUrl = props.avatarUrl || '';
  const quoteText = props.quoteText || 'The only way to roast great coffee is to taste every batch yourself.';
  const cardBg = props.cardBackgroundColor || '#ffffff';
  const textColor = props.textColor || '#231411';
  const glowColor = props.glowColor || '#a35836';
  const accentColor = props.accentColor || '#cf777d';
  // 1 = normal, 0.5 = faster, 2 = slower
  const wordSpeed = Math.max(0.2, props.wordSpeed != null ? Number(props.wordSpeed) : 1);

  // Canvas scaling
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const getInitials = (name) =>
    name.trim().split(' ').map((n) => n[0]).slice(0, 2).join('').toUpperCase();

  // --- Easing: fast-in slow-out (ease-out cubic) ---
  const easeOutCubic = (t) => 1 - Math.pow(1 - t, 3);

  // Card entrance: slide in from right, fast-in slow-out, 18 frames
  const CARD_DURATION = 18;
  const cardRawT = Math.min(frame / CARD_DURATION, 1);
  const cardT = easeOutCubic(cardRawT);
  const cardTranslateX = interpolate(cardT, [0, 1], [80, 0]);
  const cardOpacity = interpolate(cardRawT, [0, 0.3], [0, 1], {
    extrapolateRight: 'clamp',
  });

  // Card exit fade
  const fadeOutStart = durationInFrames - 15;
  const globalOpacity = interpolate(frame, [fadeOutStart, durationInFrames], [1, 0], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  // Author info fade-in after card arrives
  const AUTHOR_START = 12;
  const authorRawT = Math.min(Math.max((frame - AUTHOR_START) / 14, 0), 1);
  const authorT = easeOutCubic(authorRawT);
  const authorY = interpolate(authorT, [0, 1], [18, 0]);
  const authorOpacity = authorRawT;

  // Words: slide up (no scale change), short distance, motion blur via CSS filter
  const words = quoteText.split(' ');
  const WORD_START = 22;
  const STAGGER = 3.6 * wordSpeed; // frames between words, scaled by speed
  const WORD_ANIM_DUR = 14 * wordSpeed; // frames per word animation, scaled by speed

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    backgroundColor: 'transparent',
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    display: 'flex',
    justifyContent: 'flex-end',
    alignItems: 'center',
    paddingRight: '100px',
    fontFamily: 'Inter, system-ui, -apple-system, BlinkMacSystemFont, sans-serif',
    opacity: globalOpacity,
  };

  const cardStyle = {
    width: '700px',
    backgroundColor: cardBg,
    borderRadius: '22px',
    padding: '44px 48px',
    boxShadow: `0 8px 32px -8px rgba(0,0,0,0.12), 0 0 0 1.5px rgba(163,88,54,0.15), 0 0 60px -10px ${glowColor}`,
    display: 'flex',
    flexDirection: 'column',
    gap: '28px',
    transform: `translateX(${cardTranslateX}px)`,
    opacity: cardOpacity,
  };

  const headerStyle = {
    display: 'flex',
    alignItems: 'center',
    gap: '16px',
    transform: `translateY(${authorY}px)`,
    opacity: authorOpacity,
  };

  const avatarStyle = {
    width: '68px',
    height: '68px',
    borderRadius: '50%',
    backgroundColor: '#332423',
    color: '#ffffff',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '26px',
    fontWeight: '700',
    flexShrink: 0,
    overflow: 'hidden',
  };

  const nameStyle = {
    fontSize: '24px',
    fontWeight: '700',
    color: '#000000',
    lineHeight: '1.2',
  };

  const roleStyle = {
    fontSize: '18px',
    color: '#7c6e6b',
    marginTop: '3px',
  };

  const quoteContainerStyle = {
    fontSize: '40px',
    fontWeight: '600',
    color: textColor,
    lineHeight: '1.4',
    display: 'flex',
    flexWrap: 'wrap',
    columnGap: '0.22em',
    rowGap: '0.05em',
  };

  const VerifiedBadge = () => (
    <svg width="22" height="22" viewBox="0 0 24 24" fill={accentColor} style={{ flexShrink: 0 }}>
      <path d="M22.5 12.5c0-1.58-.875-2.95-2.148-3.6.154-.435.238-.905.238-1.4 0-2.21-1.71-3.998-3.818-3.998-.47 0-.92.084-1.336.25C14.818 2.415 13.51 1.5 12 1.5s-2.816.917-3.437 2.25c-.415-.165-.866-.25-1.336-.25-2.11 0-3.818 1.79-3.818 4 0 .495.083.965.238 1.4-1.272.65-2.147 2.02-2.147 3.6 0 1.457.748 2.795 1.843 3.475-.062.46-.104.927-.104 1.402 0 2.486 2.013 4.5 4.5 4.5.475 0 .942-.042 1.402-.104.68 1.094 2.018 1.843 3.475 1.843s2.795-.748 3.475-1.843c.46.062.927.104 1.402.104 2.486 0 4.5-2.013 4.5-4.5 0-.475-.042-.94-.104-1.402 1.094-.68 1.843-2.018 1.843-3.475zm-9.933 6.93l-4-4 1.414-1.414 2.586 2.586 5.586-5.586 1.414 1.414-7 7z" />
    </svg>
  );

  return (
    <div style={rootStyle}>
      <div style={cardStyle}>
        {/* Author header */}
        <div style={headerStyle}>
          <div style={avatarStyle}>
            {avatarUrl
              ? <Img src={avatarUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
              : <span>{getInitials(authorName)}</span>
            }
          </div>
          <div style={{ display: 'flex', flexDirection: 'column' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '7px' }}>
              <span style={nameStyle}>{authorName}</span>
              <VerifiedBadge />
            </div>
            <span style={roleStyle}>{authorRole}</span>
          </div>
        </div>

        {/* Quote with word-by-word slide-up */}
        <div style={quoteContainerStyle}>
          {words.map((word, i) => {
            const wordDelay = WORD_START + i * STAGGER;
            const rawT = Math.min(Math.max((frame - wordDelay) / WORD_ANIM_DUR, 0), 1);
            const t = easeOutCubic(rawT);

            // Short travel distance only, no scale
            const wordY = interpolate(t, [0, 1], [20, 0]);
            const wordOpacity = interpolate(rawT, [0, 0.4], [0, 1], {
              extrapolateRight: 'clamp',
            });

            // Motion blur: decays quickly, fully gone by rawT=0.6 to avoid late-frame flicker
            const blurRaw = interpolate(rawT, [0, 0.6], [1, 0], {
              extrapolateLeft: 'clamp',
              extrapolateRight: 'clamp',
            });
            const blurAmount = easeOutCubic(blurRaw) * 3;

            return (
              <span
                key={i}
                style={{
                  display: 'inline-block',
                  overflow: 'hidden',
                  verticalAlign: 'bottom',
                  lineHeight: '1.5em',
                  height: '1.5em',
                }}
              >
                <span
                  style={{
                    display: 'inline-block',
                    transform: `translateY(${wordY}px)`,
                    opacity: wordOpacity,
                    filter: `blur(${blurAmount}px)`,
                  }}
                >
                  {word}
                </span>
              </span>
            );
          })}
        </div>
      </div>
    </div>
  );
};

