const QuoteCard = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  const props = item.props || {};
  const line1Text = props.line1Text;
  const line2Text = props.line2Text;
  const line3Text = props.line3Text;
  const line4Text = props.line4Text;
  const fontFamily = props.fontFamily;
  const bgColor = props.bgColor;
  const primaryColor = props.primaryColor;
  const accentColor = props.accentColor;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const safeFps = fps || 30;
  const staggerDelay = safeFps * 0.5;

  const anim1 = spring({ frame, fps: safeFps, config: { damping: 15, mass: 1, stiffness: 80 }});
  const anim2 = spring({ frame: Math.max(0, frame - staggerDelay), fps: safeFps, config: { damping: 15, mass: 1, stiffness: 80 }});
  const anim3 = spring({ frame: Math.max(0, frame - staggerDelay * 2), fps: safeFps, config: { damping: 15, mass: 1, stiffness: 80 }});
  const anim4 = spring({ frame: Math.max(0, frame - staggerDelay * 3), fps: safeFps, config: { damping: 15, mass: 1, stiffness: 80 }});

  const yDist = 80;
  const y1 = interpolate(anim1, [0, 1], [yDist, 0]);
  const y2 = interpolate(anim2, [0, 1], [yDist, 0]);
  const y3 = interpolate(anim3, [0, 1], [yDist, 0]);
  const y4 = interpolate(anim4, [0, 1], [yDist, 0]);

  const op1 = Math.min(1, Math.max(0, anim1));
  const op2 = Math.min(1, Math.max(0, anim2));
  const op3 = Math.min(1, Math.max(0, anim3));
  const op4 = Math.min(1, Math.max(0, anim4));

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: bgColor,
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    fontFamily: fontFamily,
    fontWeight: 'bold',
    fontSize: '110px',
    lineHeight: 1.2,
    textAlign: 'center'
  };

  const line1Style = {
    opacity: op1,
    transform: `translateY(${y1}px)`,
    color: primaryColor
  };
  const line2Style = {
    opacity: op2,
    transform: `translateY(${y2}px)`,
    color: primaryColor
  };
  const line3Style = {
    opacity: op3,
    transform: `translateY(${y3}px)`,
    color: primaryColor
  };
  const line4Style = {
    opacity: op4,
    transform: `translateY(${y4}px)`,
    color: accentColor
  };

  return (
    <div style={rootStyle}>
      <div style={line1Style}>{line1Text}</div>
      <div style={line2Style}>{line2Text}</div>
      <div style={line3Style}>{line3Text}</div>
      <div style={line4Style}>{line4Text}</div>
    </div>
  );
};

