const FlowingDotGridCard = ({item}) => {
  const frame = useCurrentFrame();

  const props = item.props || {};
  const bgColor = props.bgColor;
  const dotColor = props.dotColor;
  const screenshotImage = props.screenshotImage;
  const cardShadowOpacity = props.cardShadowOpacity;
  const transparentBackground = props.transparentBackground;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const rootStyle = {
    position: 'absolute',
    top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: transparentBackground ? 'transparent' : bgColor,
    overflow: 'hidden',
  };

  const cols = 54;
  const rows = 31;
  const spacing = 38;
  const fTime1 = frame * 0.03;
  const fTime2 = frame * 0.02;

  const dots = [];
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const wave1 = Math.sin(c * 0.05 + r * 0.2 + fTime1);
      const wave2 = Math.sin(c * 0.1 - r * 0.05 + fTime2);
      const combinedWave = wave1 * 0.7 + wave2 * 0.3;
      const opacity = 0.215 + combinedWave * 0.135;
      const radius = 1.5 + combinedWave * 0.5;
      dots.push(
        <circle key={`${r}-${c}`} cx={c * spacing} cy={r * spacing} r={radius} fill={dotColor} opacity={opacity} />
      );
    }
  }

  const cardOpacity = interpolate(frame, [5, 25], [0, 1], { extrapolateRight: 'clamp' });
  const cardScale = interpolate(frame, [5, 25], [0.92, 1], {
    easing: Easing.out(Easing.cubic), extrapolateRight: 'clamp'
  });

  return (
    <div style={rootStyle}>
      <svg style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%' }}>
        <g transform={`translate(${(DESIGN_WIDTH - (cols - 1) * spacing) / 2}, ${(DESIGN_HEIGHT - (rows - 1) * spacing) / 2})`}>
          {dots}
        </g>
      </svg>

      {screenshotImage ? (
        <div style={{
          position: 'absolute',
          top: '50%', left: '50%',
          transform: `translate(-50%, -50%) scale(${cardScale})`,
          width: 1160, height: 652,
          backgroundColor: '#ffffff',
          borderRadius: 16,
          boxShadow: `0 12px 48px rgba(0,0,0,${cardShadowOpacity})`,
          opacity: cardOpacity,
          overflow: 'hidden',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}>
          <Img src={screenshotImage} style={{ width: '100%', height: '100%', objectFit: 'contain' }} />
        </div>
      ) : null}
    </div>
  );
};

const MarkerHighlightGraphic = ({item}) => {
  const frame = useCurrentFrame();
  const { durationInFrames } = useVideoConfig();
  const props = item.props || {};
  const bgImage = props.bgImage;
  const line1Text = props.line1Text;
  const line2Text = props.line2Text;
  const line3Text = props.line3Text;
  const highlightColor = props.highlightColor;
  const textColor = props.textColor;
  const fontFamily = props.fontFamily;
  const transparentBackground = props.transparentBackground === true || props.transparentBackground === 'true';
  const highlightPad = parseFloat(props.highlightPad) || 0;
  const lineSpacing = parseFloat(props.lineSpacing) || 148;
  const ruleWidth = parseFloat(props.ruleWidth) || 10;
  const marginWidth = parseFloat(props.marginWidth) || 6;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const baseScale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const zoom = interpolate(frame, [0, durationInFrames - 1], [1.0, 1.05], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const totalScale = baseScale * zoom;
  const offsetX = (DESIGN_WIDTH * (1 - zoom)) / 2;
  const offsetY = (DESIGN_HEIGHT * (1 - zoom)) / 2;

  const getSweep = (start) => {
    const dd = 22;
    const hd = 42;
    const ed = 22;
    const t = frame - start;
    if (t < 0) return { left: 0, width: 0 };
    const drawRight = interpolate(t, [0, dd], [0, 100], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: Easing.out(Easing.cubic) });
    const eraseLeft = interpolate(t - dd - hd, [0, ed], [0, 100], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: Easing.in(Easing.cubic) });
    return { left: Math.max(0, eraseLeft), width: Math.max(0, drawRight - eraseLeft) };
  };

  const s1 = getSweep(15);
  const s2 = getSweep(105);
  const s3 = getSweep(195);

  const show = !transparentBackground;
  const edgeGrad = 'linear-gradient(to bottom, rgba(255,255,255,0.58) 0%, rgba(255,255,255,0.0) 30%, rgba(255,255,255,0.0) 70%, rgba(255,255,255,0.58) 100%)';

  const FS = 100;
  const BASELINE_OFFSET = 80;
  const LH = lineSpacing;
  const lineY1 = 432;
  const lineY2 = lineY1 + LH;
  const lineY3 = lineY1 + LH * 2;
  const top1 = lineY1 - BASELINE_OFFSET;
  const top2 = lineY2 - BASELINE_OFFSET;
  const top3 = lineY3 - BASELINE_OFFSET;

  const hlTopPx = (-highlightPad) + 'px';
  const hlBotPx = (-highlightPad) + 'px';

  // translate3d before scale — forces GPU compositing layer, avoids per-frame rasterization
  const transformStr = 'translate3d(' + offsetX + 'px,' + offsetY + 'px,0) scale(' + totalScale + ')';
  const rootSt = { position: 'absolute', top: 0, left: 0, width: DESIGN_WIDTH, height: DESIGN_HEIGHT, transform: transformStr, transformOrigin: 'top left', willChange: 'transform', overflow: 'hidden', backgroundColor: '#f4f0e6' };
  const bgSt   = { position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', objectFit: 'cover', objectPosition: 'center 20%', willChange: 'transform' };

  const mkRow = (top) => ({ position: 'absolute', left: 210, right: 60, top: top, display: 'flex', alignItems: 'baseline', fontSize: FS + 'px', fontFamily: fontFamily, fontWeight: '900', color: textColor });
  const row1St = mkRow(top1);
  const row2St = mkRow(top2);
  const row3St = mkRow(top3);

  const bullSt = { fontSize: FS + 'px', lineHeight: '1', fontFamily: fontFamily, fontWeight: '900', marginRight: '28px', opacity: 0.75, flexShrink: 0 };
  const wrapSt = { position: 'relative', display: 'inline-block', lineHeight: '1' };
  const txtSt  = { position: 'relative', zIndex: 2, letterSpacing: '-0.02em', whiteSpace: 'nowrap', lineHeight: '1' };

  const mkColor = (sw) => ({ position: 'absolute', top: hlTopPx, bottom: hlBotPx, left: sw.left + '%', width: sw.width + '%', backgroundColor: highlightColor, mixBlendMode: 'multiply', zIndex: 0 });
  const mkEdge  = (sw) => ({ position: 'absolute', top: hlTopPx, bottom: hlBotPx, left: sw.left + '%', width: sw.width + '%', background: edgeGrad, zIndex: 1, pointerEvents: 'none' });
  const hl1c = mkColor(s1); const hl1e = mkEdge(s1);
  const hl2c = mkColor(s2); const hl2e = mkEdge(s2);
  const hl3c = mkColor(s3); const hl3e = mkEdge(s3);

  const rc = 'rgba(131,157,84,0.28)';
  const rl = (t) => ({position:'absolute',left:0,right:0,top:t,height:ruleWidth,backgroundColor:rc});
  const rl0=rl(lineY1-LH*3); const rl1=rl(lineY1-LH*2); const rl2=rl(lineY1-LH);
  const rl3=rl(lineY1);      const rl4=rl(lineY2);       const rl5=rl(lineY3);
  const rl6=rl(lineY3+LH);   const rl7=rl(lineY3+LH*2); const rl8=rl(lineY3+LH*3);
  const marginSt = {position:'absolute',left:152,top:0,bottom:0,width:marginWidth,backgroundColor:'rgba(0,132,133,0.55)'};

  return (
    <div style={rootSt}>
      {bgImage && <Img src={bgImage} style={bgSt} />}
      {show && <div style={rl0}/>}{show && <div style={rl1}/>}{show && <div style={rl2}/>}
      {show && <div style={rl3}/>}{show && <div style={rl4}/>}{show && <div style={rl5}/>}
      {show && <div style={rl6}/>}{show && <div style={rl7}/>}{show && <div style={rl8}/>}
      {show && <div style={marginSt}/>}
      <div style={row1St}><span style={bullSt}>*</span><div style={wrapSt}><div style={hl1c}/><div style={hl1e}/><span style={txtSt}>{line1Text}</span></div></div>
      <div style={row2St}><span style={bullSt}>*</span><div style={wrapSt}><div style={hl2c}/><div style={hl2e}/><span style={txtSt}>{line2Text}</span></div></div>
      <div style={row3St}><span style={bullSt}>*</span><div style={wrapSt}><div style={hl3c}/><div style={hl3e}/><span style={txtSt}>{line3Text}</span></div></div>
    </div>
  );
};

const PollCard = ({item}) => {
  const baseFrame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const backgroundImage = props.backgroundImage;
  const questionText = props.questionText;
  const votesText = props.votesText;
  const sourceName = props.sourceName;
  const sourceTime = props.sourceTime;
  const badgeColor = props.badgeColor;
  const barColorWinner = props.barColorWinner;
  const barColorOthers = props.barColorOthers;
  const opt1Label = props.opt1Label;
  const opt2Label = props.opt2Label;
  const opt3Label = props.opt3Label;
  const opt4Label = props.opt4Label;
  const opt1Value = props.opt1Value;
  const opt2Value = props.opt2Value;
  const opt3Value = props.opt3Value;
  const opt4Value = props.opt4Value;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;

  const frame = Math.floor(baseFrame / 3) * 3;
  const rawProgress = interpolate(frame, [6, 54], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const easeOutCubic = (x) => 1 - Math.pow(1 - x, 3);
  const progress = easeOutCubic(rawProgress);

  const options = [
    { label: opt1Label, value: opt1Value, isWinner: true },
    { label: opt2Label, value: opt2Value, isWinner: false },
    { label: opt3Label, value: opt3Value, isWinner: false },
    { label: opt4Label, value: opt4Value, isWinner: false },
  ];

  const total = options.reduce((s, o) => s + (o.value || 0), 0) || 100;

  return (
    <div style={{ position: 'absolute', top: 0, left: 0, width: DESIGN_WIDTH, height: DESIGN_HEIGHT, fontFamily: 'Roboto, sans-serif' }}>
      {backgroundImage ? (
        <Img src={backgroundImage} style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', objectFit: 'cover', zIndex: 0 }} />
      ) : (
        <div style={{ position: 'absolute', inset: 0, backgroundColor: '#a3b86e', zIndex: 0 }} />
      )}

      <div style={{ position: 'absolute', left: '17%', top: '19%', width: '66%', zIndex: 2, display: 'flex', flexDirection: 'column' }}>

        <div style={{ display: 'flex', alignItems: 'center', gap: 20, marginBottom: 28 }}>
          <div style={{ width: 72, height: 72, borderRadius: '50%', backgroundColor: badgeColor, display: 'flex', justifyContent: 'center', alignItems: 'center', fontWeight: 900, fontSize: 20, fontFamily: 'Roboto, sans-serif', color: '#fff', flexShrink: 0 }}>
            {(sourceName || '').substring(0, 3).toUpperCase()}
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <span style={{ fontWeight: 800, fontSize: 30, color: '#000' }}>{sourceName}</span>
            <span style={{ fontSize: 26, color: '#888' }}>{sourceTime}</span>
          </div>
        </div>

        <div style={{ fontWeight: 700, fontSize: 36, color: '#000', marginBottom: 10, lineHeight: 1.35 }}>{questionText}</div>
        <div style={{ fontSize: 24, color: '#888', marginBottom: 36 }}>{votesText}</div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
          {options.map((opt, i) => {
            const pct = total > 0 ? Math.round((opt.value / total) * 100) : 0;
            const barW = progress * pct;
            const rollingNum = Math.floor(progress * pct);
            const displayNum = frame >= 54 ? pct + '%' : rollingNum + '%';
            return (
              <div key={i} style={{ position: 'relative', width: '100%', height: 82, border: '1.5px solid rgba(0,0,0,0.12)', borderRadius: 8, overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 24px', boxSizing: 'border-box' }}>
                <div style={{ position: 'absolute', top: 0, left: 0, bottom: 0, width: `${barW}%`, backgroundColor: opt.isWinner ? barColorWinner : barColorOthers, zIndex: 1 }} />
                <div style={{ position: 'relative', zIndex: 2, fontSize: 26, fontWeight: 600, color: opt.isWinner ? '#000' : '#555' }}>{opt.label}</div>
                <div style={{ position: 'relative', zIndex: 2, fontSize: opt.isWinner ? 44 : 30, fontWeight: opt.isWinner ? 800 : 600, color: opt.isWinner ? '#000' : '#444', minWidth: 120, textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>{displayNum}</div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

const GoogleSearchOverlay = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const props = item.props || {};
  const searchText = props.searchText || '';
  const showCardBackground = props.showCardBackground !== undefined ? props.showCardBackground : true;
  const cardColor = props.cardColor || '#FFFFFF';

  const colors = {
    blue: '#dd5847',
    red: '#EA4335',
    yellow: '#84d2ff',
    green: '#34A853',
    textGray: '#5F6368',
    borderGray: '#DFE1E5',
    bgGray: '#F8F9FA',
  };

  const totalFrames = 8 * fps;
  const entranceDuration = 1.5 * fps;
  const fadeOutStart = 7.5 * fps;
  const typeStart = 2.5 * fps;
  const typeEnd = 6.5 * fps;

  // 1. Slide up entrance
  const slideY = interpolate(frame, [0, entranceDuration], [DESIGN_HEIGHT * 0.6, 0], {
    easing: Easing.out(Easing.cubic),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  // 2. Ken Burns slow zoom — applied to entire wrapper
  const kenBurns = interpolate(frame, [0, totalFrames], [1.0, 1.1], {
    easing: Easing.inOut(Easing.ease),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  // 3. Search bar pop
  const barScale = interpolate(frame, [2 * fps, 2.5 * fps], [1, 1.04], {
    easing: Easing.out(Easing.cubic),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
