  const barShadowBlur = interpolate(frame, [2 * fps, 2.5 * fps], [8, 20], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  // 4. Typing
  const typeProgress = interpolate(frame, [typeStart, typeEnd], [0, searchText.length], {
    easing: Easing.linear,
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
