const BulletPointOverlay = ({item}) => {
  const frame = useCurrentFrame();
  const props = item.props || {};

  const bgColor = props.bgColor;
  const transparentBackground = props.transparentBackground;
  const text1 = props.text1;
  const text2 = props.text2;
  const text3 = props.text3;
  const text4 = props.text4;
  const fontFamily = props.fontFamily;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // Layout constants
  const CARD_W = 735;
  const CARD_H = 160;
  const VID_LEFT = 1350;
  const VID_TOP = 172;
  const VID_W = 514;
  const VID_H = 715;
  const VID_RX = 26;

  // Animation timing
  const ENTER_DUR = 14;
  const SLIDE_DIST = 50;
  const TEXT_DELAY = 6;
  const EXIT_START = 155;
  const EXIT_DUR = 14;
  const cardEnterFrames = [20, 45, 70, 95];

  const easeOutCubic = t => 1 - Math.pow(1 - t, 3);
  const easeInCubic  = t => Math.pow(t, 3);

  const getCardAnim = (enterFrame) => {
    if (frame < enterFrame) return { opacity: 0, tx: -SLIDE_DIST, show: false };
    if (frame < enterFrame + ENTER_DUR) {
      const t = easeOutCubic((frame - enterFrame) / ENTER_DUR);
      return { opacity: t, tx: (1 - t) * -SLIDE_DIST, show: true };
    }
    if (frame < EXIT_START) return { opacity: 1, tx: 0, show: true };
    if (frame < EXIT_START + EXIT_DUR) {
      const t = easeInCubic((frame - EXIT_START) / EXIT_DUR);
      return { opacity: 1 - t, tx: t * -SLIDE_DIST, show: true };
    }
    return { opacity: 0, tx: -SLIDE_DIST, show: false };
  };

  const getTextAnim = (enterFrame) => {
    const tIn = enterFrame + TEXT_DELAY;
    if (frame < tIn) return { opacity: 0, tx: -SLIDE_DIST * 0.5 };
    if (frame < tIn + ENTER_DUR) {
      const t = easeOutCubic((frame - tIn) / ENTER_DUR);
      return { opacity: t, tx: (1 - t) * -SLIDE_DIST * 0.5 };
    }
    if (frame < EXIT_START) return { opacity: 1, tx: 0 };
    if (frame < EXIT_START + EXIT_DUR) {
      const t = easeInCubic((frame - EXIT_START) / EXIT_DUR);
      return { opacity: 1 - t, tx: t * -SLIDE_DIST * 0.5 };
    }
    return { opacity: 0, tx: -SLIDE_DIST * 0.5 };
  };

  // SVG icon paths — dark gray stroke on white circle, consistent with overall gray palette
  const ICON_STROKE = '#272e3b';
  const icons = [
    // Chef hat / cook
    <svg width="46" height="46" viewBox="0 0 24 24" fill="none" stroke={ICON_STROKE} strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round">
      <path d="M6 13.87A4 4 0 0 1 7.41 6a5.11 5.11 0 0 1 1.05-1.54 5 5 0 0 1 7.08 0A5.11 5.11 0 0 1 16.59 6 4 4 0 0 1 18 13.87V21H6z"/>
