const TalkingHeadOverlay = ({item}) => {
  const frame = useCurrentFrame();
  const {fps = 30} = useVideoConfig();

  const props = item.props || {};
  const bgColor = props.backgroundColor;
  const textColor = props.textColor;
  const font = props.fontFamily;

  const bullets = [
    props.bullet1Text,
    props.bullet2Text,
    props.bullet3Text,
    props.bullet4Text,
    props.bullet5Text,
  ];

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const CUTOUT_X = 1210;
  const CUTOUT_W = 624;
  const CUTOUT_H = Math.round(CUTOUT_W * 4 / 3); // 3:4 → 832px
  const CUTOUT_Y = Math.round((1080 - CUTOUT_H) / 2); // vertically centered → 124px

  const LIST_LEFT = 80;
  const CIRCLE_SIZE = 90;
  const GAP = 28;
  const TEXT_MAX_WIDTH = CUTOUT_X - 40 - LIST_LEFT - CIRCLE_SIZE - GAP; // 972px

  const ROW_H = 130;
  const TOTAL_LIST_H = ROW_H * 5; // 650px
  const LIST_TOP = Math.round((DESIGN_HEIGHT - TOTAL_LIST_H) / 2) + 20; // ~235px

  const BALL_TRAVEL = 350;
  const BALL_START_OFFSET = -BALL_TRAVEL;

  const BULLET_DURATION = 1.5;
  const FIRST_BULLET_START = 0.3;

  const ROLL_FRAMES = Math.round(0.5 * fps);    // 15f
  const BOUNCE_FRAMES = Math.round(0.35 * fps); // 11f
  const TYPE_START_F = ROLL_FRAMES + BOUNCE_FRAMES;
  const TYPE_FRAMES = Math.round(0.8 * fps);    // 24f

  // Physical rotation over the travel distance (cumulative degrees turned)
  const TRAVEL_DEG = (BALL_TRAVEL / (Math.PI * CIRCLE_SIZE)) * 360; // ~446°
  // The remainder after full 360° turns tells us how far off "upright" we'd end up
  const remainder = TRAVEL_DEG % 360; // ~86°
  // So we pre-rotate the ball by -remainder at the start (it looks tilted ~-86°)
  // As it rolls exactly TRAVEL_DEG, it arrives at -remainder + TRAVEL_DEG = multiple of 360° = upright (0°)
  const START_ROTATION = -remainder; // e.g. ~-86°  (number faces ~-86° at frame 0 of this bullet)

  function getBulletState(i) {
    const startFrame = (FIRST_BULLET_START + i * BULLET_DURATION) * fps;
    const localFrame = frame - startFrame;
    if (localFrame < 0) return { visible: false };

    let ballOffset = 0;
    // Default: upright (0° extra offset from multiples of 360)
    let ballRotation = 0;

    if (localFrame < ROLL_FRAMES) {
      // Roll phase: ease-out quart
      const t = localFrame / ROLL_FRAMES;
      const ease = 1 - Math.pow(1 - t, 4);
      ballOffset = BALL_START_OFFSET * (1 - ease);
      // Rotation goes continuously from START_ROTATION → 0° as ball travels BALL_TRAVEL
      // At t=0: START_ROTATION. At t=1: START_ROTATION + TRAVEL_DEG = 0 (mod 360 multiples)
      ballRotation = START_ROTATION + ease * TRAVEL_DEG;
    } else if (localFrame < TYPE_START_F) {
      // Bounce phase: only position bounces, rotation stays at 0° (number upright)
      const t = (localFrame - ROLL_FRAMES) / BOUNCE_FRAMES;
      const decay = Math.exp(-5 * t);
      ballOffset = decay * Math.sin(t * Math.PI * 2.2) * 10;
      ballRotation = 0;
    }
    // After bounce: ballOffset = 0, ballRotation = 0 (upright)

    let typeProgress = 0;
    if (localFrame >= TYPE_START_F) {
      const t = (localFrame - TYPE_START_F) / TYPE_FRAMES;
      typeProgress = Math.min(1, 1 - Math.pow(Math.max(0, 1 - t), 2.2));
    }

    return { visible: true, ballOffset, ballRotation, typeProgress };
  }

  // Text styles shared between phantom and visible layers
  const textStyle = {
    width: TEXT_MAX_WIDTH,
    fontSize: '40px',
    lineHeight: '1.35',
    fontWeight: '500',
    letterSpacing: '-0.01em',
    wordBreak: 'break-word',
    overflowWrap: 'break-word',
  };

  return (
    <div style={{
      position: 'absolute',
      top: 0, left: 0,
      width: DESIGN_WIDTH,
      height: DESIGN_HEIGHT,
      transform: `scale(${scale})`,
      transformOrigin: 'top left',
      backgroundColor: 'transparent',
      fontFamily: font,
      overflow: 'hidden',
    }}>
      {/* SVG background with static cutout */}
      <svg width={DESIGN_WIDTH} height={DESIGN_HEIGHT} style={{ position: 'absolute', top: 0, left: 0 }}>
        <defs>
          <mask id="bgMask">
            <rect x="0" y="0" width={DESIGN_WIDTH} height={DESIGN_HEIGHT} fill="white" />
            <rect x={CUTOUT_X} y={CUTOUT_Y} width={CUTOUT_W} height={CUTOUT_H} rx="28" fill="black" />
          </mask>
        </defs>
        <rect x="0" y="0" width={DESIGN_WIDTH} height={DESIGN_HEIGHT} fill={bgColor} mask="url(#bgMask)" />
        <rect x={CUTOUT_X} y={CUTOUT_Y} width={CUTOUT_W} height={CUTOUT_H} rx="28" fill="none" stroke={textColor} strokeWidth="5" />
      </svg>

      {/* Bullet rows */}
      {bullets.map((text, i) => {
        const state = getBulletState(i);
        if (!state.visible) return null;

        const rowCenterY = LIST_TOP + i * ROW_H + ROW_H / 2;
        const charCount = Math.floor(state.typeProgress * text.length);
        const displayText = text.slice(0, charCount);
        const isTyping = state.typeProgress > 0 && state.typeProgress < 1;
        const cursorOn = isTyping && Math.floor(frame / 4) % 2 === 0;

        return (
          <div key={i} style={{
            position: 'absolute',
            top: rowCenterY,
            left: LIST_LEFT,
            transform: 'translateY(-50%)',
            display: 'flex',
            flexDirection: 'row',
            alignItems: 'center',
            gap: GAP,
            width: CIRCLE_SIZE + GAP + TEXT_MAX_WIDTH,
          }}>
            {/* Ball */}
            <div style={{
              flexShrink: 0,
              width: CIRCLE_SIZE,
              height: CIRCLE_SIZE,
              borderRadius: '50%',
              backgroundColor: textColor,
              color: bgColor,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '40px',
              fontWeight: 'bold',
              transform: `translateX(${state.ballOffset}px) rotate(${state.ballRotation}deg)`,
            }}>
              {String(i + 1)}
            </div>

            {/*
              Text wrapper: position relative so children can stack.
              The PHANTOM layer (visibility:hidden, full text) always occupies
              the final height — the flex container never resizes during typing.
              The VISIBLE layer (position:absolute, inset 0) shows the typed chars,
              positioned on top of the phantom so it never shifts the layout.
            */}
            <div style={{ position: 'relative', width: TEXT_MAX_WIDTH }}>
              {/* Phantom: full text, invisible, holds the final height */}
              <div style={{
                ...textStyle,
                visibility: 'hidden',
                userSelect: 'none',
                pointerEvents: 'none',
              }}>
                {text}
              </div>

              {/* Visible typed text: absolutely positioned, no layout influence */}
              {state.typeProgress > 0 && (
                <div style={{
                  ...textStyle,
                  position: 'absolute',
                  top: 0,
                  left: 0,
                  color: textColor,
                }}>
                  {displayText}
                  {cursorOn && (
                    <span style={{
                      display: 'inline-block',
                      width: '3px',
                      height: '40px',
                      backgroundColor: textColor,
                      marginLeft: '5px',
                      verticalAlign: 'text-bottom',
                    }} />
                  )}
                </div>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
};

