const BoldGlitchTitle05 = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();
  const props = item.props || {};
  const mainTitle = props.mainTitle || 'SHOP THE LOOK';
  const subtitleText = props.subtitleText || 'COZY HOME COLLECTION';
  const textColor = props.textColor || '#FFFFFF';
  const glowColor = props.glowColor || 'rgba(255,255,255,0.5)';
  const bgOpacity = props.bgOpacity !== undefined ? parseFloat(props.bgOpacity) : 0.88;

  const DESIGN_WIDTH = 1920, DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width||DESIGN_WIDTH)/DESIGN_WIDTH, (item?.height||DESIGN_HEIGHT)/DESIGN_HEIGHT);

  const outStart = Math.max(0, durationInFrames - 30);

  let textOpacity = 1, shadowStr = 'none', scanI = 0.06;

  if (frame < 8) {
    textOpacity = 0.08; scanI = 0.35;
  } else if (frame < 12) {
    textOpacity = frame%2===0 ? 1 : 0.1;
    scanI = 0.5;
  } else if (frame < 25) {
    const n = Math.abs(Math.sin(frame*12.9898)*43758.5453)%1;
    textOpacity = n>0.3 ? 1 : 0.6;
    const spread = n>0.5 ? 22 : 0;
    shadowStr = `0 0 6px ${textColor}, 0 0 ${spread}px ${glowColor}`;
    scanI = 0.3;
  } else if (frame < outStart) {
    const micro = (frame-25)%22<2;
    textOpacity = micro ? 0.7 : 1;
    shadowStr = `0 0 28px ${glowColor}`;
    scanI = 0.06;
  } else if (frame < outStart+10) {
    const n = Math.abs(Math.sin(frame*78.233)*43758.5453)%1;
    textOpacity = n>0.5 ? 1 : 0.15;
    shadowStr = n>0.5 ? `0 0 22px ${glowColor}` : 'none';
    scanI = 0.45;
  } else {
    const fp = (frame-(outStart+10))/20;
    textOpacity = interpolate(fp,[0,1],[1,0],{extrapolateRight:'clamp'});
    shadowStr = `0 0 ${interpolate(fp,[0,1],[30,0],{extrapolateRight:'clamp'})}px ${glowColor}`;
    scanI = 0.3;
  }

  // Fine glitch slices during flicker phases
  const isFlicker = frame < 25 || frame >= outStart;
  const NUM_SLICES = 12;
  const sliceShifts = Array.from({length:NUM_SLICES}).map((_,i) => {
    if (!isFlicker) return 0;
    const maxS = frame<12 ? 40 : 18;
    const active = random(`fa${i}${Math.floor(frame/2)}`) > 0.72;
    return active ? (random(`fs${i}${frame}`)-0.5)*2*maxS : 0;
  });

  // RGB offset during flicker
  const rgbActive = frame < 25 || frame >= outStart;
  const rOff = rgbActive ? (random('r'+frame)-0.5)*2*(frame<12?18:9) : 0;
  const cOff = rgbActive ? (random('c'+frame)-0.5)*2*(frame<12?18:9)*-1 : 0;

  const rootStyle = {
    position:'absolute', top:0, left:0, width:DESIGN_WIDTH, height:DESIGN_HEIGHT,
    transform:`scale(${scale})`, transformOrigin:'top left',
    backgroundColor:`rgba(10,10,10,${bgOpacity})`, overflow:'hidden'
  };

  return (
    <div style={rootStyle}>
      {/* Scanlines */}
      <div style={{
        position:'absolute', top:0, left:0, width:'100%', height:'100%',
        background:'repeating-linear-gradient(to bottom, transparent 0px, transparent 3px, rgba(0,0,0,0.4) 4px, rgba(0,0,0,0.4) 5px)',
        opacity:scanI, pointerEvents:'none', mixBlendMode:'overlay', zIndex:20
      }}/>

      {/* RGB Red layer */}
      {rOff !== 0 && <div style={{position:'absolute', top:0, left:rOff, width:'100%', height:'100%', mixBlendMode:'screen', opacity:0.55}}>
        <div style={{position:'absolute', top:'48%', left:'50%', transform:'translate(-50%,-50%)',
          fontFamily:'"Montserrat","Inter",sans-serif', fontWeight:900, fontSize:'125px',
          textTransform:'uppercase', color:'#789e00', whiteSpace:'nowrap', opacity:textOpacity}}>{mainTitle}</div>
      </div>}
      {/* RGB Cyan layer */}
      {cOff !== 0 && <div style={{position:'absolute', top:0, left:cOff, width:'100%', height:'100%', mixBlendMode:'screen', opacity:0.55}}>
        <div style={{position:'absolute', top:'48%', left:'50%', transform:'translate(-50%,-50%)',
          fontFamily:'"Montserrat","Inter",sans-serif', fontWeight:900, fontSize:'125px',
          textTransform:'uppercase', color:'#00e8e9', whiteSpace:'nowrap', opacity:textOpacity}}>{mainTitle}</div>
      </div>}

      {/* Main text */}
      <div style={{position:'absolute', top:'48%', left:'50%', transform:'translate(-50%,-50%)',
        fontFamily:'"Montserrat","Inter",sans-serif', fontWeight:900, fontSize:'125px',
        textTransform:'uppercase', color:textColor, opacity:textOpacity, textShadow:shadowStr,
        whiteSpace:'nowrap', textAlign:'center', lineHeight:1}}>{mainTitle}</div>

      {/* Subtitle */}
      <div style={{position:'absolute', top:'56%', left:'50%', transform:'translate(-50%,-50%)',
        fontFamily:'"Montserrat","Inter",sans-serif', fontWeight:400, fontSize:'20px',
        letterSpacing:'0.2em', textTransform:'uppercase', color:textColor,
        opacity:textOpacity, textShadow:shadowStr, whiteSpace:'nowrap', textAlign:'center', lineHeight:1}}>{subtitleText}</div>

      {/* Fine glitch slice overlays */}
      {sliceShifts.map((shift,i) => shift !== 0 && (
        <div key={i} style={{
          position:'absolute', top:0, left:shift, width:'100%', height:'100%',
          clipPath:`inset(${(i/NUM_SLICES)*100}% 0 ${100-((i+1)/NUM_SLICES)*100}% 0)`
        }}>
          <div style={{position:'absolute', top:'48%', left:'50%', transform:'translate(-50%,-50%)',
            fontFamily:'"Montserrat","Inter",sans-serif', fontWeight:900, fontSize:'125px',
            textTransform:'uppercase', color:textColor, opacity:textOpacity*0.8,
            textShadow:shadowStr, whiteSpace:'nowrap'}}>{mainTitle}</div>
        </div>
      ))}
    </div>
  );
};

const CinematicTitle = ({item}) => {
  const frame = useCurrentFrame();
  const { fps, durationInFrames } = useVideoConfig();

  const props = item.props || {};
  const seriesTitle = props.seriesTitle;
  const mainTitle = props.mainTitle;
  const highlightColor = props.highlightColor;
  const bgColor = "#e8e6e0";
  const transparentBackground = props.transparentBackground;
  const fontFamilySeries = props.fontFamilySeries;
  const fontFamilyMain = props.fontFamilyMain;

  const safeFps = fps || 30;
  const safeDuration = durationInFrames || 330;
  // Cut at 0.8s (24 frames) — instant switch, no fade
  const cutFrame = Math.round(safeFps * 0.8);

  const parseHex = (hex) => {
    if (!hex || !hex.startsWith('#')) return [255, 234, 0];
    let c = hex.substring(1).split('');
    if(c.length === 3){
        c = [c[0], c[0], c[1], c[1], c[2], c[2]];
    }
    c = '0x' + c.join('');
    return [(c>>16)&255, (c>>8)&255, c&255];
  };
  const rgb = parseHex(highlightColor);

  const isHighlight = frame < cutFrame;
  const textColor = isHighlight ? highlightColor : '#111111';
  const textShadow = 'none';

  const scale = interpolate(frame, [0, safeDuration], [1, 1.05]);

  const splitTitle = (title) => {
    if (!title) return { left: '', right: '' };
    const commaIdx = title.lastIndexOf(',');
    if (commaIdx !== -1) {
      return {
        left: title.substring(0, commaIdx + 1) + ' ',
        right: title.substring(commaIdx + 1).trim()
      };
    }
    const spaceIdx = title.lastIndexOf(' ');
    if (spaceIdx !== -1) {
      return {
        left: title.substring(0, spaceIdx + 1),
        right: title.substring(spaceIdx + 1)
      };
    }
    return { left: '', right: title };
  };

  const { left, right } = React.useMemo(() => splitTitle(mainTitle), [mainTitle]);

  const watermarks = React.useMemo(() => {
    const symbols = ['∑','∫','π','Δ','α','β','∞','≈','≠','≤','≥','Ω','µ','√'];
    const out = [];
    let seed = 12345;
    const rng = () => { seed = (seed * 9301 + 49297) % 233280; return seed / 233280; };
    for (let i = 0; i < 40; i++) {
      out.push({ id: i, char: symbols[Math.floor(rng() * symbols.length)],
        left: rng()*110-5 + '%', top: rng()*110-5 + '%',
        size: 150 + rng()*450, rot: (rng()-0.5)*120, opacity: 0.02+rng()*0.03 });
    }
    return out;
  }, []);

  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor: transparentBackground ? 'transparent' : bgColor,
    overflow: 'hidden'
  };

  return (
    <div style={rootStyle}>
      {/* Grid layer — identical to Background Layer MG */}
      {!transparentBackground && (
        <div style={{ position: 'absolute', inset: 0, zIndex: 1, pointerEvents: 'none' }}>
          <svg width="100%" height="100%">
            <defs>
              <pattern id="title_grid" width="80" height="80" patternUnits="userSpaceOnUse">
                <path d="M 40 0 L 40 80 M 0 40 L 80 40" stroke="#999" strokeOpacity="0.06" strokeWidth="1.5"/>
                <path d="M 33 40 L 47 40 M 40 33 L 40 47" stroke="#999" strokeOpacity="0.15" strokeWidth="2"/>
              </pattern>
            </defs>
            <rect width="100%" height="100%" fill="url(#title_grid)"/>
          </svg>
        </div>
      )}
      {/* Watermark symbols — identical to Background Layer MG */}
      {!transparentBackground && (
        <div style={{ position: 'absolute', inset: 0, zIndex: 2, pointerEvents: 'none' }}>
          {watermarks.map(wm => (
            <div key={wm.id} style={{
              position: 'absolute', left: wm.left, top: wm.top,
              fontSize: wm.size, color: '#888', opacity: wm.opacity,
              transform: 'rotate(' + wm.rot + 'deg)', lineHeight: 1, fontFamily: 'serif',
            }}>{wm.char}</div>
          ))}
        </div>
      )}
      {/* Film grain */}
      <div style={{ position: 'absolute', inset: 0, opacity: 0.06, pointerEvents: 'none', zIndex: 3 }}>
        <svg style={{ width: '100%', height: '100%' }}>
          <filter id="film-grain">
            <feTurbulence type="fractalNoise" baseFrequency="0.75" numOctaves="3" stitchTiles="stitch" />
            <feColorMatrix type="saturate" values="0" />
          </filter>
          <rect width="100%" height="100%" filter="url(#film-grain)" />
        </svg>
      </div>

      <div style={{
        position: 'absolute',
        inset: 0,
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        transform: `scale(${scale})`,
        transformOrigin: 'center center',
        padding: '0 80px',
        zIndex: 10
      }}>
        <div style={{
          fontFamily: fontFamilySeries,
          fontWeight: 400,
          fontSize: 32,
          letterSpacing: '0.15em',
          color: '#555555',
          textTransform: 'uppercase',
          marginBottom: 24,
          textAlign: 'center'
        }}>
          {seriesTitle}
        </div>

        <div style={{
          fontFamily: fontFamilyMain,
          fontWeight: 900,
          fontSize: 130,
          letterSpacing: '-0.02em',
          textTransform: 'uppercase',
          lineHeight: 1.1,
          textAlign: 'center',
          whiteSpace: 'pre-wrap',
          maxWidth: 1700
        }}>
          {left && <span style={{ color: '#111111' }}>{left}</span>}
          <span style={{ color: textColor, textShadow: textShadow }}>{right}</span>
        </div>
      </div>
    </div>
  );
};

const CommunityWelcome = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  // Props
  const props = item.props || {};
  const titleText = props.titleText || 'Ride On';
  const taglineText = props.taglineText || 'Every wheel is welcome';
  const headerLabel1 = props.headerLabel1 || 'RIDE ON';
  const headerLabel2 = props.headerLabel2 || 'RIDE ON';
  const headerLabel3 = props.headerLabel3 || 'RIDE ON';
  const bgText1 = props.bgText1 || 'Ride On';
  const bgText2 = props.bgText2 || 'Every wheel is welcome';
  const bgText3 = props.bgText3 || 'CYCLING CLUB';
  const primaryColor = props.primaryColor || '#FFFFFF';
  // Logo: asset type — runtime passes resolved URL string directly
  const logoUrl = props.logoUrl || '';
  const bgBlue = props.bgBlue || '#3b5f79';
  const bgAmber = props.bgAmber || '#2d536c';
  const bgOrange = props.bgOrange || '#0b283f';
  const bgGray = props.bgGray || '#0E0E14';
  const bgPurple = props.bgPurple || '#0A0A0F';
  const bgTeal = props.bgTeal || '#0A0A0F';

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const startDelay = 10;
  const morphTrigger = 60;

  const logoEntrance = spring({
    frame: frame - startDelay,
    fps,
    config: { damping: 12, stiffness: 100 }
  });

  const morphProgress = spring({
    frame: frame - morphTrigger,
    fps,
    config: { damping: 20, stiffness: 80 }
  });

  const taglineEntrance = spring({
    frame: frame - (morphTrigger + 20),
    fps,
    config: { damping: 15, stiffness: 100 }
  });

  const bgPulse = Math.cos(frame / 150) * 0.2 + 1;

  const logoRotation = interpolate(morphProgress, [0, 1], [0, 140]);
  const logoScale = interpolate(morphProgress, [0, 1], [1, 1.8]);
  const logoOpacity = interpolate(morphProgress, [0, 0.42], [1, 0], {
    extrapolateRight: 'clamp',
    easing: Easing.bezier(0.4, 0, 1, 1),
  });

  const titleScale = interpolate(morphProgress, [0, 1], [0.92, 1]);
  const titleOpacity = interpolate(morphProgress, [0.2, 0.55], [0, 1], { extrapolateRight: 'clamp' });
  const titleBlur = interpolate(morphProgress, [0.2, 0.7], [8, 0], { extrapolateRight: 'clamp' });

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    backgroundColor: '#08080E',
    overflow: 'hidden',
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    fontFamily: 'Inter, -apple-system, BlinkMacSystemFont, sans-serif',
    color: primaryColor,
  };

  const noiseFilter = '<svg width="0" height="0"><filter id="grainy"><feTurbulence type="fractalNoise" baseFrequency="0.8" numOctaves="3" stitchTiles="stitch"/><feColorMatrix type="saturate" values="0"/></filter></svg>';

  const Orb = ({ color, size, top, left, delay }) => {
    const movement = Math.sin((frame + delay) / 100) * 30;
    return (
      <div style={{
        position: 'absolute',
        width: size,
        height: size,
        borderRadius: '50%',
        background: color,
        top,
        left,
        filter: 'blur(120px)',
        opacity: 0.6,
        transform: `translate(${movement}px, ${movement * 0.5}px) scale(${bgPulse})`,
      }} />
    );
  };

  return (
    <div style={rootStyle}>
      <div style={{ position: 'absolute', inset: 0, zIndex: 0 }}>
        <Orb color={bgBlue} size={1300} top={-200} left={-200} delay={0} />
        <Orb color={bgAmber} size={900} top={450} left={900} delay={300} />
        <Orb color={bgOrange} size={700} top={600} left={400} delay={600} />
        <Orb color={bgGray} size={600} top={0} left={1400} delay={900} />
        <Orb color={bgPurple} size={500} top={700} left={100} delay={400} />
        <Orb color={bgTeal} size={500} top={-100} left={1500} delay={700} />
        <div style={{
            position: 'absolute',
            inset: 0,
            opacity: 0.07,
            filter: 'url(#grainy)',
            zIndex: 1,
            pointerEvents: 'none'
        }} />
      </div>

      <div style={{ position: 'absolute', width: 0, height: 0 }} dangerouslySetInnerHTML={{ __html: noiseFilter }} />

      <div style={{
        position: 'absolute',
        top: 60,
        width: '100%',
        display: 'flex',
        justifyContent: 'center',
        gap: 200,
        zIndex: 2,
        opacity: interpolate(frame, [0, 30], [0, 0.5]),
        transform: `translateY(${interpolate(frame, [0, 30], [-50, 0], { extrapolateRight: 'clamp' })}px)`
      }}>
        {[headerLabel1, headerLabel2, headerLabel3].map((label, i) => (
          <span key={i} style={{
            fontSize: 16,
            letterSpacing: '0.4em',
            fontWeight: 600,
            textTransform: 'uppercase',
            opacity: 0.7
          }}>
            {label}
          </span>
        ))}
      </div>

      <div style={{ position: 'absolute', inset: 0, zIndex: 5, pointerEvents: 'none', overflow: 'hidden' }}>
        <div style={{
          position: 'absolute',
          top: '10%',
          left: '-6%',
          fontSize: 320,
          fontWeight: 900,
          fontFamily: '"Playfair Display", "Georgia", serif',
          fontStyle: 'italic',
          color: 'rgba(255,255,255,0.02)',
          whiteSpace: 'nowrap',
          lineHeight: 1,
          letterSpacing: '-0.02em',
          opacity: interpolate(frame, [20, 55], [0, 1], { extrapolateRight: 'clamp' }),
        }}>
          {bgText1}
        </div>
        <div style={{
          position: 'absolute',
          top: '37%',
          right: '-5%',
          fontSize: 280,
          fontWeight: 700,
          fontFamily: '"Oswald", "Arial Narrow", sans-serif',
          textTransform: 'uppercase',
          color: 'rgba(255,255,255,0.02)',
          whiteSpace: 'nowrap',
          lineHeight: 1,
          letterSpacing: '0.03em',
          opacity: interpolate(frame, [28, 60], [0, 1], { extrapolateRight: 'clamp' }),
        }}>
          {bgText2}
        </div>
        <div style={{
          position: 'absolute',
          top: '63%',
          left: '-3%',
          fontSize: 310,
          fontWeight: 400,
          fontFamily: '"Abril Fatface", "Georgia", cursive',
          color: 'rgba(255,255,255,0.02)',
          whiteSpace: 'nowrap',
          lineHeight: 1,
          letterSpacing: '0.02em',
          opacity: interpolate(frame, [36, 65], [0, 1], { extrapolateRight: 'clamp' }),
