                  <>
                    <svg width="170" height="170" viewBox="0 0 100 100" style={{ transform: 'rotate(-25deg)' }}>
                      <circle
                        cx="50" cy="50" r="40"
                        fill="none"
                        stroke={primaryColor}
                        strokeWidth="12"
                        strokeDasharray="251"
                        strokeDashoffset={interpolate(logoEntrance, [0, 1], [251, 60])}
