};

const DoodleOverlay = ({item}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const props = item.props || {};

  const titleText = props.titleText;
  const tag1Text = props.tag1Text;
  const tag2Text = props.tag2Text;
  const listItems = [
    props.listItem1,
    props.listItem2,
    props.listItem3,
    props.listItem4,
    props.listItem5
  ];
  const primaryColor = props.primaryColor;
  const textColor = props.textColor;
  const titleFont = props.titleFont;
  const listFont = props.listFont;
  const isTransparent = props.transparentBackground === true || props.transparentBackground === 'true';
  const bgColor = props.bgColor;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const safeFps = fps || 30;
  const safeSpring = (delay, config) => {
    return spring({ frame: Math.max(0, frame - (delay || 0)), fps: safeFps, config: config || { damping: 14, mass: 0.8, stiffness: 120 } });
  };

  const windowX = 140;
  const windowY = 240;
  const windowW = 740;
  const windowH = 680;
  const windowRx = 40;

  const titleSpring = safeSpring(5);
  const tag1Spring = safeSpring(35);
  const tag2Spring = safeSpring(45);

  const titleOpacity = Math.min(1, Math.max(0, interpolate(titleSpring, [0, 1], [0, 1])));

  const renderedListItems = listItems.map(function(text, i) {
    const itemSpring = safeSpring(55 + i * 8);
    const itemOpacity = Math.min(1, Math.max(0, interpolate(itemSpring, [0, 1], [0, 1])));
    const itemY = interpolate(itemSpring, [0, 1], [40, 0]);
    return { text: text, itemOpacity: itemOpacity, itemY: itemY, key: i };
  });

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: 'scale(' + scale + ')',
    transformOrigin: 'top left',
    backgroundColor: 'transparent',
    overflow: 'hidden'
  };

  return (
    <div style={rootStyle}>
      {!isTransparent && (
        <svg style={{ position: 'absolute', top: 0, left: 0, width: DESIGN_WIDTH, height: DESIGN_HEIGHT, zIndex: 0 }}>
          <defs>
            <mask id="video-cutout-mask">
              <rect width="100%" height="100%" fill="white" />
              {/* Cutout is full size from frame 0 — no animation */}
              <rect x={windowX} y={windowY} width={windowW} height={windowH} rx={windowRx} fill="black" />
            </mask>
          </defs>
          <rect width="100%" height="100%" fill={bgColor} mask="url(#video-cutout-mask)" />
        </svg>
      )}

      <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', zIndex: 1 }}>

        {/* Title */}
        <div style={{
          position: 'absolute',
          top: 90,
          width: '100%',
          textAlign: 'center',
          fontSize: 100,
          fontFamily: titleFont,
          color: textColor,
          transform: 'scale(' + titleSpring + ')',
          opacity: titleOpacity,
          fontWeight: 'bold',
          letterSpacing: '2px'
        }}>
          {titleText}
        </div>

        {/* Window border — static, no animation */}
        <div style={{
          position: 'absolute',
          left: windowX,
          top: windowY,
          width: windowW,
          height: windowH,
          border: '6px solid ' + primaryColor,
          borderRadius: windowRx,
          boxSizing: 'border-box'
        }}>
          <div style={{
            position: 'absolute',
            inset: -16,
            border: '3px dashed ' + primaryColor,
            borderRadius: (windowRx + 8),
            opacity: 0.5
          }} />
        </div>

        {/* Tag 1 */}
        <div style={{
          position: 'absolute',
          left: windowX + windowW - 60,
          top: windowY - 40,
          transform: 'scale(' + tag1Spring + ') rotate(10deg)',
          transformOrigin: 'center center'
        }}>
          <div style={{
            backgroundColor: primaryColor,
            color: '#FFFFFF',
            padding: '12px 36px',
            borderRadius: '255px 15px 225px 15px/15px 225px 15px 255px',
            fontFamily: titleFont,
            fontSize: 44,
            boxShadow: '6px 6px 0px rgba(0,0,0,0.1)',
            border: '3px solid white',
            whiteSpace: 'nowrap'
          }}>
            {tag1Text}
          </div>
        </div>

        {/* Tag 2 */}
        <div style={{
          position: 'absolute',
          left: windowX - 40,
          top: windowY + windowH - 70,
          transform: 'scale(' + tag2Spring + ') rotate(-8deg)',
          transformOrigin: 'center center'
        }}>
          <div style={{
            backgroundColor: primaryColor,
            color: '#FFFFFF',
            padding: '12px 36px',
            borderRadius: '15px 255px 15px 225px/225px 15px 255px 15px',
            fontFamily: titleFont,
            fontSize: 44,
            boxShadow: '-6px 6px 0px rgba(0,0,0,0.1)',
            border: '3px solid white',
            whiteSpace: 'nowrap'
          }}>
            {tag2Text}
          </div>
        </div>

        {/* List */}
        <div style={{
          position: 'absolute',
          left: 1020,
          top: 300,
          width: 800,
          display: 'flex',
          flexDirection: 'column',
          gap: 65
        }}>
          {renderedListItems.map(function(listItem) {
            return (
              <div key={listItem.key} style={{
                display: 'flex',
                alignItems: 'center',
                transform: 'translateY(' + listItem.itemY + 'px)',
                opacity: listItem.itemOpacity
              }}>
                <div style={{
                  width: 28,
                  height: 28,
                  backgroundColor: primaryColor,
                  borderRadius: '60% 40% 50% 50%/50% 50% 60% 40%',
                  marginRight: 32,
                  flexShrink: 0,
                  boxShadow: '3px 3px 0px rgba(0,0,0,0.08)'
                }} />
                <div style={{
                  fontSize: 50,
                  fontFamily: listFont,
                  color: textColor,
                  fontWeight: 600,
                  lineHeight: 1.2
                }}>
                  {listItem.text}
                </div>
              </div>
            );
          })}
