      </div>
    </div>
  );
};

const VerticalScrollRoller = ({item}) => {
  const frame = useCurrentFrame();
  const props = item.props || {};

  const words = [
    props.word1,
    props.word2,
    props.word3,
    props.word4,
    props.word5,
    props.word6,
  ].filter(Boolean);

  const validWords = words.length > 0 ? words : ['TONE'];
  const fontFamily = props.fontFamily;
  const textColor = props.textColor;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const ENTER_FRAMES = 14; // spring settle frames (longer to allow bounce)
  const HOLD = 18;         // frames to hold at center
  const EXIT_FRAMES = 8;   // frames to exit
  const INTERVAL = ENTER_FRAMES + HOLD;

  const slots = Array.from({length: 15}).map((_, i) => ({
    word: validWords[i % validWords.length],
    index: i,
  }));

  const textStyle = {
    fontFamily,
    fontSize: '160px',
    fontWeight: 900,
    color: textColor,
    textTransform: 'uppercase',
    margin: 0,
    lineHeight: 1,
    textAlign: 'center',
    whiteSpace: 'nowrap',
    letterSpacing: '0.02em',
    userSelect: 'none',
  };

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      transform: `scale(${scale})`,
      transformOrigin: 'top left',
      backgroundColor: 'transparent',
      overflow: 'hidden',
    }}>
      {slots.map(({word, index}) => {
        const startTime = index * INTERVAL;
        const enterEnd = startTime + ENTER_FRAMES;
        const exitStart = enterEnd + HOLD;
        const exitEnd = exitStart + EXIT_FRAMES;

        if (frame < startTime || frame > exitEnd + 2) return null;

        // --- compute Y position ---
        let y = 0;
        let phase = 'hold';

        if (frame <= enterEnd) {
          phase = 'enter';
          // Spring: fast drop with slight overshoot then settle — damping=18 gives gentle bounce
          const spr = spring({
            frame: frame - startTime,
            fps: 30,
            from: -240,
            to: 0,
            config: { damping: 18, stiffness: 200, mass: 1 },
          });
          y = spr;
        } else if (frame >= exitStart) {
          phase = 'exit';
          // Ease-in acceleration downward — no bounce on exit
          const t = interpolate(frame, [exitStart, exitEnd], [0, 1], {extrapolateLeft: 'clamp', extrapolateRight: 'clamp'});
          y = interpolate(Easing.in(Easing.cubic)(t), [0, 1], [0, 900]);
        }

        // --- main opacity ---
        let mainOpacity = 1;
        if (phase === 'enter') {
          mainOpacity = interpolate(frame, [startTime, startTime + 4], [0.15, 1], {extrapolateLeft: 'clamp', extrapolateRight: 'clamp'});
        } else if (phase === 'exit') {
          mainOpacity = interpolate(frame, [exitStart, exitEnd], [1, 0], {extrapolateLeft: 'clamp', extrapolateRight: 'clamp'});
        }

        // Motion blur: speed → blur radius + scaleY stretch
        // Enter: fast at start (blur=12px), decelerates to 0 (no blur at bounce)
        // Exit: accelerates from 0 to fast (blur=14px at bottom)
        let blurPx = 0;
        let stretchY = 1;
        if (phase === 'enter') {
          const speed = interpolate(frame, [startTime, startTime + ENTER_FRAMES * 0.55], [1, 0], {extrapolateLeft: 'clamp', extrapolateRight: 'clamp'});
          blurPx = speed * 12;
          stretchY = 1 + speed * 0.25;
        } else if (phase === 'exit') {
          const speed = interpolate(frame, [exitStart, exitEnd], [0, 1], {extrapolateLeft: 'clamp', extrapolateRight: 'clamp'});
          blurPx = speed * 14;
          stretchY = 1 + speed * 0.3;
        }

        const centerY = DESIGN_HEIGHT / 2;

        return (
          <div key={index} style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none' }}>
            <div style={{
              position: 'absolute',
              top: centerY,
              left: 0, right: 0,
              transform: `translateY(calc(-50% + ${y}px)) scaleY(${stretchY})`,
              opacity: mainOpacity,
              filter: blurPx > 0.3 ? `blur(${blurPx.toFixed(1)}px)` : 'none',
              willChange: 'transform, filter',
              ...textStyle,
            }}>
              {word}
            </div>
          </div>
        );
      })}
    </div>
  );
};

const ScrollVelocityMarquee = ({item}) => {
  const frame = useCurrentFrame();
  const { durationInFrames } = useVideoConfig();

  const props = item.props || {};
  const row1Text = props.row1Text || 'IT DOES NOT MATTER ✦ HOW SMALL THE STUDIO ✦ SO LONG';
  const row1Joiner = props.row1Joiner || '✦';
  const row2Text = props.row2Text || 'DO NOT • BLINK • AS YOU • KEEP SHOOTING';
  const row2Joiner = props.row2Joiner || '•';
  const fontFamily = props.fontFamily || 'Montserrat, sans-serif';
  const textColor = props.textColor || '#f3f2ff';
  const lineColor = props.lineColor || '#f3f2ff';
  const cruiseSpeed = props.cruiseSpeed !== undefined ? props.cruiseSpeed : 18;
  const easeFrames = props.easeFrames !== undefined ? props.easeFrames : 60;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  // Safe velocity integration to calculate position with ease-in and ease-out
  const getScrollPosition = (f, speed, ease, total) => {
    const E = Math.max(0, Math.min(ease, total / 2));
    const V = speed;
    const T = total;

    if (E === 0) return V * f;

    if (f <= E) {
      // Acceleration phase
      return 0.5 * V * (f * f) / E;
    } else if (f <= T - E) {
      // Cruise phase
      return 0.5 * V * E + V * (f - E);
    } else {
      // Deceleration phase
      const fp = f - (T - E);
      const posAtCruiseEnd = 0.5 * V * E + V * (T - 2 * E);
      return posAtCruiseEnd + (V * fp) - (0.5 * V * (fp * fp) / E);
    }
  };

  const pos = getScrollPosition(frame, cruiseSpeed, easeFrames, durationInFrames);

  // Generate long repeating text to ensure seamless looping without DOM measurements
  const getRepeatedText = (text, joiner) => {
    const separator = `\u00A0\u00A0\u00A0\u00A0${joiner}\u00A0\u00A0\u00A0\u00A0`;
    return Array(40).fill(text).join(separator);
  };

  const fullText1 = getRepeatedText(row1Text, row1Joiner);
  const fullText2 = getRepeatedText(row2Text, row2Joiner);

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: 'transparent',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center'
  };

  const marqueeContainerStyle = {
    width: '100%',
    borderTop: `2px solid ${lineColor}`,
    borderBottom: `2px solid ${lineColor}`,
    padding: '30px 0',
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
    overflow: 'hidden',
    position: 'relative',
    backgroundColor: 'transparent'
  };

  const rowStyle = {
    position: 'relative',
    height: '110px',
    width: '100%',
    overflow: 'visible'
  };

  const textStyle = {
    position: 'absolute',
    top: 0,
    left: '50%',
    whiteSpace: 'nowrap',
    fontFamily: fontFamily,
    fontSize: '100px',
    fontWeight: 700,
    lineHeight: '110px',
    color: textColor,
    textTransform: 'uppercase'
  };

  return (
    <div style={rootStyle}>
      <div style={marqueeContainerStyle}>
        <div style={rowStyle}>
          <div style={{
            ...textStyle,
            transform: `translateX(calc(-50% + ${pos}px))`
          }}>
            {fullText1}
          </div>
        </div>
        <div style={rowStyle}>
          <div style={{
            ...textStyle,
            transform: `translateX(calc(-50% - ${pos}px))`
          }}>
            {fullText2}
          </div>
        </div>
      </div>
    </div>
  );
};

const TakeawayOverlayBaked = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const titleText = "Takeaway";
  const bodyText = "Grow your listener base — don't rely on playlists alone";
  const accentColor = "#ffffff";
  const textColor = "#ffffff";
  const titleFontFamily = "Inter";
  const bodyFontFamily = "Inter";
  const transparentBackground = true;

  const DESIGN_WIDTH = 1200;
  const DESIGN_HEIGHT = 300;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const TITLE_IN_START = 0;
  const TITLE_IN_END   = 20;
  const LINE_START     = 18;
  const LINE_END       = 58;
  const LINE_MAX_W     = 270;  // 与标题文字等宽
  const BODY_START     = 34;
  const LETTER_STAGGER = 0.9;
  const LETTER_DUR     = 7;
  const FADE_OUT_START = durationInFrames - 18;
  const FADE_OUT_END   = durationInFrames - 2;

  const globalOpacity = interpolate(
    frame,
    [Math.max(0, FADE_OUT_START), Math.max(1, FADE_OUT_END)],
    [1, 0],
    { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );

  const titleProgress = interpolate(frame, [TITLE_IN_START, TITLE_IN_END], [0, 1], {
    easing: Easing.bezier(0.25, 1, 0.5, 1),
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const titleOpacity = titleProgress;
  const titleBlur    = interpolate(titleProgress, [0, 1], [14, 0]);
  const tg = titleProgress;
  const titleShadow = [
    `0 0 4px rgba(255,255,255,${0.95*tg})`,
    `0 0 12px rgba(255,255,255,${0.8*tg})`,
    `0 0 28px rgba(255,255,255,${0.55*tg})`,
    `0 0 56px rgba(255,255,255,${0.3*tg})`,
  ].join(',');

  const lineProgress = interpolate(frame, [LINE_START, LINE_END], [0, 1], {
    easing: Easing.bezier(0.16, 1, 0.3, 1),
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const lineW = lineProgress * LINE_MAX_W;
  const lineGlowPeak = interpolate(frame, [LINE_START, LINE_END, LINE_END + 15], [0, 1, 0.65], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const lineVisible = frame >= LINE_START;

  const svgH = 44;
  const cy = svgH / 2;

  // 左端宽（两点），右端尖（一点）
  const triPoints = (w, hL) => {
    if (w <= 0) return `0,${cy} 0,${cy} 0,${cy}`;
    return `0,${cy - hL} ${w},${cy} 0,${cy + hL}`;
  };

  const hexToRgb = (hex) => {
    const h = (hex || '#874cff').replace('#', '');
    return {
      r: parseInt(h.slice(0,2),16),
      g: parseInt(h.slice(2,4),16),
      b: parseInt(h.slice(4,6),16)
    };
  };
  const {r, g: gc, b} = hexToRgb(accentColor);
  const ac = `${r},${gc},${b}`;

  const rawWords = (bodyText || '').split(' ');

  const rootStyle = {
    position: 'absolute',
    top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: transparentBackground ? 'transparent' : 'rgba(10,10,18,0.82)',
    padding: '36px 48px',
    boxSizing: 'border-box',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'flex-start',
    alignItems: 'flex-start',
    opacity: globalOpacity,
  };

  const titleStyle = {
    fontFamily: titleFontFamily, fontSize: 52, fontWeight: 700,
    color: textColor, margin: 0, letterSpacing: '0.01em',
    lineHeight: 1.15, whiteSpace: 'nowrap',
    opacity: titleOpacity,
    filter: `blur(${titleBlur}px)`,
    textShadow: titleShadow,
  };

  const lineSvgWrap = {
    marginTop: 4,
    marginBottom: 8,
    flexShrink: 0,
    opacity: lineVisible ? 1 : 0,
    display: 'block',
    overflow: 'visible',
  };

  const bodyContainerStyle = { position: 'relative', width: '100%', lineHeight: 1.55 };

  let letterIdx = 0;
  const wordNodes = rawWords.map((word, wi) => {
    const wordLetters = word.split('').map(ch => {
      const gi = letterIdx++;
      const start = BODY_START + gi * LETTER_STAGGER;
      const end   = start + LETTER_DUR;
      const lp = interpolate(frame, [start, end], [0, 1], {
        easing: Easing.bezier(0.22, 1, 0.36, 1),
        extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
      });
      const lY    = interpolate(lp, [0, 1], [-9, 0]);
      const lBlur = interpolate(lp, [0, 1], [3, 0]);
      const g = lp;
      const ls = [
        `0 0 3px rgba(255,255,255,${0.98*g})`,
        `0 0 9px rgba(255,255,255,${0.85*g})`,
        `0 0 20px rgba(255,255,255,${0.65*g})`,
        `0 0 40px rgba(255,255,255,${0.38*g})`,
        `0 0 72px rgba(255,255,255,${0.18*g})`,
      ].join(',');
      return (
        <span key={gi} style={{
          display: 'inline-block', opacity: lp,
          transform: `translateY(${lY}px)`, verticalAlign: 'baseline',
          fontFamily: bodyFontFamily, fontSize: 34, fontWeight: 300,
          color: textColor, filter: `blur(${lBlur}px)`,
          textShadow: ls, whiteSpace: 'pre',
        }}>{ch}</span>
      );
    });
    let spaceNode = null;
    if (wi < rawWords.length - 1) {
      const si = letterIdx++;
      const sp = interpolate(frame,
        [BODY_START+si*LETTER_STAGGER, BODY_START+si*LETTER_STAGGER+LETTER_DUR],
        [0,1], {extrapolateLeft:'clamp',extrapolateRight:'clamp'});
      spaceNode = <span key={'sp-'+wi} style={{display:'inline-block',width:'0.28em',opacity:sp}} />;
    }
    return (
      <span key={'w-'+wi} style={{display:'inline-block',whiteSpace:'nowrap'}}>
        {wordLetters}{spaceNode}
      </span>
    );
  });

  return (
    <div style={rootStyle}>
      <div style={titleStyle}>{titleText}</div>

      <svg
        width={LINE_MAX_W}
        height={svgH}
        viewBox={`0 0 ${LINE_MAX_W} ${svgH}`}
        style={lineSvgWrap}
        overflow="visible"
      >
        <polygon
          points={triPoints(lineW, 18)}
          fill={`rgba(${ac},${0.45 * lineGlowPeak})`}
          style={{filter: 'blur(8px)'}}
        />
        <polygon
          points={triPoints(lineW, 10)}
          fill={`rgba(${ac},${0.7 * lineGlowPeak})`}
          style={{filter: 'blur(3px)'}}
        />
        <polygon
          points={triPoints(lineW, 2.5)}
          fill={`rgba(${ac},0.95)`}
        />
        <polygon
          points={triPoints(lineW, 0.8)}
          fill={`rgba(255,255,255,${0.85 * lineProgress})`}
        />
      </svg>

      <div style={bodyContainerStyle}>
        <div style={{position:'relative',width:'100%',lineHeight:1.55,color:textColor}}>
          {wordNodes}
        </div>
      </div>
    </div>
  );
};

const createTickerRow = (options) => {
    const { top, delay, direction, opacity, fontSize, repeatText, mainFont, frame, fps } = options;
    const flyIn = spring({ frame: Math.max(0, frame - delay), fps, config: { damping: 15 } });
    const offsetX = interpolate(flyIn, [0, 1], [direction * 1500, 0]);
    const rowStyle = { position: 'absolute', top, left: -500, width: 4000, display: 'flex', gap: '50px', transform: `translateX(${offsetX}px)`, opacity };
    const textStyle = { fontSize, fontWeight: 900, fontStyle: 'italic', whiteSpace: 'nowrap', color: 'white', fontFamily: mainFont, textTransform: 'uppercase' };
    const elements = Array(15).fill(0).map((_, i) => (<span key={i} style={textStyle}>{repeatText}</span>));
    return <div style={rowStyle}>{elements}</div>;
};

const createScatteredText = (options) => {
    const { delay, top, left, fontSize, opacity, startX, outline, repeatText, mainFont, frame, fps } = options;
    const flyIn = spring({ frame: Math.max(0, frame - delay), fps, config: { damping: 16, stiffness: 120 } });
    const xOffset = interpolate(flyIn, [0, 1], [startX, 0]);
    const style = { position: 'absolute', top, left, transform: `translateX(${xOffset}px)`, fontSize, fontWeight: 900, fontStyle: 'italic', opacity, whiteSpace: 'nowrap', textTransform: 'uppercase', fontFamily: mainFont, color: outline ? 'transparent' : 'white', WebkitTextStroke: outline ? '3px white' : 'none' };
    return <div style={style}>{repeatText}</div>;
};

const createRotatedContent = (options) => {
    const { backgroundColor, transparentBackground, repeatText, mainFont, frame, fps } = options;
    const gridStyle = { position: 'absolute', inset: 0, backgroundImage: `linear-gradient(to right, rgba(255,255,255,0.08) 2px, transparent 2px), linear-gradient(to bottom, rgba(255,255,255,0.08) 2px, transparent 2px)`, backgroundSize: '120px 120px' };
