                {createTickerRow({ top: 1600, delay: 15, direction: -1, opacity: 0.12, fontSize: 100, repeatText, mainFont, frame, fps })}
                {createScatteredText({ delay: 10, top: 400, left: 100, fontSize: 350, opacity: 0.03, startX: 1000, outline: false, repeatText, mainFont, frame, fps })}
                {createScatteredText({ delay: 12, top: 1100, left: 700, fontSize: 400, opacity: 0.02, startX: -1500, outline: false, repeatText, mainFont, frame, fps })}
                {createScatteredText({ delay: 14, top: 800, left: 200, fontSize: 150, opacity: 0.08, startX: -800, outline: false, repeatText, mainFont, frame, fps })}
                {createScatteredText({ delay: 16, top: 1000, left: 1500, fontSize: 180, opacity: 0.06, startX: 800, outline: false, repeatText, mainFont, frame, fps })}
                {createScatteredText({ delay: 18, top: 350, left: 1600, fontSize: 120, opacity: 0.1, startX: -500, outline: false, repeatText, mainFont, frame, fps })}
                {createScatteredText({ delay: 20, top: 1400, left: 300, fontSize: 160, opacity: 0.05, startX: 1000, outline: false, repeatText, mainFont, frame, fps })}
                {createScatteredText({ delay: 22, top: 850, left: 1700, fontSize: 200, opacity: 0.15, startX: 1200, outline: true, repeatText, mainFont, frame, fps })}
                {createScatteredText({ delay: 17, top: 650, left: 1150, fontSize: 60, opacity: 0.8, startX: 800, outline: false, repeatText, mainFont, frame, fps })}
                {createScatteredText({ delay: 19, top: 1300, left: 1050, fontSize: 60, opacity: 0.8, startX: -800, outline: false, repeatText, mainFont, frame, fps })}
