const createWipeCol = (options) => {
    const { left, delay, origin, width, backgroundColor, transparentBackground, repeatText, mainFont, frame, fps } = options;
    const progress = spring({ frame: Math.max(0, frame - delay), fps, config: { damping: 20 } });
