const createTitleLayer = (options) => {
    const { delay, isTrail, color, mainFont, titleText, frame, fps } = options;
    const localFrame = Math.max(0, frame - delay);
    if (frame < delay) return null;
    const scaleX = spring({ frame: localFrame, fps, config: { damping: 15, stiffness: 220 } });
    const scaleY = spring({ frame: localFrame, fps, config: { damping: 15, stiffness: 180 } });
    const translateY = interpolate(scaleY, [0, 1], [300, 0]);
    const opacity = isTrail ? interpolate(localFrame, [0, 20], [0.6, 0], { extrapolateRight: 'clamp' }) : 1;
    const shadowColor = '#260022';
    const shadow = isTrail ? 'none' : `2px 2px 0 ${shadowColor}, 4px 4px 0 ${shadowColor}, 6px 6px 0 ${shadowColor}, 8px 8px 0 ${shadowColor}, 10px 10px 0 ${shadowColor}, 12px 12px 0 ${shadowColor}, 14px 14px 0 ${shadowColor}, 16px 16px 0 ${shadowColor}`;
    const style = { position: 'absolute', transform: `translateY(${translateY}px) rotate(-8deg) scaleX(${scaleX}) scaleY(${scaleY})`, opacity, display: 'flex', flexDirection: 'column', alignItems: 'center', fontFamily: mainFont, fontWeight: 900, fontStyle: 'italic', textTransform: 'uppercase', lineHeight: 0.85, color, textShadow: shadow, fontSize: 220, textAlign: 'center', zIndex: isTrail ? 1 : 10 };
    const lines = titleText.split('\n').map((line, i) => (<span key={i} style={{ display: 'block' }}>{line}</span>));
    return <div style={style}>{lines}</div>;
};

const VibeEffectsOpener = ({ item }) => {
    const frame = useCurrentFrame();
