        const f = frame - (EXIT_START + colDelay);
        if (f <= 0) return 1;
        if (f >= EXIT_DUR) return 0;
        return 1 - easeInExpo(f / EXIT_DUR);
    };

    const col0Scale = colScale(0);
    const col1Scale = colScale(4);
    const col2Scale = colScale(8);

    const titleExitOpacity = interpolate(frame, [EXIT_START, EXIT_START + 8], [1, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

    const rootStyle = { position: 'absolute', top: 0, left: 0, width: DESIGN_WIDTH, height: DESIGN_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'top left', backgroundColor: 'transparent', overflow: 'hidden' };

    const renderCol = (left, colWidth, origin, scaleY) => {
        const wrapStyle = { position: 'absolute', left, top: 0, width: colWidth, height: 1080, transformOrigin: origin, transform: `scaleY(${scaleY})`, overflow: 'hidden' };
        const innerStyle = { position: 'absolute', left: -left, top: 0, width: 1920, height: 1080 };
