                        {createWipeCol({ left: 640, delay: 4, origin: 'bottom', width: 641, backgroundColor, transparentBackground, repeatText, mainFont, frame, fps })}
                        {createWipeCol({ left: 1280, delay: 8, origin: 'top', width: 640, backgroundColor, transparentBackground, repeatText, mainFont, frame, fps })}
                    </>
                ) : (
                    <>
                        {renderCol(0, 641, 'top', col0Scale)}
                        {renderCol(640, 641, 'bottom', col1Scale)}
                        {renderCol(1280, 640, 'top', col2Scale)}
                    </>
                )}
            </div>
            <div style={{ position: 'absolute', inset: 0, display: 'flex', justifyContent: 'center', alignItems: 'center', opacity: titleExitOpacity }}>
