                {createTitleLayer({ delay: 32, isTrail: true, color: accentColor, mainFont, titleText, frame, fps })}
                {createTitleLayer({ delay: 30, isTrail: false, color: '#FFFFFF', mainFont, titleText, frame, fps })}
