  // Props
  const props = item.props || {};
  const titleText = props.titleText || 'NEW EPISODE';
  const subtitleText = props.subtitleText || 'STREAMING ON SPOTIFY';
  const marqueeText = props.marqueeText || 'NEW EPISODE DROPPED •';
  const accentColor = props.accentColor || '#ff69b4';
  const primaryColor = props.primaryColor || '#000000';
  const backgroundColor = props.backgroundColor || '#FFFFFF';
  const fontFamily = props.fontFamily || '"Press Start 2P", cursive';

  // Dimensions
  const DESIGN_WIDTH = 820;
  const DESIGN_HEIGHT = 220;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // Card Spec
  const CARD_WIDTH = 700;
  const CARD_HEIGHT = 160;
  const BORDER_WIDTH = 2;

  // Animation: Entrance Spring (Bouncier)
  const entrance = spring({
    frame,
    fps,
    config: { damping: 12, stiffness: 120, mass: 1.2 }
  });

  // Entrance Y: start below canvas, end at center
  // Centering Y: (220 - 160) / 2 = 30px from top. 
  // But we have shadow offsets (+12px), so we shift slightly up to optical center.
  const targetY = 20; 
  const startY = 300;
  const currentY = interpolate(entrance, [0, 1], [startY, targetY]);

  // Animation: Text Reveal (After card lands)
  const textOpacity = interpolate(frame, [15, 25], [0, 1], { extrapolateRight: 'clamp' });
  const textY = interpolate(frame, [15, 25], [10, 0], { extrapolateRight: 'clamp' });

  // Animation: Marquee Scroll
  // Continuous scroll right-to-left
  const scrollSpeed = 2;
  const scrollOffset = (frame * scrollSpeed);

  // Animation: Pulse Line
  const pulse = (Math.sin(frame / 5) + 1) / 2; // 0 to 1 oscillating
  const pulseOpacity = interpolate(pulse, [0, 1], [0.3, 1]);

  // Styles
  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    display: 'flex',
    justifyContent: 'center',
    fontFamily: fontFamily,
    backgroundColor: 'transparent',
  };

  const wrapperStyle = {
    position: 'relative',
    width: CARD_WIDTH,
    height: CARD_HEIGHT,
    marginTop: currentY, // Animate position
  };

  const commonCardStyle = {
    position: 'absolute',
    width: '100%',
    height: '100%',
    border: `${BORDER_WIDTH}px solid ${primaryColor}`,
    backgroundColor: backgroundColor,
    boxSizing: 'border-box',
  };

  // Offset shadows
  const shadow2Style = {
    ...commonCardStyle,
    top: 12,
    left: 12,
    zIndex: 0,
  };

  const shadow1Style = {
    ...commonCardStyle,
    top: 6,
    left: 6,
    zIndex: 1,
  };

  // Main content card
  const mainCardStyle = {
    ...commonCardStyle,
    top: 0,
    left: 0,
    zIndex: 2,
    display: 'flex',
    flexDirection: 'column',
    overflow: 'hidden',
  };

  // Pink Header
  const headerStyle = {
    height: 24,
    backgroundColor: accentColor,
    borderBottom: `${BORDER_WIDTH}px solid ${primaryColor}`,
    display: 'flex',
    alignItems: 'center',
    overflow: 'hidden',
    whiteSpace: 'nowrap',
  };

  const marqueeTextStyle = {
    color: '#FFFFFF',
    fontSize: 10,
    fontWeight: 'bold',
    paddingLeft: 10,
    transform: `translateX(-${scrollOffset}px)`,
    display: 'inline-block',
  };

  // Body Content
  const bodyStyle = {
    flex: 1,
    padding: '20px 24px',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    opacity: textOpacity,
    transform: `translateY(${textY}px)`,
  };

  const titleStyle = {
    fontSize: 22,
    color: primaryColor,
    lineHeight: 1.2,
    marginBottom: 8,
    textTransform: 'uppercase',
  };

  const subtitleStyle = {
    fontSize: 12,
    color: '#666666',
    marginBottom: 16,
    textTransform: 'uppercase',
  };

  const pulseLineStyle = {
    width: 60,
    height: 4,
    backgroundColor: accentColor,
    opacity: pulseOpacity,
  };

  // Helper to repeat text for marquee
  const repeatedMarquee = Array(40).fill(marqueeText).join(' ');

  return (
    <div style={rootStyle}>
      <div style={wrapperStyle}>
        <div style={shadow2Style} />
        <div style={shadow1Style} />
        <div style={mainCardStyle}>
          <div style={headerStyle}>
            <div style={marqueeTextStyle}>
              {repeatedMarquee}
            </div>
          </div>
          <div style={bodyStyle}>
            <div style={titleStyle}>{titleText}</div>
            <div style={subtitleStyle}>{subtitleText}</div>
            <div style={pulseLineStyle} />
          </div>
        </div>
      </div>
    </div>
  );
};

