const Component = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const mainTitle = props.mainTitle || 'STREET FOOD STORIES';
  const titleFontFamily = props.titleFontFamily || 'Montserrat, sans-serif';
  const textColor = props.textColor || '#e9f5ff';

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const safeFps = fps || 30;
  const safeDuration = durationInFrames || 150;
  const exitStart = Math.max(40, safeDuration - 30);

  const textFadeOut = interpolate(frame, [exitStart - 15, exitStart], [1, 0], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp'
  });

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: 'transparent',
    overflow: 'hidden'
  };

  const textContainerStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: '100%',
    height: '100%',
    display: 'flex',
    flexDirection: 'row',
    justifyContent: 'center',
    alignItems: 'center',
    alignContent: 'center',
    flexWrap: 'wrap',
    opacity: textFadeOut,
    fontFamily: titleFontFamily,
    fontSize: '125px',
    fontWeight: 800,
    textTransform: 'uppercase',
    padding: '0 100px',
    boxSizing: 'border-box'
  };

  const words = mainTitle.split(' ');
  let charGlobalIndex = 0;

  const wordElements = words.map((word, wIdx) => {
    const chars = word.split('');
    const charElements = chars.map((char, cIdx) => {
      const charDelay = 25 + charGlobalIndex * 2;
      charGlobalIndex++;
      const charProgress = spring({
        frame: Math.max(0, frame - charDelay),
        fps: safeFps,
        config: { damping: 14, mass: 0.6 }
      });
      const charY = interpolate(charProgress, [0, 1], [50, 0]);
      const charOpacity = interpolate(charProgress, [0, 1], [0, 1]);
      const charBlur = interpolate(charProgress, [0, 1], [10, 0], { extrapolateRight: 'clamp' });

      const style = {
        display: 'inline-block',
        color: textColor,
        opacity: charOpacity,
        transform: `translateY(${charY}px)`,
        filter: `blur(${charBlur}px)`,
        margin: '0 2px'
      };

      return { char, style, key: `char-${wIdx}-${cIdx}` };
    });

    charGlobalIndex++;

    const wordStyle = {
      display: 'inline-block',
      whiteSpace: 'nowrap',
      marginRight: wIdx < words.length - 1 ? '30px' : '0px',
      marginTop: '15px',
      marginBottom: '15px'
    };

    return { charElements, style: wordStyle, key: `word-${wIdx}` };
  });

  return (
    <div style={rootStyle}>
      <div style={textContainerStyle}>
        {wordElements.map(wordObj => (
          <div key={wordObj.key} style={wordObj.style}>
            {wordObj.charElements.map(charObj => (
              <span key={charObj.key} style={charObj.style}>{charObj.char}</span>
            ))}
          </div>
        ))}
      </div>
    </div>
  );
};

const CinematicTitleCard = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const mainTitle = props.mainTitle || 'PIXEL FOUNDRY';
  const subtitleText = props.subtitleText || 'FOR YOUR NEXT GAME';
  const textColor = props.textColor || '#eff3ff';
  const fontFamily = props.fontFamily || 'Montserrat, sans-serif';

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const safeFps = fps || 30;
  const d = durationInFrames || 150;
  const exitStart = Math.max(0, d - 30);

  const titleSpring = spring({
    frame,
    fps: safeFps,
    config: { damping: 15, mass: 1, stiffness: 80 }
  });
  const titleYEntrance = interpolate(titleSpring, [0, 1], [50, 0]);
  const titleYExit = interpolate(frame, [exitStart, exitStart + 20], [0, -50], { 
    easing: Easing.inOut(Easing.ease), 
    extrapolateLeft: 'clamp', 
    extrapolateRight: 'clamp' 
  });
  const titleY = frame < exitStart ? titleYEntrance : titleYExit;

  const titleOpacityEntrance = interpolate(frame, [0, 20], [0, 1], { extrapolateRight: 'clamp' });
  const titleOpacityExit = interpolate(frame, [exitStart, exitStart + 20], [1, 0], { 
    extrapolateLeft: 'clamp', 
    extrapolateRight: 'clamp' 
  });
  const titleOpacity = frame < exitStart ? titleOpacityEntrance : titleOpacityExit;

  const lineSpring = spring({
    frame: Math.max(0, frame - 15),
    fps: safeFps,
    config: { damping: 18, mass: 0.8 }
  });
  const lineScaleXExit = interpolate(frame, [exitStart, exitStart + 20], [1, 0], { 
    easing: Easing.inOut(Easing.ease), 
    extrapolateLeft: 'clamp', 
    extrapolateRight: 'clamp' 
  });
  const lineScaleX = frame < exitStart ? lineSpring : lineScaleXExit;

  const subYExit = interpolate(frame, [exitStart, exitStart + 20], [0, 50], { 
    easing: Easing.inOut(Easing.ease), 
    extrapolateLeft: 'clamp', 
    extrapolateRight: 'clamp' 
  });
  const subY = frame < exitStart ? 0 : subYExit;

  const subGroupOpacityExit = interpolate(frame, [exitStart, exitStart + 20], [1, 0], { 
    extrapolateLeft: 'clamp', 
    extrapolateRight: 'clamp' 
  });
  const subGroupOpacity = frame < exitStart ? 1 : subGroupOpacityExit;

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: 'transparent',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    overflow: 'hidden'
  };

  const titleStyle = {
    fontFamily,
    fontWeight: 800,
    fontSize: '110px',
    color: textColor,
    margin: 0,
    padding: 0,
    transform: `translateY(${titleY}px)`,
    opacity: titleOpacity,
    textAlign: 'center',
    letterSpacing: '0.05em'
  };

  const lineStyle = {
    width: '960px',
    height: '2px',
    backgroundColor: textColor,
    margin: '40px 0',
    transform: `scaleX(${lineScaleX})`,
    transformOrigin: 'center'
  };

  const subWrapperStyle = {
    transform: `translateY(${subY}px)`,
    opacity: subGroupOpacity,
    textAlign: 'center'
  };

  const charStyle = {
    fontFamily,
    fontWeight: 400,
    fontSize: '44px',
    color: textColor,
    letterSpacing: '0.15em',
    textTransform: 'uppercase',
  };

  return (
    <div style={rootStyle}>
      <h1 style={titleStyle}>{mainTitle}</h1>
      <div style={lineStyle} />
      <div style={subWrapperStyle}>
        {subtitleText.split('').map((char, i) => {
          const charOpacity = frame < exitStart
            ? interpolate(frame, [25 + i * 2, 25 + i * 2 + 5], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
            : 1;
          return (
            <span key={i} style={{ ...charStyle, opacity: charOpacity, whiteSpace: 'pre' }}>
              {char}
            </span>
          );
        })}
      </div>
    </div>
  );
};

