const Component = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
  const safeFps = fps || 30;

  const props = item.props || {};
  const startNumber = parseInt(props.startNumber || '10', 10);
  const endNumber = parseInt(props.endNumber || '1', 10);
  const tickerText = props.tickerText || 'LAUNCHING IN';
  const subText = props.subText || 'UNTIL LIVE';

  const accentColor = props.accentColor || '#86b000';
  const bgColor = props.bgColor || '#FFFFFF';
  const textColor = props.textColor || '#000000';
  const headerTextColor = props.headerTextColor || '#FFFFFF';

  const numberFont = props.numberFont || '"VT323", monospace';
  const textFont = props.textFont || '"Silkscreen", cursive';

  const DESIGN_WIDTH = 480;
  const DESIGN_HEIGHT = 220;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const safeSpring = (delay = 0, config = { damping: 15 }) => {
    return spring({ frame: Math.max(0, frame - delay), fps: safeFps, config });
  };

  // Animations
  const bounceScale = safeSpring(0, { damping: 12, stiffness: 120 });

  // Countdown logic: starts 1 second (safeFps frames) after bounce begins
  const countdownStartFrame = safeFps;
  const elapsedFrames = Math.max(0, frame - countdownStartFrame);
  const secondsPassed = Math.floor(elapsedFrames / safeFps);
  const currentNumber = startNumber - secondsPassed;
  const displayNum = Math.max(endNumber, Math.min(startNumber, currentNumber));

  // Ticker logic
  const tickerX = -(frame * 1.5);
  const repeatedTickerText = React.useMemo(() => {
    return new Array(100).fill(tickerText).join(' • ');
  }, [tickerText]);

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: 'transparent',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center'
  };

  const cardStyle = {
    width: 260,
    height: 150,
    backgroundColor: bgColor,
    border: '2px solid #000',
    boxShadow: '4px 4px 0px #000, 8px 8px 0px rgba(0,0,0,0.2)',
    display: 'flex',
    flexDirection: 'column',
    transform: `scale(${bounceScale})`,
    boxSizing: 'border-box'
  };

  const headerStyle = {
    height: 24,
    backgroundColor: accentColor,
    borderBottom: '2px solid #000',
    display: 'flex',
    alignItems: 'center',
    overflow: 'hidden',
    whiteSpace: 'nowrap',
    boxSizing: 'border-box',
    position: 'relative'
  };

  const tickerStyle = {
    fontFamily: textFont,
    fontSize: 10,
    color: headerTextColor,
    transform: `translateX(${tickerX}px)`,
    letterSpacing: 1,
    paddingLeft: 10
  };

  const bodyStyle = {
    flex: 1,
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    position: 'relative',
    overflow: 'hidden'
  };

  const numberStyle = {
    fontFamily: numberFont,
    fontSize: 80,
    lineHeight: 1,
    color: textColor,
    margin: 0,
    marginTop: 10,
    textShadow: '2px 2px 0px rgba(0,0,0,0.1)'
  };

  const subTextStyle = {
    fontFamily: textFont,
    fontSize: 11,
    color: textColor,
    marginTop: 4,
    letterSpacing: 1,
    textTransform: 'uppercase'
  };

  return (
    <div style={rootStyle}>
      <div style={cardStyle}>
        <div style={headerStyle}>
          <div style={tickerStyle}>
            {repeatedTickerText}
          </div>
        </div>
