          <div style={numberStyle}>{displayNum}</div>
          <div style={subTextStyle}>{subText}</div>
        </div>
      </div>
    </div>
  );
};

const DialChapterCard = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const props = item.props || {};
  const mainTitle = props.mainTitle || 'Spend smarter, not just faster';
  const subtitle = props.subtitle || 'Groceries · Transit · Coffee · Rent · Travel';
  const emoji = props.emoji || '🍎';
  const themeColor = props.themeColor || '#a65246';
  const bgColor = props.bgColor || '#F5F0E8';
  const trackColor = props.trackColor || '#cc9161';
  const prevEmoji = props.prevEmoji || '🍌';
  const prevTitle = props.prevTitle || 'Groceries';
  const nextEmoji = props.nextEmoji || '🍓';
  const nextTitle = props.nextTitle || 'Coffee';

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  // ── Easing helpers ──────────────────────────────────────────────
  const easeOutExpo  = (t) => t === 1 ? 1 : 1 - Math.pow(2, -10 * t);
  const easeOutQuart = (t) => 1 - Math.pow(1 - t, 4);
  const easeInOutCubic = (t) => t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
  const easeInCubic  = (t) => t * t * t;

  // Clamps frame into a 0→1 progress over [startF, endF]
  const progress = (startF, endF, ease = (t) => t) => {
    const t = Math.min(1, Math.max(0, (frame - startF) / (endF - startF)));
    return ease(t);
  };

  // ── Timeline (all in frames) ────────────────────────────────────
  const F = fps;
  // Card entrance: slides up from bottom over 18 frames
  const entranceEnd   = Math.round(F * 0.6);
  // Banana label: fades in from frame 0, done by frame 14
  const prevTextEnd   = Math.round(F * 0.47);
  // Dial roll: starts at frame 18, settles by frame 60 (2s)
  const rollStart     = Math.round(F * 0.6);
  const rollEnd       = Math.round(F * 2.2);
  // Apple text: starts right as roll is settling
  const appleTextStart = Math.round(F * 1.7);
  const appleTextEnd   = Math.round(F * 2.4);
  // Strawberry text: follows apple closely
  const nextTextStart  = Math.round(F * 2.0);
  const nextTextEnd    = Math.round(F * 2.6);
  // Exit
  const exitStart     = Math.round(F * 6.5);
  const exitEnd       = Math.round(F * 8.0);

  // ── Animation values ────────────────────────────────────────────
  const entranceP   = progress(0, entranceEnd, easeOutExpo);
  const rollP       = progress(rollStart, rollEnd, easeInOutCubic);
  const exitP       = progress(exitStart, exitEnd, easeInCubic);

  // Card slide-up entrance + exit — start fully off-screen below
  const globalY = interpolate(entranceP, [0, 1], [DESIGN_HEIGHT, 0])
                - exitP * DESIGN_HEIGHT;

  // Dial offset: starts at NODE_SPACING (nodes offset down), rolls to 0
  const NODE_SPACING = 430;
  const rollOffset = interpolate(rollP, [0, 1], [NODE_SPACING, 0]);

  // Apple (center) text
  const appleP = progress(appleTextStart, appleTextEnd, easeOutQuart);
  const textOpacity = appleP;
  const textSlideY  = interpolate(appleP, [0, 1], [40, 0]);

  // Banana (prev) text: fades in early with card entrance
  const prevFadeP   = progress(0, prevTextEnd, easeOutQuart);
  // After roll completes, banana dims and shrinks
  const prevDimP    = rollP; // 0→1 as roll progresses
  const prevTextOpacity = prevFadeP * interpolate(prevDimP, [0, 1], [1, 1.0]);
  const prevTextSlideX  = interpolate(prevFadeP, [0, 1], [-28, 0]);
  const prevTextScale   = interpolate(prevDimP, [0, 1], [1, 0.70]);

  // Strawberry (next) text — easeOutQuart, clean 0→1
  const nextP = progress(nextTextStart, nextTextEnd, easeOutQuart);
  const nextTextOpacity = nextP;
  const nextTextSlideX  = interpolate(nextP, [0, 1], [-28, 0]);

  // ── Arc geometry ────────────────────────────────────────────────
  const arcRadius  = 900;
  const arcCenterX = 310 - arcRadius;
  const arcCenterY = DESIGN_HEIGHT / 2;
  const nodeScreenX = 310;
  const nodeSize   = 180;
  const r          = nodeSize / 2;

  const yToTheta = (screenY) => Math.atan2(screenY - arcCenterY, nodeScreenX - arcCenterX);

  const centerNodeY = DESIGN_HEIGHT / 2;
  const prevNodeY   = centerNodeY - NODE_SPACING;
  const nextNodeY   = centerNodeY + NODE_SPACING;

  const getNodePos = (baseY) => {
    const screenY = baseY + rollOffset;
    const theta = yToTheta(screenY);
    return {
      x: arcCenterX + arcRadius * Math.cos(theta),
      y: arcCenterY + arcRadius * Math.sin(theta),
      screenY,
    };
  };

  const prev   = getNodePos(prevNodeY);
  const center = getNodePos(centerNodeY);
  const next   = getNodePos(nextNodeY);

  // Arc path
  const tTop   = yToTheta(-NODE_SPACING);
  const tBot   = yToTheta(DESIGN_HEIGHT + NODE_SPACING);
  const arcPath = [
    'M', arcCenterX + arcRadius * Math.cos(tTop), arcCenterY + arcRadius * Math.sin(tTop),
    'A', arcRadius, arcRadius, 0, 0, 1,
    arcCenterX + arcRadius * Math.cos(tBot), arcCenterY + arcRadius * Math.sin(tBot),
  ].join(' ');

  // Node fade near screen edges
  const edgeOpacity = (sy) => {
    if (sy < -r || sy > DESIGN_HEIGHT + r) return 0;
    return interpolate(sy, [-r, 80, DESIGN_HEIGHT - 80, DESIGN_HEIGHT + r], [0, 1, 1, 0], {
      extrapolateLeft: 'clamp', extrapolateRight: 'clamp',
    });
  };

  const labelGap = 160; // gap from circle edge to text — matches apple text offset

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      overflow: 'hidden',
      transform: `scale(${scale})`,
      transformOrigin: 'top left',
    }}>
      <div style={{
        position: 'absolute', width: '100%', height: '100%',
        transform: `translateY(${globalY}px)`,
        backgroundColor: bgColor,
        backgroundImage: `radial-gradient(${trackColor}35 1.5px, transparent 1.5px)`,
        backgroundSize: '32px 32px',
      }}>

        <svg
          width={DESIGN_WIDTH}
          height={DESIGN_HEIGHT}
          viewBox={`0 0 ${DESIGN_WIDTH} ${DESIGN_HEIGHT}`}
          style={{ position: 'absolute', top: 0, left: 0, overflow: 'hidden' }}
        >
          <defs>
            <clipPath id="cc">
              <rect x="0" y="0" width={DESIGN_WIDTH} height={DESIGN_HEIGHT} />
            </clipPath>
            <filter id="ns" x="-40%" y="-40%" width="180%" height="180%">
              <feDropShadow dx="0" dy="8" stdDeviation="14" floodColor="#00000030" />
            </filter>
          </defs>

          {/* ARC LINE */}
          <path
            d={arcPath}
            fill="none"
            stroke={trackColor}
            strokeWidth="3"
            opacity="0.7"
            clipPath="url(#cc)"
          />

          {/* PREV NODE — banana */}
          <circle cx={prev.x} cy={prev.y} r={r} fill={bgColor} opacity={edgeOpacity(prev.screenY)} />
          <circle cx={prev.x} cy={prev.y} r={r} fill={themeColor} opacity={edgeOpacity(prev.screenY) * 0.4} />
          <foreignObject x={prev.x - r} y={prev.y - r} width={nodeSize} height={nodeSize} opacity={edgeOpacity(prev.screenY)}>
            <div style={{ width: nodeSize, height: nodeSize, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '84px', lineHeight: 1 }}>{prevEmoji}</div>
          </foreignObject>

          {/* NEXT NODE — strawberry */}
          <circle cx={next.x} cy={next.y} r={r} fill={bgColor} opacity={edgeOpacity(next.screenY)} />
          <circle cx={next.x} cy={next.y} r={r} fill={themeColor} opacity={edgeOpacity(next.screenY) * 0.4} />
          <foreignObject x={next.x - r} y={next.y - r} width={nodeSize} height={nodeSize} opacity={edgeOpacity(next.screenY)}>
            <div style={{ width: nodeSize, height: nodeSize, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '84px', lineHeight: 1 }}>{nextEmoji}</div>
          </foreignObject>

          {/* CENTER NODE — apple, on top */}
          <circle cx={center.x} cy={center.y} r={r} fill={themeColor} filter="url(#ns)" />
          <foreignObject x={center.x - r} y={center.y - r} width={nodeSize} height={nodeSize}>
            <div style={{
              width: nodeSize, height: nodeSize,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: '84px', lineHeight: 1,
            }}>
              {emoji}
            </div>
          </foreignObject>
        </svg>

        {/* PREV (BANANA) LABEL — anchored to actual node x/y on the arc */}
        <div style={{
          position: 'absolute',
          left: prev.x + r + labelGap,
          top: prev.y,
          transform: `translateX(${prevTextSlideX}px) scale(${prevTextScale}) translateY(-50%)`,
          transformOrigin: 'left center',
          opacity: prevTextOpacity * edgeOpacity(prev.screenY),
          pointerEvents: 'none',
        }}>
          <span style={{
            fontFamily: 'Georgia, serif',
            fontSize: '52px',
            fontWeight: 'bold',
            color: themeColor,
            opacity: 0.6,
            letterSpacing: '-1px',
            lineHeight: 1,
            whiteSpace: 'nowrap',
            display: 'block',
          }}>{prevTitle}</span>
        </div>

        {/* NEXT (STRAWBERRY) LABEL — anchored to actual node x/y on the arc */}
        <div style={{
          position: 'absolute',
          left: next.x + r + labelGap,
          top: next.y,
          transform: `translateX(${nextTextSlideX}px) translateY(-50%)`,
          transformOrigin: 'left center',
          opacity: nextTextOpacity * edgeOpacity(next.screenY),
          pointerEvents: 'none',
        }}>
          <span style={{
            fontFamily: 'Georgia, serif',
            fontSize: '36px',
            fontWeight: 'bold',
            color: themeColor,
            opacity: 0.6,
            letterSpacing: '-1px',
            lineHeight: 1,
            whiteSpace: 'nowrap',
            display: 'block',
          }}>{nextTitle}</span>
        </div>

        {/* CENTER (APPLE) TEXT */}
        <div style={{
          position: 'absolute',
          left: 560, top: 0,
          width: DESIGN_WIDTH - 560 - 80,
          height: '100%',
          display: 'flex', flexDirection: 'column', justifyContent: 'center',
          opacity: textOpacity,
          transform: `translateY(${textSlideY}px)`,
        }}>
          <h1 style={{
            fontFamily: 'Georgia, serif',
            fontSize: '108px', fontWeight: 'bold',
            color: themeColor, lineHeight: 1.1,
            margin: 0, marginBottom: '32px', letterSpacing: '-2px',
          }}>
            {mainTitle}
          </h1>
          <p style={{
            fontFamily: 'Arial, sans-serif',
            fontSize: '34px', fontWeight: 600,
            color: themeColor, opacity: 0.75,
            textTransform: 'uppercase', letterSpacing: '3px',
            margin: 0,
          }}>
            {subtitle}
          </p>
        </div>

      </div>
    </div>
  );
};

