const MinimalTitleCard = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const titleLine1 = props.titleLine1;
  const titleLine2 = props.titleLine2;
  const subtitle = props.subtitle;
  const backgroundColor = props.backgroundColor;
  const textColor = props.textColor;
  const subtitleColor = props.subtitleColor;
  const transparentBackground = props.transparentBackground;
  const fontFamily = props.fontFamily;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const safeFps = fps || 30;

  // Gradient edge width (%) — black→transparent transition zone
  const EDGE = 8;
  // The gradient goes 135deg. For the mask to be fully hidden at start,
  // the transparent edge must be at or below 0%. So start offset = -(EDGE).
  // For fully revealed, the black trailing edge must be at or above 100%.
  // So end offset = 100 + EDGE. Range = 100 + 2*EDGE.
  const RANGE = 100 + 2 * EDGE;

  // easeOut cubic
  const easeOutCubic = (t) => 1 - Math.pow(1 - t, 3);
  // easeIn cubic
  const easeInCubic = (t) => Math.pow(t, 3);

  // --- Wipe IN: frames 0 → WIPE_IN_DURATION ---
  const WIPE_IN_DURATION = 60;
  const tIn = Math.min(1, Math.max(0, frame / WIPE_IN_DURATION));
  // offset goes from -EDGE (fully hidden) to 100+EDGE (fully revealed)
  const inOffset = easeOutCubic(tIn) * RANGE - EDGE;

  // --- Wipe OUT: same direction (left-top → right-bottom), continues past screen ---
  // At wipeOutProgress=0: offset at 100+EDGE (fully revealed, nothing masked)
  // At wipeOutProgress=1: offset at 100+EDGE + RANGE (trailing black edge past 100%, all hidden)
  const WIPE_OUT_DURATION = 45;
  const WIPE_OUT_START = durationInFrames - WIPE_OUT_DURATION;
  const tOut = Math.min(1, Math.max(0, (frame - WIPE_OUT_START) / WIPE_OUT_DURATION));
  // Wipe OUT mask: transparent sweeps left-top → right-bottom (same direction as in)
  // outOffset goes from -EDGE (fully visible) to 100+EDGE (fully hidden)
  const outMaskOffset = easeInCubic(tOut) * RANGE - EDGE;

  // Build combined mask:
  // During in-phase: black region sweeps in from left-top → right-bottom
  // During out-phase: transparent region sweeps out from left-top → right-bottom
  // We pick the appropriate gradient based on which phase is active
  let maskImage;
  if (tOut > 0) {
    // Out phase: transparent sweeps over, erasing content left-top → right-bottom
    maskImage = `linear-gradient(135deg, transparent ${outMaskOffset - EDGE}%, transparent ${outMaskOffset}%, black ${outMaskOffset + EDGE}%)`;
  } else {
    // In phase: black region reveals content left-top → right-bottom
    maskImage = `linear-gradient(135deg, black ${inOffset - EDGE}%, black ${inOffset}%, transparent ${inOffset + EDGE}%)`;
  }

  // --- Text animations ---
  // Start text after wipe is ~halfway through
  const TEXT_START = 30;
  const delay1 = TEXT_START;
  const delay2 = TEXT_START + 15;
  const delay3 = TEXT_START + 35;

  const spring1 = spring({
    frame: Math.max(0, frame - delay1),
    fps: safeFps,
    config: { damping: 14, mass: 0.8 }
  });

  const spring2 = spring({
    frame: Math.max(0, frame - delay2),
    fps: safeFps,
    config: { damping: 14, mass: 0.8 }
  });

  const fade3 = interpolate(frame - delay3, [0, 15], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp'
  });

  const opacity1 = interpolate(spring1, [0, 1], [0, 1], { extrapolateRight: 'clamp' });
  const translateY1 = interpolate(spring1, [0, 1], [40, 0]);

  const opacity2 = interpolate(spring2, [0, 1], [0, 1], { extrapolateRight: 'clamp' });
  const translateY2 = interpolate(spring2, [0, 1], [40, 0]);

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: transparentBackground ? 'transparent' : backgroundColor,
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    fontFamily: fontFamily,
    overflow: 'hidden',
    WebkitMaskImage: maskImage,
    maskImage: maskImage,
  };

  const line1Style = {
    fontSize: '72px',
    fontWeight: 700,
    color: textColor,
    letterSpacing: '-0.02em',
    opacity: opacity1,
    transform: `translateY(${translateY1}px)`,
    margin: 0,
    lineHeight: 1.1
  };

  const line2Style = {
    fontSize: '140px',
    fontWeight: 800,
    color: textColor,
    letterSpacing: '-0.04em',
    opacity: opacity2,
    transform: `translateY(${translateY2}px)`,
    margin: '10px 0 0 0',
    lineHeight: 1.1
  };

  const subtitleStyle = {
    fontSize: '42px',
    fontWeight: 400,
    fontStyle: 'italic',
    color: subtitleColor,
    opacity: fade3,
    margin: '35px 0 0 0',
    letterSpacing: '-0.01em'
  };

  return (
    <div style={rootStyle}>
      <div style={line1Style}>{titleLine1}</div>
      <div style={line2Style}>{titleLine2}</div>
      <div style={subtitleStyle}>{subtitle}</div>
    </div>
  );
};

const EventAnnouncement = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  // Editable properties
  const props = item.props || {};
  const line1 = props.line1 || 'PUPPY HOUR';
  const line2 = props.line2 || 'STARTS';
  const subtitle = props.subtitle || 'Please keep leashes handy';
  const primaryColor = props.primaryColor || '#1A1A1A';
  const accentColor = props.accentColor || '#b2a5ff';
  const gradientStart = props.gradientStart || '#ffe9e5'; // Light Blue
  const gradientMid = props.gradientMid || '#f0edff';   // Warm Peach
  const gradientEnd = props.gradientEnd || '#FFFFFF';   // White

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // Background: Breathing Gradient Animation
  // We oscillate the interpolation factor 't' over time to shift colors
  const breatheDuration = 180; // frames (approx 6s loop)
  const t = (1 + Math.sin((frame / breatheDuration) * Math.PI * 2)) / 2;

  const bg1 = interpolateColors(t, [0, 0.5, 1], [gradientStart, gradientMid, gradientStart]);
  const bg2 = interpolateColors(t, [0, 0.5, 1], [gradientMid, gradientEnd, gradientMid]);
  const bg3 = interpolateColors(t, [0, 0.5, 1], [gradientEnd, gradientStart, gradientEnd]);

  // Title Entrance: Spring with letter-spacing expansion
  const springConfig = { damping: 100, stiffness: 200, mass: 3 };
  const entrance = spring({ frame, fps, config: springConfig });

  const tracking = interpolate(entrance, [0, 1], [-0.08, -0.02]); // em units: tight to less tight
  const titleOpacity = interpolate(entrance, [0, 1], [0, 1]);
  const titleY = interpolate(entrance, [0, 1], [80, 0]);

  // Sparkle Animation: Rotate and Pulse
  const sparklePulse = 1 + Math.sin(frame / 20) * 0.15;
  const sparkleRot = frame * 0.4;
  // Sparkle enters slightly after title start
  const sparkleEntrance = spring({ frame: Math.max(0, frame - 10), fps, config: { damping: 15 } });
  const sparkleScale = interpolate(sparkleEntrance, [0, 1], [0, 1]);

  // Subtitle Entrance
  const subEntrance = spring({ frame: Math.max(0, frame - 25), fps, config: { damping: 20 } });
  const subOpacity = interpolate(subEntrance, [0, 1], [0, 1]);
  const subY = interpolate(subEntrance, [0, 1], [30, 0]);

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    overflow: 'hidden',
    fontFamily: 'Inter, sans-serif',
  };

  const backgroundStyle = {
    position: 'absolute',
    top: 0, left: 0, right: 0, bottom: 0,
    background: `linear-gradient(135deg, ${bg1}, ${bg2}, ${bg3})`,
    zIndex: 0,
  };

  const contentContainerStyle = {
    position: 'relative',
    zIndex: 1,
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  };

  const titleStyle = {
    fontSize: '200px',
    lineHeight: '0.85',
    fontWeight: 900,
    color: primaryColor,
    textTransform: 'uppercase',
    textAlign: 'center',
    letterSpacing: `${tracking}em`,
    opacity: titleOpacity,
    transform: `translateY(${titleY}px)`,
    margin: 0,
    textShadow: '0 10px 30px rgba(0,0,0,0.05)',
  };

  const subtitleStyle = {
    fontSize: '42px',
    fontWeight: 500,
    color: primaryColor,
    marginTop: '50px',
    opacity: subOpacity,
    transform: `translateY(${subY}px)`,
    letterSpacing: '0.05em',
  };

  // Decorative Sparkle Positioned relative to title block
  const starContainerStyle = {
    position: 'absolute',
    left: '-150px',
    top: '-80px',
    width: '160px',
    height: '160px',
    transform: `scale(${sparkleScale})`,
    opacity: titleOpacity,
  };

  const starSvgStyle = {
    width: '100%',
    height: '100%',
    transform: `rotate(${sparkleRot}deg) scale(${sparklePulse})`,
    filter: `drop-shadow(0 0 15px ${accentColor})`,
  };

  return (
    <div style={rootStyle}>
      <div style={backgroundStyle} />

      <div style={contentContainerStyle}>
        <div style={starContainerStyle}>
          <svg viewBox="0 0 100 100" style={starSvgStyle}>
            <path 
              d="M 50 0 C 60 40 60 40 100 50 C 60 60 60 60 50 100 C 40 60 40 60 0 50 C 40 40 40 40 50 0 Z" 
              fill={accentColor}
            />
          </svg>
        </div>

        <h1 style={titleStyle}>
          <div>{line1}</div>
          <div>{line2}</div>
        </h1>

        <div style={subtitleStyle}>{subtitle}</div>
      </div>
    </div>
  );
};

const PaperFlashcards = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const p = item.props || {};

  const row1w1 = p.row1w1 || 'input';
  const row1w2 = p.row1w2 || 'goals';
  const row2w1 = p.row2w1 || 'output';
  const row2w2 = p.row2w2 || 'goals';
  const row3w1 = p.row3w1 || 'outcome';
  const row3w2 = p.row3w2 || 'goals';
  const note1  = p.note1  || 'spend 15 hours/week\non my channel';
  const note2  = p.note2  || 'post 1 video\nevery week';
  const note3  = p.note3  || 'gain x subscribers\nevery month';
  const textColor = p.textColor || '#708a3b';

  const DESIGN_WIDTH  = 1920;
  const DESIGN_HEIGHT = 1080;
  const scl = Math.min(
    (item?.width  || DESIGN_WIDTH)  / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );
  const F = fps || 30;

  // Intro / outro slide timing
  const INTRO = Math.round(0.8 * F);   // 0.8s slide-in
  const TOTAL = Math.round(11 * F);    // total 11s
  const OUTRO_START = TOTAL - Math.round(0.8 * F); // last 0.8s slide-out

  // 1拍三 slide offset (choppy, no easing)
  const q3frame = Math.floor(frame / 3) * 3;
  let slideY = 0;
  if (q3frame < INTRO) {
    // Slide in: from DESIGN_HEIGHT down to 0, in steps
    const steps = Math.floor(INTRO / 3);
    const step = Math.floor(q3frame / 3);
    slideY = Math.round(DESIGN_HEIGHT * (1 - step / steps));
  } else if (q3frame >= OUTRO_START) {
    // Slide out: from 0 up to -DESIGN_HEIGHT
    const steps = Math.floor((TOTAL - OUTRO_START) / 3);
    const step = Math.floor((q3frame - OUTRO_START) / 3);
    slideY = -Math.round(DESIGN_HEIGHT * (step / steps));
  }

  // Offset inner frame so original animation timing is preserved
  const innerFrame = Math.max(0, frame - INTRO);

  // Static paper background
  const bg = '#def0e3';
  const noiseSeed = 7;

  // Static ink dots — small, sparse, natural
  const dots = Array.from({ length: 22 }, (_, i) => {
    const h = (n) => Math.abs(Math.sin(n * 9301.7 + i * 127.1) % 1);
    return {
      x: h(1) * 100,
      y: h(2) * 100,
      sz: 1.0 + h(3) * 2.5,
      op: 0.12 + h(4) * 0.22,
    };
  });

  // 1拍三 helpers
  const q3 = (f) => Math.floor(f / 3) * 3;

  const wordAnim = (t) => {
    if (innerFrame < t) return { op: 0, ty: 20 };
    const loc = q3(innerFrame - t);
    if (loc < 3) return { op: 0.7, ty: 10 };
    return { op: 1, ty: 0 };
  };

  const choppyOp = (t) => {
    if (innerFrame < t) return 0;
    const loc = q3(innerFrame - t);
    if (loc < 3) return 0.5;
    if (loc < 6) return 0.8;
    return 1;
  };

  // Timing
  const c1  = Math.floor(0.4 * F);
  const w1a = c1,      w1b = c1 + 6;
  const c2  = Math.floor(1.8 * F);
  const w2a = c2,      w2b = c2 + 6;
  const c3  = Math.floor(3.2 * F);
  const w3a = c3,      w3b = c3 + 6;
  const n1  = w1b + 8;
  const n2  = w2b + 8;
  const n3  = w3b + 8;

  const CARD_W = 740;
  const CARD_H = 112;

  // Horizontally centred, with small organic offsets per row (matching original video)
  const centerX   = (DESIGN_WIDTH - CARD_W) / 2; // = 590, all cards same left
  const card1Left = centerX;
  const card2Left = centerX;
  const card3Left = centerX;
  const card1Top  = 270;
  const card2Top  = 480;
  const card3Top  = 672;

  const Word = ({ text, t }) => {
    const { op, ty } = wordAnim(t);
    return (
      <span style={{
        display: 'inline-block',
        opacity: op,
        transform: `translateY(${ty}px)`,
        fontFamily: '"Nunito", sans-serif',
        fontWeight: '800',
        fontSize: '74px',
        color: textColor,
        letterSpacing: '-1px',
        lineHeight: 1,
      }}>
        {text}
      </span>
    );
  };

  // Card entrance: 1拍三 scale pop — 3 steps over 9 frames
  const cardAnim = (tw1) => {
    if (innerFrame < tw1) return { scaleV: 0, ty: 16, op: 0 };
    const step = Math.min(3, Math.floor((innerFrame - tw1) / 3));
    if (step === 0) return { scaleV: 0.7, ty: 12, op: 0.6 };
    if (step === 1) return { scaleV: 1.08, ty: 4,  op: 0.85 };
    if (step === 2) return { scaleV: 1.0,  ty: 0,  op: 1 };
    return { scaleV: 1.0, ty: 0, op: 1 };
  };

  const Card = ({ w1, w2, tw1, tw2, left, top }) => {
    if (innerFrame < tw1) return null;
    const { scaleV, ty, op } = cardAnim(tw1);
    return (
      <div style={{
        position: 'absolute',
        left,
        top,
        width: CARD_W,
        height: CARD_H,
        opacity: op,
        transform: `translateY(${ty}px) scale(${scaleV})`,
        transformOrigin: 'center center',
        backgroundColor: 'rgba(255,255,255,0.88)',
        borderRadius: '18px',
        border: '1.5px solid rgba(0,0,0,0.06)',
        boxShadow: '3px 5px 0 rgba(0,0,0,0.06)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        gap: '18px',
        overflow: 'hidden',
      }}>
        <Word text={w1} t={tw1} />
        <Word text={w2} t={tw2} />
      </div>
    );
  };

  // Note text
  const Note = ({ text, t, style }) => {
    const op = choppyOp(t);
    if (op === 0) return null;
    return (
      <div style={{ position: 'absolute', opacity: op, pointerEvents: 'none', ...style }}>
        <span style={{
          display: 'block',
          fontFamily: '"Nunito", sans-serif',
          fontStyle: 'italic',
          fontWeight: '400',
          fontSize: '34px',
          color: textColor,
          whiteSpace: 'pre-line',
          lineHeight: 1.4,
          textAlign: 'center',
        }}>{text}</span>
      </div>
    );
  };

  // SVG arrow — absolute positioned, connects note to card edge
  // We pass exact pixel coords for start and end of the arc
  const Arrow = ({ t, x1, y1, x2, y2 }) => {
    if (innerFrame < t) return null;
    // Calculate bounding box
    const minX = Math.min(x1, x2) - 20;
    const minY = Math.min(y1, y2) - 60;
    const maxX = Math.max(x1, x2) + 20;
    const maxY = Math.max(y1, y2) + 20;
    const w = maxX - minX;
    const h = maxY - minY;
    const lx1 = x1 - minX;
    const ly1 = y1 - minY;
    const lx2 = x2 - minX;
    const ly2 = y2 - minY;
    const cpx = (lx1 + lx2) / 2;
    const cpy = Math.min(ly1, ly2) - 70;
    const pathD = `M ${lx1} ${ly1} Q ${cpx} ${cpy} ${lx2} ${ly2}`;

    // Path length estimate
    const pathLen = Math.round(Math.sqrt(Math.pow(lx2-lx1,2) + Math.pow(ly2-ly1,2)) * 1.4);

    // 1拍三 growth: 5 steps × 3 frames = 15 frames total
    // Use direct floor division (no nested q3) to prevent shrink-back on boundary frames
    const stepCount = 5;
    const step = Math.min(stepCount, Math.floor((innerFrame - t) / 3));
    const revealLen = Math.round(pathLen * (step / stepCount));

    // Two-layer reveal: dashed line underneath, cover mask on top shrinking from right.
    // Layer 1: fixed "13 9" dashed path (always full length)
    // Layer 2: background-color solid path with dasharray "0 revealLen 99999"
    //          — hides everything from revealLen onwards (no loop logic, no edge-case bugs)
    const headOpacity = step >= stepCount ? 0.75 : 0;
    const coverStart = revealLen > 0 ? revealLen : 0;

    return (
      <svg
        style={{ position: 'absolute', left: minX, top: minY, overflow: 'visible', pointerEvents: 'none' }}
        width={w} height={h} viewBox={`0 0 ${w} ${h}`} fill="none"
      >
        {/* Layer 1: full dashed line */}
        <path
          d={pathD}
          stroke="#2a2a2a"
          strokeWidth="5"
          strokeDasharray="13 9"
          strokeLinecap="round"
          fill="none"
        />
        {/* Layer 2: cover mask — hides the portion not yet revealed */}
        <path
          d={pathD}
          stroke="#def0e3"
          strokeWidth="7"
          strokeDasharray={`0 ${coverStart} 99999`}
          strokeLinecap="butt"
          fill="none"
        />
        <circle cx={lx2} cy={ly2} r="4" fill="#2a2a2a" opacity={headOpacity} />
      </svg>
    );
  };

  // Precise note + arrow positions matching original video:
  // Note1: top-left, its right edge connects to card1 top-left corner area
  //   note1 centre ~(300, 130), card1 top-left ~(530, 165)
  // Note2: right side, its left edge connects to card2 right edge
  //   note2 centre ~(1480, 330), card2 right edge ~(1240, 430)
  // Note3: bottom-left, its right edge connects to card3 left edge
  //   note3 centre ~(240, 660), card3 left ~(460, 614)

  return (
    <div style={{
      width: DESIGN_WIDTH,
      height: DESIGN_HEIGHT,
      transform: `scale(${scl}) translateY(${slideY}px)`,
      transformOrigin: 'top left',
      backgroundColor: bg,
      position: 'relative',
      overflow: 'hidden',
    }}>

      {/* Static paper texture — single soft noise layer */}
      <svg style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', pointerEvents: 'none' }}>
        <filter id="paper-texture" x="0%" y="0%" width="100%" height="100%" colorInterpolationFilters="sRGB">
          <feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="4" stitchTiles="stitch" seed={noiseSeed} result="noise" />
          <feColorMatrix type="saturate" values="0" in="noise" result="grey" />
          <feBlend in="SourceGraphic" in2="grey" mode="overlay" result="blended" />
          <feComponentTransfer in="blended">
            <feFuncA type="linear" slope="0.15" />
          </feComponentTransfer>
        </filter>
        <rect width="100%" height="100%" filter="url(#paper-texture)" fill="#93c5c4" />
      </svg>

      {/* Ink dots */}
      {dots.map((d, i) => (
        <div key={i} style={{
          position: 'absolute',
          left: `${d.x}%`, top: `${d.y}%`,
          width: d.sz, height: d.sz,
          borderRadius: '50%',
          backgroundColor: '#1c1410',
          opacity: d.op,
          pointerEvents: 'none',
        }} />
      ))}

      {/* Cards */}
      <Card w1={row1w1} w2={row1w2} tw1={w1a} tw2={w1b} left={card1Left} top={card1Top} />
      <Card w1={row2w1} w2={row2w2} tw1={w2a} tw2={w2b} left={card2Left} top={card2Top} />
      <Card w1={row3w1} w2={row3w2} tw1={w3a} tw2={w3b} left={card3Left} top={card3Top} />

      {/* Note 1 — top left, arrow curves to card1 top-left */}
      <Note text={note1} t={n1} style={{ top: 140, left: 100, width: 320, textAlign: 'center' }} />
      <Arrow t={n1} x1={420} y1={230} x2={card1Left + 40} y2={card1Top + 8} />

      {/* Note 2 — right side, arrow from card2 right edge to note */}
      <Note text={note2} t={n2} style={{ top: 396, right: 90, width: 300, textAlign: 'center' }} />
      <Arrow t={n2} x1={DESIGN_WIDTH - 90 - 300 + 20} y1={card2Top + 20} x2={card2Left + CARD_W + 12} y2={card2Top + 56} />

      {/* Note 3 — bottom left, arrow to card3 left edge */}
      <Note text={note3} t={n3} style={{ top: 740, left: 80, width: 330, textAlign: 'center' }} />
      <Arrow t={n3} x1={410} y1={792} x2={card3Left + 16} y2={card3Top + CARD_H - 24} />

    </div>
  );
};

const GoldenChapterCard = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps, durationInFrames } = useVideoConfig();

  // Editable properties
  const mainText = item?.propertyOverrides?.mainText ?? 'STUDIO PORTFOLIO';
  const subText = item?.propertyOverrides?.subText ?? 'FEATURED SHOTS';
  const sphereNumber = item?.propertyOverrides?.sphereNumber ?? '';
  const sphereXProp = item?.propertyOverrides?.sphereX ?? 1200;
  const sphereYProp = item?.propertyOverrides?.sphereY ?? 480;
  const bannerMaxWidth = item?.propertyOverrides?.bannerMaxWidth ?? 520;
  const bannerPaddingRight = item?.propertyOverrides?.bannerPaddingRight ?? 30;
  const animSpeed = item?.propertyOverrides?.animSpeed ?? 1;
  const exitDurationSec = item?.propertyOverrides?.exitDuration ?? 3;

  // Canvas Logic
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  // Animation timing
  const exitStartFrame = fps * exitDurationSec;
  const entranceDuration = 40;
  const isExiting = frame >= exitStartFrame;
  const exitFrame = frame - exitStartFrame;
  const reversedFrame = isExiting ? Math.max(0, entranceDuration - exitFrame) : frame;
  const effectiveFrame = isExiting ? reversedFrame : frame;
  const scaledFrame = effectiveFrame / Math.max(0.1, animSpeed);

  // Animations
  const sphereSpring = spring({
    frame: scaledFrame,
    fps,
    config: { damping: 20, stiffness: 120, mass: 0.6 },
  });

  const bannerSpring = spring({
    frame: scaledFrame - 15,
    fps,
    config: { damping: 18, stiffness: 80 },
  });

  const textSpring = spring({
    frame: scaledFrame - 25,
    fps,
    config: { damping: 22, stiffness: 90 },
  });

  // Interpolations
  const sphereScale = interpolate(sphereSpring, [0, 1], [0, 1]);

  const bannerWidth = interpolate(bannerSpring, [0, 1], [0, bannerMaxWidth]);
  const bannerOpacity = interpolate(bannerSpring, [0, 0.2], [0, 1]);

  const contentOpacity = interpolate(textSpring, [0, 1], [0, 1]);
  const contentTranslate = interpolate(textSpring, [0, 1], [30, 0]);

  // 3D ball number rotation
  const spinProgress = spring({ frame: scaledFrame, fps, config: { damping: 25, stiffness: 100, mass: 0.8 } });
  const rotateY = interpolate(spinProgress, [0, 1], [-180, 0]);
  const numberScaleX = Math.cos(rotateY * Math.PI / 180);
  const numberOpacity = rotateY > -90 ? 1 : 0;

  // Styling Constants
  const POS_X = sphereXProp;
  const POS_Y = sphereYProp;
  const SPHERE_SIZE = 140;
  const BANNER_HEIGHT = 110;

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: 'transparent',
    fontFamily: '"Montserrat", "Inter", sans-serif',
  };

  const containerStyle = {
    position: 'absolute',
    top: POS_Y - (SPHERE_SIZE / 2),
    left: POS_X - (SPHERE_SIZE / 2),
    width: SPHERE_SIZE + 600,
    height: SPHERE_SIZE + 50,
  };

  const bannerStyle = {
    position: 'absolute',
    top: (SPHERE_SIZE - BANNER_HEIGHT) / 2,
    left: SPHERE_SIZE / 2,
    width: bannerWidth,
    height: BANNER_HEIGHT,
    backgroundColor: '#111111',
    border: '2px solid #dab8ff',
    borderLeft: 'none',
    borderRadius: '0 12px 12px 0',
    overflow: 'hidden',
    opacity: bannerOpacity,
    boxShadow: '0 8px 25px rgba(0,0,0,0.4)',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    paddingLeft: SPHERE_SIZE / 2 + 30,
    paddingRight: bannerPaddingRight,
  };

  const textContainerStyle = {
    opacity: contentOpacity,
    transform: `translateX(${contentTranslate}px)`,
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
  };

  const mainTextStyle = {
    color: '#dab8ff',
    fontSize: '32px',
    fontWeight: 800,
    letterSpacing: '1px',
    marginBottom: '2px',
    whiteSpace: 'nowrap',
    textTransform: 'uppercase',
    textShadow: '0 2px 10px rgba(218,184,255, 0.2)',
  };

  const subTextStyle = {
    color: '#e3cbff',
    fontSize: '16px',
    fontWeight: 600,
    letterSpacing: '3px',
    textTransform: 'uppercase',
  };

  const subStripStyle = {
    marginTop: '6px',
    width: '100%',
    height: '4px',
    backgroundColor: '#3e408d',
    borderRadius: '2px',
  };

  const sphereStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: SPHERE_SIZE,
    height: SPHERE_SIZE,
    borderRadius: '50%',
    background: 'radial-gradient(circle at 35% 35%, #e3cbff 0%, #dab8ff 45%, #937bfd 80%, #4b4eac 100%)',
    boxShadow: '0 15px 35px rgba(0,0,0,0.5), inset -8px -8px 20px rgba(0,0,0,0.2), inset 8px 8px 20px rgba(255,255,255,0.15)',
    transform: `scale(${sphereScale})`,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    zIndex: 10,
    overflow: 'hidden',
  };

  const numberStyle = {
    color: '#1c1d49',
    fontSize: '72px',
    fontWeight: 900,
    fontFamily: '"Oswald", sans-serif',
    transform: `scaleX(${numberScaleX})`,
    opacity: numberOpacity,
    textShadow: numberScaleX > 0.5 ? '2px 2px 4px rgba(0,0,0,0.3)' : 'none',
  };

  return (
    <div style={rootStyle}>
      <div style={containerStyle}>
        <div style={bannerStyle}>
          <div style={textContainerStyle}>
            <div style={mainTextStyle}>{mainText}</div>
            <div style={subTextStyle}>{subText}</div>
            <div style={subStripStyle} />
          </div>
        </div>
        <div style={sphereStyle}>
          {sphereNumber ? <span style={numberStyle}>{sphereNumber}</span> : null}
        </div>
      </div>
    </div>
  );
};

