const NewsBroadcastTitle = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps, durationInFrames } = useVideoConfig();

  // Props extraction with defaults
  const props = item.props || {};
  const mainTitle = props.mainTitle || 'ENERGY DESK';
  const subtitle = props.subtitle || 'POWERING TOMORROW';
  const primaryColor = props.primaryColor || '#131b02'; // Deep Navy
  const accentColor = props.accentColor || '#008b8b'; // News Red
  const bgColor = props.bgColor || '#F1F5F9'; // Light Silver

  // Responsive Scaling
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  // Animation Timing Config
  const exitDuration = 30;
  const exitStart = durationInFrames - exitDuration;

  // 1. Background Planes Entrance (0s start)
  const bgEntrance = spring({
    frame,
    fps,
    config: { damping: 20, stiffness: 60, mass: 1.5 },
  });

  // 2. Main Title Entrance (0.3s ~ 10 frames delay)
  const titleDelay = 10;
  const titleEntrance = spring({
    frame: frame - titleDelay,
    fps,
    config: { damping: 15, stiffness: 80, mass: 1 },
  });

  // 3. Line Divider Entrance (0.6s ~ 18 frames delay)
  const lineDelay = 18;
  const lineProgress = spring({
    frame: frame - lineDelay,
    fps,
    config: { damping: 20, stiffness: 150 },
  });

  // 4. Subtitle Entrance (0.8s ~ 24 frames delay)
  const subDelay = 24;
  const subEntrance = spring({
    frame: frame - subDelay,
    fps,
    config: { damping: 20 },
  });

  // 5. Exit Animation
  const exitProgress = interpolate(
    frame,
    [exitStart, durationInFrames],
    [0, 1],
    { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );

  // Global Exit Transforms
  const globalOpacity = 1 - exitProgress;
  const globalScale = interpolate(exitProgress, [0, 1], [1, 0.95]);

  // Continuous Drift for Background
  const drift = interpolate(frame, [0, durationInFrames], [0, -40]);

  // Styles
  const rootStyle = {
    position: 'absolute',
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    backgroundColor: bgColor,
    overflow: 'hidden',
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    opacity: globalOpacity,
  };

  // Geometric Light Ray Helper
  const LightRay = ({ angle, top, left, width, opacity, delayOffset = 0, item }) => {
    const slideIn = interpolate(bgEntrance, [0, 1], [150, 0]);
    const rayStyle = {
      position: 'absolute',
      top,
      left,
      width,
      height: 600,
      background: 'linear-gradient(90deg, transparent 0%, rgba(255,255,255,0.6) 50%, transparent 100%)',
      transform: `rotate(${angle}deg) translateX(${slideIn + drift}px)`,
      opacity: opacity,
      filter: 'blur(40px)',
    };
    return <div style={rayStyle} />;
  };

  const contentContainerStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: '100%',
    height: '100%',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    transform: `scale(${globalScale})`,
    zIndex: 10,
  };

  const titleStyle = {
    fontFamily: '"Times New Roman", Times, serif',
    fontWeight: '800',
    fontSize: '150px',
    color: primaryColor,
    letterSpacing: '-4px',
    lineHeight: 0.9,
    textAlign: 'center',
    opacity: interpolate(titleEntrance, [0, 1], [0, 1]),
    transform: `scale(${interpolate(titleEntrance, [0, 1], [0.95, 1])}) translateY(${interpolate(titleEntrance, [0, 1], [30, 0])}px)`,
    textShadow: '0 10px 30px rgba(0,0,0,0.05)',
  };

  const dividerStyle = {
    position: 'relative',
    width: '600px',
    height: '6px',
    margin: '40px 0',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
  };

  const thinLineStyle = {
    position: 'absolute',
    width: '100%',
    height: '1px',
    backgroundColor: primaryColor,
    opacity: 0.2,
    transform: `scaleX(${lineProgress})`,
  };

  const accentDashStyle = {
    position: 'absolute',
    width: '80px',
    height: '6px',
    backgroundColor: accentColor,
    transform: `scaleX(${interpolate(frame - (lineDelay + 8), [0, 15], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })})`,
    transformOrigin: 'left',
  };

  const subStyle = {
    fontFamily: '"Helvetica Neue", Helvetica, Arial, sans-serif',
    fontWeight: '500',
    fontSize: '32px',
    color: primaryColor,
    letterSpacing: '12px',
    textTransform: 'uppercase',
    opacity: subEntrance,
    transform: `translateY(${interpolate(subEntrance, [0, 1], [15, 0])}px)`,
  };

  return (
    <div style={rootStyle}>
      {/* Background Shapes */}
      <LightRay angle={-25} top={-200} left={-200} width={2000} opacity={0.6} />
      <LightRay angle={-25} top={200} left={-400} width={2500} opacity={0.4} />
      <LightRay angle={-15} top={500} left={0} width={2200} opacity={0.3} />

      {/* Subtle Grid Texture */}
      <div style={{
        position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
        backgroundImage: `linear-gradient(${primaryColor} 1px, transparent 1px), linear-gradient(90deg, ${primaryColor} 1px, transparent 1px)`,
        backgroundSize: '80px 80px',
        opacity: 0.03 * bgEntrance,
        transform: `scale(${1 + (drift * -0.001)})`
      }} />

      {/* Content */}
      <div style={contentContainerStyle}>
        <h1 style={titleStyle}>{mainTitle}</h1>

        <div style={dividerStyle}>
          <div style={thinLineStyle} />
          <div style={accentDashStyle} />
        </div>

        <h2 style={subStyle}>{subtitle}</h2>
      </div>
    </div>
  );
};

const VoxTypewriterTitleClean = ({item}) => {
  const frame = useCurrentFrame();
  const { fps, durationInFrames } = useVideoConfig();

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const safeFps = fps || 30;

  const textSubtitle = (item.props && item.props.subtitleText) !== undefined ? item.props.subtitleText : "Why furniture shipping keeps getting slower";
  const textChapter = (item.props && item.props.chapterText) !== undefined ? item.props.chapterText : "Chapter 2:";
  const textTitle = (item.props && item.props.titleText) !== undefined ? item.props.titleText : "Wishlists";
  const bgColor = (item.props && item.props.bgColor) !== undefined ? item.props.bgColor : "#f0eae1";
  const titleColor = (item.props && item.props.titleColor) !== undefined ? item.props.titleColor : "#0a0a0a";
  const chapterColor = (item.props && item.props.chapterColor) !== undefined ? item.props.chapterColor : "#1a1a1a";
  const subtitleColor = (item.props && item.props.subtitleColor) !== undefined ? item.props.subtitleColor : "#706c66";
  const animSpeed = (item.props && item.props.animSpeed) !== undefined ? item.props.animSpeed : 1.0;

  const safeSpring = (delay = 0, config = { damping: 18, stiffness: 120 }) => {
    return spring({ frame: Math.max(0, frame - delay / animSpeed), fps: safeFps, config });
  };

  const animStartDelay = Math.floor(0.15 * safeFps);
  const subtitleSpring = safeSpring(animStartDelay, { damping: 20, stiffness: 100 });
  const subtitleY = interpolate(subtitleSpring, [0, 1], [-40, 0]);
  const subtitleOpacity = interpolate(subtitleSpring, [0, 1], [0, 1]);

  const chapterSpring = safeSpring(animStartDelay + Math.floor(0.08 * safeFps), { damping: 20, stiffness: 100 });
  const chapterY = interpolate(chapterSpring, [0, 1], [40, 0]);
  const chapterOpacity = interpolate(chapterSpring, [0, 1], [0, 1]);

  const typeStartFrame = Math.floor((animStartDelay + Math.floor(0.1 * safeFps)) / animSpeed);
  const typeDuration = 1.0 / animSpeed;
  const typeEndFrame = typeStartFrame + Math.floor(typeDuration * safeFps);
  const typeProgressRaw = interpolate(frame, [typeStartFrame, typeEndFrame], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const getCharOpacity = (charIndex) => {
    const totalChars = textTitle.length;
    const charStartProgress = charIndex / totalChars;
    const charEndProgress = Math.min((charIndex + 1.5) / totalChars, 1);
    return interpolate(typeProgressRaw, [charStartProgress, charEndProgress], [0, 1], {
      extrapolateLeft: 'clamp',
      extrapolateRight: 'clamp',
    });
  };

  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const seededRandom = (seed) => {
    const x = Math.sin(seed * 9999) * 10000;
    return x - Math.floor(x);
  };

  const textureData = React.useMemo(() => {
    const fibers = [];
    for (let i = 0; i < 500; i++) {
      const x = seededRandom(i * 1.7) * 1920;
      const y = seededRandom(i * 2.3) * 1080;
      const distX = Math.abs(x - 960) / 960;
      const distY = Math.abs(y - 540) / 540;
      const dist = Math.sqrt(distX * distX + distY * distY);
      const edgeFactor = Math.pow(dist, 1.2);
      const baseOp = 0.1 + seededRandom(i * 3.1) * 0.2;
      const op = baseOp * (0.15 + edgeFactor * 0.85);
      const w = 1 + seededRandom(i * 4.2) * 2.5;
      const h = 10 + seededRandom(i * 5.1) * 35;
      const rot = seededRandom(i * 6.3) * 180 - 90;
      const shade = Math.floor(130 + seededRandom(i * 7.4) * 70);
      fibers.push({x, y, w, h, rot, op, shade});
    }
    const scr = [];
    for (let i = 0; i < 150; i++) {
      const x = seededRandom(i * 3.2) * 1920;
      const y = seededRandom(i * 4.1) * 1080;
      const distX = Math.abs(x - 960) / 960;
      const distY = Math.abs(y - 540) / 540;
      const dist = Math.sqrt(distX * distX + distY * distY);
      const edgeFactor = Math.pow(dist, 1.3);
      const baseOp = 0.08 + seededRandom(i * 5.2) * 0.15;
      const op = baseOp * (0.1 + edgeFactor * 0.9);
      const w = 0.5 + seededRandom(i * 6.1) * 1.5;
      const h = 25 + seededRandom(i * 7.2) * 80;
      const rot = seededRandom(i * 8.3) * 50 - 25;
      const shade = Math.floor(150 + seededRandom(i * 9.4) * 60);
      scr.push({x, y, w, h, rot, op, shade});
    }
    const spk = [];
    for (let i = 0; i < 400; i++) {
      const x = seededRandom(i * 2.1) * 1920;
      const y = seededRandom(i * 3.4) * 1080;
      const distX = Math.abs(x - 960) / 960;
      const distY = Math.abs(y - 540) / 540;
      const dist = Math.sqrt(distX * distX + distY * distY);
      const edgeFactor = Math.pow(dist, 1.4);
      const baseOp = 0.12 + seededRandom(i * 4.5) * 0.2;
      const op = baseOp * (0.1 + edgeFactor * 0.9);
      const sz = 1 + seededRandom(i * 5.6) * 4;
      const shade = Math.floor(140 + seededRandom(i * 6.7) * 80);
      spk.push({x, y, sz, op, shade});
    }
    return {fibers, scr, spk};
  }, []);

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: bgColor,
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
  };

  const gridStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: '100%',
    height: '100%',
    backgroundImage: 'linear-gradient(to right, rgba(200,198,192,0.3) 1px, transparent 1px), linear-gradient(to bottom, rgba(200,198,192,0.3) 1px, transparent 1px)',
    backgroundSize: '40px 40px',
    pointerEvents: 'none',
  };

  const fontStack = '"Georgia", "Times New Roman", serif';

  const subtitleStyle = {
    fontFamily: fontStack,
    fontSize: '32px',
    color: subtitleColor,
    marginBottom: '20px',
    fontStyle: 'italic',
    letterSpacing: '0.5px',
    textAlign: 'center',
    transform: `translateY(${subtitleY}px)`,
    opacity: subtitleOpacity,
    filter: 'blur(0.8px)',
  };

  const chapterStyle = {
    fontFamily: fontStack,
    fontSize: '42px',
    fontWeight: 'bold',
    color: chapterColor,
    marginBottom: '10px',
    textAlign: 'center',
    transform: `translateY(${chapterY}px)`,
    opacity: chapterOpacity,
    filter: 'blur(0.4px)',
    textShadow: '0 1px 0 rgba(85,63,81,0.08)',
  };

  const titleStyle = {
    fontFamily: fontStack,
    fontSize: '150px',
    fontWeight: 900,
    color: titleColor,
    letterSpacing: '-4px',
    lineHeight: 1,
    textAlign: 'left',
    minHeight: '160px',
    textShadow: '0 1px 0 rgba(64,43,61,0.12), 0 2px 1px rgba(64,43,61,0.06)',
    position: 'relative',
  };

  const titleWrapperStyle = {
    position: 'relative',
    width: 'auto',
    display: 'flex',
    justifyContent: 'center',
  };

  const titleInnerStyle = {
    position: 'relative',
  };

  return (
    <div style={rootStyle}>
      <div style={gridStyle} />
      {textureData.fibers.map((f, i) => (
        <div key={'f'+i} style={{position: 'absolute', left: f.x, top: f.y, width: f.w, height: f.h, borderRadius: 1, backgroundColor: `rgb(${f.shade},${f.shade},${f.shade})`, opacity: f.op, transform: `rotate(${f.rot}deg)`, pointerEvents: 'none'}} />
      ))}
      {textureData.scr.map((s, i) => (
        <div key={'s'+i} style={{position: 'absolute', left: s.x, top: s.y, width: s.w, height: s.h, backgroundColor: `rgb(${s.shade},${s.shade},${s.shade})`, opacity: s.op, transform: `rotate(${s.rot}deg)`, pointerEvents: 'none'}} />
      ))}
      {textureData.spk.map((p, i) => (
        <div key={'p'+i} style={{position: 'absolute', left: p.x, top: p.y, width: p.sz, height: p.sz, borderRadius: '50%', backgroundColor: `rgb(${p.shade},${p.shade},${p.shade})`, opacity: p.op, pointerEvents: 'none'}} />
