const FloatingQuestions = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const markText = props.markText;
  const fillColor = props.fillColor;
  const strokeColor = props.strokeColor;
  const fontFamily = props.fontFamily;
  const strokeWidth = props.strokeWidth;
  const bobAmplitude = props.bobAmplitude;
  const introAnimation = props.introAnimation;
  const arcRadius = props.arcRadius !== undefined ? props.arcRadius : 120;
  const spread = props.spread !== undefined ? props.spread : 90;

  const safeFps = fps || 30;
  const totalFrames = durationInFrames || 90;

  // Outro: fade + scale out over last 12 frames
  const outroStart = totalFrames - 12;
  const outroProgress = frame >= outroStart
    ? Math.min(1, (frame - outroStart) / 12)
    : 0;
  const globalOpacity = 1 - outroProgress;
  const globalOutroScale = 1 - outroProgress * 0.15;

  // Arc layout: 5 marks spread along a circular arc (top half)
  const count = 5;
  const marks = Array.from({length: count}, (_, i) => {
    // angle from -spread/2 to +spread/2 in degrees, centered at top (270deg)
    const t = count > 1 ? i / (count - 1) : 0.5;
    const angleDeg = -spread / 2 + t * spread;
    const angleRad = (angleDeg - 90) * (Math.PI / 180); // offset so 0deg = top
    const x = Math.cos(angleRad) * arcRadius;
    const y = Math.sin(angleRad) * arcRadius;
    const sizeFactor = 1 - Math.abs(t - 0.5) * 0.3; // center slightly bigger
    const baseSize = 85 * sizeFactor;
    const rotation = angleDeg * 0.4; // slight tilt following arc
    const phase = i * 1.2;
    return { id: i + 1, x, y, size: baseSize, r: rotation, phase };
  });

  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor: 'transparent',
    opacity: globalOpacity,
    transform: `scale(${globalOutroScale})`,
    overflow: 'visible',
  };

  const containerStyle = {
    position: 'absolute',
    left: '50%',
    top: '75%',
    width: 0,
    height: 0,
  };

  return (
    <div style={rootStyle}>
      <div style={containerStyle}>
        {marks.map((m, i) => {
          const delay = i * 2;
          const springFrame = Math.max(0, frame - delay);

          let scale = 1;
          if (introAnimation) {
            scale = spring({
              frame: springFrame,
              fps: safeFps,
              config: { damping: 14, stiffness: 200 }
            });
          }

          const floatY = Math.sin((frame / 90) * Math.PI * 4 + m.phase) * bobAmplitude;
          const markTransform = `translate(-50%, -50%) scale(${scale}) translateY(${floatY}px) rotate(${m.r}deg)`;

          const markStyle = {
            position: 'absolute',
            left: m.x,
            top: m.y,
            transform: markTransform,
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            width: m.size * 1.5,
            height: m.size * 1.5,
          };

          const strokeLayerStyle = {
            position: 'absolute',
            fontSize: m.size,
            fontFamily: fontFamily,
            fontWeight: 900,
            color: fillColor,
            WebkitTextStroke: `${strokeWidth}px ${strokeColor}`,
            textShadow: `0px 6px 12px rgba(0,3,1,0.15)`,
            zIndex: 1,
            lineHeight: 1,
          };

          const fillLayerStyle = {
            position: 'absolute',
            fontSize: m.size,
            fontFamily: fontFamily,
            fontWeight: 900,
            color: fillColor,
            zIndex: 2,
            lineHeight: 1,
          };

          return (
            <div key={m.id} style={markStyle}>
              <div style={strokeLayerStyle}>{markText}</div>
              <div style={fillLayerStyle}>{markText}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

