  const fontFamily = props.fontFamily || 'Georgia, Times New Roman, serif';

  const safeSpring = (delay = 0, config = { damping: 18, stiffness: 120 }) => {
    return spring({ frame: Math.max(0, frame - delay), fps: safeFps, config });
  };

  const animStartDelay = Math.floor(0.15 * safeFps);
  const subtitleSpring = safeSpring(animStartDelay, { damping: 20, stiffness: 100 });
  const subtitleY = interpolate(subtitleSpring, [0, 1], [-40, 0]);
  const subtitleOpacity = interpolate(subtitleSpring, [0, 1], [0, 1]);

  const chapterSpring = safeSpring(animStartDelay + Math.floor(0.08 * safeFps), { damping: 20, stiffness: 100 });
  const chapterY = interpolate(chapterSpring, [0, 1], [40, 0]);
  const chapterOpacity = interpolate(chapterSpring, [0, 1], [0, 1]);

  const typeStartFrame = animStartDelay + Math.floor(0.1 * safeFps);
  const typeDuration = 1.0;
  const typeEndFrame = typeStartFrame + Math.floor(typeDuration * safeFps);
  const typeProgressRaw = interpolate(frame, [typeStartFrame, typeEndFrame], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const getCharOpacity = (charIndex) => {
    const totalChars = textTitle.length;
    const charStartProgress = charIndex / totalChars;
    const charEndProgress = Math.min((charIndex + 1.5) / totalChars, 1);
    return interpolate(typeProgressRaw, [charStartProgress, charEndProgress], [0, 1], {
      extrapolateLeft: 'clamp',
      extrapolateRight: 'clamp',
    });
  };

  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const seededRandom = (seed) => {
    const x = Math.sin(seed * 9999) * 10000;
    return x - Math.floor(x);
  };

  const textureData = React.useMemo(() => {
    const fibers = [];
    for (let i = 0; i < 500; i++) {
      const x = seededRandom(i * 1.7) * 1920;
      const y = seededRandom(i * 2.3) * 1080;
      const distX = Math.abs(x - 960) / 960;
      const distY = Math.abs(y - 540) / 540;
      const dist = Math.sqrt(distX * distX + distY * distY);
      const edgeFactor = Math.pow(dist, 1.2);
      const baseOp = 0.1 + seededRandom(i * 3.1) * 0.2;
      const op = baseOp * (0.15 + edgeFactor * 0.85);
      const w = 1 + seededRandom(i * 4.2) * 2.5;
      const h = 10 + seededRandom(i * 5.1) * 35;
      const rot = seededRandom(i * 6.3) * 180 - 90;
      const shade = Math.floor(130 + seededRandom(i * 7.4) * 70);
      fibers.push({x, y, w, h, rot, op, shade});
    }
    const scr = [];
    for (let i = 0; i < 150; i++) {
      const x = seededRandom(i * 3.2) * 1920;
      const y = seededRandom(i * 4.1) * 1080;
      const distX = Math.abs(x - 960) / 960;
      const distY = Math.abs(y - 540) / 540;
      const dist = Math.sqrt(distX * distX + distY * distY);
      const edgeFactor = Math.pow(dist, 1.3);
      const baseOp = 0.08 + seededRandom(i * 5.2) * 0.15;
      const op = baseOp * (0.1 + edgeFactor * 0.9);
      const w = 0.5 + seededRandom(i * 6.1) * 1.5;
      const h = 25 + seededRandom(i * 7.2) * 80;
      const rot = seededRandom(i * 8.3) * 50 - 25;
      const shade = Math.floor(150 + seededRandom(i * 9.4) * 60);
      scr.push({x, y, w, h, rot, op, shade});
    }
    const spk = [];
    for (let i = 0; i < 400; i++) {
      const x = seededRandom(i * 2.1) * 1920;
      const y = seededRandom(i * 3.4) * 1080;
      const distX = Math.abs(x - 960) / 960;
      const distY = Math.abs(y - 540) / 540;
      const dist = Math.sqrt(distX * distX + distY * distY);
      const edgeFactor = Math.pow(dist, 1.4);
      const baseOp = 0.12 + seededRandom(i * 4.5) * 0.2;
      const op = baseOp * (0.1 + edgeFactor * 0.9);
      const sz = 1 + seededRandom(i * 5.6) * 4;
      const shade = Math.floor(140 + seededRandom(i * 6.7) * 80);
      spk.push({x, y, sz, op, shade});
    }
    return {fibers, scr, spk};
  }, []);

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: bgColor,
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
  };

  const gridStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: '100%',
    height: '100%',
    backgroundImage: 'linear-gradient(to right, rgba(200,198,192,0.3) 1px, transparent 1px), linear-gradient(to bottom, rgba(200,198,192,0.3) 1px, transparent 1px)',
    backgroundSize: '40px 40px',
    pointerEvents: 'none',
  };

  const subtitleStyle = {
    fontFamily,
    fontSize: '32px',
    color: subtitleColor,
    marginBottom: '20px',
    fontStyle: 'italic',
    letterSpacing: '0.5px',
    textAlign: 'center',
    transform: `translateY(${subtitleY}px)`,
    opacity: subtitleOpacity,
    filter: 'blur(0.8px)',
  };

  const chapterStyle = {
    fontFamily,
    fontSize: '42px',
    fontWeight: 'bold',
    color: chapterColor,
    marginBottom: '10px',
    textAlign: 'center',
    transform: `translateY(${chapterY}px)`,
    opacity: chapterOpacity,
    filter: 'blur(0.4px)',
    textShadow: '0 1px 0 rgba(66,75,51,0.08)',
  };

  const titleStyle = {
    fontFamily,
    fontSize: '150px',
    fontWeight: 900,
    color: textColor,
    letterSpacing: '-4px',
    lineHeight: 1,
    textAlign: 'left',
    minHeight: '160px',
    textShadow: '0 1px 0 rgba(47,55,31,0.12), 0 2px 1px rgba(47,55,31,0.06)',
    position: 'relative',
  };

  const titleWrapperStyle = {
    position: 'relative',
    width: 'auto',
    display: 'flex',
    justifyContent: 'center',
  };

  const titleInnerStyle = {
    position: 'relative',
  };

  return (
    <div style={rootStyle}>
      <div style={gridStyle} />
      {textureData.fibers.map((f, i) => (
        <div key={'f'+i} style={{position: 'absolute', left: f.x, top: f.y, width: f.w, height: f.h, borderRadius: 1, backgroundColor: `rgb(${f.shade},${f.shade},${f.shade})`, opacity: f.op, transform: `rotate(${f.rot}deg)`, pointerEvents: 'none'}} />
      ))}
      {textureData.scr.map((s, i) => (
        <div key={'s'+i} style={{position: 'absolute', left: s.x, top: s.y, width: s.w, height: s.h, backgroundColor: `rgb(${s.shade},${s.shade},${s.shade})`, opacity: s.op, transform: `rotate(${s.rot}deg)`, pointerEvents: 'none'}} />
      ))}
      {textureData.spk.map((p, i) => (
        <div key={'p'+i} style={{position: 'absolute', left: p.x, top: p.y, width: p.sz, height: p.sz, borderRadius: '50%', backgroundColor: `rgb(${p.shade},${p.shade},${p.shade})`, opacity: p.op, pointerEvents: 'none'}} />
      ))}
      <div style={{position: 'absolute', top: 0, left: 0, width: '15%', height: '100%', backdropFilter: 'blur(2px)', WebkitBackdropFilter: 'blur(2px)', maskImage: 'linear-gradient(to right, rgba(0,0,0,1) 0%, rgba(0,0,0,0) 100%)', WebkitMaskImage: 'linear-gradient(to right, rgba(0,0,0,1) 0%, rgba(0,0,0,0) 100%)', pointerEvents: 'none'}} />
      <div style={{position: 'absolute', top: 0, right: 0, width: '15%', height: '100%', backdropFilter: 'blur(2px)', WebkitBackdropFilter: 'blur(2px)', maskImage: 'linear-gradient(to left, rgba(0,0,0,1) 0%, rgba(0,0,0,0) 100%)', WebkitMaskImage: 'linear-gradient(to left, rgba(0,0,0,1) 0%, rgba(0,0,0,0) 100%)', pointerEvents: 'none'}} />
      <div style={{zIndex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center'}}>
