const VideoProgressBarV2 = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const primaryColor = props.primaryColor;
  const highlightColor = props.highlightColor || primaryColor;
  const promptText = props.promptText;
  const highlightWord = props.highlightWord;
  const segment1 = props.segment1;
  const segment2 = props.segment2;
  const segment3 = props.segment3;
  const segment4 = props.segment4;
  const fontFamily = props.fontFamily;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const progress = Math.min(1, Math.max(0, frame / (durationInFrames - 1)));
  const percentage = Math.floor(progress * 100);
  const totalSecs = Math.round(durationInFrames / fps);

  // Larger video window — fills more vertical space
  const WIN_W = 1160;
  const WIN_H = 640;
  const WIN_R = 24;

  // Layout constants (absolute positions within 1920x1080)
  // Title above window, gap 32px; window top at 110px
  const TITLE_TOP = 60;
  const WIN_TOP = 150;
  // Shadow div center offset from vertical center
  // Canvas center = 540. Win center Y = WIN_TOP + WIN_H/2 = 110 + 320 = 430
  // offset from 50% (540): 430 - 540 = -110
  const WIN_CENTER_OFFSET_Y = WIN_TOP + WIN_H / 2 - DESIGN_HEIGHT / 2; // -110

  const UI_TOP = WIN_TOP + WIN_H; // 750 — percentage/pills/bar start here

  const renderPromptText = () => {
    if (!highlightWord || !promptText) return promptText;
    const regex = new RegExp(`(${highlightWord})`, 'gi');
    const parts = promptText.split(regex);
    return parts.map((part, i) =>
      part.toLowerCase() === highlightWord.toLowerCase() ? (
        <span key={i} style={{ color: highlightColor, fontWeight: 700 }}>{part}</span>
      ) : (
        <span key={i}>{part}</span>
      )
    );
  };

  const segments = [segment1, segment2, segment3, segment4];
  const activeIndex = Math.min(3, Math.floor(progress * 4));
  const numTicks = 80;

  return (
    <div style={{
      position: 'absolute',
      top: 0, left: 0,
      width: DESIGN_WIDTH,
      height: DESIGN_HEIGHT,
      transform: `scale(${scale})`,
      transformOrigin: 'top left',
      fontFamily: fontFamily,
      backgroundColor: 'transparent',
    }}>

      {/*
        ── MASK via box-shadow ──
        The div is the exact size of the video window.
        box-shadow 3000px white fills everything outside the rounded rect.
        The window interior stays transparent so the video layer below shows through.
      */}
      <div style={{
        position: 'absolute',
        top: WIN_TOP,
        left: (DESIGN_WIDTH - WIN_W) / 2,
        width: WIN_W,
        height: WIN_H,
        borderRadius: WIN_R,
        backgroundColor: 'transparent',
        boxShadow: '0 0 0 3000px #ffffff',
      }} />

      {/* ── Title ── */}
      <div style={{
        position: 'absolute',
        top: TITLE_TOP,
        left: 0,
        right: 0,
        display: 'flex',
        justifyContent: 'center',
        fontSize: 48,
        fontWeight: 500,
        color: '#27272a',
        letterSpacing: '-0.02em',
        zIndex: 2,
      }}>
        {renderPromptText()}
      </div>

      {/* ── Bottom UI ── */}
      <div style={{
        position: 'absolute',
        top: UI_TOP,
        left: 0,
        right: 0,
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        zIndex: 2,
      }}>

        {/* Percentage badge */}
        <div style={{
          marginTop: 20,
          padding: '5px 18px',
          backgroundColor: '#f4f4f5',
          borderRadius: 20,
          fontSize: 19,
          fontWeight: 600,
          color: '#71717a',
        }}>
          {percentage}%
        </div>

        {/* Segment pills */}
        <div style={{ display: 'flex', gap: 20, marginTop: 16 }}>
          {segments.map((seg, i) => {
            const isActive = i === activeIndex;
            const startFrame = (i / 4) * durationInFrames;
            const sp = spring({
              frame: Math.max(0, frame - startFrame),
              fps,
              config: { damping: 14, stiffness: 200 },
            });
            const scaleVal = isActive ? interpolate(sp, [0, 1], [1, 1.06]) : 1;
            return (
              <div key={i} style={{
                padding: '12px 28px',
                borderRadius: 14,
                backgroundColor: isActive ? primaryColor : '#f4f4f5',
                color: isActive ? '#ffffff' : '#52525b',
                fontSize: 20,
                fontWeight: 600,
                transform: `scale(${scaleVal})`,
                boxShadow: isActive ? `0 10px 20px ${primaryColor}40` : 'none',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
              }}>
                {seg}
              </div>
            );
          })}
        </div>

        {/* Floating progress bar card */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          gap: 20,
          marginTop: 24,
          backgroundColor: '#ffffff',
          padding: '16px 60px',
          borderRadius: 28,
          boxShadow: '0 8px 32px rgba(0,0,0,0.10)',
        }}>
          <div style={{ fontSize: 17, color: '#a1a1aa', fontWeight: 500, fontVariantNumeric: 'tabular-nums' }}>
            00 sec
          </div>
          <div style={{ display: 'flex', gap: 6 }}>
            {Array.from({length: numTicks}).map((_, i) => {
              const fillP = i / (numTicks - 1);
              const isFilled = fillP <= progress;
              const ds = spring({
                frame: isFilled ? Math.max(0, frame - Math.floor(fillP * durationInFrames)) : 0,
                fps,
                config: { damping: 15 },
              });
              const dotScale = isFilled ? interpolate(ds, [0, 1], [0.5, 1]) : 1;
              return (
                <div key={i} style={{
                  width: 4,
                  height: 15,
                  borderRadius: 2,
                  backgroundColor: isFilled ? primaryColor : '#e4e4e7',
                  transform: `scaleY(${dotScale})`,
                  transformOrigin: 'bottom',
                }} />
              );
            })}
          </div>
          <div style={{ fontSize: 17, color: '#a1a1aa', fontWeight: 500, fontVariantNumeric: 'tabular-nums' }}>
            {totalSecs} sec
          </div>
        </div>
      </div>
    </div>
  );
};

