  const props = item.props || {};

  const safeFps = fps || 30;
  const safeSpring = (delay = 0, config = { damping: 15, mass: 1, stiffness: 100 }) => {
    return spring({ frame: Math.max(0, frame - delay), fps: safeFps, config });
  };

  // Properties
  const transparentBackground = props.transparentBackground;
  const bgColor = transparentBackground ? 'transparent' : (props.bgColor);
  const goldColor = props.goldColor;
  const creamColor = props.creamColor;
  const fontFamily = props.fontFamily;

  // Animation Springs
  const bgSpring = safeSpring(0);
  const borderSpring = safeSpring(10);
  const s1 = safeSpring(15); // Title
  const s2 = safeSpring(30); // Chart
  const s3 = safeSpring(45); // Name tag
  const s4 = safeSpring(60); // Bullets
  const s5 = safeSpring(75); // Quote
  const s6 = safeSpring(90); // Timeline

  const rootStyle = {
    position: 'absolute',
    inset: 0,
