  );

  const CornerDiamond = ({ top, bottom, left, right, color, item }) => {
    const style = { position: 'absolute', width: 14, height: 14, backgroundColor: color, transform: 'rotate(45deg)' };
    if (top !== undefined) style.top = top;
    if (bottom !== undefined) style.bottom = bottom;
    if (left !== undefined) style.left = left;
    if (right !== undefined) style.right = right;
    return <div style={style} />;
  };

  const ChartRow = ({ label, percentage, color, textColor, progress, item }) => (
    <div style={{ marginBottom: 35 }}>
      <div style={{ color: textColor, fontSize: 28, letterSpacing: 2, marginBottom: 15 }}>{label}</div>
      <div style={{ width: '100%', height: 18, border: `1px solid ${color}`, padding: 3, boxSizing: 'border-box' }}>
        <div style={{ width: `${progress * percentage}%`, height: '100%', backgroundColor: color }} />
      </div>
    </div>
  );

  const Bullet = ({ text, color, textColor, delayOffset, item }) => {
    const bSpring = safeSpring(60 + delayOffset);
    return (
      <div style={{ display: 'flex', alignItems: 'center', marginBottom: 30, opacity: bSpring, transform: `translateX(${interpolate(bSpring, [0, 1], [-20, 0])})` }}>
        <div style={{ marginRight: 25 }}>
          <svg width="24" height="24" viewBox="0 0 24 24">
            <path d="M12 0 L24 12 L12 24 L0 12 Z" fill={color} />
          </svg>
        </div>
        <div style={{ color: textColor, fontSize: 34, letterSpacing: 1 }}>{text}</div>
      </div>
    );
  };

  return (
    <div style={rootStyle}>
      {/* Background Pattern */}
      <div style={{ position: 'absolute', inset: 0, opacity: interpolate(bgSpring, [0, 1], [0, 0.05]) }}>
        <svg width="100%" height="100%" xmlns="http://www.w3.org/2000/svg">
          <defs>
            <pattern id="deco-pattern" x="0" y="0" width="120" height="120" patternUnits="userSpaceOnUse">
              <circle cx="60" cy="60" r="60" stroke={goldColor} strokeWidth="1" fill="none" />
              <circle cx="120" cy="120" r="60" stroke={goldColor} strokeWidth="1" fill="none" />
              <circle cx="0" cy="120" r="60" stroke={goldColor} strokeWidth="1" fill="none" />
              <circle cx="120" cy="0" r="60" stroke={goldColor} strokeWidth="1" fill="none" />
              <circle cx="0" cy="0" r="60" stroke={goldColor} strokeWidth="1" fill="none" />
            </pattern>
          </defs>
          <rect x="0" y="0" width="100%" height="100%" fill="url(#deco-pattern)" />
        </svg>
      </div>

      {/* Main Double Border */}
      <div style={{ position: 'absolute', inset: 30, border: `2px solid ${goldColor}`, opacity: borderSpring, pointerEvents: 'none' }} />
      <div style={{ position: 'absolute', inset: 42, border: `1px solid ${goldColor}`, opacity: borderSpring, pointerEvents: 'none' }} />
      {/* Border Corner Accents */}
      <div style={{ position: 'absolute', top: 30, left: 30, width: 20, height: 20, borderBottom: `2px solid ${goldColor}`, borderRight: `2px solid ${goldColor}`, opacity: borderSpring }} />
      <div style={{ position: 'absolute', top: 30, right: 30, width: 20, height: 20, borderBottom: `2px solid ${goldColor}`, borderLeft: `2px solid ${goldColor}`, opacity: borderSpring }} />
      <div style={{ position: 'absolute', bottom: 30, left: 30, width: 20, height: 20, borderTop: `2px solid ${goldColor}`, borderRight: `2px solid ${goldColor}`, opacity: borderSpring }} />
      <div style={{ position: 'absolute', bottom: 30, right: 30, width: 20, height: 20, borderTop: `2px solid ${goldColor}`, borderLeft: `2px solid ${goldColor}`, opacity: borderSpring }} />

      {/* Section 1: Title */}
      <div style={{ position: 'absolute', top: 120, left: 120, width: 750, textAlign: 'center' }}>
        <div style={{ color: creamColor, fontSize: 32, letterSpacing: 8, opacity: s1, transform: `translateY(${interpolate(s1, [0, 1], [20, 0])})` }}>
          {props.chapterSubtitle}
        </div>
        <div style={{ margin: '25px 0' }}>
          <LineWithDiamond progress={s1} color={goldColor} />
        </div>
        <div style={{ color: goldColor, fontSize: 85, fontWeight: 'bold', letterSpacing: 4, transform: `scale(${interpolate(s1, [0, 1], [0.95, 1])})`, opacity: s1, lineHeight: 1.1 }}>
          {props.chapterTitle}
        </div>
        <div style={{ margin: '25px 0' }}>
          <LineWithDiamond progress={s1} color={goldColor} />
        </div>
      </div>

      {/* Section 3: Name Tag */}
      <div style={{ position: 'absolute', top: 480, left: 145, width: 700, padding: 45, border: `2px solid ${goldColor}`, textAlign: 'center', opacity: s3, transform: `scale(${interpolate(s3, [0, 1], [0.95, 1])})`, boxSizing: 'border-box' }}>
        <div style={{ position: 'absolute', inset: 8, border: `1px solid ${goldColor}` }} />
        <CornerDiamond top={-7} left={-7} color={goldColor} />
        <CornerDiamond top={-7} right={-7} color={goldColor} />
        <CornerDiamond bottom={-7} left={-7} color={goldColor} />
        <CornerDiamond bottom={-7} right={-7} color={goldColor} />
        <div style={{ color: goldColor, fontSize: 50, letterSpacing: 10, fontWeight: 'bold' }}>{props.nameText}</div>
        <div style={{ color: creamColor, fontSize: 26, letterSpacing: 6, marginTop: 15, fontStyle: 'italic' }}>{props.roleText}</div>
      </div>

      {/* Section 5: Highlight Quote */}
      <div style={{ position: 'absolute', top: 780, left: 120, width: 750, textAlign: 'center', opacity: s5, transform: `translateY(${interpolate(s5, [0, 1], [20, 0])})` }}>
        <div style={{ color: goldColor, fontSize: 100, position: 'absolute', left: 40, top: -50, opacity: 0.2, fontFamily: 'serif' }}>"</div>
        <div style={{ color: creamColor, fontSize: 40, fontStyle: 'italic', lineHeight: 1.5, letterSpacing: 1, padding: '0 40px' }}>
          {props.quoteText}
        </div>
        <div style={{ color: goldColor, fontSize: 100, position: 'absolute', right: 40, bottom: -90, opacity: 0.2, fontFamily: 'serif' }}>"</div>
      </div>

      {/* Section 2: Chart */}
      {frame >= 30 && (
      <div style={{ position: 'absolute', top: 140, left: 1050, width: 700 }}>
        <ChartRow label={props.chartLabel1} percentage={82} color={goldColor} textColor={creamColor} progress={s2} />
        <ChartRow label={props.chartLabel2} percentage={90} color={goldColor} textColor={creamColor} progress={s2} />
        <ChartRow label={props.chartLabel3} percentage={78} color={goldColor} textColor={creamColor} progress={s2} />
      </div>
      )}

      {/* Section 4: Bullets */}
      <div style={{ position: 'absolute', top: 480, left: 1050, width: 700 }}>
        <Bullet text={props.bullet1} color={goldColor} textColor={creamColor} delayOffset={0} />
        <Bullet text={props.bullet2} color={goldColor} textColor={creamColor} delayOffset={5} />
        <Bullet text={props.bullet3} color={goldColor} textColor={creamColor} delayOffset={10} />
      </div>

      {/* Section 6: Timeline */}
      <div style={{ position: 'absolute', top: 820, left: 1050, width: 700, opacity: s6 }}>
        <div style={{ width: '100%', height: 2, background: goldColor, marginTop: 40, transform: `scaleX(${s6})`, transformOrigin: 'left' }} />
        <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: -11 }}>
          {[props.time1, props.time2, props.time3, props.time4].map((y, i) => (
            <div key={i} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: 80, transform: `translateY(${interpolate(s6, [0, 1], [15, 0])})`, opacity: s6 }}>
              <svg width="20" height="20" viewBox="0 0 24 24">
                <path d="M12 0 L24 12 L12 24 L0 12 Z" fill={goldColor}/>
              </svg>
              <div style={{ color: creamColor, marginTop: 25, fontSize: 28, letterSpacing: 3 }}>{y}</div>
            </div>
          ))}
        </div>
      </div>

    </div>
  );
};

const AnimatedBarChart = ({item}) => {
  const frame = useCurrentFrame();
const DESIGN_WIDTH = 1920;
const DESIGN_HEIGHT = 1080;
const scale = Math.min(
  (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
  (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
);

  const props = item.props;
  const val1 = props.val1;
  const val2 = props.val2;
  const val3 = props.val3;
  const val4 = props.val4;
  const yr1 = props.yr1;
  const yr2 = props.yr2;
  const yr3 = props.yr3;
  const yr4 = props.yr4;
  const color1 = props.color1;
  const color2 = props.color2;
  const color3 = props.color3;
  const color4 = props.color4;
  const bgColor = props.bgColor;
  const waveColor = props.waveColor;
  const axisColor = props.axisColor;
  const textFont = props.textFont;

  const CHART_LEFT = 380;
  const CHART_RIGHT = 1600;
  const CHART_TOP = 150;
  const CHART_BOTTOM = 900;
  const CHART_H = CHART_BOTTOM - CHART_TOP;

  // Y-axis: 0 to 10,000 hrs
  const yMax = 10000;
  const yTicks = [0, 2500, 5000, 7500, 10000];
  const yLabel = (v) => v === 0 ? '0' : `${(v/1000).toFixed(v % 1000 === 0 ? 0 : 1)}K hrs`;
  const yToPixel = (v) => CHART_BOTTOM - (v / yMax) * CHART_H;

  // Actual data values
  const dataValues = [365, 730, 1460, 10000];
  const maxH = dataValues.map(v => Math.max((v / yMax) * CHART_H, 6));

  const bellEase = Easing.bezier(0.25, 0, 0.1, 1);

  const p1 = interpolate(frame, [0,   42],  [0, 1], {extrapolateLeft:'clamp', extrapolateRight:'clamp', easing: bellEase});
  const p2 = interpolate(frame, [40,  82],  [0, 1], {extrapolateLeft:'clamp', extrapolateRight:'clamp', easing: bellEase});
  const p3 = interpolate(frame, [80,  122], [0, 1], {extrapolateLeft:'clamp', extrapolateRight:'clamp', easing: bellEase});
  const p4 = interpolate(frame, [120, 162], [0, 1], {extrapolateLeft:'clamp', extrapolateRight:'clamp', easing: bellEase});

  const heights = [p1*maxH[0], p2*maxH[1], p3*maxH[2], p4*maxH[3]];

  const lo1 = interpolate(frame, [40,  50],  [0, 1], {extrapolateLeft:'clamp', extrapolateRight:'clamp'});
  const lo2 = interpolate(frame, [80,  90],  [0, 1], {extrapolateLeft:'clamp', extrapolateRight:'clamp'});
  const lo3 = interpolate(frame, [120, 130], [0, 1], {extrapolateLeft:'clamp', extrapolateRight:'clamp'});
  const lo4 = interpolate(frame, [160, 170], [0, 1], {extrapolateLeft:'clamp', extrapolateRight:'clamp'});
  const labelOps = [lo1, lo2, lo3, lo4];

  const makeFill = (cx, bw, base, h) => {
    if (h <= 0) return 'M 0 0';
    const ins = 2;
    const r = Math.min(6, h / 2);
    const l = cx - bw/2 + ins, rr = cx + bw/2 - ins;
    const t = base - h + ins;
    return `M${l},${base} L${l},${t+r} A${r},${r} 0 0,1 ${l+r},${t} L${rr-r},${t} A${r},${r} 0 0,1 ${rr},${t+r} L${rr},${base} Z`;
  };
  const makeStroke = (cx, bw, base, h) => {
    if (h <= 0) return 'M 0 0';
    const r = Math.min(6, h / 2);
    const l = cx - bw/2, rr = cx + bw/2;
    const t = base - h;
    return `M${l},${base} L${l},${t+r} A${r},${r} 0 0,1 ${l+r},${t} L${rr-r},${t} A${r},${r} 0 0,1 ${rr},${t+r} L${rr},${base} Z`;
  };

  const BW = 110;
  const BASE = CHART_BOTTOM;
  const centers = [500, 800, 1100, 1400];
  const values  = [val1, val2, val3, val4];
  const years   = [yr1,  yr2,  yr3,  yr4];
  const colors  = [color1, color2, color3, color4];
  const labelTops = maxH.map(h => BASE - h - 62);

  return (
    <div style={{position:'absolute',inset:0,backgroundColor:bgColor,overflow:'hidden',userSelect:'none'}}>
      <svg style={{position:'absolute',inset:0,width:1920,height:1080}} xmlns="http://www.w3.org/2000/svg">
        <path d="M 550,1080 C 800,1080 1000,1000 1200,900 C 1400,800 1600,650 1920,480 L 1920,1080 Z" fill={waveColor}/>
        {yTicks.map((val, i) => {
          const y = yToPixel(val);
          return (
            <g key={`ytick-${i}`}>
              <line
                x1={CHART_LEFT} y1={y}
                x2={CHART_RIGHT} y2={y}
                stroke="#B8B2AA"
                strokeWidth="1"
                strokeDasharray={val === 0 ? 'none' : '4 6'}
                strokeOpacity="0.55"
              />
            </g>
          );
        })}
        <polyline
          points={`${CHART_LEFT},${CHART_TOP} ${CHART_LEFT},${CHART_BOTTOM} ${CHART_RIGHT},${CHART_BOTTOM}`}
          stroke={axisColor} strokeWidth="3" fill="none" strokeLinecap="square"
        />
        {centers.map((cx, i) => (
          <g key={`bar-${i}`}>
            <path d={makeFill(cx, BW, BASE, heights[i])}   fill={colors[i]} fillOpacity="0.72" stroke="none"/>
            <path d={makeStroke(cx, BW, BASE, heights[i])} fill="none" stroke="#1C1C1C" strokeWidth="2" strokeDasharray="8 6" strokeOpacity="0.75"/>
          </g>
        ))}
      </svg>

      {yTicks.map((val, i) => {
        const y = yToPixel(val);
        return (
          <div key={`ylabel-${i}`} style={{
            position:'absolute',
            right: 1920 - CHART_LEFT + 12,
            top: y - 14,
            width: 140,
            textAlign:'right',
            fontFamily: textFont,
            fontWeight: 400,
            fontSize: 22,
            color: '#888078',
            pointerEvents:'none',
            letterSpacing: '0px'
          }}>
            {yLabel(val)}
          </div>
        );
      })}

      {centers.map((cx, i) => (
        <React.Fragment key={`lbl-${i}`}>
          <div style={{
            position:'absolute', left:cx-150, width:300, top:labelTops[i],
            textAlign:'center', opacity:labelOps[i],
            fontFamily:textFont, fontWeight:700, fontSize:46, color:axisColor,
            letterSpacing:'-1px', pointerEvents:'none'
          }}>
            {values[i]}
          </div>
          <div style={{
            position:'absolute', left:cx-100, width:200, top:BASE+24,
            textAlign:'center',
            fontFamily: textFont,
            fontWeight:500, fontSize:28, color:axisColor, pointerEvents:'none'
          }}>
            {years[i]}
          </div>
        </React.Fragment>
      ))}
    </div>
  );
}

const BlackFridayShowcase = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const safeFps = fps || 30;

  const props = item.props || {};
  const bgColor = props.bgColor;
  const transparentBackground = props.transparentBackground;
  const glowColor = props.glowColor;
  const accentColor = props.accentColor;
  const textColor = props.textColor;
  const titleFont = props.titleFont;
  const bodyFont = props.bodyFont;

  const titleText = props.titleText;
  const quoteText = props.quoteText;
  const nameTagBrand = props.nameTagBrand;
  const nameTagEvent = props.nameTagEvent;

  const bar1Label = props.bar1Label;
  const bar1Value = props.bar1Value;
  const bar2Label = props.bar2Label;
  const bar2Value = props.bar2Value;
  const bar3Label = props.bar3Label;
  const bar3Value = props.bar3Value;

  const bullet1 = props.bullet1;
  const bullet2 = props.bullet2;
  const bullet3 = props.bullet3;

  const timeline1 = props.timeline1;
  const timeline2 = props.timeline2;
  const timeline3 = props.timeline3;
  const timeline4 = props.timeline4;

  const safeSpring = (delay = 0, config = { damping: 15 }) => {
    return spring({
      frame: Math.max(0, frame - delay),
      fps: safeFps,
      config
    });
  };

  // Main Background
  const backgroundColor = transparentBackground ? 'transparent' : bgColor;

  // Animations
  const bgFade = interpolate(frame, [0, 15], [0, 1]);
  const titleSpring = safeSpring(10, { damping: 14 });
  const titleOpacity = interpolate(frame, [10, 25], [0, 1]);

  const chartPanelSpring = safeSpring(20);
  const chartOpacity = interpolate(frame, [20, 35], [0, 1]);

  const bulletPanelSpring = safeSpring(25);
  const bulletOpacity = interpolate(frame, [25, 40], [0, 1]);

  const nameTagSpring = safeSpring(30);
  const nameTagOpacity = interpolate(frame, [30, 45], [0, 1]);

  const quoteSpring = safeSpring(35);
  const quoteOpacity = interpolate(frame, [35, 50], [0, 1]);

  const timelineLineSpring = safeSpring(40);
  const timelineOpacity = interpolate(frame, [40, 55], [0, 1]);

  const chartBars = [
    { label: bar1Label, val: bar1Value, s: safeSpring(35) },
    { label: bar2Label, val: bar2Value, s: safeSpring(45) },
    { label: bar3Label, val: bar3Value, s: safeSpring(55) },
  ];

  const bullets = [
    { text: bullet1, s: safeSpring(40) },
    { text: bullet2, s: safeSpring(50) },
    { text: bullet3, s: safeSpring(60) },
  ];

  const timelineNodes = [
    { text: timeline1, s: safeSpring(50) },
    { text: timeline2, s: safeSpring(60) },
    { text: timeline3, s: safeSpring(70) },
    { text: timeline4, s: safeSpring(80) },
  ];

  // Shared Glass Style
  const glassPanel = {
    backgroundColor: 'rgba(255, 255, 255, 0.03)',
    borderTop: '1px solid rgba(255, 255, 255, 0.15)',
    borderLeft: '1px solid rgba(255, 255, 255, 0.08)',
    borderRight: '1px solid rgba(255, 255, 255, 0.02)',
    borderBottom: '1px solid rgba(255, 255, 255, 0.02)',
    borderRadius: 24,
    boxShadow: `0 20px 50px rgba(0,0,0,0.8), inset 0 0 30px ${accentColor}11`,
    position: 'absolute',
  };

  return (
    <div style={{ position: 'absolute', inset: 0, backgroundColor, overflow: 'hidden' }}>
      {/* Ambient Red Glows */}
      <div style={{ position: 'absolute', top: -300, left: '10%', width: 1000, height: 1000, background: `radial-gradient(circle, ${glowColor} 0%, transparent 60%)`, opacity: bgFade * 0.6, borderRadius: '50%' }} />
      <div style={{ position: 'absolute', bottom: -400, right: '-5%', width: 1200, height: 1200, background: `radial-gradient(circle, ${glowColor} 0%, transparent 60%)`, opacity: bgFade * 0.4, borderRadius: '50%' }} />

      {/* 1. Chapter Title */}
      <div style={{ 
        ...glassPanel, 
        left: 260, top: 100, width: 1400, height: 260, 
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        opacity: titleOpacity, 
        transform: `scale(${interpolate(titleSpring, [0, 1], [0.95, 1])}) translateY(${interpolate(titleSpring, [0, 1], [20, 0])}px)`
      }}>
        <h1 style={{ 
          fontFamily: titleFont, fontSize: 160, fontWeight: 900, 
          color: textColor, margin: 0, letterSpacing: 8,
          textShadow: `-2px -2px 0px rgba(255,255,255,0.2), 5px 5px 0px rgba(0,0,0,0.9), 0 0 50px ${accentColor}`
        }}>
          {titleText}
