      }}>
        <span style={{ fontFamily: titleFont, color: textColor, fontSize: 24, fontWeight: 'bold', letterSpacing: 2 }}>{nameTagBrand}</span>
        <span style={{ width: 2, height: 24, backgroundColor: accentColor, boxShadow: `0 0 10px ${accentColor}` }} />
        <span style={{ fontFamily: bodyFont, color: 'rgba(255,255,255,0.8)', fontSize: 22 }}>{nameTagEvent}</span>
