            <div key={i} style={{ 
              position: 'absolute', left: nodeCenter - 60, top: 12, width: 120,
              display: 'flex', flexDirection: 'column', alignItems: 'center', 
              opacity: interpolate(n.s, [0, 1], [0, 1]), 
              transform: `scale(${interpolate(n.s, [0, 1], [0.5, 1])})` 
            }}>
              <div style={{ 
                width: 22, height: 22, borderRadius: '50%', 
                backgroundColor: bgColor, 
                border: `4px solid ${accentColor}`, 
                boxShadow: `0 0 15px ${accentColor}`, 
                boxSizing: 'border-box' 
              }} />
              <span style={{ 
                marginTop: 18, fontFamily: titleFont, color: textColor, fontSize: 22, letterSpacing: 1,
                textShadow: `0 2px 4px rgba(0,0,0,0.8)`
              }}>
                {n.text}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const Component = ({item}) => {
