const StyleShowcase = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
  const safeFps = fps || 30;

  const props = item.props || {};
  const transparentBg = props.transparentBackground;
  const bgColor = props.bgColor;
  const primaryColor = props.primaryColor;
  const textColor = props.textColor;
  const primaryFont = props.primaryFont;

  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor: transparentBg ? 'transparent' : bgColor,
    overflow: 'hidden'
  };

  const titleWords = (props.titleText).split(' ');
  const bars = [
    { label: props.bar1Label, value: props.bar1Value },
    { label: props.bar2Label, value: props.bar2Value },
    { label: props.bar3Label, value: props.bar3Value },
  ];
  const bullets = [props.bullet1Text, props.bullet2Text, props.bullet3Text];
  const quoteWords = (props.quoteText).split(' ');
  const timelines = [props.timeline1Text, props.timeline2Text, props.timeline3Text, props.timeline4Text];

  return (
    <div style={rootStyle}>
      {/* 1. Chapter Title */}
      <div style={{ 
        position: 'absolute', left: 100, top: 100, width: 1000, 
        display: 'flex', flexWrap: 'wrap', gap: '0 30px' 
      }}>
        {titleWords.map((word, i) => {
          const wSpring = spring({ frame: Math.max(0, frame - (i * 4)), fps: safeFps, config: { damping: 15 } });
          const y = interpolate(wSpring, [0, 1], [50, 0]);
          const opacity = interpolate(wSpring, [0, 1], [0, 1]);
          return (
            <span key={i} style={{ 
              fontFamily: primaryFont, fontSize: 190, color: primaryColor, 
              textTransform: 'uppercase', lineHeight: 0.9,
              opacity, transform: `translateY(${y}px)`, display: 'inline-block',
              margin: 0
            }}>
              {word}
            </span>
          );
        })}
      </div>

      {/* 2. Data Chart */}
      <div style={{ position: 'absolute', right: 100, top: 100, width: 560, display: 'flex', flexDirection: 'column', gap: 40 }}>
        {bars.map((bar, i) => {
          const delay = 15 + i * 5;
          const bSpring = spring({ frame: Math.max(0, frame - delay), fps: safeFps, config: { damping: 15 } });
          const barW = bSpring * bar.value;
          const textOp = interpolate(bSpring, [0, 0.5], [0, 1], { extrapolateRight: 'clamp' });
          return (
            <div key={i} style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontFamily: primaryFont, fontSize: 36, textTransform: 'uppercase', opacity: textOp }}>
                <span style={{ color: textColor }}>{bar.label}</span>
                <span style={{ color: primaryColor }}>{bar.value}%</span>
              </div>
              {frame >= (15 + i * 5) && <div style={{ width: '100%', height: 28, backgroundColor: 'rgba(255,255,255,0.1)', overflow: 'hidden' }}>
                <div style={{ width: `${barW}%`, height: '100%', backgroundColor: primaryColor }} />
              </div>}
            </div>
          );
        })}
      </div>

      {/* 3. Bullet Points */}
      <div style={{ position: 'absolute', right: 100, top: 480, width: 560, display: 'flex', flexDirection: 'column', gap: 24 }}>
        {bullets.map((txt, i) => {
          const delay = 35 + i * 5;
          const blSpring = spring({ frame: Math.max(0, frame - delay), fps: safeFps, config: { damping: 15 } });
          const x = interpolate(blSpring, [0, 1], [-30, 0]);
          const opacity = interpolate(blSpring, [0, 1], [0, 1]);
          return (
            <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 24, opacity, transform: `translateX(${x}px)` }}>
              <div style={{ width: 24, height: 24, backgroundColor: primaryColor, flexShrink: 0 }} />
