            </div>
          );
        })}
      </div>

      {/* 4. Name Tag */}
      {(() => {
        const nSpring = spring({ frame: Math.max(0, frame - 55), fps: safeFps, config: { damping: 15 } });
        const opacity = interpolate(nSpring, [0, 1], [0, 1]);
        const y = interpolate(nSpring, [0, 1], [30, 0]);
        return (
          <div style={{ position: 'absolute', left: 100, bottom: 220, display: 'flex', flexDirection: 'column', opacity, transform: `translateY(${y}px)` }}>
