        {quoteWords.map((word, i) => {
          const qSpring = spring({ frame: Math.max(0, frame - (45 + i * 3)), fps: safeFps, config: { damping: 15 } });
          const opacity = interpolate(qSpring, [0, 1], [0, 1]);
          const y = interpolate(qSpring, [0, 1], [15, 0]);
          return (
            <span key={i} style={{ 
              fontFamily: primaryFont, fontSize: 50, color: textColor, 
              fontStyle: 'italic', opacity, transform: `translateY(${y}px)`,
              display: 'inline-block', lineHeight: 1.1
            }}>
              {word}
            </span>
          );
        })}
      </div>

      {/* 6. Timeline */}
      {(() => {
        const tlDelay = 40;
        const lineWidth = interpolate(frame - tlDelay, [0, 25], [0, 100], { extrapolateRight: 'clamp', easing: Easing.bezier(0.25, 0.1, 0.25, 1) });
        return (
          <div style={{ position: 'absolute', left: 100, right: 100, bottom: 60, height: 80 }}>
            {frame >= 40 && <div style={{ position: 'absolute', top: 38, left: 0, height: 6, backgroundColor: 'rgba(255,255,255,0.15)', width: '100%' }} />}
            <div style={{ position: 'absolute', top: 38, left: 0, height: 6, backgroundColor: primaryColor, width: `${lineWidth}%` }} />

            {timelines.map((yr, i) => {
              const leftPercent = i * (100 / (timelines.length - 1));
              const dotDelay = tlDelay + (leftPercent / 100) * 25;
              const dSpring = spring({ frame: Math.max(0, frame - dotDelay), fps: safeFps, config: { damping: 15 } });
              const scale = interpolate(dSpring, [0, 1], [0, 1]);
              const opacity = interpolate(dSpring, [0, 1], [0, 1]);
              return (
                <div key={i} style={{ 
                  position: 'absolute', left: `${leftPercent}%`, top: 41, 
                  transform: 'translate(-50%, -50%)', display: 'flex', flexDirection: 'column', alignItems: 'center' 
                }}>
                  <div style={{ 
                    width: 28, height: 28, borderRadius: 14, 
                    backgroundColor: primaryColor, transform: `scale(${scale})` 
                  }} />
                  <div style={{ 
                    position: 'absolute', top: 35, 
                    fontFamily: primaryFont, fontSize: 32, color: textColor, opacity 
                  }}>
                    {yr}
                  </div>
                </div>
              );
            })}
          </div>
        );
      })()}
    </div>
  );
};

const CartoonStyleShowcase = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const props = item.props || {};

  const transparentBackground = props.transparentBackground;
  const bgColor = transparentBackground ? 'transparent' : (props.bgColor);
  const primaryColor = props.primaryColor;
  const accentColor = props.accentColor;
  const fontFamily = props.fontFamily;
  const bodyFontFamily = props.bodyFontFamily;

  const safeSpring = (delay = 0, config = { damping: 15, mass: 0.8, stiffness: 120 }) => {
    return spring({ frame: Math.max(0, frame - delay), fps, config });
  };

  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor: bgColor,
    overflow: 'hidden',
    fontFamily,
    color: primaryColor,
  };

  // Timings based on brief
  const titleDelay = 0;
  const chartDelay = 36;
  const nameDelay = 72;
  const bulletDelays = [108, 120, 132];
  const quoteDelay = 150;
  const timelineDelay = 174;

  // Title Animation
  const titlePop = safeSpring(titleDelay);
  const titleY = interpolate(titlePop, [0, 1], [50, 0]);

  // Chart Animations
  const bar1Width = safeSpring(chartDelay, { damping: 18 }) * (props.chartVal1);
  const bar2Width = safeSpring(chartDelay + 6, { damping: 18 }) * (props.chartVal2);
  const bar3Width = safeSpring(chartDelay + 12, { damping: 18 }) * (props.chartVal3);

  // Name Tag
  const namePop = safeSpring(nameDelay);

  // Quote Animation
  const quotePop = safeSpring(quoteDelay);

  // Timeline Animation
  const timelineDraw = safeSpring(timelineDelay, { damping: 20 });

  const Sparkle = ({ left, top, delay, size = 40, rotation = 0, item }) => {
    const s = safeSpring(delay);
    return (
      <div style={{ position: 'absolute', left, top, width: size, height: size, transform: `scale(${s}) rotate(${rotation}deg)` }}>
        <svg width="100%" height="100%" viewBox="0 0 24 24" style={{ overflow: 'visible' }}>
          <path
            d="M12 0 C12 10, 22 12, 22 12 C22 12, 12 14, 12 24 C12 14, 2 12, 2 12 C2 12, 12 10, 12 0 Z"
            fill="transparent"
            stroke={accentColor}
            strokeWidth="1.5"
          />
        </svg>
      </div>
    );
  };

  return (
    <div style={rootStyle}>
      {/* 1. Chapter Title */}
      <div style={{ position: 'absolute', left: 120, top: 120, transform: `scale(${titlePop}) translateY(${titleY}px)`, opacity: titlePop }}>
        <div style={{ position: 'relative', display: 'inline-block', marginBottom: 20 }}>
          <svg style={{ position: 'absolute', inset: -20, width: 'calc(100% + 40px)', height: 'calc(100% + 40px)' }}>
            <ellipse cx="50%" cy="50%" rx="48%" ry="48%" fill="transparent" stroke={accentColor} strokeWidth="3" />
          </svg>
          <span style={{ fontSize: 24, fontWeight: 'bold', color: primaryColor, position: 'relative' }}>{props.estdText}</span>
        </div>
        <h1 style={{ fontSize: 130, margin: 0, lineHeight: 0.9, textTransform: 'uppercase', letterSpacing: '-2px' }}>
          {(props.titleText).split('\n').map((line, i) => (
            <div key={i}>{line}</div>
          ))}
        </h1>
      </div>
      <Sparkle left={80} top={80} delay={titleDelay + 10} rotation={15} />
      <Sparkle left={550} top={350} delay={titleDelay + 20} size={60} rotation={45} />

      {/* 2. Data Chart */}
      <div style={{ position: 'absolute', right: 160, top: 120, width: 450, opacity: Math.min(1, frame - chartDelay > 0 ? 1 : 0) }}>
        {[[props.chartLabel1, bar1Width], [props.chartLabel2, bar2Width], [props.chartLabel3, bar3Width]].map((item, i) => (
          <div key={i} style={{ marginBottom: 30 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 10, fontSize: 28, fontFamily: bodyFontFamily, fontWeight: 'bold' }}>
              <span>{item[0]}</span>
              <span>{Math.round(item[1])}%</span>
            </div>
            <div style={{ width: '100%', height: 24, backgroundColor: 'rgba(60,81,0, 0.1)', borderRadius: 12, border: `2px solid ${primaryColor}` }}>
              <div style={{ width: `${item[1]}%`, height: '100%', backgroundColor: primaryColor, borderRadius: 10, borderRight: `4px solid ${accentColor}` }} />
            </div>
          </div>
        ))}
      </div>

      {/* 3. Name Tag */}
      <div style={{ position: 'absolute', left: 120, bottom: 260, transform: `scale(${namePop})` }}>
        <div style={{ border: `4px solid ${primaryColor}`, borderRadius: 20, backgroundColor: bgColor, padding: '20px 40px', boxShadow: `8px 8px 0px ${accentColor}` }}>
          <div style={{ fontSize: 24, fontFamily: bodyFontFamily, color: accentColor, fontWeight: 'bold' }}>MEET THE ARTIST</div>
          <div style={{ fontSize: 48, marginTop: 5 }}>{props.nameTag}</div>
          <div style={{ fontSize: 28, fontFamily: bodyFontFamily, marginTop: 10 }}>{props.roleTag}</div>
        </div>
      </div>

      {/* 4. Bullet Points */}
      <div style={{ position: 'absolute', right: 650, top: 400, width: 500, fontFamily: bodyFontFamily }}>
        {[props.bullet1, props.bullet2, props.bullet3].map((text, i) => {
          const bPop = safeSpring(bulletDelays[i]);
          return (
            <div key={i} style={{ display: 'flex', alignItems: 'center', marginBottom: 25, transform: `translateX(${(1 - bPop) * 50}px)`, opacity: bPop }}>
              <svg width="32" height="32" viewBox="0 0 32 32" style={{ marginRight: 20, flexShrink: 0 }}>
                <path d="M16 2 L22 10 L30 16 L22 22 L16 30 L10 22 L2 16 L10 10 Z" fill={accentColor} />
              </svg>
              <span style={{ fontSize: 36, fontWeight: 'bold' }}>{text}</span>
            </div>
          );
        })}
      </div>

      {/* 5. Highlight Quote */}
      <div style={{ position: 'absolute', right: 160, bottom: 260, width: 500, transform: `scale(${quotePop})`, opacity: quotePop }}>
        <div style={{ position: 'relative', padding: 30, border: `3px solid ${primaryColor}`, borderRadius: '30px 30px 30px 0px', backgroundColor: 'rgba(0,145,145, 0.05)' }}>
          <div style={{ position: 'absolute', top: -30, left: -20, fontSize: 80, color: accentColor, lineHeight: 1 }}>"</div>
          <p style={{ fontFamily: bodyFontFamily, fontSize: 26, fontStyle: 'italic', margin: 0, lineHeight: 1.4 }}>
            {props.quoteText}
          </p>
        </div>
      </div>

      {/* 6. Timeline */}
      <div style={{ position: 'absolute', left: 120, right: 120, bottom: 80, height: 100 }}>
        {/* Line at circle center: circles are 24px, center = 12px */}
        {frame >= 174 && <div style={{ position: 'absolute', top: 10, left: 20, right: 20, height: 4, backgroundColor: `rgba(60,81,0, 0.2)` }} />}
        <div style={{ position: 'absolute', top: 10, left: 20, width: `calc((100% - 40px) * ${timelineDraw})`, height: 4, backgroundColor: primaryColor }} />

        <div style={{ display: 'flex', justifyContent: 'space-between', position: 'relative', padding: '0 20px' }}>
        {[props.timeline1, props.timeline2, props.timeline3, props.timeline4].map((val, i) => {
          const stepDelay = timelineDelay + i * 15;
          const sPop = safeSpring(stepDelay);
          return (
            <div key={i} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', transform: `scale(${sPop})` }}>
              <div style={{ width: 24, height: 24, borderRadius: 12, backgroundColor: bgColor, border: `4px solid ${i === 3 ? accentColor : primaryColor}`, zIndex: 2 }} />
              <div style={{ marginTop: 12, fontSize: 24, fontWeight: 'bold' }}>{val}</div>
            </div>
          );
        })}
        </div>
      </div>

      {/* Extra Sparkles */}
      <Sparkle left={1700} top={250} delay={chartDelay + 20} size={50} rotation={-10} />
      <Sparkle left={900} top={150} delay={100} size={30} />
      <Sparkle left={400} top={850} delay={nameDelay + 20} size={45} rotation={25} />

    </div>
  );
};

const ChapterOverview = ({ item }) => {
