  const bgColor = props.backgroundColor;
  const cardColor = props.cardColor;
  const cardBorderColor = props.cardBorderColor;
  const iconBadgeColor = props.iconBadgeColor;
  const subtitleColor = props.subtitleColor;
  const labelColor = props.labelColor;
  const labelFont = props.labelFont;
  const subtitleFont = props.subtitleFont;

  const cards = React.useMemo(() => [
    { id: 1, label: props.part1Label, text: props.part1Text, icon: props.part1Icon },
    { id: 2, label: props.part2Label, text: props.part2Text, icon: props.part2Icon },
    { id: 3, label: props.part3Label, text: props.part3Text, icon: props.part3Icon },
    { id: 4, label: props.part4Label, text: props.part4Text, icon: props.part4Icon }
  ], [
    props.part1Label, props.part1Text, props.part1Icon,
    props.part2Label, props.part2Text, props.part2Icon,
    props.part3Label, props.part3Text, props.part3Icon,
    props.part4Label, props.part4Text, props.part4Icon
  ]);

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const rootStyle = {
    position: 'absolute',
    top: 0, left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: bgColor,
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    overflow: 'hidden'
  };

  const gridStyle = {
    display: 'grid',
    gridTemplateColumns: 'repeat(2, 820px)',
    gridTemplateRows: 'repeat(2, 350px)',
    gap: '28px 44px',
  };

  const cardBaseStyle = {
    backgroundColor: cardColor,
    border: `8px solid ${cardBorderColor}`,
    borderRadius: '36px',
    padding: '30px 40px 28px',
    boxSizing: 'border-box',
    display: 'flex',
    flexDirection: 'column',
    overflow: 'hidden',
  };

  const headerStyle = {
    display: 'flex',
    alignItems: 'center',
    gap: '20px',
    flexShrink: 0,
    marginBottom: '18px',
  };

  const badgeStyle = {
    width: '68px',
    height: '68px',
    background: `radial-gradient(circle at 38% 32%, #d7f1ff, ${iconBadgeColor})`,
    borderRadius: '50%',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    flexShrink: 0,
  };

  const iconTextStyle = {
    fontSize: '34px',
    lineHeight: 1,
    color: '#1a4041',
    fontFamily: 'Nunito, system-ui, sans-serif',
    fontWeight: 900,
  };

  const labelTextStyle = {
    fontSize: '50px',
    color: labelColor,
    fontFamily: labelFont,
    fontWeight: 700,
    margin: 0,
    lineHeight: 1,
    letterSpacing: '-0.01em',
  };

  const subtitleTextStyle = {
    fontSize: '48px',
    color: subtitleColor,
    fontFamily: subtitleFont,
    fontWeight: 800,
    lineHeight: 1.22,
    whiteSpace: 'pre-wrap',
    letterSpacing: '-0.01em',
    flex: 1,
    overflow: 'hidden',
  };

  // Stagger: 14 frames between each card (left→right, top→bottom)
  // Slide from 120px below, with a longer spring so mid-state shows clear offset
  const STAGGER = 14;
  const SLIDE_DISTANCE = 120;

  return (
    <div style={rootStyle}>
      <div style={gridStyle}>
        {cards.map((c, index) => {
          const delay = index * STAGGER;
          const progress = spring({
            frame: Math.max(0, frame - delay),
            fps: safeFps,
            config: { damping: 20, mass: 1.1, stiffness: 90 }
          });
          const yOffset = interpolate(progress, [0, 1], [SLIDE_DISTANCE, 0]);
          const opacity = interpolate(progress, [0, 1], [0, 1]);

          const iconContent = (index === 2 || index === 3)
            ? <span style={iconTextStyle}>{index === 2 ? '?' : 'A'}</span>
            : <span style={{ fontSize: '34px', lineHeight: 1 }}>{c.icon}</span>;

          return (
            <div
              key={c.id}
              style={{
                ...cardBaseStyle,
                opacity,
                transform: `translateY(${yOffset}px)`,
              }}
            >
              <div style={headerStyle}>
                <div style={badgeStyle}>{iconContent}</div>
                <div style={labelTextStyle}>{c.label}</div>
              </div>
              <div style={subtitleTextStyle}>{c.text}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

