const MonochromeEditorial = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const chapterNumber = props.chapterNumber;
  const titleText = props.titleText;
  const subtitleText = props.subtitleText;
  const primaryColor = props.primaryColor;
  const serifFont = props.serifFont;
  const sansFont = props.sansFont;
  const bgImage = props.bgImage;
  const backgroundColor = props.transparentBackground ? 'transparent' : props.bgColor;

  // --- Easing curves ---
  const smoothSettle = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 3.5);
  };
  const lineDraw = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 2.8);
  };

  // --- Exit (last 25 frames) ---
  const totalFrames = durationInFrames || 120;
  const exitStart = totalFrames - 25;
  const exitRaw = Math.max(0, Math.min(1, (frame - exitStart) / 25));
  const exitProgress = exitRaw * exitRaw;
  const exitOpacity = 1 - exitProgress;
  const exitScale = 1 - exitProgress * 0.02;

  // --- Background: scale 1.05 → 1.0 over 45 frames + opacity ---
  const bgRaw = Math.min(1, Math.max(0, frame / 45));
  const bgProgress = smoothSettle(bgRaw);
  const bgScale = 1.05 - 0.05 * bgProgress;
  const bgOpacity = smoothSettle(Math.min(1, Math.max(0, frame / 20))) * 0.35;

  // --- SVG line draw: starts at frame 10, 50 frames duration ---
  const lineRaw = Math.min(1, Math.max(0, (frame - 10) / 50));
  const lineProgress = lineDraw(lineRaw);
  const pathLength = 350;
  const drawOffset = pathLength * (1 - lineProgress);

  // --- Number: starts at frame 8, 50 frames ---
  const numRaw = Math.min(1, Math.max(0, (frame - 8) / 50));
  const numProgress = smoothSettle(numRaw);
  const numY = (1 - numProgress) * 70;
  const numOpacity = smoothSettle(Math.min(1, Math.max(0, (frame - 8) / 18)));

  // --- Text column: starts at frame 30, 45 frames ---
  const textRaw = Math.min(1, Math.max(0, (frame - 30) / 45));
  const textProgress = smoothSettle(textRaw);
  const textY = (1 - textProgress) * 60;
  const textOpacity = smoothSettle(Math.min(1, Math.max(0, (frame - 30) / 15)));

  // --- Subtitle: starts at frame 55, 35 frames ---
  const subRaw = Math.min(1, Math.max(0, (frame - 55) / 35));
  const subProgress = smoothSettle(subRaw);
  const subOpacity = subProgress;

  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor,
    overflow: 'hidden',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    opacity: exitOpacity,
    transform: `scale(${exitScale})`
  };

  const bgContainerStyle = {
    position: 'absolute',
    inset: 0,
    transform: `scale(${bgScale})`,
    transformOrigin: 'center center',
    opacity: bgOpacity,
    display: 'flex'
  };

  const svgStyle = {
    position: 'absolute',
    inset: 0,
    opacity: lineProgress
  };

  const contentStyle = {
    position: 'relative',
    display: 'flex',
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
    gap: 80,
    width: 1200,
    height: 600
  };

  const numberStyle = {
    transform: `translateY(${numY}px)`,
    opacity: numOpacity,
    fontSize: 320,
    fontFamily: serifFont,
    fontStyle: 'italic',
    fontWeight: 'bold',
    color: primaryColor,
    lineHeight: 1
  };

  const textColumnStyle = {
    display: 'flex',
    flexDirection: 'column',
    gap: 20,
    maxWidth: 700,
    transform: `translateY(${textY}px)`,
    opacity: textOpacity
  };

  const titleStyle = {
    fontSize: 96,
    fontFamily: serifFont,
    color: primaryColor,
    lineHeight: 1.15,
    whiteSpace: 'pre-wrap'
  };

  const subtitleStyle = {
    fontSize: 24,
    fontFamily: sansFont,
    color: primaryColor,
    opacity: 0.75 * subOpacity,
    lineHeight: 1.5,
    textTransform: 'uppercase',
    letterSpacing: 4
  };

  return (
    <div style={rootStyle}>
      {bgImage && !props.transparentBackground && (
        <div style={bgContainerStyle}>
          <Img src={bgImage} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
        </div>
      )}

      <div style={svgStyle}>
        <svg width="1920" height="1080" viewBox="0 0 1920 1080" fill="none">
          <path d="M 460 190 L 310 190 L 310 340" stroke={primaryColor} strokeWidth="2" strokeDasharray={pathLength} strokeDashoffset={drawOffset} />
          <path d="M 1460 190 L 1610 190 L 1610 340" stroke={primaryColor} strokeWidth="2" strokeDasharray={pathLength} strokeDashoffset={drawOffset} />
          <path d="M 310 740 L 310 890 L 460 890" stroke={primaryColor} strokeWidth="2" strokeDasharray={pathLength} strokeDashoffset={drawOffset} />
          <path d="M 1610 740 L 1610 890 L 1460 890" stroke={primaryColor} strokeWidth="2" strokeDasharray={pathLength} strokeDashoffset={drawOffset} />
        </svg>
      </div>

      <div style={contentStyle}>
        <div style={numberStyle}>
          {chapterNumber}
        </div>
        <div style={textColumnStyle}>
          <div style={titleStyle}>{titleText}</div>
          <div style={subtitleStyle}>{subtitleText}</div>
        </div>
      </div>
    </div>
  );
};

