  const iconEmoji = props.iconEmoji;
  const line1Text = props.line1Text;
  const line2Highlight = props.line2Highlight;
  const line2NormalAfter = props.line2NormalAfter;
  const highlightColor = props.highlightColor;
  const textColor = props.textColor;
  const backgroundColor = props.backgroundColor;
  const waveColor = props.waveColor;
  const fontFamily = props.fontFamily;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);
  const safeFps = fps || 30;

  const enterSlide = interpolate(frame, [0, 10], [1080, 0], {
    easing: Easing.bezier(0.22, 1, 0.36, 1),
