  });
  const enterOpacity = interpolate(frame, [0, 10], [0, 1], {
    extrapolateRight: 'clamp'
  });

  const exitStart = Math.max(10, durationInFrames - 12);
  const exitSlide = interpolate(frame, [exitStart, durationInFrames - 1], [0, 1080], {
    easing: Easing.inOut(Easing.ease),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp'
  });
  const exitBlur = interpolate(frame, [exitStart, durationInFrames - 1], [0, 18], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp'
  });

  const totalY = enterSlide + exitSlide;

  const iconScale = spring({
    frame: Math.max(0, frame - 8),
    fps: safeFps,
    config: { damping: 15, stiffness: 250 }
  });

  const renderText = (text, startIndex, color) => {
    if (!text) return null;
    return text.split('').map((char, i) => {
      const index = startIndex + i;
      const delay = 18 + index * 2;
      const fade = interpolate(frame, [delay, delay + 8], [0, 1], {
        extrapolateRight: 'clamp',
        extrapolateLeft: 'clamp'
      });
      const slide = interpolate(frame, [delay, delay + 8], [28, 0], {
        extrapolateRight: 'clamp',
        extrapolateLeft: 'clamp'
      });
      return (
        <span
          key={index}
          style={{
            display: 'inline-block',
            opacity: fade,
            // translate3d 替代 translateY，强制字符层提升为独立 GPU 合成层
            transform: `translate3d(0, ${slide}px, 0)`,
            willChange: 'transform',
            color: color,
            whiteSpace: 'pre'
          }}
        >
          {char}
        </span>
      );
    });
  };

  return (
    <div style={{
      position: 'absolute',
      top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      // translate3d(0,0,0) 前置 scale，强制根容器提升为 GPU 合成层
      transform: `translate3d(0, 0, 0) scale(${scale})`,
      transformOrigin: 'top left',
      willChange: 'transform',
      backgroundColor: 'transparent',
    }}>
      <div style={{
        position: 'absolute',
        top: 0, left: 0,
        width: '100%', height: '100%',
        // translate3d 替代 translateY，面板整体滑动走 GPU 合成
        transform: `translate3d(0, ${totalY}px, 0)`,
        willChange: 'transform',
        opacity: enterOpacity,
        filter: `blur(${exitBlur}px)`,
        backgroundColor: backgroundColor,
        overflow: 'hidden'
      }}>

        <svg style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none', filter: 'drop-shadow(0px 16px 32px rgba(0,0,0,0.04))' }}>
          <path d="M 0 0 L 1920 0 L 1920 200 C 1300 450, 600 50, 0 300 Z" fill={waveColor} />
        </svg>
        <svg style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none', filter: 'drop-shadow(0px -16px 32px rgba(0,0,0,0.04))' }}>
          <path d="M 0 1080 L 1920 1080 L 1920 800 C 1200 1050, 500 700, 0 900 Z" fill={waveColor} />
        </svg>

        <div style={{
          position: 'absolute',
          top: 0, left: 0, width: '100%', height: '100%',
          display: 'flex', flexDirection: 'column',
          alignItems: 'center', justifyContent: 'center',
          zIndex: 10
        }}>
          <div style={{
            width: 180, height: 180,
            borderRadius: 40,
            backgroundColor: '#ffffff',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            boxShadow: '0px 24px 48px rgba(0,0,0,0.06)',
            // scale 前置 translate3d(0,0,0)，强制图标卡独立 GPU 合成层
            transform: `translate3d(0, 0, 0) scale(${iconScale})`,
            willChange: 'transform',
            marginBottom: 60,
            fontSize: 90
          }}>
            {iconEmoji}
          </div>

          <div style={{
            fontFamily: fontFamily,
            fontWeight: 700,
            fontSize: 120,
            lineHeight: 1.15,
            textAlign: 'center',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            letterSpacing: '-0.02em'
          }}>
            <div>
              {renderText(line1Text, 0, textColor)}
            </div>
            <div>
              {renderText(line2Highlight, (line1Text || '').length, highlightColor)}
              {renderText(line2NormalAfter, (line1Text || '').length + (line2Highlight || '').length, textColor)}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

