const SplitIntroCard = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const bgColor = props.transparentBackground ? 'transparent' : props.bgColor;
  const leftPanelColor = props.leftPanelColor;
  const photoUrl = props.photoUrl;

  const titleText = props.titleText;
  const bodyText = props.bodyText;
  const titleFont = props.titleFont;
  const bodyFont = props.bodyFont;
  const titleColor = props.titleColor;
  const bodyColor = props.bodyColor;

  // --- Easing ---
  const smoothSettle = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 3.5);
  };

  // --- Exit ---
  const totalFrames = durationInFrames || 150;
  const exitStart = totalFrames - 25;
  const exitRaw = Math.max(0, Math.min(1, (frame - exitStart) / 25));
  const exitProgress = exitRaw * exitRaw;
  const exitOpacity = 1 - exitProgress;
  const exitScale = 1 - exitProgress * 0.02;

  // --- Left panel slide in: frame 0, 50 frames ---
  const leftRaw = Math.min(1, Math.max(0, frame / 50));
  const leftProgress = smoothSettle(leftRaw);
  const leftPanelTranslate = (1 - leftProgress) * -100;

  // --- Photo subtle scale (continuous, from 1.05 to 1.0) ---
  const photoScale = 1.05 - 0.05 * smoothSettle(Math.min(1, Math.max(0, frame / 90)));

  // --- Title: starts at frame 25, 50 frames ---
  const titleRaw = Math.min(1, Math.max(0, (frame - 25) / 50));
  const titleProgress = smoothSettle(titleRaw);
  const titleOpacity = smoothSettle(Math.min(1, Math.max(0, (frame - 25) / 18)));
  const titleY = (1 - titleProgress) * 60;

  // --- Body text: starts at frame 55, 40 frames ---
  const bodyRaw = Math.min(1, Math.max(0, (frame - 55) / 40));
  const bodyProgress = smoothSettle(bodyRaw);
  const bodyOpacity = smoothSettle(Math.min(1, Math.max(0, (frame - 55) / 15)));
  const bodyY = (1 - bodyProgress) * 40;

  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor: bgColor,
    overflow: 'hidden',
    opacity: exitOpacity,
    transform: `scale(${exitScale})`
  };

  const rightPanelStyle = {
    position: 'absolute',
    right: 0,
    width: '65%',
    height: '100%',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    padding: '0 120px',
    boxSizing: 'border-box'
  };

  const leftPanelStyle = {
    position: 'absolute',
    left: 0,
    width: '35%',
    height: '100%',
    transform: `translateX(${leftPanelTranslate}%)`,
    overflow: 'hidden'
  };

  const titleStyle = {
    fontFamily: titleFont,
    fontSize: '96px',
    color: titleColor,
    margin: '0 0 40px 0',
    opacity: titleOpacity,
    transform: `translateY(${titleY}px)`,
    lineHeight: 1.1
  };

  const bodyStyle = {
    fontFamily: bodyFont,
    fontSize: '30px',
    color: bodyColor,
    margin: 0,
    lineHeight: 1.5,
    opacity: bodyOpacity,
    transform: `translateY(${bodyY}px)`,
    maxWidth: '800px',
    whiteSpace: 'pre-wrap'
  };

  return (
    <div style={rootStyle}>
      <div style={rightPanelStyle}>
        <h1 style={titleStyle}>{titleText}</h1>
        <p style={bodyStyle}>{bodyText}</p>
      </div>

      <div style={leftPanelStyle}>
        {photoUrl && (
          <Img
            src={photoUrl}
            style={{ width: '100%', height: '100%', objectFit: 'cover', transform: `scale(${photoScale})` }}
          />
        )}
        <div style={{ position: 'absolute', inset: 0, backgroundColor: leftPanelColor }}></div>
      </div>
    </div>
  );
};

const CreativeWatercolor = ({item}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const props = item.props || {};
  const bgColor = props.bgColor;
  const transparentBackground = props.transparentBackground;
  const textColor = props.textColor;
  const titleText = props.titleText;
  const subtitleText = props.subtitleText;
  const footerText = props.footerText;
  const titleFont = props.titleFont;
  const bodyFont = props.bodyFont;

  const washBlue = props.washBlue;
  const washPink = props.washPink;
  const washPeach = props.washPeach;
  const washFlower = props.washFlower;

  const safeFps = fps || 30;
  const safeSpring = (delay = 0, config = { damping: 20, stiffness: 100 }) => {
    return spring({ frame: Math.max(0, frame - delay), fps: safeFps, config });
  };

  const titleSpring = safeSpring(15);
  const subtitleSpring = safeSpring(25);
  const lineSpring = safeSpring(35);
  const footerSpring = safeSpring(40);
  const washAlpha = interpolate(frame, [0, 45], [0, 1], { extrapolateRight: 'clamp' });
  const washScale = interpolate(frame, [0, 120], [0.95, 1.05], { extrapolateRight: 'clamp' });
  const flowerRotate = interpolate(frame, [0, 120], [-5, 5], { extrapolateRight: 'clamp' });

  const backgroundColor = transparentBackground ? 'transparent' : bgColor;

  const hexToRgba = (hex, alpha) => {
    let r = 0, g = 0, b = 0;
    const cleanHex = hex.replace('#', '');
    if (cleanHex.length === 3) {
      r = parseInt(cleanHex[0] + cleanHex[0], 16);
      g = parseInt(cleanHex[1] + cleanHex[1], 16);
      b = parseInt(cleanHex[2] + cleanHex[2], 16);
    } else if (cleanHex.length === 6) {
      r = parseInt(cleanHex.substring(0, 2), 16);
      g = parseInt(cleanHex.substring(2, 4), 16);
      b = parseInt(cleanHex.substring(4, 6), 16);
    }
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  };

  const transformBezier = (points, tx, ty, rotDeg, scale) => {
    return points.map(pt => {
      const rad = rotDeg * (Math.PI / 180);
      const scaledX = pt.x * scale;
      const scaledY = pt.y * scale;
      const rx = scaledX * Math.cos(rad) - scaledY * Math.sin(rad);
      const ry = scaledX * Math.sin(rad) + scaledY * Math.cos(rad);
      return { x: rx + tx, y: ry + ty };
    });
  };

  const getPetalStr = (rotDeg, scale, tx, ty) => {
    const pts = [
      {x: 0, y: 0}, {x: 40, y: -40}, {x: 60, y: -130},
      {x: 0, y: -190}, {x: -60, y: -130}, {x: -40, y: -40}
    ];
    const t = transformBezier(pts, tx, ty, rotDeg, scale);
    return `M ${t[0].x},${t[0].y} C ${t[1].x},${t[1].y} ${t[2].x},${t[2].y} ${t[3].x},${t[3].y} C ${t[4].x},${t[4].y} ${t[5].x},${t[5].y} ${t[0].x},${t[0].y} Z`;
  };

  const getLeafStr = (rotDeg, scale, tx, ty) => {
    const pts = [
      {x: 0, y: 0}, {x: -50, y: 40}, {x: -80, y: 100},
      {x: -20, y: 180}, {x: 20, y: 100}, {x: -10, y: 40}
    ];
    const t = transformBezier(pts, tx, ty, rotDeg, scale);
    return `M ${t[0].x},${t[0].y} C ${t[1].x},${t[1].y} ${t[2].x},${t[2].y} ${t[3].x},${t[3].y} C ${t[4].x},${t[4].y} ${t[5].x},${t[5].y} ${t[0].x},${t[0].y} Z`;
  };

  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor,
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'row',
    width: 1920,
    height: 1080,
  };

  const leftContainer = {
    position: 'absolute',
    left: 0,
    top: 0,
    width: '50%',
    height: '100%',
    opacity: washAlpha,
  };

  const textContainer = {
    position: 'absolute',
    left: '50%',
    top: '20%',
    width: '45%',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'flex-start',
  };

  const titleStyle = {
    fontFamily: titleFont,
    fontSize: 88,
    fontWeight: 300,
    color: textColor,
    lineHeight: 1.15,
    letterSpacing: '0.02em',
    whiteSpace: 'pre-wrap',
    opacity: titleSpring,
    transform: `translateY(${(1 - titleSpring) * 40}px)`,
    margin: 0,
  };

  const subtitleStyle = {
    fontFamily: bodyFont,
    fontSize: 28,
    fontWeight: 400,
    color: textColor,
    lineHeight: 1.4,
    whiteSpace: 'pre-wrap',
    opacity: subtitleSpring,
    transform: `translateY(${(1 - subtitleSpring) * 30}px)`,
    marginTop: 100,
  };

  const footerContainer = {
    position: 'absolute',
    bottom: 0,
    left: '5%',
    width: '90%',
    height: 120,
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
  };

  const separatorLine = {
    width: '100%',
    height: 2,
    backgroundColor: textColor,
    transform: `scaleX(${lineSpring})`,
    transformOrigin: 'left',
    opacity: 0.8,
  };

  const footerTextStyle = {
    fontFamily: bodyFont,
    fontSize: 16,
    fontWeight: 500,
    color: textColor,
    letterSpacing: '0.1em',
    textAlign: 'right',
    marginTop: 20,
    opacity: footerSpring,
  };

  return (
    <div style={rootStyle}>
      <div style={leftContainer}>
        <svg width="100%" height="100%" viewBox="0 0 960 1080">
          <defs>
            <radialGradient id="gradBlue" cx="50%" cy="50%" r="50%">
              <stop offset="0%" stopColor={hexToRgba(washBlue, 0.6)} />
              <stop offset="60%" stopColor={hexToRgba(washBlue, 0.4)} />
              <stop offset="100%" stopColor={hexToRgba(washBlue, 0)} />
            </radialGradient>
