const CreativePortfolio = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const props = item.props || {};

  const backgroundColor = props.transparentBackground ? 'transparent' : props.bgColor;
  const titleText = props.titleText;
  const subtitleText = props.subtitleText;
  const titleFont = props.titleFont;
  const labelFont = props.labelFont;
  const titleColor = props.titleColor;
  const labelColor = props.labelColor;

  const v1 = props.seg1Val;
  const v2 = props.seg2Val;
  const v3 = props.seg3Val;
  const v4 = props.seg4Val;
  const total = v1 + v2 + v3 + v4;

  const p1 = (v1 / total) * 360;
  const p2 = (v2 / total) * 360;
  const p3 = (v3 / total) * 360;
  const p4 = (v4 / total) * 360;

  const start1 = -90;
  const start2 = start1 + p1;
  const start3 = start2 + p2;
  const start4 = start3 + p3;

  const safeSpring = (delay) => spring({
    frame: Math.max(0, frame - delay),
    fps: fps || 30,
    config: { damping: 18, stiffness: 90 }
  });

  const titleOpacity = safeSpring(0);
  const p1Anim = safeSpring(24);
  const p2Anim = safeSpring(48);
  const p3Anim = safeSpring(72);
  const p4Anim = safeSpring(96);
  const bgAnim = safeSpring(10);

  const washOffset = interpolate(frame, [0, 180], [0, 20]);

  const polarToCartesian = (cx, cy, radius, angleInDegrees) => {
    const angleInRadians = (angleInDegrees * Math.PI) / 180.0;
    return {
      x: cx + radius * Math.cos(angleInRadians),
      y: cy + radius * Math.sin(angleInRadians)
    };
  };

  const getArcPath = (cx, cy, radius, startAngle, endAngle) => {
    if (endAngle - startAngle < 0.01) endAngle = startAngle + 0.01;
    const start = polarToCartesian(cx, cy, radius, startAngle);
    const end = polarToCartesian(cx, cy, radius, endAngle);
    const largeArcFlag = endAngle - startAngle <= 180 ? "0" : "1";
    return [
      "M", start.x, start.y,
      "A", radius, radius, 0, largeArcFlag, 1, end.x, end.y
    ].join(" ");
  };

  const hexToRgba = (colorStr, alpha) => {
    if (!colorStr || typeof colorStr !== 'string') return `rgba(0,0,0,${alpha})`;
    if (!colorStr.startsWith('#')) return colorStr;
    const hex = colorStr.replace('#', '');
    const r = parseInt(hex.length === 3 ? hex.slice(0, 1).repeat(2) : hex.slice(0, 2), 16);
    const g = parseInt(hex.length === 3 ? hex.slice(1, 2).repeat(2) : hex.slice(2, 4), 16);
    const b = parseInt(hex.length === 3 ? hex.slice(2, 3).repeat(2) : hex.slice(4, 6), 16);
    return `rgba(${isNaN(r) ? 0 : r}, ${isNaN(g) ? 0 : g}, ${isNaN(b) ? 0 : b}, ${alpha})`;
  };

  const renderPieSegment = (cx, cy, radius, strokeWidth, color, startAngle, endAngle, progress, label, val) => {
    const currentEndAngle = interpolate(progress, [0, 1], [startAngle, endAngle]);
    const isVisible = progress > 0.01;
    const midAngle = (startAngle + endAngle) / 2;
    const lineStart = polarToCartesian(cx, cy, radius + strokeWidth / 2 + 10, midAngle);
    const lineMid = polarToCartesian(cx, cy, radius + strokeWidth / 2 + 50, midAngle);
    const isLeft = midAngle > 90 && midAngle < 270;
    const lineEnd = { x: lineMid.x + (isLeft ? -50 : 50), y: lineMid.y };

    const textBaseAlpha = Math.max(0, interpolate(progress, [0.8, 1], [0, 1]));
    const lineStroke = hexToRgba(labelColor, textBaseAlpha * 0.4);
    const textMainFill = hexToRgba(labelColor, textBaseAlpha);
    const textSubFill = hexToRgba(labelColor, textBaseAlpha * 0.7);

    return (
      <g key={label}>
        {isVisible && (
          <path
            d={getArcPath(cx, cy, radius, startAngle, currentEndAngle)}
            fill="none"
            stroke={color}
            strokeWidth={strokeWidth}
          />
        )}
        {progress > 0.8 && (
          <g>
            <path 
              d={`M ${lineStart.x} ${lineStart.y} L ${lineMid.x} ${lineMid.y} L ${lineEnd.x} ${lineEnd.y}`}
              fill="none"
              stroke={lineStroke}
              strokeWidth="2"
            />
            <text
              x={lineEnd.x + (isLeft ? -15 : 15)}
              y={lineEnd.y + 5}
              fontFamily={labelFont}
              fontSize="24"
              fill={textMainFill}
              textAnchor={isLeft ? "end" : "start"}
              fontWeight="500"
              letterSpacing="1px"
            >
              {label.toUpperCase()}
            </text>
            <text
              x={lineEnd.x + (isLeft ? -15 : 15)}
              y={lineEnd.y + 30}
              fontFamily={labelFont}
              fontSize="18"
              fill={textSubFill}
              textAnchor={isLeft ? "end" : "start"}
            >
              {val}%
            </text>
          </g>
        )}
      </g>
    );
  };

  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor,
    overflow: 'hidden',
    display: 'flex'
  };

  const bgOpacity = interpolate(bgAnim, [0, 1], [0, 0.7]);
  const dividerOpacity = interpolate(titleOpacity, [0, 1], [0, 0.2]);
  const dividerScale = titleOpacity;
  const titleTranslateY = interpolate(titleOpacity, [0, 1], [40, 0]);
  const centerDecorAlpha = interpolate(titleOpacity, [0, 1], [0, 0.3]);

  return (
    <div style={rootStyle}>
      {/* Watercolor Background Washes */}
      <div style={{ position: 'absolute', inset: 0, opacity: bgOpacity }}>
        <svg style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', zIndex: 0 }}>
          <defs>
            <filter id="watercolorBlur" x="-50%" y="-50%" width="200%" height="200%">
              <feGaussianBlur stdDeviation="100" />
            </filter>
          </defs>
          <g filter="url(#watercolorBlur)">
            <circle cx={400 - washOffset} cy={200 + washOffset} r="400" fill={hexToRgba(props.seg1Color, 0.6)} />
            <circle cx={1600 + washOffset} cy={900 - washOffset} r="500" fill={hexToRgba(props.seg3Color, 0.4)} />
            <circle cx={800} cy={1000} r="450" fill={hexToRgba(props.seg2Color, 0.5)} />
            <circle cx={1400} cy={100} r="350" fill={hexToRgba(props.seg4Color, 0.4)} />
          </g>
        </svg>
      </div>

      {/* Vertical divider line */}
      <div style={{
        position: 'absolute',
        left: '50%',
        top: '15%',
        bottom: '15%',
        width: '1px',
        backgroundColor: labelColor,
        opacity: dividerOpacity,
        transform: `scaleY(${dividerScale})`,
        transformOrigin: 'top'
      }} />

      {/* Typography */}
      <div style={{
        position: 'absolute',
        left: 200,
        top: 360,
        width: 700,
        display: 'flex',
        flexDirection: 'column',
        gap: 60,
        zIndex: 10,
        opacity: titleOpacity,
        transform: `translateY(${titleTranslateY}px)`
      }}>
        <h1 style={{
          fontFamily: titleFont,
          fontSize: 88,
          lineHeight: 1.1,
          color: titleColor,
          margin: 0,
          fontWeight: 400,
          whiteSpace: 'pre-wrap'
        }}>
          {titleText}
        </h1>
        <p style={{
          fontFamily: labelFont,
          fontSize: 16,
          color: labelColor,
          margin: 0,
          fontWeight: 400,
          opacity: 0.8,
          whiteSpace: 'pre-wrap',
          lineHeight: 1.5
        }}>
          {subtitleText}
        </p>
      </div>

      {/* Pie Chart */}
      <svg style={{ position: 'absolute', right: 50, top: 140, width: 900, height: 800, zIndex: 10 }}>
        <g transform="translate(450, 400)">
          {renderPieSegment(0, 0, 180, 120, props.seg1Color, start1, start2, p1Anim, props.seg1Label, v1)}
          {renderPieSegment(0, 0, 180, 120, props.seg2Color, start2, start3, p2Anim, props.seg2Label, v2)}
          {renderPieSegment(0, 0, 180, 120, props.seg3Color, start3, start4, p3Anim, props.seg3Label, v3)}
          {renderPieSegment(0, 0, 180, 120, props.seg4Color, start4, start1 + 360, p4Anim, props.seg4Label, v4)}

          {/* Center Decor */}
          <circle cx={0} cy={0} r={5} fill={hexToRgba(labelColor, centerDecorAlpha)} />
        </g>
      </svg>
    </div>
  );
};

const WatercolorArtists = ({item}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const props = item.props || {};

  const safeFps = fps || 30;
  const bgColor = props.transparentBackground ? 'transparent' : (props.bgColor);
  const titleText = props.titleText;
  const titleFontFamily = props.titleFontFamily;
  const textFontFamily = props.textFontFamily;

  const hexToRgba = (hex, alpha) => {
    if (!hex) return `rgba(0,0,0,${alpha})`;
    let h = hex.replace('#', '');
    if (h.length === 3) h = h[0] + h[0] + h[1] + h[1] + h[2] + h[2];
    const r = parseInt(h.substring(0, 2), 16) || 0;
    const g = parseInt(h.substring(2, 4), 16) || 0;
    const b = parseInt(h.substring(4, 6), 16) || 0;
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  };

  const renderSplash = (color, f_delay, index) => {
    const f = Math.max(0, frame - f_delay);
    const scale = spring({ frame: f, fps: safeFps, config: { damping: 14, mass: 1.2 } });
    const rotate = interpolate(f, [0, 150], [index * 45, index * 45 + 15]);
    const opacity = interpolate(f, [0, 30], [0, 0.8], { extrapolateRight: 'clamp' });

    return (
      <div style={{ position: 'absolute', width: 440, height: 440, left: -70, top: -70, transform: `scale(${scale}) rotate(${rotate}deg)`, opacity }}>
        <svg width="440" height="440" viewBox="0 0 100 100">
          <defs>
            <filter id={`blur2-${index}`} x="-20%" y="-20%" width="140%" height="140%">
              <feGaussianBlur stdDeviation="12" />
            </filter>
          </defs>
          <g transform="scale(0.95) translate(2.5, 2.5)">
            <path d="M 48 12 C 75 8, 88 28, 92 48 C 96 75, 72 88, 48 92 C 22 96, 8 72, 12 48 C 8 22, 22 12, 48 12 Z" fill={hexToRgba(color, 0.5)} filter={`url(#blur2-${index})`} />
          </g>
        </svg>
        <div style={{ position: 'absolute', inset: 0 }}>
          <svg width="440" height="440" viewBox="0 0 100 100">
            <defs>
              <filter id={`blur1-${index}`} x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="6" />
              </filter>
            </defs>
            <path d="M 50 18 C 72 15, 82 35, 86 50 C 90 72, 70 82, 50 86 C 28 90, 15 70, 18 50 C 15 28, 28 18, 50 18 Z" fill={hexToRgba(color, 0.7)} filter={`url(#blur1-${index})`} />
          </svg>
        </div>
      </div>
    );
  };

  const renderOrganicBorder = (color, f_delay, index) => {
    const f = Math.max(0, frame - f_delay);
    const scale = spring({ frame: f, fps: safeFps, config: { damping: 16 } });
    const opacity = interpolate(f, [0, 30], [0, 0.9], { extrapolateRight: 'clamp' });
    const rotate = interpolate(f, [0, 150], [-10, 5]);

    return (
      <div style={{ position: 'absolute', width: 350, height: 350, left: -25, top: -25, transform: `scale(${scale}) rotate(${rotate}deg)`, opacity }}>
        <svg width="350" height="350" viewBox="0 0 100 100">
          <defs>
            <filter id={`blur-border-${index}`} x="-20%" y="-20%" width="140%" height="140%">
              <feGaussianBlur stdDeviation="1.5" />
            </filter>
          </defs>
          <path d="M 50 4 C 76 6, 94 24, 96 50 C 98 76, 76 96, 50 96 C 24 96, 4 76, 4 50 C 4 24, 24 4, 50 4 Z" fill="none" stroke={hexToRgba(color, 0.8)} strokeWidth="2.5" filter={`url(#blur-border-${index})`} />
          <path d="M 50 8 C 80 12, 92 30, 92 50 C 92 70, 80 88, 50 92 C 20 88, 8 70, 8 50 C 8 30, 20 12, 50 8 Z" fill="none" stroke={hexToRgba(color, 0.5)} strokeWidth="1.5" filter={`url(#blur-border-${index})`} />
          <path d="M 50 1 C 70 1, 99 20, 99 50 C 99 80, 70 99, 50 99 C 30 99, 1 80, 1 50 C 1 20, 30 1, 50 1 Z" fill="none" stroke={hexToRgba(color, 0.3)} strokeWidth="1" filter={`url(#blur-border-${index})`} />
        </svg>
      </div>
    );
  };

  const renderMember = (name, role, color, image, delay, index) => {
    const f = Math.max(0, frame - delay);
    const y = interpolate(f, [0, 30], [60, 0], { extrapolateRight: 'clamp' });
    const opacity = interpolate(f, [0, 20], [0, 1], { extrapolateRight: 'clamp' });

    return (
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', transform: `translateY(${y}px)`, opacity, width: 360 }}>
        <div style={{ position: 'relative', width: 300, height: 300, marginBottom: 50 }}>
          {renderSplash(color, delay, index)}
          <div style={{ position: 'absolute', left: 0, top: 0, width: 300, height: 300, borderRadius: '50%', backgroundColor: 'rgba(255, 255, 255, 0.4)', overflow: 'hidden', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
            {image && <Img src={image} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />}
          </div>
          {renderOrganicBorder(color, delay + 5, index)}
        </div>
        <div style={{ fontFamily: titleFontFamily, fontSize: 36, color: '#2A1E1E', marginBottom: 12, textAlign: 'center', lineHeight: 1.2 }}>
          {name}
        </div>
        <div style={{ fontFamily: textFontFamily, fontSize: 16, color: '#5b645a', letterSpacing: '0.15em', textTransform: 'uppercase', textAlign: 'center' }}>
          {role}
        </div>
      </div>
    );
  };

  const titleF = Math.max(0, frame - 5);
  const titleY = interpolate(titleF, [0, 35], [40, 0], { extrapolateRight: 'clamp' });
  const titleOpacity = interpolate(titleF, [0, 25], [0, 1], { extrapolateRight: 'clamp' });

  return (
    <div style={{ position: 'absolute', inset: 0, backgroundColor: bgColor, display: 'flex', flexDirection: 'column', alignItems: 'center', paddingTop: 140 }}>
      <div style={{ fontFamily: titleFontFamily, fontSize: 64, color: '#1A1212', letterSpacing: '0.04em', transform: `translateY(${titleY}px)`, opacity: titleOpacity, marginBottom: 120 }}>
        {titleText}
      </div>
      <div style={{ display: 'flex', flexDirection: 'row', gap: 140, justifyContent: 'center' }}>
        {renderMember(props.name1, props.role1, props.color1, props.image1, 24, 1)}
        {renderMember(props.name2, props.role2, props.color2, props.image2, 54, 2)}
        {renderMember(props.name3, props.role3, props.color3, props.image3, 84, 3)}
      </div>
    </div>
  );
};

const CreativeWatercolorTimeline = ({item}) => {
