    year3, text3,
    year4, text4,
    titleFontFamily,
    bodyFontFamily,
    lineColor,
    accentColor1,
    accentColor2,
    bgColor,
    transparentBackground
  } = props;

  const safeFps = fps || 30;
  const safeSpring = (delay = 0, config = { damping: 15 }) => {
    return spring({ frame: Math.max(0, frame - delay), fps: safeFps, config });
  };

  const backgroundColor = transparentBackground ? 'transparent' : bgColor;
  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor,
    overflow: 'hidden'
  };

  const getRgba = (color, alpha) => {
    if (!color) return `rgba(0,0,0,${alpha})`;
    const hexMatch = color.match(/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i);
    if (hexMatch) {
      return `rgba(${parseInt(hexMatch[1], 16)}, ${parseInt(hexMatch[2], 16)}, ${parseInt(hexMatch[3], 16)}, ${alpha})`;
    }
    const shortHexMatch = color.match(/^#?([a-f\d])([a-f\d])([a-f\d])$/i);
    if (shortHexMatch) {
      return `rgba(${parseInt(shortHexMatch[1]+shortHexMatch[1], 16)}, ${parseInt(shortHexMatch[2]+shortHexMatch[2], 16)}, ${parseInt(shortHexMatch[3]+shortHexMatch[3], 16)}, ${alpha})`;
    }
    return color;
  };

  const titleOpacity = interpolate(frame, [0, 20], [0, 1], { extrapolateRight: 'clamp' });
  const titleY = interpolate(frame, [0, 20], [20, 0], { extrapolateRight: 'clamp' });

  const lineProgress = interpolate(frame, [15, 60], [0, 1], { extrapolateRight: 'clamp' });
  const lineHeight = lineProgress * 650;

  const nodes = [
    { year: year1, text: text1, y: 350, delay: 45 },
    { year: year2, text: text2, y: 500, delay: 75 },
    { year: year3, text: text3, y: 650, delay: 105 },
    { year: year4, text: text4, y: 800, delay: 135 }
  ];

  return (
    <div style={rootStyle}>
      {!transparentBackground && (
        <>
          <svg width="1200" height="1200" viewBox="0 0 100 100" style={{ position: 'absolute', left: -300, top: -400 }}>
            <defs>
              <radialGradient id="grad-bg-1" cx="50%" cy="50%" r="50%">
                <stop offset="0%" stopColor={getRgba(accentColor2, 0.25)} />
                <stop offset="50%" stopColor={getRgba(accentColor1, 0.1)} />
                <stop offset="100%" stopColor={getRgba(accentColor1, 0)} />
              </radialGradient>
            </defs>
            <circle cx="50" cy="50" r="50" fill="url(#grad-bg-1)" />
          </svg>
          <svg width="1400" height="1400" viewBox="0 0 100 100" style={{ position: 'absolute', right: -400, bottom: -500 }}>
            <defs>
              <radialGradient id="grad-bg-2" cx="50%" cy="50%" r="50%">
                <stop offset="0%" stopColor={getRgba(accentColor1, 0.2)} />
                <stop offset="60%" stopColor={getRgba(accentColor2, 0.05)} />
                <stop offset="100%" stopColor={getRgba(accentColor2, 0)} />
              </radialGradient>
            </defs>
            <circle cx="50" cy="50" r="50" fill="url(#grad-bg-2)" />
          </svg>
        </>
      )}

      <div style={{
        position: 'absolute', top: 120, left: 0, right: 0, textAlign: 'center',
        opacity: titleOpacity, transform: `translateY(${titleY}px)`,
        fontFamily: titleFontFamily, fontSize: 64, color: lineColor,
        letterSpacing: '0.1em', fontWeight: 'bold'
      }}>
        {titleText}
      </div>

      <div style={{ position: 'absolute', top: 0, left: 0, width: 1920, height: 1080 }}>
        <div style={{
          position: 'absolute', left: 959, top: 250, width: 2,
          height: lineHeight, backgroundColor: lineColor
        }} />

        {nodes.map((node, i) => {
          const progress = interpolate(frame, [node.delay, node.delay + 20], [0, 1], { extrapolateRight: 'clamp' });
          const scale = safeSpring(node.delay);
          const yOffset = interpolate(progress, [0, 1], [15, 0]);

          return (
            <div key={i} style={{
              position: 'absolute', top: node.y, left: 960,
              width: 0, height: 0, display: 'flex', alignItems: 'center', justifyContent: 'center'
            }}>

              <div style={{ position: 'absolute', transform: `scale(${scale})` }}>
                 <div style={{ position: 'absolute', left: -25, top: -25, width: 50, height: 50 }}>
                    <svg width="50" height="50"><circle cx="24" cy="26" r="22" fill={getRgba(accentColor1, 0.6)}/></svg>
                 </div>
                 <div style={{ position: 'absolute', left: -25, top: -25, width: 50, height: 50 }}>
                    <svg width="50" height="50"><circle cx="27" cy="24" r="18" fill={getRgba(accentColor2, 0.7)}/></svg>
                 </div>
                 <div style={{ position: 'absolute', left: -25, top: -25, width: 50, height: 50 }}>
                    <svg width="50" height="50"><circle cx="25" cy="25" r="4" fill={lineColor}/></svg>
                 </div>
              </div>

              <div style={{
                position: 'absolute', right: 60, width: 300, textAlign: 'right',
                opacity: progress, transform: `translateY(${yOffset}px)`,
                fontFamily: titleFontFamily, fontSize: 40, color: lineColor, fontWeight: 'bold'
              }}>
                {node.year}
              </div>

              <div style={{
                position: 'absolute', left: 60, width: 450, textAlign: 'left',
                opacity: progress, transform: `translateY(${yOffset}px)`,
                fontFamily: bodyFontFamily, fontSize: 28, color: lineColor, fontWeight: 'normal',
                whiteSpace: 'normal', overflowWrap: 'break-word', lineHeight: 1.4
              }}>
                {node.text}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const WatercolorAnchor = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();
  const props = item.props || {};

  const bgColor = props.transparentBackground ? 'transparent' : props.bgColor;
  const textColor = props.textColor;
  const titleFont = props.titleFont;
  const bodyFont = props.bodyFont;
  const washColor1 = props.washColor1;
  const washColor2 = props.washColor2;
  const washColor3 = props.washColor3;

  const parseHex = (hex) => {
    if (!hex) return [0,0,0];
    const h = hex.replace('#','');
    return [parseInt(h.substring(0,2),16)||0, parseInt(h.substring(2,4),16)||0, parseInt(h.substring(4,6),16)||0];
  };
  const rgba = (hex, a) => { const [r,g,b] = parseHex(hex); return `rgba(${r},${g},${b},${a})`; };

  const smoothSettle = (t) => t<=0?0:t>=1?1:1-Math.pow(1-t,3.5);
  const bellCurveLate = (t) => t<=0?0:t>=1?1:t<0.4?0.15*Math.pow(t/0.4,2.5):0.15+0.85*(1-Math.pow(1-(t-0.4)/0.6,2.8));
  const lineDraw = (t) => t<=0?0:t>=1?1:1-Math.pow(1-t,2.8);

  const total = durationInFrames || 150;
  const exitRaw = Math.max(0, Math.min(1, (frame-(total-25))/25));
  const ex = 1 - exitRaw*exitRaw;

  const anim = (delay, dur) => smoothSettle(Math.min(1, Math.max(0, (frame-delay)/dur)));
  const fadeIn = (delay) => smoothSettle(Math.min(1, Math.max(0, (frame-delay)/15)));

  // Wash background
  const washA = anim(0, 50) * ex;
  const washScale = 1.04 - 0.04*anim(0,45);

  // Title (delay 5)
  const ttA = fadeIn(5)*ex;
  const ttY = (1-anim(5,48))*45;

  // Subtitle (delay 20)
  const stA = fadeIn(20)*ex;
  const stY = (1-anim(20,35))*30;

  // Body (delay 30)
  const bdA = fadeIn(30)*ex;
  const bdY = (1-anim(30,35))*25;

  // Timeline vertical line (delay 10)
  const tlH = lineDraw(Math.min(1, Math.max(0,(frame-10)/55)))*500;
  const tlA = fadeIn(10)*ex;

  // Timeline nodes (stagger from 25)
  const nd = [0,1,2,3].map(i => {
    const d = 25+i*6;
    return { a: fadeIn(d)*ex, y: (1-anim(d,30))*15 };
  });

  // Pie chart (delay 15, 60f)
  const chRaw = Math.min(1, Math.max(0,(frame-15)/60));
  const chP = bellCurveLate(chRaw);
  const chLblA = anim(15+60*0.55, 18)*ex;

  // Name tag (delay 35)
  const nmA = fadeIn(35)*ex;

  // Footer line (delay 25)
  const lineW = anim(25, 40);
  const lineA = fadeIn(25)*ex;

  // Donut arc helper
  const arcPath = (cx, cy, r, startDeg, endDeg) => {
    if (endDeg - startDeg < 0.5) return '';
    const s = { x: cx+Math.cos(startDeg*Math.PI/180)*r, y: cy+Math.sin(startDeg*Math.PI/180)*r };
    const e = { x: cx+Math.cos(endDeg*Math.PI/180)*r, y: cy+Math.sin(endDeg*Math.PI/180)*r };
    return `M ${s.x} ${s.y} A ${r} ${r} 0 ${endDeg-startDeg>180?1:0} 1 ${e.x} ${e.y}`;
  };

  const segs = [{p:0.35,c:washColor1},{p:0.30,c:washColor2},{p:0.20,c:washColor3},{p:0.15,c:washColor1}];
  let ang = -90;

  return (
    <div style={{position:'absolute',inset:0,backgroundColor:bgColor,overflow:'hidden',fontFamily:bodyFont}}>
      {/* Watercolor washes */}
      <div style={{position:'absolute',top:'-10%',left:'-5%',width:900,height:900,
        background:`radial-gradient(circle,${rgba(washColor1,washA*0.4)} 0%,transparent 65%)`,
        transform:`scale(${washScale})`,transformOrigin:'center'}}/>
      <div style={{position:'absolute',bottom:'-15%',right:'-10%',width:1100,height:1100,
        background:`radial-gradient(circle,${rgba(washColor2,washA*0.35)} 0%,transparent 60%)`,
        transform:`scale(${washScale})`,transformOrigin:'center'}}/>

      {/* Title area (left) */}
      <div style={{position:'absolute',left:120,top:120,transform:`translateY(${ttY}px)`}}>
        <div style={{fontFamily:titleFont,fontSize:90,fontWeight:300,color:rgba(textColor,ttA),lineHeight:1.1,letterSpacing:'0.02em',whiteSpace:'pre-wrap'}}>
          CREATIVE{'\n'}WATERCOLOR
        </div>
      </div>

      {/* Subtitle */}
      <div style={{position:'absolute',left:120,top:360,transform:`translateY(${stY}px)`}}>
        <div style={{fontSize:28,color:rgba(textColor,stA*0.7),lineHeight:1.4,whiteSpace:'pre-wrap'}}>
          Here is where your{'\n'}presentation begins
        </div>
      </div>

      {/* Body text */}
      <div style={{position:'absolute',left:120,top:500,width:550,transform:`translateY(${bdY}px)`}}>
        <div style={{fontSize:26,lineHeight:1.5,color:rgba(textColor,bdA*0.8)}}>
          Our studio brings artistic vision to every project through color, texture, and organic form.
        </div>
      </div>

      {/* Name tag (lower-left) */}
      <div style={{position:'absolute',left:120,bottom:100}}>
        <div style={{fontSize:32,fontFamily:titleFont,color:rgba(textColor,nmA)}}>Elena Marchetti</div>
        <div style={{fontSize:16,letterSpacing:'0.12em',textTransform:'uppercase',color:rgba(textColor,nmA*0.6),marginTop:8}}>LEAD ARTIST</div>
      </div>

      {/* Footer separator line */}
      <div style={{position:'absolute',bottom:80,left:120,right:120,height:1,backgroundColor:rgba(textColor,lineA*0.3),transform:`scaleX(${lineW})`,transformOrigin:'left'}}/>

      {/* Vertical timeline (center) */}
      <div style={{position:'absolute',left:780,top:200,width:2,height:500}}>
        <div style={{position:'absolute',top:0,width:2,height:tlH,backgroundColor:rgba(textColor,tlA*0.2)}}/>
        {['2018','2020','2022','2024'].map((yr,i) => {
          const ny = i*130;
          return (
            <div key={i} style={{position:'absolute',top:ny,left:0,transform:`translateY(${nd[i].y}px)`}}>
              <div style={{position:'absolute',left:-12,top:-4,width:8,height:8,borderRadius:'50%',backgroundColor:rgba(washColor1,nd[i].a*0.7)}}/>
              <div style={{position:'absolute',left:20,top:-8,fontFamily:titleFont,fontSize:24,fontWeight:'bold',color:rgba(textColor,nd[i].a)}}>{yr}</div>
              <div style={{position:'absolute',left:20,top:18,fontSize:15,color:rgba(textColor,nd[i].a*0.6)}}>Waypoint</div>
            </div>
          );
        })}
      </div>

      {/* Pie/donut chart (right) */}
      <div style={{position:'absolute',right:150,top:180,width:380,height:380}}>
        <svg width={380} height={380}>
          {segs.map((s,i) => {
            const segAngle = s.p*360*chP;
            const path = arcPath(190, 190, 130, ang, ang+segAngle);
            ang += s.p*360;
            return path ? <path key={i} d={path} fill="none" stroke={rgba(s.c,ex)} strokeWidth={50} strokeLinecap="butt"/> : null;
          })}
        </svg>
        {[{pct:'35%',a:-30},{pct:'30%',a:80},{pct:'20%',a:170},{pct:'15%',a:250}].map((l,i) => {
          const lx = 190+Math.cos(l.a*Math.PI/180)*170;
          const ly = 190+Math.sin(l.a*Math.PI/180)*170;
          return <div key={`l${i}`} style={{position:'absolute',left:lx-20,top:ly-10,width:40,textAlign:'center',fontSize:16,fontWeight:600,color:rgba(textColor,chLblA)}}>{l.pct}</div>;
        })}
      </div>

      {/* Team member circles (right bottom) */}
      <div style={{position:'absolute',right:150,bottom:140,display:'flex',gap:40}}>
        {[washColor1,washColor2,washColor3].map((c,i) => {
          const cA = fadeIn(30+i*8)*ex;
          return <div key={i} style={{width:80,height:80,borderRadius:'50%',backgroundColor:rgba(c,cA*0.15),border:`2px solid ${rgba(c,cA*0.5)}`}}/>;
        })}
      </div>
    </div>
  );
};

const CinematicTitle = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const labelPrefixText = props.labelPrefixText;
  const labelNumberText = props.labelNumberText;
  const titleText = props.titleText;
  const glowColor = props.glowColor;
  const backgroundColor = props.backgroundColor;
  const transparentBackground = props.transparentBackground;
  const titleFontFamily = props.titleFontFamily;
  const labelFontFamily = props.labelFontFamily;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const easeInOut = (t) => t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
  const easeIn = (t) => t * t * t;

  const fadeInEnd = 15;
  const fadeOutStart = Math.max(fadeInEnd + 1, durationInFrames - 20);
  const fadeOutEnd = Math.max(fadeOutStart + 1, durationInFrames);

  const masterOpacity = interpolate(
    frame,
    [0, fadeInEnd, fadeOutStart, fadeOutEnd],
    [0, 1, 1, 0],
    { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );

  const glowBuild = interpolate(frame, [9, 40], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  const labelRaw = interpolate(frame, [10, 42], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const labelEased = easeIn(labelRaw);
  const labelBlur = interpolate(labelEased, [0, 1], [9, 0]);

  const titleRaw = interpolate(frame, [18, 55], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const titleEased = easeInOut(titleRaw);
  const titleOpacity = interpolate(titleRaw, [0, 0.4, 1], [0, 0.9, 1]);
  const titleY = interpolate(titleEased, [0, 1], [-40, 0]);
  const titleBlur = interpolate(titleEased, [0, 1], [12, 0]);
  const titleShadow = `0 0 16px ${glowColor}99, 0 0 40px ${glowColor}2e`;

  const gc = glowColor || '#f3f2ff';
  const bgColor = transparentBackground ? 'transparent' : (backgroundColor || '#161422');

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      transform: `scale(${scale})`, transformOrigin: 'top left',
      backgroundColor: bgColor,
      overflow: 'hidden',
    }}>
      {/* Dot grid */}
      <div style={{
        position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
        backgroundImage: 'radial-gradient(circle, rgba(243,242,255,0.18) 1px, transparent 1px)',
        backgroundSize: '28px 28px',
        pointerEvents: 'none',
      }} />

      {/* Film grain */}
      <svg style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', opacity: 0.06, pointerEvents: 'none' }}>
        <filter id="cg">
          <feTurbulence type="fractalNoise" baseFrequency="0.7" numOctaves="4" stitchTiles="stitch"/>
          <feColorMatrix type="saturate" values="0"/>
        </filter>
        <rect width="100%" height="100%" filter="url(#cg)"/>
      </svg>

      {/* 中心大辉光 — 强且宽 */}
      <div style={{
        position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
        background: `radial-gradient(ellipse 62% 52% at 50% 52%, rgba(243,242,255,0.28) 0%, rgba(243,242,255,0.10) 35%, rgba(243,242,255,0.01) 65%, transparent 80%)`,
        opacity: glowBuild * masterOpacity,
        pointerEvents: 'none',
      }} />

      {/* 外缘散射环 — 亮-暗-亮 */}
      <div style={{
        position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
        background: `radial-gradient(ellipse 110% 110% at 50% 50%, transparent 55%, rgba(243,242,255,0.04) 72%, rgba(243,242,255,0.07) 88%, rgba(243,242,255,0.03) 100%)`,
        opacity: glowBuild * masterOpacity,
        pointerEvents: 'none',
      }} />

      {/* 四角暗角压边 */}
      <div style={{
        position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
        background: `radial-gradient(ellipse 80% 75% at 50% 50%, transparent 40%, rgba(2,1,8,0.55) 100%)`,
        pointerEvents: 'none',
      }} />

      {/* Content */}
      <div style={{
        position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
        display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
        opacity: masterOpacity,
      }}>
        {/* Label */}
        <div style={{
          display: 'flex', alignItems: 'baseline', gap: '14px',
          marginBottom: '80px',
          opacity: labelEased,
          filter: `blur(${labelBlur}px)`,
          color: gc,
          fontFamily: labelFontFamily,
          letterSpacing: '0.06em',
        }}>
          <span style={{ fontWeight: 300, fontSize: '30px', textTransform: 'capitalize', opacity: 0.88 }}>
            {labelPrefixText}
          </span>
          <span style={{ fontWeight: 700, fontSize: '34px' }}>
            {labelNumberText}
          </span>
        </div>

        {/* Title */}
        <h1 style={{
          margin: 0, padding: 0,
          fontFamily: titleFontFamily,
          fontWeight: 900,
          fontSize: '200px',
          lineHeight: 1,
          color: gc,
          textTransform: 'uppercase',
          letterSpacing: '-0.01em',
          opacity: titleOpacity,
          transform: `translateY(${titleY}px)`,
          filter: `blur(${titleBlur}px)`,
          textShadow: titleShadow,
        }}>
          {titleText}
        </h1>
      </div>
    </div>
  );
};

const ParallelogramCallout = ({item}) => {
  const frame = useCurrentFrame();
  const { durationInFrames } = useVideoConfig();
  const props = item.props || {};
  const textContent = props.textContent;
  const boxColor = props.boxColor;
  const textColor = props.textColor;
  const skewAngle = props.skewAngle;
  const fontFamily = props.fontFamily;
  const transparentBackground = props.transparentBackground;
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);
  const IN_END = 36;
  const OUT_START = durationInFrames - 28;
  // In: slow start, accelerates hard near the end — peak velocity at ~85% of duration
  // cubic-bezier(0.6, 0, 0.1, 1): long flat start, steep drop near end
  const easeIn  = Easing.bezier(0.6, 0, 0.1, 1);
  // Out: launches fast immediately, decelerates gently — mirror of in
  const easeOut = Easing.bezier(0.9, 0, 0.4, 1);
  const slideIn = interpolate(frame, [0, IN_END], [1, 0], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp',
    easing: easeIn
  });
  const slideOut = interpolate(frame, [OUT_START, durationInFrames], [0, 1], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp',
    easing: easeOut
  });
  const slideT = frame < OUT_START ? slideIn : slideOut;
  const FONT_SIZE = 72;
  const PAD_H = 36;
  const PAD_V = 24;
  const SHAPE_H = FONT_SIZE + PAD_V * 2;
  const skewDeg = typeof skewAngle === 'number' ? skewAngle : 15;
  const OFFSET = Math.tan(skewDeg * Math.PI / 180) * SHAPE_H;
  const txt = textContent ? String(textContent).toUpperCase() : '';
  const SHAPE_W = Math.round(txt.length * FONT_SIZE * 0.58 + PAD_H * 2);
  const TOTAL_W = SHAPE_W + OFFSET;
  const pts = '0,' + SHAPE_H + ' ' + SHAPE_W + ',' + SHAPE_H + ' ' + TOTAL_W + ',0 ' + OFFSET + ',0';
  const RIGHT_MARGIN = 150;
  const BOTTOM_MARGIN = 100;
  const svgLeft = DESIGN_WIDTH - RIGHT_MARGIN - TOTAL_W;
  const svgTop  = DESIGN_HEIGHT - BOTTOM_MARGIN - SHAPE_H;
  const slideOffsetX = slideT * (DESIGN_WIDTH - svgLeft + 50);
  const actualLeft = svgLeft + slideOffsetX;
  const textX = OFFSET + PAD_H;
  const textY = SHAPE_H / 2;
  const scaleStr = 'scale(' + scale + ')';
  const svgLeftStr = actualLeft + 'px';
  const svgTopStr  = svgTop + 'px';
  const rootStyle = {
    position:'absolute', top:0, left:0,
    width:DESIGN_WIDTH, height:DESIGN_HEIGHT,
    transform:scaleStr, transformOrigin:'top left',
    overflow:'hidden',
    backgroundColor: transparentBackground ? 'transparent' : '#e1e9f6'
  };
  const svgStyle = { position:'absolute', left:svgLeftStr, top:svgTopStr, overflow:'visible' };
  return (
    <div style={rootStyle}>
      <svg width={TOTAL_W} height={SHAPE_H} style={svgStyle}>
        <polygon points={pts} fill={boxColor} />
        <text
          x={textX} y={textY}
          fill={textColor}
          fontFamily={fontFamily}
          fontSize={FONT_SIZE}
          fontWeight="900"
          dominantBaseline="middle"
          textAnchor="start"
          style={{textTransform:'uppercase', letterSpacing:'1px'}}
        >{textContent}</text>
      </svg>
    </div>
  );
};

const StartupPhaseFinalV5 = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const textLine1 = props.textLine1;
  const textLine2 = props.textLine2;
  const numberText = props.numberText;
  const accentColor = props.accentColor;
  const bgColor = props.bgColor;
  const numColor = props.numColor;
  const fontFamily = props.fontFamily;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;

  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const RECT_LEFT = 1106;
  const RECT_TOP = 238;
  const RECT_W = 512;
  const RECT_H = 890;

  const SQ_LEFT = 218;
  const SQ_TOP = 686;

  const LN_LEFT = 292;
  const LN_TOP = 692;
  const LINE_TARGET_W = RECT_LEFT - LN_LEFT + 18;

  const cameraX = interpolate(frame, [0, durationInFrames - 1], [-34, 18], {
    easing: Easing.bezier(0.45, 0, 0.55, 1),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const textSlideX = interpolate(frame, [6, 26], [-110, 0], {
    easing: Easing.bezier(0.16, 1, 0.3, 1),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const squareScale = interpolate(frame, [8, 20], [0, 1], {
    easing: Easing.bezier(0.22, 1, 0.36, 1),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const squareOpacity = interpolate(frame, [8, 11, 20], [0, 0.78, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const squareDash = interpolate(frame, [8, 20], [208, 0], {
    easing: Easing.bezier(0.25, 1, 0.5, 1),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const lineW = interpolate(frame, [20, 44], [0, LINE_TARGET_W], {
    easing: Easing.bezier(0.22, 0.9, 0.2, 1),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const lineOpacity = interpolate(frame, [20, 24], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const canvasRef = React.useRef(null);

  React.useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    canvas.width = 960;
    canvas.height = 540;
    const imgData = ctx.createImageData(960, 540);
    const d = imgData.data;
    let s = 12345;
    const r = () => {
      s = (s * 9301 + 49297) % 233280;
      return s / 233280;
    };
    for (let i = 0; i < d.length; i += 4) {
      if (r() < 0.28) {
        const c = Math.floor(35 + r() * 160);
        d[i] = c;
        d[i + 1] = c;
        d[i + 2] = c;
        d[i + 3] = Math.floor(18 + r() * 70);
      } else {
        d[i + 3] = 0;
      }
    }
    ctx.putImageData(imgData, 0, 0);
  }, []);

  const useCustomOne = String(numberText).trim() === '1';

  const oneCutoutPath = `
    M 270 128
    L 426 128
    L 426 650
    L 276 650
    L 276 282
    L 122 356
    L 122 210
    Z
  `;

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
