  };

  const canvasWrapStyle = {
    position: 'absolute',
    inset: 0,
    pointerEvents: 'none',
    opacity: 0.28,
  };

  const canvasElemStyle = {
    width: '100%',
    height: '100%',
    imageRendering: 'pixelated',
  };

  const textWrapStyle = {
    position: 'absolute',
    left: 218,
    top: 246,
    transform: `translateX(${textSlideX}px)`,
    fontFamily,
    fontSize: 158,
    fontWeight: 850,
    color: '#ffffff',
    lineHeight: 0.96,
    letterSpacing: -6,
  };

  const sqSvgStyle = {
    position: 'absolute',
    left: SQ_LEFT,
    top: SQ_TOP,
    width: 96,
    height: 96,
    overflow: 'visible',
    transform: `scale(${squareScale})`,
    transformOrigin: '48px 48px',
    opacity: squareOpacity,
  };

  const lnSvgStyle = {
    position: 'absolute',
    left: LN_LEFT,
    top: LN_TOP,
    width: 900,
    height: 96,
    overflow: 'visible',
    opacity: lineOpacity,
  };

  const redBlockStyle = {
    position: 'absolute',
    left: RECT_LEFT,
    top: RECT_TOP,
    width: RECT_W,
    height: RECT_H,
    overflow: 'visible',
    filter: 'drop-shadow(-22px 0 48px rgba(0,0,0,0.68))',
  };

  return (
    <div style={rootStyle}>
      <div style={cameraStyle}>
        <div style={rightGlowStyle} />
        <div style={gridStyle} />

        <div style={textWrapStyle}>
          <div>{textLine1}</div>
