        <svg style={sqSvgStyle} viewBox="0 0 96 96">
          <defs>
            <filter id="sqGlowV5" x="-100%" y="-100%" width="300%" height="300%">
              <feGaussianBlur stdDeviation="12" />
            </filter>
          </defs>
          <rect x="20" y="20" width="52" height="52" fill="none" stroke={accentColor} strokeWidth="22" opacity="0.48" filter="url(#sqGlowV5)" strokeDasharray="208" strokeDashoffset={squareDash} />
          <rect x="20" y="20" width="52" height="52" fill="none" stroke={accentColor} strokeWidth="10" strokeDasharray="208" strokeDashoffset={squareDash} />
          <rect x="20" y="20" width="52" height="52" fill="none" stroke="#ffb1a4" strokeWidth="2.5" opacity="0.92" strokeDasharray="208" strokeDashoffset={squareDash} />
        </svg>

        {lineW > 0 && (
          <svg style={lnSvgStyle} viewBox="0 0 900 96">
            <defs>
              <filter id="lineGlowV5" x="-20%" y="-200%" width="140%" height="500%">
                <feGaussianBlur stdDeviation="14" />
