          </svg>
        )}

        <svg style={redBlockStyle} viewBox={`0 0 ${RECT_W} ${RECT_H}`} preserveAspectRatio="none">
          <defs>
            <linearGradient id="redBlockGradV5" x1="0" y1="0" x2="1" y2="1">
              <stop offset="0%" stopColor="#ff3932" />
              <stop offset="42%" stopColor={accentColor} />
              <stop offset="100%" stopColor="#ab0e00" />
            </linearGradient>
            <mask id="oneCutMaskV5" maskUnits="userSpaceOnUse">
              <rect x="0" y="0" width={RECT_W} height={RECT_H} fill="#ffffff" />
              {useCustomOne ? (
