const ComparisonTable = ({ item }) => {
  const frame = useCurrentFrame();
  const props = item.props || {};

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const bgColor = props.bgColor;
  const dotColor = props.dotColor;
  const titleColor = props.titleColor;
  const accentLineColor = props.accentLineColor;

  const wipePct = interpolate(frame, [0, 45], [-30, 150], { extrapolateRight: 'clamp' });
  const maskStyle = {
    WebkitMaskImage: `linear-gradient(45deg, rgba(0,1,9,1) ${wipePct}%, rgba(0,1,9,0) ${wipePct + 15}%)`,
    maskImage: `linear-gradient(45deg, rgba(0,1,9,1) ${wipePct}%, rgba(0,1,9,0) ${wipePct + 15}%)`,
  };

  const dotRows = 35;
  const dotCols = 60;
  const dots = React.useMemo(() => {
    const arr = [];
    for (let r = 0; r < dotRows; r++)
      for (let c = 0; c < dotCols; c++)
        arr.push({ r, c });
    return arr;
  }, []);

  const easeOut = Easing.bezier(0.25, 0.1, 0.25, 1);
  const DUR = 22;

  const progress = (start) => interpolate(frame, [start, start + DUR], [0, 1], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut
  });

  const D = [20, 45, 85, 125, 165];
  const headerP  = progress(D[0]);
  const group1P  = progress(D[1]);
  const group2P  = progress(D[2]);
  const group3P  = progress(D[3]);
  const group4P  = progress(D[4]);

  const rowContent = (brand, model, c2, c3, c4, c5, c6, p) => {
    const slideX = interpolate(p, [0, 1], [-60, 0]);
    return (
      <div style={{
        display: 'grid',
        gridTemplateColumns: '400px 280px 200px 260px 200px 260px',
        alignItems: 'center',
        transform: `translateX(${slideX}px)`,
        opacity: p,
        height: 160
      }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
          <span style={{ fontFamily: "'Barlow Condensed', sans-serif", fontWeight: 700, fontSize: 24, letterSpacing: 2, color: '#e0e7f5', textTransform: 'uppercase' }}>{brand}</span>
          <span style={{ fontFamily: "'Inter', sans-serif", fontWeight: 400, fontSize: 36, color: '#edf4ff', letterSpacing: 0.5 }}>{model}</span>
        </div>
        {[c2, c3, c4, c5, c6].map((text, i) => (
          <div key={i} style={{ fontFamily: "'Inter', sans-serif", fontWeight: 400, fontSize: 32, color: '#edf4ff' }}>{text}</div>
        ))}
      </div>
    );
  };

  const line = (p) => (
    <div style={{
      height: 2,
      backgroundColor: accentLineColor,
      width: `${p * 100}%`,
      transformOrigin: 'left'
    }} />
  );

  const rootStyle = {
    position: 'absolute', top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`, transformOrigin: 'top left',
    backgroundColor: props.transparentBackground ? 'transparent' : bgColor,
    overflow: 'hidden',
    ...maskStyle
  };

  return (
    <div style={rootStyle}>
      <svg style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%' }}>
        {dots.map(pt => {
          const wave = Math.sin(frame / 20 + pt.c * 0.15 + pt.r * 0.15);
          return (
            <circle
              key={`${pt.r}-${pt.c}`}
              cx={pt.c * 32 + 16}
              cy={pt.r * 32 + 16}
              r={interpolate(wave, [-1, 1], [0.5, 1.8])}
              fill={dotColor}
              opacity={interpolate(wave, [-1, 1], [0.03, 0.2])}
            />
          );
        })}
      </svg>

      <div style={{ position: 'absolute', top: 220, left: 160, width: 1600 }}>
        <div style={{
          display: 'grid',
          gridTemplateColumns: '400px 280px 200px 260px 200px 260px',
          alignItems: 'end',
          paddingBottom: 24,
          opacity: headerP
        }}>
          {[props.h1, props.h2, props.h3, props.h4, props.h5, props.h6].map((txt, i) => (
            <span key={i} style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 20, fontWeight: 600, color: titleColor, letterSpacing: 2, textTransform: 'uppercase' }}>
              {txt}
            </span>
          ))}
        </div>

        {line(group1P)}
        {rowContent(props.r1_b, props.r1_m, props.r1_2, props.r1_3, props.r1_4, props.r1_5, props.r1_6, group1P)}
        {line(group2P)}
        {rowContent(props.r2_b, props.r2_m, props.r2_2, props.r2_3, props.r2_4, props.r2_5, props.r2_6, group2P)}
        {line(group3P)}
        {rowContent(props.r3_b, props.r3_m, props.r3_2, props.r3_3, props.r3_4, props.r3_5, props.r3_6, group3P)}
        {line(group4P)}
        {rowContent(props.r4_b, props.r4_m, props.r4_2, props.r4_3, props.r4_4, props.r4_5, props.r4_6, group4P)}
      </div>
    </div>
  );
};

const PriceTagCard = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
  const props = item.props || {};

  const priceText = props.priceText;
  const labelText = props.labelText;
  const cardColor = props.cardColor;
  const textColor = props.textColor;
  const transparentBackground = props.transparentBackground;
  const fontFamily = props.fontFamily;

  const DESIGN_WIDTH = 600;
  const DESIGN_HEIGHT = 500;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const safeFps = fps || 30;
  const totalFrames = 90;
  const exitDuration = 18;
  const exitStart = totalFrames - exitDuration;

  const entrance = spring({
    frame,
    fps: safeFps,
    config: { damping: 40, stiffness: 120, mass: 1 }
  });

  const exit = spring({
    frame: Math.max(0, frame - exitStart),
    fps: safeFps,
    config: { damping: 40, stiffness: 120, mass: 1 }
  });

  const translateY = interpolate(entrance, [0, 1], [300, 0]) + interpolate(exit, [0, 1], [0, 300]);

  const entranceOpacity = interpolate(frame, [8, 20], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const exitOpacity = interpolate(frame, [exitStart, exitStart + 10], [1, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const opacity = Math.min(entranceOpacity, exitOpacity);

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: transparentBackground ? 'transparent' : '#111111',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    overflow: 'hidden',
  };

  const cardStyle = {
    width: 440,
    height: 360,
    backgroundColor: cardColor,
    borderRadius: 40,
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    transform: `translateY(${translateY}px)`,
    opacity: opacity,
    padding: '0 32px',
    boxSizing: 'border-box'
  };

  const priceStyle = {
    color: textColor,
    fontFamily: fontFamily,
    fontStyle: 'italic',
    fontSize: 130,
    fontWeight: 300,
    lineHeight: 0.95,
    margin: 0,
    padding: 0,
    letterSpacing: '-0.01em',
    whiteSpace: 'nowrap'
  };

  const labelStyle = {
    color: textColor,
    fontFamily: fontFamily,
    fontStyle: 'italic',
    fontSize: 40,
    fontWeight: 650,
    marginTop: 14,
    letterSpacing: '0.08em',
    textTransform: 'uppercase',
    whiteSpace: 'nowrap'
  };

  return (
    <div style={rootStyle}>
      <div style={cardStyle}>
        <div style={priceStyle}>{priceText}</div>
        <div style={labelStyle}>{labelText}</div>
      </div>
    </div>
  );
};

const BroadcastOverlay = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const bgColor = props.bgColor;
  const dividerColor = props.dividerColor;
  const l1Label = props.l1Label;
  const l1Value = props.l1Value;
  const l2Label = props.l2Label;
  const l2Value = props.l2Value;
  const l3Label = props.l3Label;
  const l3Value = props.l3Value;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const PANEL_W = 620;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const SLIDE_DUR   = 36;
  const easeBellIn  = Easing.bezier(0.4, 0, 0.1, 1);
  const easeBellOut = Easing.bezier(0.9, 0.1, 0.6, 1);
  const easeTextIn  = Easing.bezier(0.16, 1, 0.3, 1);

  const bgIn  = interpolate(frame, [0, SLIDE_DUR], [-PANEL_W, 0], { extrapolateLeft:'clamp', extrapolateRight:'clamp', easing: easeBellIn });
  const bgOut = interpolate(frame, [durationInFrames - SLIDE_DUR, durationInFrames], [0, -PANEL_W], { extrapolateLeft:'clamp', extrapolateRight:'clamp', easing: easeBellOut });
  const panelX = frame < durationInFrames / 2 ? bgIn : bgOut;

  const TEXT_IN_START = 14, TEXT_IN_DUR = 42;
  const textIn  = interpolate(frame, [TEXT_IN_START, TEXT_IN_START + TEXT_IN_DUR], [-PANEL_W, 0], { extrapolateLeft:'clamp', extrapolateRight:'clamp', easing: easeTextIn });
  const textOut = interpolate(frame, [durationInFrames - SLIDE_DUR, durationInFrames], [0, -PANEL_W], { extrapolateLeft:'clamp', extrapolateRight:'clamp', easing: easeBellOut });
  const textX = frame < durationInFrames / 2 ? textIn : textOut;

  // Dot grid — single SVG, single global drift, no per-column phase offset
  // This eliminates the jitter caused by independent per-column translate values
  const COL_COUNT   = 14;
  const DOT_SPACING = 36;
  const COL_WIDTH   = PANEL_W / COL_COUNT;
  const DOTS_PER_COL = Math.ceil((DESIGN_HEIGHT + DOT_SPACING) / DOT_SPACING) + 2;
  const DRIFT_SPEED = 0.20;

  // Single global Y drift — all columns move in perfect unison
  const globalDrift = (frame * DRIFT_SPEED) % DOT_SPACING;

  const dotGrid = React.useMemo(() => {
    const circles = [];
    for (let ci = 0; ci < COL_COUNT; ci++) {
      const baseX   = (ci + 0.5) * COL_WIDTH;
      const dotSize = random(`ds${ci}`) * 1.6 + 1.6;
      const opacity = random(`op${ci}`) * 0.22 + 0.18;
      for (let di = 0; di < DOTS_PER_COL; di++) {
        const xOff   = (random(`wx${ci}-${di}`) - 0.5) * 12;
        const sizeVar = random(`sv${ci}-${di}`) * 0.8;
        const opVar   = (random(`ov${ci}-${di}`) - 0.5) * 0.1;
        circles.push({
          key: `${ci}-${di}`,
          cx: baseX + xOff,
          cy: di * DOT_SPACING - DOT_SPACING,
          r: dotSize + sizeVar,
          opacity: Math.max(0.05, opacity + opVar),
        });
      }
    }
    return circles;
  }, []);

  const rootStyle = {
    position: 'absolute', top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: 'transparent',
  };

  const textStyle = {
    fontFamily: "'Barlow Condensed', sans-serif",
    fontWeight: 800, fontStyle: 'italic',
    fontSize: '72px', lineHeight: '1.05',
    margin: 0, padding: 0,
    display: 'flex', alignItems: 'baseline',
    letterSpacing: '-0.5px', whiteSpace: 'nowrap',
  };

  return (
    <div style={rootStyle}>
      <div style={{
        position: 'absolute', left: 0, top: 0,
        width: PANEL_W, height: DESIGN_HEIGHT,
        backgroundColor: bgColor,
        transform: `translateX(${panelX}px)`,
        borderRight: `3px solid ${dividerColor}`,
        boxSizing: 'border-box',
        overflow: 'hidden',
        willChange: 'transform',
      }}>
        {/* Single SVG — one global translateY for all dots, zero jitter */}
        <svg
          style={{ position:'absolute', left:0, top:0, pointerEvents:'none', overflow:'visible' }}
          width={PANEL_W} height={DESIGN_HEIGHT}
          viewBox={`0 0 ${PANEL_W} ${DESIGN_HEIGHT}`}
        >
          <g transform={`translate(0, ${globalDrift})`}>
            {dotGrid.map(d => (
              <circle key={d.key} cx={d.cx} cy={d.cy} r={d.r} fill="#ffffff" opacity={d.opacity} />
            ))}
          </g>
        </svg>
      </div>

      <div style={{
        position: 'absolute', left: 0, top: 0,
        width: PANEL_W, height: DESIGN_HEIGHT,
        transform: `translateX(${textX}px)`,
        overflow: 'hidden', willChange: 'transform', pointerEvents: 'none',
      }}>
        <div style={{
          position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
          display: 'flex', flexDirection: 'column', justifyContent: 'center',
          paddingLeft: '52px', paddingRight: '40px',
          gap: '20px', boxSizing: 'border-box',
        }}>
          <div style={textStyle}>
            <span style={{color:'#000000', marginRight:'12px'}}>{l1Label}</span>
            <span style={{color:'#ffffff'}}>{l1Value}</span>
          </div>
          <div style={textStyle}>
            <span style={{color:'#000000', marginRight:'12px'}}>{l2Label}</span>
            <span style={{color:'#ffffff'}}>{l2Value}</span>
          </div>
          <div style={textStyle}>
            <span style={{color:'#000000', marginRight:'12px'}}>{l3Label}</span>
            <span style={{color:'#ffffff'}}>{l3Value}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

const SnapdragonPromo = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps, durationInFrames } = useVideoConfig();

  const props = item.props || {};
  const titleLine1 = props.titleLine1;
  const titleLine2 = props.titleLine2;
  const specs = [
    props.spec1, props.spec2, props.spec3, props.spec4,
    props.spec5, props.spec6, props.spec7, props.spec8
  ];
  const neonColor = props.neonColor;
  const dotColor = props.dotColor;
  const transparentBackground = props.transparentBackground;

  const DESIGN_WIDTH = 608;
  const DESIGN_HEIGHT = 1080;
  const SAFE_BOTTOM = 108;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const SLIDE_IN_DUR  = 54;
  const SLIDE_OUT_DUR = 54;
  // 中点钳制:时长 < in+out(如默认 90)时保持严格递增,时长充裕时还原原节奏
  const SLIDE_MID_IN  = Math.max(1, Math.min(SLIDE_IN_DUR, Math.floor(durationInFrames / 2) - 1));
  const SLIDE_MID_OUT = Math.min(durationInFrames - 1, Math.max(SLIDE_MID_IN + 1, durationInFrames - SLIDE_OUT_DUR));
  const easeBellIn    = Easing.bezier(0.4, 0, 0.1, 1);
  const easeBellOut   = Easing.bezier(0.9, 0.1, 0.6, 1);
  const easeContentIn = Easing.bezier(0.16, 1, 0.3, 1);

  const bgIn  = interpolate(frame, [0, SLIDE_IN_DUR], [-DESIGN_WIDTH, 0], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeBellIn
  });
  const bgOut = interpolate(frame, [durationInFrames - SLIDE_OUT_DUR, durationInFrames], [0, -DESIGN_WIDTH], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeBellOut
  });
  const cardX = frame < durationInFrames / 2 ? bgIn : bgOut;

  const TEXT_IN_START = 18;
  const TEXT_IN_DUR   = 42;
  const contentIn  = interpolate(frame, [TEXT_IN_START, TEXT_IN_START + TEXT_IN_DUR], [-DESIGN_WIDTH * 0.15, 0], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeContentIn
  });
  const contentOut = interpolate(frame, [durationInFrames - SLIDE_OUT_DUR, durationInFrames], [0, -DESIGN_WIDTH * 0.15], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeBellOut
  });
  const contentX = frame < durationInFrames / 2 ? contentIn : contentOut;

  const NEON_START = 58;

  const rootStyle = {
    position: 'absolute',
    top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    overflow: 'hidden',
    backgroundColor: 'transparent',
  };

  const rows = 35, cols = 20, spacing = 32;
  const dots = [];
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const x = c * spacing, y = r * spacing;
      const wave = Math.sin(c * 0.2 + r * 0.15 + frame * 0.05);
      dots.push(<circle key={`${r}-${c}`} cx={x} cy={y}
        r={interpolate(wave, [-1,1],[0.5,2])}
        fill={dotColor}
        opacity={interpolate(wave, [-1,1],[0.05,0.25])} />);
    }
  }

  const getNeonOpacity = (localF) => {
    if (localF <= 0)  return 0;
    if (localF <= 6)  return interpolate(localF, [0,6],   [0,0.12]);
    if (localF <= 14) return interpolate(localF, [6,14],  [0.12,1.0]);
    if (localF <= 20) return interpolate(localF, [14,20], [1.0,0.2]);
    if (localF <= 30) return interpolate(localF, [20,30], [0.2,1.0]);
    if (localF <= 37) return interpolate(localF, [30,37], [1.0,0.55]);
    if (localF <= 46) return interpolate(localF, [37,46], [0.55,1.0]);
    return 1.0 + Math.sin((localF - 46) * 0.06) * 0.03;
  };

  const getNeonGlow = (opacity) => {
    const g = Math.max(0, Math.min(1, opacity));
    return [
      `0 0 ${6*g}px ${neonColor}`,
      `0 0 ${16*g}px ${neonColor}CC`,
      `0 0 ${30*g}px ${neonColor}88`,
      `0 0 ${44*g}px ${neonColor}44`,
    ].join(', ');
  };

  const TitleLine = ({ text, globalDelay, item }) => {
    const localF = Math.max(0, frame - (NEON_START + globalDelay));
    if (localF === 0) return <div style={{ color:'transparent', fontSize:66, fontWeight:800, lineHeight:1.1, fontFamily:"'Barlow Condensed', sans-serif" }}>{text}</div>;
    const opacity = getNeonOpacity(localF);
    return (
      <div style={{ opacity, color:neonColor, fontSize:66, fontWeight:800, lineHeight:1.1,
        letterSpacing:'0.02em', textShadow:getNeonGlow(opacity), textTransform:'uppercase',
        fontFamily:"'Barlow Condensed', sans-serif" }}>
        {text}
      </div>
    );
  };

  const SPEC_STAGGER = 30;
  const SPEC_START   = NEON_START + 52;

  const SpecLine = ({ text, delay, item }) => {
    const localF = Math.max(0, frame - delay);
    const tailLen = Math.min(4, text.length);
    const mainStr = text.slice(0, text.length - tailLen);
    const tailStr = text.slice(text.length - tailLen);
    const slideIn  = spring({ frame:localF, fps, config:{ damping:18, stiffness:120 } });
    const hrSpring = spring({ frame:Math.max(0,localF-5), fps, config:{ damping:24, stiffness:120, overshootClamping:true } });
    const dotScale = spring({ frame:Math.max(0,localF-12), fps, config:{ damping:15, mass:0.5 } });
    return (
      <div style={{ position:'relative', width:'100%', paddingBottom:12 }}>
        <div style={{ display:'flex', alignItems:'center', fontSize:28, fontWeight:500, color:'#fff', fontFamily:"'Inter', sans-serif" }}>
          <span style={{ display:'inline-block', transform:`translateX(${interpolate(slideIn,[0,1],[-30,0])}px)`, opacity:interpolate(slideIn,[0,1],[0,1]), whiteSpace:'pre' }}>{mainStr}</span>
          <span style={{ display:'inline-flex' }}>
            {tailStr.split('').map((char,i) => {
              const charOp = interpolate(Math.max(0,localF-(10+i*4)),[0,5],[0,1],{extrapolateRight:'clamp'});
              return <span key={i} style={{ opacity:charOp, whiteSpace:'pre' }}>{char}</span>;
            })}
          </span>
        </div>
        <div style={{ position:'absolute', bottom:0, left:0, right:0, height:1.5, backgroundColor:'rgba(255,255,255,0.3)', transform:`scaleX(${Math.min(1,hrSpring)})`, transformOrigin:'left' }} />
        <div style={{ position:'absolute', bottom:-2, right:0, width:6, height:6, backgroundColor:'#fff', transform:`scale(${dotScale})`, transformOrigin:'center' }} />
      </div>
    );
  };

  const dividerOp = interpolate(frame,
    [0, SLIDE_MID_IN, SLIDE_MID_OUT, durationInFrames],
    [0, 1, 1, 0],
    { extrapolateLeft:'clamp', extrapolateRight:'clamp' }
  );

  return (
    <div style={rootStyle}>
      <div style={{ position:'absolute', top:0, left:0, width:DESIGN_WIDTH, height:DESIGN_HEIGHT,
        backgroundColor: transparentBackground ? 'transparent' : '#1a1a1a',
        transform:`translateX(${cardX}px)`, willChange:'transform' }}>
        <svg width="100%" height="100%" style={{ position:'absolute', top:0, left:0 }}>{dots}</svg>
        <div style={{ position:'absolute', top:0, right:0, width:2, height:'100%',
          backgroundColor:'#888888', opacity:dividerOp }} />
      </div>
      <div style={{ position:'absolute', top:80, left:80, width:488,
        transform:`translateX(${cardX + contentX}px)`, willChange:'transform', zIndex:1 }}>
        <div style={{ marginBottom:40 }}>
          <TitleLine text={titleLine1} globalDelay={0} />
          <TitleLine text={titleLine2} globalDelay={20} />
        </div>
        <div style={{ display:'flex', flexDirection:'column', gap:20, paddingBottom:SAFE_BOTTOM }}>
          {specs.map((spec, i) => <SpecLine key={i} text={spec} delay={SPEC_START + i * SPEC_STAGGER} />)}
        </div>
      </div>
    </div>
  );
};

const InvestmentSlide = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const titleText = props.titleText;
  const subtitleText = props.subtitleText;
  const titleFont = props.titleFont;
  const bodyFont = props.bodyFont;

  const v1 = parseFloat(props.seg1Value) || 0;
  const v2 = parseFloat(props.seg2Value) || 0;
  const v3 = parseFloat(props.seg3Value) || 0;
  const v4 = parseFloat(props.seg4Value) || 0;
  const total = (v1 + v2 + v3 + v4) || 1;
  const p1 = v1 / total;
  const p2 = v2 / total;
  const p3 = v3 / total;
  const p4 = v4 / total;

  const color1 = props.color1;
  const color2 = props.color2;
  const color3 = props.color3;
  const color4 = props.color4;

  const backgroundColor = props.transparentBackground ? 'transparent' : props.bgColor;

  // --- Easing curves ---
  const smoothSettle = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 3.5);
  };
  const bellCurveLate = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return t < 0.4
      ? 0.15 * Math.pow(t / 0.4, 2.5)
      : 0.15 + 0.85 * (1 - Math.pow(1 - (t - 0.4) / 0.6, 2.8));
  };

  // --- NO dynamic opacity/transform on root (triggers compositor promotion) ---
  // Exit: bake into child elements instead
  const totalFrames = durationInFrames || 180;
  const exitStart = totalFrames - 25;
  const exitRaw = Math.max(0, Math.min(1, (frame - exitStart) / 25));
  const exitProgress = exitRaw * exitRaw;
  const exitAlpha = 1 - exitProgress;

  // --- Frame border: fade in over 40 frames ---
  const frameRaw = Math.min(1, Math.max(0, frame / 40));
  const frameOpacity = smoothSettle(frameRaw) * exitAlpha;

  // --- Title: starts at frame 5, 50 frames ---
  const titleRaw = Math.min(1, Math.max(0, (frame - 5) / 50));
  const titleProgress = smoothSettle(titleRaw);
  const titleOpacity = smoothSettle(Math.min(1, Math.max(0, (frame - 5) / 18))) * exitAlpha;
  const titleY = (1 - titleProgress) * 60;

  // --- Separator line: starts frame 20, 45 frames ---
  const sepRaw = Math.min(1, Math.max(0, (frame - 20) / 45));
  const separatorWidth = smoothSettle(sepRaw) * 100;

  // --- Donut chart segments: bellCurveLate, staggered ---
  const C = 2 * Math.PI * 130;
  const d1 = p1 * C;
  const d2 = p2 * C;
  const d3 = p3 * C;
  const d4 = p4 * C;

  const chartRaw1 = Math.min(1, Math.max(0, (frame - 30) / 60));
  const chartRaw2 = Math.min(1, Math.max(0, (frame - 36) / 60));
  const chartRaw3 = Math.min(1, Math.max(0, (frame - 42) / 60));
  const chartRaw4 = Math.min(1, Math.max(0, (frame - 48) / 60));

  const s1 = bellCurveLate(chartRaw1) * d1;
  const s2 = bellCurveLate(chartRaw2) * d2;
  const s3 = bellCurveLate(chartRaw3) * d3;
  const s4 = bellCurveLate(chartRaw4) * d4;

  // --- Legend items: staggered, appear when chart at 55% ---
  const legendDelay1 = 30 + 60 * 0.55;
  const legendDelay2 = 36 + 60 * 0.55;
  const legendDelay3 = 42 + 60 * 0.55;
  const legendDelay4 = 48 + 60 * 0.55;

  const legendRaw = (delay) => Math.min(1, Math.max(0, (frame - delay) / 20));
  const l1Op = smoothSettle(legendRaw(legendDelay1)) * exitAlpha;
  const l2Op = smoothSettle(legendRaw(legendDelay2)) * exitAlpha;
  const l3Op = smoothSettle(legendRaw(legendDelay3)) * exitAlpha;
  const l4Op = smoothSettle(legendRaw(legendDelay4)) * exitAlpha;

  const GAP = 2.5;

  // Bake exitAlpha into SVG stroke opacity
  const chartAlpha = exitAlpha;

  const hexToRgba = (hex, alpha) => {
    if (!hex) return `rgba(0,1,9,${alpha})`;
    const h = hex.replace('#', '');
    const r = parseInt(h.length === 3 ? h[0]+h[0] : h.substring(0,2), 16) || 0;
    const g = parseInt(h.length === 3 ? h[1]+h[1] : h.substring(2,4), 16) || 0;
    const b = parseInt(h.length === 3 ? h[2]+h[2] : h.substring(4,6), 16) || 0;
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  };

  const LegendItem = ({ label, value, color, opacity, item }) => (
    <div style={{
      display: 'flex', alignItems: 'center', gap: 24,
      opacity,
      transform: `translateX(${(1 - opacity) * -15}px)`
    }}>
      <div style={{ width: 16, height: 16, backgroundColor: color, borderRadius: '50%' }} />
      <div style={{ display: 'flex', flexDirection: 'column', minWidth: 200 }}>
        <span style={{ fontFamily: bodyFont, fontSize: 24, color: '#dee6f3', fontWeight: 300, letterSpacing: 0.5 }}>{label}</span>
      </div>
      <div style={{ flex: 1, borderBottom: '1px dashed rgba(237,244,255,0.15)', margin: '0 20px', position: 'relative', top: 4 }} />
      <span style={{ fontFamily: titleFont, fontSize: 30, color: color, fontWeight: 500 }}>{value}%</span>
    </div>
  );

  return (
    <div style={{ position: 'absolute', inset: 0, backgroundColor, overflow: 'hidden' }}>
      <div style={{
        position: 'absolute',
        inset: 40,
        border: '1px solid rgba(237,244,255,0.1)',
        pointerEvents: 'none',
        opacity: frameOpacity
      }}>
        <div style={{ position: 'absolute', top: -1, left: -1, width: 20, height: 20, borderTop: '2px solid rgba(237,244,255,0.5)', borderLeft: '2px solid rgba(237,244,255,0.5)' }} />
        <div style={{ position: 'absolute', top: -1, right: -1, width: 20, height: 20, borderTop: '2px solid rgba(237,244,255,0.5)', borderRight: '2px solid rgba(237,244,255,0.5)' }} />
        <div style={{ position: 'absolute', bottom: -1, left: -1, width: 20, height: 20, borderBottom: '2px solid rgba(237,244,255,0.5)', borderLeft: '2px solid rgba(237,244,255,0.5)' }} />
        <div style={{ position: 'absolute', bottom: -1, right: -1, width: 20, height: 20, borderBottom: '2px solid rgba(237,244,255,0.5)', borderRight: '2px solid rgba(237,244,255,0.5)' }} />
      </div>

      <div style={{
        position: 'absolute',
        inset: 80,
        display: 'flex',
        alignItems: 'center',
        opacity: exitAlpha
      }}>
        <div style={{ flex: '0 0 50%', paddingRight: 60, display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
          <div style={{ opacity: titleOpacity, transform: `translateY(${titleY}px)` }}>
            <h1 style={{ fontFamily: titleFont, fontSize: 72, color: color1, margin: '0 0 10px 0', fontWeight: 600, lineHeight: 1.1 }}>
              {titleText}
            </h1>
            <h2 style={{ fontFamily: bodyFont, fontSize: 30, color: '#9ba4b3', margin: 0, fontWeight: 300, letterSpacing: 2 }}>
              {subtitleText}
            </h2>
          </div>

          <div style={{
            height: 1,
            backgroundColor: 'rgba(237,244,255,0.2)',
            margin: '40px 0 60px 0',
            width: `${separatorWidth}%`
          }} />

          <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
            <LegendItem label={props.seg1Label} value={props.seg1Value} color={color1} opacity={l1Op} />
            <LegendItem label={props.seg2Label} value={props.seg2Value} color={color2} opacity={l2Op} />
            <LegendItem label={props.seg3Label} value={props.seg3Value} color={color3} opacity={l3Op} />
            <LegendItem label={props.seg4Label} value={props.seg4Value} color={color4} opacity={l4Op} />
          </div>
        </div>

        <div style={{ flex: '0 0 50%', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
          <div style={{ width: 700, height: 700, transform: 'rotate(-90deg)' }}>
            <svg viewBox="-20 -20 440 440" width="100%" height="100%" style={{ overflow: 'hidden' }}>
              <g opacity={frameOpacity}>
                <circle cx="200" cy="200" r="130" stroke={`rgba(237,244,255,0.03)`} strokeWidth="140" fill="transparent" />
                <circle cx="200" cy="200" r="205" stroke={`rgba(237,244,255,0.1)`} strokeWidth="1" fill="transparent" />
                <circle cx="200" cy="200" r="55" stroke={`rgba(237,244,255,0.1)`} strokeWidth="1" fill="transparent" />
              </g>
              <g opacity={chartAlpha}>
                <circle cx="200" cy="200" r="130" fill="transparent" stroke={color1} strokeWidth="140" strokeDasharray={`${Math.max(0, s1 - GAP)} ${C}`} strokeDashoffset={0} strokeLinecap="butt" />
                <circle cx="200" cy="200" r="130" fill="transparent" stroke={color2} strokeWidth="140" strokeDasharray={`${Math.max(0, s2 - GAP)} ${C}`} strokeDashoffset={-d1} strokeLinecap="butt" />
                <circle cx="200" cy="200" r="130" fill="transparent" stroke={color3} strokeWidth="140" strokeDasharray={`${Math.max(0, s3 - GAP)} ${C}`} strokeDashoffset={-(d1+d2)} strokeLinecap="butt" />
                <circle cx="200" cy="200" r="130" fill="transparent" stroke={color4} strokeWidth="140" strokeDasharray={`${Math.max(0, s4 - GAP)} ${C}`} strokeDashoffset={-(d1+d2+d3)} strokeLinecap="butt" />
              </g>
            </svg>
          </div>
        </div>
      </div>
    </div>
  );
};

const VoxAreaChart = ({ item }) => {
  const baseFrame = useCurrentFrame();
  const { fps, durationInFrames } = useVideoConfig();
  const frame = Math.floor(baseFrame / 3) * 3;

  const props = item.props || {};
  const titleText = props.titleText;
  const subtitleText = props.subtitleText;
  const blueText = props.blueText;
  const pinkText = props.pinkText;
  const backgroundColor = props.backgroundColor;
  const blueColor = props.blueColor;
  const pinkColor = props.pinkColor;
  const yellowColor = props.yellowColor;
  const transparentBackground = props.transparentBackground;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);
  const safeFps = fps || 30;

  const startX = 180;
  const endX = 1740;
  const startY = 910;
  const endY = 340;
  const chartW = endX - startX;
  const chartH = startY - endY;
  const maxVal = 16;

  const mapX = (year) => startX + ((year - 1999) / 24) * chartW;
  const mapY = (val) => startY - (val / maxVal) * chartH;

  const blueData = [
    {x:1999,y:14.6},{x:2001,y:12.9},{x:2003,y:11.2},{x:2005,y:8.8},
    {x:2007,y:7.5},{x:2009,y:6.3},{x:2011,y:4.6},{x:2013,y:2.8},
    {x:2015,y:1.9},{x:2017,y:1.5},{x:2019,y:1.1},{x:2021,y:1.2},{x:2023,y:1.3}
  ];

  const pinkData = [
    {x:1999,y:0},{x:2003,y:0},{x:2008,y:0.1},{x:2010,y:0.3},
    {x:2012,y:1.0},{x:2014,y:2.2},{x:2016,y:3.9},{x:2018,y:7.4},
    {x:2020,y:10.1},{x:2022,y:13.3},{x:2023,y:14.4}
  ];

  const buildPath = (data) => {
    let p = 'M ' + mapX(data[0].x) + ' ' + startY + ' ';
    data.forEach(d => { p += 'L ' + mapX(d.x) + ' ' + mapY(d.y) + ' '; });
    p += 'L ' + mapX(data[data.length-1].x) + ' ' + startY + ' Z';
    return p;
  };

  const bluePathStr = buildPath(blueData);
  const pinkPathStr = buildPath(pinkData);
  const yTicks = [0,2,4,6,8,10,12,14,16];
  const xTicks = [1999,2003,2008,2013,2018,2023];

  const yAxisTop = interpolate(frame, [0,15], [startY, endY-30], {extrapolateRight:'clamp'});
  const xAxisRight = interpolate(frame, [0,15], [startX, endX+30], {extrapolateRight:'clamp'});
  const ticksOpacity = interpolate(frame, [5,20], [0,1], {extrapolateLeft:'clamp',extrapolateRight:'clamp'});
  const blueRevealW = interpolate(frame, [15,90], [0, chartW+50], {extrapolateLeft:'clamp',extrapolateRight:'clamp'});
  const pinkRevealW = interpolate(frame, [30,105], [0, chartW+50], {extrapolateLeft:'clamp',extrapolateRight:'clamp'});

  const itunesSpring = spring({frame: Math.max(0, frame-45), fps:safeFps, config:{damping:15}});
  const itunesLineY = interpolate(itunesSpring, [0,1], [startY, mapY(16)]);
  const crossSpring = spring({frame: Math.max(0, frame-75), fps:safeFps, config:{damping:15}});
  const crossLineY = interpolate(crossSpring, [0,1], [startY, mapY(16)]);

  const textOpacity = interpolate(frame, [105,120], [0,1], {extrapolateLeft:'clamp',extrapolateRight:'clamp'});
  const bg = transparentBackground ? 'transparent' : (backgroundColor || '#e8e6e0');

  const watermarks = React.useMemo(() => {
    const symbols = ['∑','∫','π','Δ','α','β','∞','≈','≠','≤','≥','Ω','µ','√'];
    const out = [];
    let seed = 12345;
    const rng = () => { seed = (seed * 9301 + 49297) % 233280; return seed / 233280; };
    for (let i = 0; i < 40; i++) {
      out.push({ id: i, char: symbols[Math.floor(rng() * symbols.length)],
        left: `${rng()*110-5}%`, top: `${rng()*110-5}%`,
        size: 150 + rng()*450, rot: (rng()-0.5)*120, opacity: 0.02+rng()*0.03 });
    }
    return out;
  }, []);

  return (
    <div style={{position:'absolute',top:0,left:0,width:DESIGN_WIDTH,height:DESIGN_HEIGHT,transform:'scale('+scale+')',transformOrigin:'top left',backgroundColor:bg,overflow:'hidden'}}>

      {!transparentBackground && (
        <>
          {/* Grid background — from News Card */}
          <div style={{ position: 'absolute', inset: 0, zIndex: 1 }}>
            <svg width="100%" height="100%">
              <defs>
                <pattern id="acgrid" width="80" height="80" patternUnits="userSpaceOnUse">
                  <path d="M 40 0 L 40 80 M 0 40 L 80 40" stroke="#999" strokeOpacity="0.06" strokeWidth="1.5"/>
                  <path d="M 33 40 L 47 40 M 40 33 L 40 47" stroke="#999" strokeOpacity="0.15" strokeWidth="2"/>
                </pattern>
              </defs>
              <rect width="100%" height="100%" fill="url(#acgrid)"/>
            </svg>
          </div>

          {/* Watermark symbols — from News Card */}
          <div style={{ position: 'absolute', inset: 0, zIndex: 2 }}>
            {watermarks.map(wm => (
              <div key={wm.id} style={{
                position: 'absolute', left: wm.left, top: wm.top,
                fontSize: wm.size, color: '#888', opacity: wm.opacity,
                transform: `rotate(${wm.rot}deg)`, lineHeight: 1, fontFamily: 'serif',
              }}>{wm.char}</div>
            ))}
          </div>
        </>
      )}

      {/* Title + subtitle — left aligned */}
      <div style={{position:'absolute',top:160,left:startX,opacity:textOpacity,display:'flex',flexDirection:'column',gap:10,zIndex:10}}>
