const Chart = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const props = item.props || {};
  const titleText      = props.titleText;
  const subtitleText   = props.subtitleText;
  const seriesALabel   = props.seriesALabel;
  const seriesBLabel   = props.seriesBLabel;
  const moreAboveLabel = props.moreAboveLabel;
  const moreBelowLabel = props.moreBelowLabel;
  const seriesAPos     = props.seriesAPos;
  const seriesANeg     = props.seriesANeg;
  const seriesBPos     = props.seriesBPos;
  const seriesBNeg     = props.seriesBNeg;
  const bgColor        = props.bgColor;
  const textColor      = props.textColor;
  const gridColor      = props.gridColor;
  const titleFontFamily  = props.titleFontFamily;
  const labelFontFamily  = props.labelFontFamily;
  const transparentBackground = props.transparentBackground;

  const data = [
    { year: '2000', a: +2.3, b: -2.2 },
    { year: '2004', a: +3.0, b: -2.8 },
    { year: '2008', a: +3.2, b: -3.0 },
    { year: '2012', a: +4.3, b: -4.1 },
    { year: '2016', a: +2.5, b: -2.4 },
    { year: '2020', a: +3.6, b: -3.1 },
  ];

  const SAFE_L = 192; const SAFE_R = 1728; const SAFE_T = 108; const SAFE_B = 972;
  const TITLE_Y    = SAFE_T + 52;
  const SUBTITLE_Y = TITLE_Y + 46;
  const LEGEND_Y   = SUBTITLE_Y + 38;
  const CHART_TOP  = LEGEND_Y + 28;
  const CHART_BOT  = SAFE_B - 40;
  const CHART_H    = CHART_BOT - CHART_TOP;

  const ANNOT_X    = SAFE_L;
  const ANNOT_MAX  = 310;
  const TICK_RIGHT = ANNOT_MAX + 78;
  const CHART_LEFT = TICK_RIGHT + 16;
  const CHART_RIGHT = SAFE_R;
  const YEAR_Y     = CHART_BOT + 36;

  const PX_PER_PT = CHART_H / 10;
  const ZERO_Y    = CHART_TOP + 5 * PX_PER_PT;

  const ticks      = [-4,-2,0,2,4].map(v => ({ v, y: ZERO_Y - v * PX_PER_PT }));
  const minorTicks = [-5,-3,-1,1,3,5].map(v => ({ v, y: ZERO_Y - v * PX_PER_PT }));

  const aboveMidY = ZERO_Y - 3 * PX_PER_PT;
  const belowMidY = ZERO_Y + 3 * PX_PER_PT;

  const aboveLine1 = moreAboveLabel + ' ↑';
  const aboveLine2 = 'than avg';
  const belowLine1 = moreBelowLabel + ' ↓';
  const belowLine2 = 'than avg';

  const chartWidth = CHART_RIGHT - CHART_LEFT;
  const groupWidth = chartWidth / 6;
  const yearCX = data.map((_, i) => CHART_LEFT + groupWidth * i + groupWidth / 2);
  const barWidth = groupWidth * 0.20;
  const barGap   = groupWidth * 0.04;

  const BAR_GROW = 28; const LABEL_FADE = 8; const AB_GAP = 22; const YEAR_GAP = 36; const START = 8;
  const easeOut = (t) => 1 - Math.pow(1 - Math.min(1, Math.max(0, t)), 3);

  const watermarks = React.useMemo(() => {
    const symbols = ['∑','∫','π','Δ','α','β','∞','≈','≠','≤','≥','Ω','µ','√'];
    const out = [];
    let seed = 12345;
    const rng = () => { seed = (seed * 9301 + 49297) % 233280; return seed / 233280; };
    for (let i = 0; i < 40; i++) {
      out.push({ id: i, char: symbols[Math.floor(rng() * symbols.length)],
        left: `${rng()*110-5}%`, top: `${rng()*110-5}%`,
        size: 150 + rng()*450, rot: (rng()-0.5)*120, opacity: 0.02+rng()*0.03 });
    }
    return out;
  }, []);

  const rootStyle = { position: 'absolute', inset: 0, backgroundColor: transparentBackground ? 'transparent' : bgColor };

  return (
    <div style={rootStyle}>

      {/* Grid background — from News Card */}
      {!transparentBackground && (
        <div style={{ position: 'absolute', inset: 0, zIndex: 1 }}>
          <svg width="100%" height="100%">
            <defs>
              <pattern id="cgrid" width="80" height="80" patternUnits="userSpaceOnUse">
                <path d="M 40 0 L 40 80 M 0 40 L 80 40" stroke="#999" strokeOpacity="0.06" strokeWidth="1.5"/>
                <path d="M 33 40 L 47 40 M 40 33 L 40 47" stroke="#999" strokeOpacity="0.15" strokeWidth="2"/>
              </pattern>
            </defs>
            <rect width="100%" height="100%" fill="url(#cgrid)"/>
          </svg>
        </div>
      )}

      {/* Watermark symbols — from News Card */}
      {!transparentBackground && (
        <div style={{ position: 'absolute', inset: 0, zIndex: 2 }}>
          {watermarks.map(wm => (
            <div key={wm.id} style={{
              position: 'absolute', left: wm.left, top: wm.top,
              fontSize: wm.size, color: '#888', opacity: wm.opacity,
              transform: `rotate(${wm.rot}deg)`, lineHeight: 1, fontFamily: 'serif',
            }}>{wm.char}</div>
          ))}
        </div>
      )}

      {/* Chart layer */}
      <div style={{ position: 'absolute', inset: 0, zIndex: 10 }}>
        <svg width="1920" height="1080" style={{ position: 'absolute', inset: 0 }}>
          <text x={SAFE_L} y={TITLE_Y} fontFamily={titleFontFamily} fontSize={50} fontWeight="800" fill={textColor}>{titleText}</text>
          <text x={SAFE_L} y={SUBTITLE_Y} fontFamily={labelFontFamily} fontSize={24} fill={textColor} style={{opacity:0.62}}>{subtitleText}</text>

          <rect x={CHART_LEFT} y={LEGEND_Y-16} width={18} height={18} fill={seriesAPos} />
          <text x={CHART_LEFT+26} y={LEGEND_Y} fontFamily={labelFontFamily} fontSize={22} fill={textColor}>{seriesALabel}</text>
          <rect x={CHART_LEFT+260} y={LEGEND_Y-16} width={18} height={18} fill={seriesBNeg} />
          <text x={CHART_LEFT+286} y={LEGEND_Y} fontFamily={labelFontFamily} fontSize={22} fill={textColor}>{seriesBLabel}</text>

          {minorTicks.map(({v,y}) => (
            <line key={`m${v}`} x1={CHART_LEFT} y1={y} x2={CHART_RIGHT} y2={y} stroke={gridColor} strokeWidth={0.5} strokeDasharray="4 4" />
          ))}
          {ticks.map(({v,y}) => (
            <g key={`t${v}`}>
              <line x1={CHART_LEFT} y1={y} x2={CHART_RIGHT} y2={y} stroke={v===0?textColor:gridColor} strokeWidth={v===0?1.5:1} />
              <text x={TICK_RIGHT} y={y+8} textAnchor="end" fontFamily={labelFontFamily} fontSize={22} fill={textColor}>
                {v===0?'0':v>0?`+${v}`:`${v}`}
              </text>
            </g>
          ))}

          <text x={ANNOT_X} y={aboveMidY - 12} fill={seriesAPos} fontFamily={labelFontFamily} fontSize={18} fontWeight="700">{aboveLine1}</text>
          <text x={ANNOT_X} y={aboveMidY + 12} fill={seriesAPos} fontFamily={labelFontFamily} fontSize={15} style={{opacity:0.75}}>{aboveLine2}</text>
          <text x={ANNOT_X} y={belowMidY - 12} fill={seriesBNeg} fontFamily={labelFontFamily} fontSize={18} fontWeight="700">{belowLine1}</text>
          <text x={ANNOT_X} y={belowMidY + 12} fill={seriesBNeg} fontFamily={labelFontFamily} fontSize={15} style={{opacity:0.75}}>{belowLine2}</text>

          {data.map((d,i) => (
            <text key={`yr${d.year}`} x={yearCX[i]} y={YEAR_Y} textAnchor="middle" fontFamily={labelFontFamily} fontSize={26} fill={textColor}>{d.year}</text>
          ))}
        </svg>

        <svg width="1920" height="1080" style={{ position: 'absolute', inset: 0 }}>
          {data.map((d,i) => {
            const cx = yearCX[i];
            const ys = START + i*YEAR_GAP;
            const agS=ys, agE=ys+BAR_GROW, bgS=ys+AB_GAP, bgE=bgS+BAR_GROW;
            const aP=easeOut((frame-agS)/BAR_GROW), bP=easeOut((frame-bgS)/BAR_GROW);
            const aLA=Math.min(1,Math.max(0,(frame-agE)/LABEL_FADE));
            const bLA=Math.min(1,Math.max(0,(frame-bgE)/LABEL_FADE));

            const aC=d.a>=0?seriesAPos:seriesANeg, hA=Math.abs(d.a)*PX_PER_PT*aP;
            const yA=d.a>=0?ZERO_Y-hA:ZERO_Y, lyA=d.a>=0?yA-13:yA+hA+27;
            const aX=cx-barWidth-barGap/2;

            const bC=d.b>=0?seriesBPos:seriesBNeg, hB=Math.abs(d.b)*PX_PER_PT*bP;
            const yB=d.b>=0?ZERO_Y-hB:ZERO_Y, lyB=d.b>=0?yB-13:yB+hB+27;
            const bX=cx+barGap/2;

            const aRGB=d.a>=0?'253,43,0':'68,180,254';
            const bRGB=d.b>=0?'210,0,20':'24,130,230';

            return (
              <g key={`b${d.year}`}>
                {hA>0&&<rect x={aX} y={yA} width={barWidth} height={Math.max(0.1,hA)} fill={aC}/>}
                <text x={aX+barWidth/2} y={lyA} fill={`rgba(${aRGB},${aLA})`} fontSize={19} fontWeight="700" fontFamily={labelFontFamily} textAnchor="middle">Retail</text>
                {hB>0&&<rect x={bX} y={yB} width={barWidth} height={Math.max(0.1,hB)} fill={bC}/>}
                <text x={bX+barWidth/2} y={lyB} fill={`rgba(${bRGB},${bLA})`} fontSize={19} fontWeight="700" fontFamily={labelFontFamily} textAnchor="middle">Tech</text>
              </g>
            );
          })}
        </svg>
      </div>
    </div>
  );
};

const TitleReveal = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();

  // ---- BAKED VALUES (from timeline item overrides + asset defaults) ----
  const mainText = "CHAPTER FOUR";
  const bgColor = "#527692";
  const textColor = "#ffffff";
  const dotColor = "#350b21";
  const fontFamily = "'Arial Black', 'Impact', sans-serif";
  // -----------------------------------------------------------------------

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;

  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const lines = String(mainText)
    .split(/\n|<br\s*\/?>/ )
    .map((l) => l.trim())
    .filter(Boolean);

  const bgMoveX = frame * 0.28;
  const bgMoveY = Math.sin(frame * 0.025) * 12;

  const titleReveal = interpolate(frame, [0, 45], [0, 1], {
    easing: Easing.bezier(0.16, 1, 0.3, 1),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });
  const titleX = interpolate(titleReveal, [0, 1], [-DESIGN_WIDTH * 0.7, 0], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const titleBlurRaw = interpolate(frame, [0, 45], [20, 0], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });
  const titleBlur = Math.round(titleBlurRaw * 2) / 2;

  const microX = interpolate(frame, [32, 70], [-60, 0], {
    easing: Easing.bezier(0.16, 1, 0.3, 1),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const microBlurRaw = interpolate(frame, [32, 55], [8, 0], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });
  const microBlur = Math.round(microBlurRaw * 2) / 2;

  const microAlpha = interpolate(frame, [32, 70], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const hexToRgb = (hex) => {
    const h = (hex || '#ffffff').replace('#', '');
    return {
      r: parseInt(h.substring(0,2), 16),
      g: parseInt(h.substring(2,4), 16),
      b: parseInt(h.substring(4,6), 16),
    };
  };
  const tc = hexToRgb(textColor);

  const dots = React.useMemo(() => {
    const arr = [];
    let seed = 12;
    const rand = () => { seed = (seed * 9301 + 49297) % 233280; return seed / 233280; };
    for (let c = -2; c <= 54; c++) {
      for (let r = -2; r <= 32; r++) {
        arr.push({
          x: c * 38 + (rand() - 0.5) * 8,
          y: r * 38 + (rand() - 0.5) * 8,
          size: 1.1 + rand() * 1.6,
          phase: rand() * Math.PI * 2,
        });
      }
    }
    return arr;
  }, []);

  const bgTexts = React.useMemo(() => {
    const arr = [];
    const rows = [
      {y: 30, even: true}, {y: 175, even: false}, {y: 320, even: true},
      {y: 740, even: true}, {y: 885, even: false}, {y: 1030, even: true},
    ];
    for (const {y, even} of rows) {
      for (let c = -1; c <= 8; c++) {
        arr.push({ x: c * 315 + (even ? 0 : 150), y });
      }
    }
    return arr;
  }, []);

  const label = String(mainText).replace(/\n/g, ' ').toUpperCase();
  const titleTop = lines.length > 1 ? '42%' : '50%';
  const titleTranslate = lines.length > 1 ? 'translate(-50%, -100%)' : 'translate(-50%, -50%)';

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      transform: scale === 1 ? 'scale(1)' : `scale(${scale})`,
      transformOrigin: 'top left',
      backgroundColor: bgColor,
      overflow: 'hidden',
    }}>
      <div style={{
        position: 'absolute', inset: 0,
        background: 'radial-gradient(circle at 28% 44%, rgba(255,255,255,0.04), transparent 30%), radial-gradient(circle at 74% 38%, rgba(0,0,0,0.06), transparent 34%)',
      }} />

      <svg width={DESIGN_WIDTH} height={DESIGN_HEIGHT}
        style={{ position: 'absolute', inset: 0, transform: `translate(${bgMoveX}px,${bgMoveY}px)` }}>
        {dots.map((d, i) => {
          const pulse = Math.sin(frame * 0.035 + d.phase);
          return (
            <circle key={i} cx={d.x} cy={d.y}
              r={Math.max(0.4, d.size + pulse * 0.28)}
              fill={dotColor}
              opacity={0.34 + pulse * 0.12}
            />
          );
        })}
      </svg>

      <div style={{
        position: 'absolute', inset: 0,
        transform: `translateX(${microX}px)`,
      }}>
        {bgTexts.map((t, i) => (
          <div key={i} style={{
            position: 'absolute',
            left: t.x, top: t.y,
            fontFamily, fontSize: 13, fontWeight: 900,
            color: `rgba(${tc.r},${tc.g},${tc.b},${microAlpha * 0.58})`,
            textTransform: 'uppercase',
            whiteSpace: 'nowrap',
            filter: microBlur > 0 ? `blur(${microBlur}px)` : 'none',
          }}>
            {label}
          </div>
        ))}
      </div>

      <div style={{ position: 'absolute', inset: 0, overflow: 'hidden' }}>
        <div style={{
          position: 'absolute', inset: 0,
          transform: `translateX(${titleX}px)`,
        }}>
          {lines.map((line, i) => (
            <div key={i} style={{
              position: 'absolute',
              left: '50%',
              top: i === 0 ? titleTop : '58%',
              transform: i === 0 ? titleTranslate : 'translate(-50%, 0%)',
              fontFamily,
              fontSize: i === 0 ? 164 : 150,
              fontWeight: 900,
              color: textColor,
              whiteSpace: 'nowrap',
              letterSpacing: -7,
              textTransform: 'uppercase',
              filter: titleBlur > 0 ? `blur(${titleBlur}px)` : 'none',
            }}>
              {line.toUpperCase()}
            </div>
          ))}
        </div>
      </div>

      <div style={{
        position: 'absolute', inset: 0,
        pointerEvents: 'none',
        backgroundImage: 'radial-gradient(rgba(255,255,255,0.1) 0.7px, transparent 0.7px)',
        backgroundSize: '5px 5px',
      }} />
    </div>
  );
};

const GlowingRingOverlay = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
const DESIGN_WIDTH = 1920;
const DESIGN_HEIGHT = 1080;
const scale = Math.min(
  (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
  (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
);

  const props = item.props || {};

  const titleText = props.titleText;
  const bullet1 = props.bullet1;
  const bullet2 = props.bullet2;
  const bullet3 = props.bullet3;
  const fontFamily = props.fontFamily;
