  const dotDensity = props.dotDensity;
  const ringColor = props.ringColor;
  const transparentBackground = props.transparentBackground;

  const W = 1920;
  const H = 1080;
  const canvasScale = Math.min((item?.width || W) / W, (item?.height || H) / H);
  const safeFps = fps || 30;

  const ringGrowScale = spring({ frame, fps: safeFps, config: { damping: 22, stiffness: 32, mass: 1.6 } });
  const ringOpacity = interpolate(frame, [0, 12], [0, 1], { extrapolateRight: 'clamp' });

  const tF = Math.max(0, frame - 45);
  const titleY = interpolate(tF, [0, 28], [-28, 0], { easing: Easing.out(Easing.cubic), extrapolateRight: 'clamp' });
  const titleOpacity = interpolate(tF, [0, 18], [0, 1], { extrapolateRight: 'clamp' });

  const b1F = Math.max(0, frame - 66);
  const b1Y = interpolate(b1F, [0, 18], [14, 0], { easing: Easing.out(Easing.quad), extrapolateRight: 'clamp' });
  const b1O = interpolate(frame, [66, 82], [0, 1], { extrapolateRight: 'clamp' });

  const b2F = Math.max(0, frame - 96);
  const b2Y = interpolate(b2F, [0, 18], [14, 0], { easing: Easing.out(Easing.quad), extrapolateRight: 'clamp' });
  const b2O = interpolate(frame, [96, 112], [0, 1], { extrapolateRight: 'clamp' });

  const b3F = Math.max(0, frame - 126);
  const b3Y = interpolate(b3F, [0, 18], [14, 0], { easing: Easing.out(Easing.quad), extrapolateRight: 'clamp' });
  const b3O = interpolate(frame, [126, 142], [0, 1], { extrapolateRight: 'clamp' });

  // Single-layer sparse dot grid — matches reference image: subtle, evenly spaced, low opacity
  // dotDensity=6 → spacing ~38px; higher density = smaller spacing
