  const ringLeft = (W - ringSize) / 2;
  const gi = glowIntensity;
  const titleTop = ringTop + ringSize + 18;

  const ringBoxShadow = [
    `0 0 ${gi * 2}px 2px rgba(246,240,255,1.0)`,
    `0 0 ${gi * 8}px 8px rgba(246,240,255,0.75)`,
    `0 0 ${gi * 20}px 20px rgba(246,240,255,0.45)`,
    `0 0 ${gi * 45}px 35px rgba(246,240,255,0.22)`,
    `0 0 ${gi * 80}px 55px rgba(246,240,255,0.10)`,
    `inset 0 0 ${gi * 4}px 4px rgba(246,240,255,0.90)`,
    `inset 0 0 ${gi * 12}px 10px rgba(246,240,255,0.55)`,
    `inset 0 0 ${gi * 28}px 20px rgba(246,240,255,0.25)`,
  ].join(', ');

  const textGlow = '0 0 8px rgba(246,240,255,0.9), 0 0 20px rgba(246,240,255,0.5), 0 0 40px rgba(246,240,255,0.25)';
