      {/* Single-layer dot field — sparse and clean like reference */}
      <div style={{
        position: 'absolute', top: 0, left: 0, right: 0, bottom: 0,
        backgroundImage: `radial-gradient(circle, rgba(246,240,255,0.40) 1px, transparent 1px)`,
        backgroundSize: `${dotSpacing}px ${dotSpacing}px`,
