const GroupProjectAnchor = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();
  const props = item.props || {};

  const bgColor = props.transparentBackground ? 'transparent' : props.bgColor;
  const textColor = props.textColor;
  const accentColor = props.accentColor;
  const titleFont = props.titleFont;
  const bodyFont = props.bodyFont;
  const blobColor1 = props.blobColor1;
  const blobColor2 = props.blobColor2;

  const parseHex = (hex) => {
    if (!hex) return [0,0,0];
    const h = hex.replace('#','');
    return [parseInt(h.substring(0,2),16)||0, parseInt(h.substring(2,4),16)||0, parseInt(h.substring(4,6),16)||0];
  };
  const rgba = (hex, a) => { const [r,g,b] = parseHex(hex); return `rgba(${r},${g},${b},${a})`; };

  const smoothSettle = (t) => t<=0?0:t>=1?1:1-Math.pow(1-t,3.5);
  const bellCurveLate = (t) => t<=0?0:t>=1?1:t<0.4?0.15*Math.pow(t/0.4,2.5):0.15+0.85*(1-Math.pow(1-(t-0.4)/0.6,2.8));
  const lineDraw = (t) => t<=0?0:t>=1?1:1-Math.pow(1-t,2.8);

  const total = durationInFrames || 150;
  const exitRaw = Math.max(0, Math.min(1, (frame-(total-25))/25));
  const ex = 1 - exitRaw*exitRaw;

  const anim = (delay, dur) => smoothSettle(Math.min(1, Math.max(0, (frame-delay)/dur)));
  const fadeIn = (delay) => smoothSettle(Math.min(1, Math.max(0, (frame-delay)/15)));

  // Liquid blobs (continuous motion)
  const t = frame * 0.012;
  const b1x = 960 + Math.sin(t)*300;
  const b1y = 540 + Math.cos(t*1.2)*200;
  const b2x = 960 + Math.sin(t*0.8+2)*400;
  const b2y = 540 + Math.cos(t*1.1+1)*300;
  const blobA = anim(0,40)*ex;

  // Title (delay 8)
  const ttA = fadeIn(8)*ex;
  const ttY = (1-anim(8,50))*50;

  // Subtitle (delay 20)
  const stA = fadeIn(20)*ex;
  const stY = (1-anim(20,35))*(-20);

  // Body (delay 25)
  const bdA = fadeIn(25)*ex;
  const bdY = (1-anim(25,35))*30;

  // Timeline horizontal (delay 15)
  const tlW = lineDraw(Math.min(1, Math.max(0,(frame-15)/50)))*700;
  const tlA = fadeIn(15)*ex;

  // Nodes
  const nd = [0,1,2,3].map(i => {
    const d = 25+i*6;
    return { a: fadeIn(d)*ex, s: anim(d,30) };
  });

  // Ring chart (delay 20)
  const chRaw = Math.min(1, Math.max(0,(frame-20)/60));
  const chP = bellCurveLate(chRaw);
  const ringR = 90, ringC = 2*Math.PI*ringR;

  const metrics = [{v:85,l:'85%'},{v:72,l:'72%'},{v:90,l:'90%'},{v:78,l:'78%'}];

  // Name (delay 30)
  const nmA = fadeIn(30)*ex;

  return (
    <div style={{position:'absolute',inset:0,backgroundColor:bgColor,overflow:'hidden',fontFamily:bodyFont}}>
      {/* Liquid background blobs */}
      <svg style={{position:'absolute',inset:0,width:'100%',height:'100%'}}>
        <defs>
          <filter id="gpBlur" x="-50%" y="-50%" width="200%" height="200%">
            <feGaussianBlur stdDeviation="120"/>
          </filter>
        </defs>
        <g filter="url(#gpBlur)">
          <circle cx={b1x} cy={b1y} r="500" fill={rgba(blobColor1,blobA*0.7)}/>
          <circle cx={b2x} cy={b2y} r="450" fill={rgba(blobColor2,blobA*0.6)}/>
        </g>
      </svg>

      {/* Title (bottom left, bold italic) */}
      <div style={{position:'absolute',left:100,bottom:200,width:900,transform:`translateY(${ttY}px)`}}>
        <div style={{fontFamily:titleFont,fontSize:80,fontWeight:800,fontStyle:'italic',color:rgba(textColor,ttA),lineHeight:1.15}}>
          Group Project Strategies
        </div>
      </div>

      {/* Subtitle (top right) */}
      <div style={{position:'absolute',right:100,top:80,width:400,textAlign:'right',transform:`translateY(${stY}px)`}}>
        <div style={{fontSize:28,color:rgba(textColor,stA*0.8),lineHeight:1.4}}>
          Here is where your presentation begins
        </div>
      </div>

      {/* Body text */}
      <div style={{position:'absolute',left:100,top:450,width:600,transform:`translateY(${bdY}px)`}}>
        <div style={{fontSize:28,color:rgba(textColor,bdA*0.85),lineHeight:1.5}}>
          Diverse perspectives create breakthrough solutions.
        </div>
      </div>

      {/* Timeline (bottom) */}
      <div style={{position:'absolute',left:100,bottom:100,width:750,height:60}}>
        <div style={{position:'absolute',left:0,top:8,width:tlW,height:2,backgroundColor:rgba(accentColor,tlA*0.4)}}/>
        {['Phase 1','Phase 2','Phase 3','Phase 4'].map((p,i) => (
          <div key={i} style={{position:'absolute',left:i*200,top:0}}>
            <div style={{width:6,height:6,borderRadius:'50%',backgroundColor:rgba(accentColor,nd[i].a),transform:`scale(${nd[i].s})`}}/>
            <div style={{fontSize:14,color:rgba(textColor,nd[i].a*0.7),marginTop:14,letterSpacing:'0.05em'}}>{p}</div>
          </div>
        ))}
      </div>

      {/* Progress rings (right side) */}
      <div style={{position:'absolute',right:80,top:200,display:'flex',flexDirection:'column',gap:20}}>
        {metrics.map((m,i) => {
          const mA = fadeIn(20+i*8)*ex;
          const prog = chP * m.v / 100;
          const dash = `${prog*ringC} ${ringC}`;
          return (
