const TitleCardDrop = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const line1Text = props.line1Text;
  const line2Text = props.line2Text;
  const glowColor = props.glowColor;
  const fontFamily = props.fontFamily;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const lines = [
    { text: line1Text, fontSize: 180 },
    { text: line2Text, fontSize: 180 },
  ];

  let charCount = 0;
  const computedLines = lines.map(line => ({
    ...line,
    chars: line.text.split('').map(char => {
      const index = charCount++;
      return { char, index };
    })
  }));

  const totalChars = charCount;
  const stagger = 32 / Math.max(1, totalChars);

  // 淡出：直接算好，乘进每个字母，不用父级 opacity
  const fadeOutStart = Math.max(0, durationInFrames - 18);
  const globalOpacity = interpolate(
    frame,
    [fadeOutStart, durationInFrames - 1],
    [1, 0],
    { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      transform: `scale(${scale})`, transformOrigin: 'top left',
      backgroundColor: 'transparent',
      display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
    }}>
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
        {computedLines.map((line, lineIdx) => (
          <div
            key={lineIdx}
            style={{
              display: 'block',
              textAlign: 'center',
              whiteSpace: 'nowrap',
              lineHeight: 0.88,
            }}
          >
            {line.chars.map((charItem, charIdx) => {
              const delay = charItem.index * stagger;
              const progress = interpolate(
                frame - delay,
                [0, 14],
                [0, 1],
                { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: Easing.out(Easing.cubic) }
              );
              const y = interpolate(progress, [0, 1], [-65, 0]);
              const blur = interpolate(progress, [0, 1], [14, 0]);
              // 淡入 * 淡出，合并成单一 opacity，无父级 opacity
              const charOpacityIn = interpolate(progress, [0, 0.5, 1], [0, 0.9, 1], { extrapolateRight: 'clamp' });
              const finalOpacity = charOpacityIn * globalOpacity;

              return (
                <span
                  key={charIdx}
                  style={{
                    fontFamily: `${fontFamily}, Impact, sans-serif`,
                    fontWeight: 400,
                    fontSize: `${line.fontSize}px`,
                    color: '#f6f0ff',
                    lineHeight: 0.88,
                    textTransform: 'uppercase',
                    letterSpacing: '0.01em',
                    textShadow: `0 0 8px ${glowColor}, 0 0 22px ${glowColor}, 0 0 50px rgba(246,240,255,0.4), 0 0 90px rgba(246,240,255,0.15)`,
                    transform: `translateY(${y}px)`,
                    filter: blur > 0.05 ? `blur(${blur}px)` : 'none',
                    opacity: finalOpacity,
                    display: 'inline-block',
                    whiteSpace: 'pre',
                  }}
                >
                  {charItem.char === ' ' ? '\u00A0' : charItem.char}
                </span>
              );
            })}
          </div>
        ))}
      </div>
    </div>
  );
};

const LowerThirdCR = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const props = item.props || {};
  const mainText = props.mainText;
  const subText = props.subText;
