  const subColor = props.subColor;
  const lineColor = props.lineColor;

  const DESIGN_WIDTH = 900;
  const DESIGN_HEIGHT = 120;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const easeOut = Easing.out(Easing.cubic);

  const BALL = 16;
  const BG_LEFT = 38;
  const MAIN_FULL_W = Math.round(mainText.length * 26) + 40;
  const SUB_FULL_W = Math.round(subText.length * 13) + 24;

  const BG_START = 18;
  const BG_END = 70;

  const MAIN_TOP = 14;
  const MAIN_H = 40;
  const LINE_TOP = MAIN_TOP + MAIN_H;
  const SUB_TOP = LINE_TOP + 1;
  const SUB_H = 34;

  const bgProgress = interpolate(frame, [BG_START, BG_END], [0, 1], {
    easing: easeOut, extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const mainBgW = bgProgress * MAIN_FULL_W;

  const mainMaskStop = interpolate(bgProgress, [0, 1], [50, 100], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const mainMask = 'linear-gradient(to right, black 0%, black ' + mainMaskStop + '%, transparent 100%)';

  const mainLen = Math.round(interpolate(frame, [22, 78], [0, mainText.length], {
    easing: easeOut, extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  }));
  const displayedMain = mainText.slice(0, mainLen);

  const lineW = interpolate(frame, [BG_START + 14, BG_END + 4], [0, MAIN_FULL_W - 8], {
    easing: easeOut, extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });

  const subProgress = interpolate(frame, [52, 98], [0, 1], {
    easing: easeOut, extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const subBgW = subProgress * SUB_FULL_W;
  const subMaskStop = interpolate(subProgress, [0, 1], [50, 100], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const subMask = 'linear-gradient(to right, black 0%, black ' + subMaskStop + '%, transparent 100%)';
  const displayedSub = subText.slice(0, Math.round(subProgress * subText.length));

  const blueBallX = BG_LEFT + mainBgW - 74;
  const blueBallY = MAIN_TOP + MAIN_H - BALL;
  const redBallX = BG_LEFT + mainBgW - 18;
  const redBallY = MAIN_TOP - 10;

  const fadeIn = interpolate(bgProgress, [0, 0.1], [0, 1], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const blueFadeOut = interpolate(bgProgress, [0.7, 1.0], [1, 0], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const redFadeOut = interpolate(bgProgress, [0.7, 1.0], [1, 0], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const blueBallOpacity = fadeIn * blueFadeOut;
  const redBallOpacity = fadeIn * redFadeOut;

  const rootStyle = {
    position: 'absolute', top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: 'scale(' + scale + ')',
    transformOrigin: 'top left',
    backgroundColor: 'transparent',
    fontFamily: 'Roboto, sans-serif',
    overflow: 'visible',
  };

  return (
    <div style={rootStyle}>
      {mainBgW > 1 && (
        <div style={{
          position: 'absolute', top: MAIN_TOP, left: BG_LEFT,
          width: mainBgW, height: MAIN_H,
          backgroundColor: bgColor,
          WebkitMaskImage: mainMask, maskImage: mainMask,
          display: 'flex', alignItems: 'center',
          paddingLeft: 10, boxSizing: 'border-box', overflow: 'hidden',
        }}>
          <span style={{
            fontSize: 32, fontWeight: '700', color: mainColor,
            whiteSpace: 'nowrap', letterSpacing: 0.5, lineHeight: 1,
          }}>{displayedMain}</span>
        </div>
      )}
      {lineW > 1 && (
        <div style={{
          position: 'absolute', top: LINE_TOP, left: 48,
          height: 1.5, width: lineW,
          background: 'linear-gradient(to right, ' + lineColor + ' 0%, rgba(153,153,153,0) 100%)',
        }} />
      )}
      {subBgW > 1 && (
        <div style={{
          position: 'absolute', top: SUB_TOP, left: BG_LEFT,
          width: subBgW, height: SUB_H,
          backgroundColor: bgColor,
          WebkitMaskImage: subMask, maskImage: subMask,
          display: 'flex', alignItems: 'center',
          paddingLeft: 10, boxSizing: 'border-box', overflow: 'hidden',
        }}>
          <span style={{
            fontSize: 20, fontStyle: 'italic', color: subColor,
            whiteSpace: 'nowrap', lineHeight: 1,
          }}>{displayedSub}</span>
        </div>
      )}
      <div style={{
        position: 'absolute', top: blueBallY, left: blueBallX,
        width: BALL, height: BALL, borderRadius: '50%',
        backgroundColor: blueBallColor, opacity: blueBallOpacity, zIndex: 10,
      }} />
      <div style={{
        position: 'absolute', top: redBallY, left: redBallX,
        width: BALL, height: BALL, borderRadius: '50%',
        backgroundColor: redBallColor, opacity: redBallOpacity, zIndex: 10,
      }} />
    </div>
  );
};

const SubtitleOverlay = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  const props = item.props || {};
  const line1Text = props.line1Text;
  const line2TextNormal = props.line2TextNormal;
  const line2TextHighlight = props.line2TextHighlight;
  const fontFamily = props.fontFamily;
  const primaryColor = props.primaryColor;
  const highlightColor = props.highlightColor;
  const gradientColor = props.gradientColor;
  const slideDuration = props.slideDuration;
  const revealAt = Math.min(props.revealAt, slideDuration - 1);
  const wordDelay = props.wordDelay;
  const wordDuration = slideDuration;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const gradientProgress = interpolate(frame, [0, slideDuration], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.bezier(0.95, 0, 0.05, 1)
  });
  // translate3d 替代 translateY，渐变层走 GPU 合成，避免光栅化抖动
  const gradientY = interpolate(gradientProgress, [0, 1], [200, 0]);
  const gradientOpacity = interpolate(frame, [revealAt, slideDuration], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.out(Easing.quad)
  });

  const line1Words = (line1Text || '').split(' ');
  const line2Words = (line2TextNormal || '').trim().split(' ').filter(Boolean);
  const highlightWord = line2TextHighlight || '';
  const wordInterval = Math.round(slideDuration * 0.2);

  const getWordProgress = (wordIndex) => {
    const localFrame = Math.max(0, frame - wordDelay - wordIndex * wordInterval);
    return interpolate(localFrame, [0, wordDuration], [0, 1], {
      extrapolateLeft: 'clamp',
      extrapolateRight: 'clamp',
      easing: Easing.bezier(0.22, 1, 0.36, 1)
    });
  };

  const wordStyle = (wordIndex) => {
    const p = getWordProgress(wordIndex);
    const yOffset = interpolate(p, [0, 1], [22, 0]);
    return {
      display: 'inline-block',
      opacity: p,
      // translate3d 替代 translateY，强制每个词提升为独立 GPU 合成层
      transform: `translate3d(0, ${yOffset}px, 0)`,
      willChange: 'transform',
      marginRight: '0.28em',
      transformOrigin: 'bottom center'
    };
  };

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      // translate3d(0,0,0) 前置 scale，根容器强制 GPU 合成层
      transform: `translate3d(0, 0, 0) scale(${scale})`,
      transformOrigin: 'top left',
      willChange: 'transform',
      backgroundColor: 'transparent',
      overflow: 'hidden'
    }}>
      {/* 渐变层：translate3d 替代 translateY，百分比单位保持不变 */}
      <div style={{
        position: 'absolute',
        bottom: 0, left: 0,
        width: '100%', height: '50%',
        background: `linear-gradient(to top, ${gradientColor}, transparent)`,
        transform: `translate3d(0, ${gradientY}%, 0)`,
        willChange: 'transform',
        opacity: gradientOpacity,
        zIndex: 1
      }} />
      <div style={{
        position: 'absolute',
        bottom: '12%',
        left: 0, right: 0,
        fontFamily: fontFamily,
        fontSize: '115px',
        fontWeight: 400,
        color: primaryColor,
        lineHeight: 1.15,
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        gap: '8px',
        textShadow: '0px 8px 24px rgba(0,0,0,0.4)',
        zIndex: 10
      }}>
        <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center', alignItems: 'baseline' }}>
          {line1Words.map((word, i) => (
            <span key={i} style={wordStyle(i)}>{word}</span>
          ))}
        </div>
        <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center', alignItems: 'baseline' }}>
          {line2Words.map((word, i) => (
            <span key={i} style={wordStyle(line1Words.length + i)}>{word}</span>
          ))}
          <span style={{ ...wordStyle(line1Words.length + line2Words.length), color: highlightColor }}>
            {highlightWord}
          </span>
        </div>
      </div>
    </div>
  );
};

