const KineticTextOverlay = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const line1Text = props.line1Text;
  const line2Text = props.line2Text;
  const primaryColor = props.primaryColor;
  const fontFamily = props.fontFamily;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const line1Chars = (line1Text || '').split('');
  const line2Chars = (line2Text || '').split('');

  const CHAR_INTERVAL = 3;
  const LINE1_START = 3;
  const LINE2_START = LINE1_START + line1Chars.length * CHAR_INTERVAL + 8;

  const exitDuration = 14;
  const exitStart = Math.max(0, durationInFrames - exitDuration - 4);
  const exitProgress = interpolate(frame, [exitStart, exitStart + exitDuration], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.in(Easing.cubic),
  });

  const exitX1 = interpolate(exitProgress, [0, 1], [0, -2200]);
  const exitBlur1 = interpolate(exitProgress, [0, 1], [0, 28]);
  const exitOpacity1 = interpolate(exitProgress, [0, 0.75, 1], [1, 0.6, 0]);

  const exitX2 = interpolate(exitProgress, [0, 1], [0, 2200]);
  const exitBlur2 = interpolate(exitProgress, [0, 1], [0, 28]);
  const exitOpacity2 = interpolate(exitProgress, [0, 0.75, 1], [1, 0.6, 0]);

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      transform: `scale(${scale})`, transformOrigin: 'top left',
      backgroundColor: 'transparent', overflow: 'hidden',
    }}>

      {/* LINE 1 — upper half center */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        width: '100%',
        height: '50%',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        transform: `translateX(${exitX1}px)`,
        filter: `blur(${exitBlur1}px)`,
        opacity: exitOpacity1,
      }}>
        <div style={{ display: 'flex', flexWrap: 'nowrap', alignItems: 'baseline' }}>
          {line1Chars.map((char, i) => {
            const visible = frame >= LINE1_START + i * CHAR_INTERVAL;
            return (
              <span key={i} style={{
                fontFamily,
                fontSize: '195px',
                fontWeight: 900,
                color: primaryColor,
                lineHeight: 1,
                textTransform: 'uppercase',
                whiteSpace: 'pre',
                opacity: visible ? 1 : 0,
                display: 'inline-block',
                width: char === ' ' ? '60px' : 'auto',
              }}>
                {char === ' ' ? '\u00A0' : char}
              </span>
            );
          })}
        </div>
      </div>

      {/* LINE 2 — lower half center */}
      <div style={{
        position: 'absolute',
        top: '50%',
        left: 0,
        width: '100%',
        height: '50%',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        transform: `translateX(${exitX2}px)`,
        filter: `blur(${exitBlur2}px)`,
        opacity: exitOpacity2,
      }}>
        <div style={{ display: 'flex', flexWrap: 'nowrap', alignItems: 'baseline' }}>
          {line2Chars.map((char, i) => {
            const visible = frame >= LINE2_START + i * CHAR_INTERVAL;
            return (
              <span key={i} style={{
                fontFamily,
                fontSize: '340px',
                fontWeight: 900,
                color: primaryColor,
                lineHeight: 1,
                textTransform: 'uppercase',
                whiteSpace: 'pre',
                opacity: visible ? 1 : 0,
                display: 'inline-block',
                width: char === ' ' ? '80px' : 'auto',
              }}>
                {char === ' ' ? '\u00A0' : char}
              </span>
            );
          })}
        </div>
      </div>

    </div>
  );
};

const SphereCounter = ({ item }) => {
    const frame = useCurrentFrame();
    const { fps } = useVideoConfig();
    const props = item.props || {};

    const targetNumber = props.targetNumber;
    const prefix = props.prefix;
    const sphereCenterColor = props.sphereCenterColor;
    const sphereEdgeColor = props.sphereEdgeColor;
    const textColor = props.textColor;
    const fontFamily = props.fontFamily;
    const transparentBackground = props.transparentBackground;
    const backgroundColor = props.backgroundColor;

    const DESIGN_WIDTH = 1920;
    const DESIGN_HEIGHT = 1080;
    const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

    const rootStyle = {
        position: 'absolute', top: 0, left: 0,
        width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
        transform: `scale(${scale})`, transformOrigin: 'top left',
        backgroundColor: transparentBackground === 'true' || transparentBackground === true ? 'transparent' : backgroundColor,
        overflow: 'hidden',
    };

    const safeFps = fps || 30;

    const scale1 = spring({ frame: Math.max(0, frame - 5), fps: safeFps, config: { damping: 14, stiffness: 80 } });
    const scale2 = spring({ frame: Math.max(0, frame - 12), fps: safeFps, config: { damping: 14, stiffness: 80 } });

    const float1 = Math.sin(frame / 25) * 30;
    const float2 = Math.sin((frame + 40) / 20) * 20;

    const NUMBER_DELAY = 40;
    const numberOpacity = interpolate(frame, [NUMBER_DELAY, NUMBER_DELAY + 10], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

    const characters = String(targetNumber).split('');
    const digitHeight = 300;
    const fadeZone = 0.35;

    const sequences = React.useMemo(() => {
        return characters.map((char, index) => {
            if (!/[0-9]/.test(char)) return null;
            const targetDigitInt = parseInt(char, 10);
            const cycles = 2 + Math.floor(index / 2);
            const seq = [];
            for (let i = 0; i < cycles; i++) {
                for (let j = 0; j < 10; j++) seq.push(j);
            }
            for (let j = 0; j <= targetDigitInt; j++) seq.push(j);
            return seq;
        });
    }, [targetNumber]);

    const fadePercent = Math.round(fadeZone * 100);
    const digitMask = `linear-gradient(to bottom, transparent 0%, black ${fadePercent}%, black ${100 - fadePercent}%, transparent 100%)`;

    return (
        <div style={rootStyle}>
            <div style={{
                position: 'absolute', bottom: '15%', left: '22%',
                width: 450, height: 450, borderRadius: '50%',
                background: `radial-gradient(circle at 35% 35%, ${sphereCenterColor}, ${sphereEdgeColor})`,
                boxShadow: `0 30px 60px rgba(0,0,0,0.7), inset -20px -20px 50px rgba(0,0,0,0.6)`,
                transform: `translateY(${float1}px) scale(${scale1})`,
                transformOrigin: 'center center'
            }} />

            <div style={{
                position: 'absolute', top: '18%', right: '28%',
                width: 200, height: 200, borderRadius: '50%',
                background: `radial-gradient(circle at 35% 35%, ${sphereCenterColor}, ${sphereEdgeColor})`,
                boxShadow: `0 20px 40px rgba(0,0,0,0.6), inset -10px -10px 30px rgba(0,0,0,0.5)`,
                transform: `translateY(${float2}px) scale(${scale2})`,
                transformOrigin: 'center center'
            }} />

            <div style={{
                position: 'absolute', top: 0, left: 0, right: 0, bottom: 0,
                display: 'flex', flexDirection: 'row',
                alignItems: 'center', justifyContent: 'center',
                zIndex: 10, opacity: numberOpacity,
            }}>
                {prefix && (
                    <div style={{
                        height: digitHeight,
                        lineHeight: `${digitHeight}px`,
                        fontSize: 280, fontWeight: 700,
                        color: textColor, fontFamily,
                        marginRight: 25,
                        textShadow: '0 15px 40px rgba(0,0,0,0.6)'
                    }}>
                        {prefix}
                    </div>
                )}

                {characters.map((char, i) => {
                    const seq = sequences[i];
                    if (seq) {
                        const totalItems = seq.length;
                        const delay = NUMBER_DELAY + i * 6;
                        const progress = spring({
                            frame: Math.max(0, frame - delay),
                            fps: safeFps,
                            config: { damping: 18, stiffness: 70, mass: 1.2 }
                        });
                        const translateY = progress * -(totalItems - 1) * digitHeight;

                        return (
                            <div key={`${i}-${char}`} style={{
                                height: digitHeight,
                                overflow: 'hidden',
                                position: 'relative',
                                width: 'auto',
                                WebkitMaskImage: digitMask,
                                maskImage: digitMask,
                            }}>
                                <div style={{ display: 'flex', flexDirection: 'column', transform: `translateY(${translateY}px)` }}>
                                    {seq.map((num, idx) => (
                                        <div key={idx} style={{
                                            height: digitHeight,
                                            lineHeight: `${digitHeight}px`,
                                            fontSize: 280, fontWeight: 700,
                                            color: textColor, fontFamily,
                                            textAlign: 'center',
                                            textShadow: '0 15px 40px rgba(0,0,0,0.6)'
                                        }}>
                                            {num}
                                        </div>
                                    ))}
                                </div>
                            </div>
                        );
                    }

                    return (
                        <div key={`${i}-${char}`} style={{
                            height: digitHeight,
                            lineHeight: `${digitHeight}px`,
                            fontSize: 280, fontWeight: 700,
                            color: textColor, fontFamily,
                            textShadow: '0 15px 40px rgba(0,0,0,0.6)'
                        }}>
                            {char}
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

const QuoteCard = ({item}) => {
  const frame = useCurrentFrame();
  const { durationInFrames } = useVideoConfig();

  const props = item.props || {};
  const quoteText = props.quoteText;
  const quoteColor = props.quoteColor;
  const textColor = props.textColor;
  const fontFamily = props.fontFamily;
  const transparentBackground = props.transparentBackground;

  // 扩大内部画布，给光效留出血区
  const DESIGN_WIDTH = 1060;
  const DESIGN_HEIGHT = 680;

  const hexToRgb = (hex) => {
    const h = (hex || '#ffffff').replace('#', '');
    const r = parseInt(h.substring(0,2), 16);
    const g = parseInt(h.substring(2,4), 16);
    const b = parseInt(h.substring(4,6), 16);
    return {r, g, b};
  };

  const qc = hexToRgb(quoteColor);
  const tc = hexToRgb(textColor);

  const masterAlpha = interpolate(frame, [0, 25], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const textAlpha = interpolate(frame, [12, 32], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const cardY = interpolate(frame, [0, 28], [24, 0], {
    extrapolateRight: 'clamp',
    easing: Easing.out(Easing.cubic),
  });

  const fadeOutStart = durationInFrames > 18 ? durationInFrames - 18 : 0;
  const exitAlpha = interpolate(frame, [fadeOutStart, durationInFrames], [1, 0], {
    extrapolate: 'clamp',
  });
  const exitY = interpolate(frame, [fadeOutStart, durationInFrames], [0, 24], {
    extrapolate: 'clamp',
    easing: Easing.in(Easing.cubic),
  });

  const isExiting = frame >= fadeOutStart;
  const finalAlpha = masterAlpha * exitAlpha;
  const finalTextAlpha = textAlpha * exitAlpha;
  const finalY = isExiting ? exitY : cardY;

  const rootBg = (transparentBackground === 'true' || transparentBackground === true)
    ? 'transparent'
    : 'rgba(28,5,3,0.92)';

  const QUOTE_SIZE = 160;

  return (
    <div
      style={{
        position: 'absolute', top: 0, left: 0,
        width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
        transform: 'scale(1)', transformOrigin: 'top left',
        display: 'flex', justifyContent: 'center', alignItems: 'center',
        backgroundColor: rootBg,
        overflow: 'visible',
      }}
    >
      {/* 开引号 */}
      <div
        style={{
          position: 'absolute',
          top: 60, left: 60,
          fontSize: QUOTE_SIZE,
          fontFamily: 'Georgia, "Times New Roman", serif',
          fontWeight: 'bold',
          color: `rgba(${qc.r},${qc.g},${qc.b},${finalAlpha * 0.70})`,
          lineHeight: 1,
          userSelect: 'none',
          zIndex: 0,
          transform: `translateY(${finalY}px)`,
        }}
      >
        {String.fromCharCode(8220)}
      </div>

      {/* 卡片 */}
      <div
        style={{
          width: 650,
          height: 340,
          padding: '0 48px',
          background: `linear-gradient(135deg, rgba(161,79,82,${finalAlpha}) 0%, rgba(157,74,82,${finalAlpha * 0.85}) 50%, rgba(176,93,82,${finalAlpha * 0.75}) 100%)`,
          borderRadius: 20,
          position: 'relative',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          overflow: 'visible',
          zIndex: 1,
          transform: `translateY(${finalY}px)`,
          boxShadow: `0 0 80px rgba(161,79,82,${finalAlpha * 0.55}), 0 0 160px rgba(217,137,102,${finalAlpha * 0.25})`,
        }}
      >
        {/* 右上角粉色光晕 */}
        <div style={{
          position: 'absolute',
          top: -60, right: -60,
          width: 220, height: 180,
          borderRadius: '50%',
          background: `radial-gradient(circle, rgba(217,137,102,${finalAlpha * 0.60}) 0%, rgba(217,137,102,0) 70%)`,
          filter: 'blur(24px)',
          pointerEvents: 'none',
        }} />
        {/* 左下角蓝紫光晕 */}
        <div style={{
          position: 'absolute',
          bottom: -50, left: -50,
          width: 200, height: 160,
          borderRadius: '50%',
          background: `radial-gradient(circle, rgba(176,93,82,${finalAlpha * 0.50}) 0%, rgba(176,93,82,0) 70%)`,
          filter: 'blur(20px)',
          pointerEvents: 'none',
        }} />
        <div
          style={{
            fontSize: 26,
            fontFamily: fontFamily,
            color: `rgba(${tc.r},${tc.g},${tc.b},${finalTextAlpha})`,
            textAlign: 'center',
            lineHeight: 1.55,
            fontWeight: 600,
            maxWidth: 560,
            position: 'relative',
            zIndex: 1,
          }}
        >
          {quoteText}
        </div>
      </div>

      {/* 闭引号 */}
      <div
        style={{
          position: 'absolute',
          bottom: 60, right: 60,
          fontSize: QUOTE_SIZE,
          fontFamily: 'Georgia, "Times New Roman", serif',
          fontWeight: 'bold',
          color: `rgba(${qc.r},${qc.g},${qc.b},${finalAlpha * 0.70})`,
          lineHeight: 1,
          userSelect: 'none',
          zIndex: 2,
          transform: `translateY(${finalY}px)`,
        }}
      >
        {String.fromCharCode(8221)}
      </div>
    </div>
  );
};

const RibbonGraphic = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const props = item.props || {};
  const bodyText = props.bodyText;
  const fontFamily = props.fontFamily;
  const textColor = props.textColor;
  const ribbonColorStart = props.ribbonColorStart;
  const ribbonColorMid = props.ribbonColorMid;
  const ribbonColorEnd = props.ribbonColorEnd;
  const bgBaseColor = props.bgBaseColor;
  const animationSpeed = props.animationSpeed;
  const transparentBackground = props.transparentBackground;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const adjFrame = frame * animationSpeed;

  const dashOffset = interpolate(
    adjFrame,
    [0, 54, 120, 166],
    [1000, 0, 0, -1000],
    { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );

  const pathData = 'M -110 478 C 110 260, 330 150, 520 178 C 690 202, 760 330, 704 520 C 650 708, 734 842, 905 800 C 1110 750, 1270 568, 1495 410 C 1695 270, 1850 190, 2040 102';

  const sharedPathProps = {
    d: pathData,
    fill: 'none',
    strokeLinecap: 'round',
    strokeLinejoin: 'round',
    pathLength: 1000,
    strokeDasharray: 1000,
    strokeDashoffset: dashOffset,
  };

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: transparentBackground ? 'transparent' : bgBaseColor,
    overflow: 'hidden',
  };

  const words = bodyText.split(' ');

  return (
    <div style={rootStyle}>
      {!transparentBackground && (
        <AbsoluteFill>
          <div style={{ position: 'absolute', top: -150, left: -50, width: 800, height: 800, background: ribbonColorStart, filter: 'blur(150px)', opacity: 0.35, borderRadius: '50%' }} />
          <div style={{ position: 'absolute', bottom: -250, left: '20%', width: 1000, height: 1000, background: ribbonColorMid, filter: 'blur(200px)', opacity: 0.25, borderRadius: '50%' }} />
          <div style={{ position: 'absolute', top: 100, right: -150, width: 900, height: 900, background: ribbonColorEnd, filter: 'blur(180px)', opacity: 0.3, borderRadius: '50%' }} />
        </AbsoluteFill>
      )}

      <AbsoluteFill>
        <svg viewBox={`0 0 ${DESIGN_WIDTH} ${DESIGN_HEIGHT}`} style={{ position: 'absolute', width: '100%', height: '100%' }}>
          <defs>
            <linearGradient id="main-grad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor={ribbonColorStart} />
              <stop offset="50%" stopColor={ribbonColorMid} />
              <stop offset="100%" stopColor={ribbonColorEnd} />
            </linearGradient>
            <linearGradient id="dark-grad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#330009" />
              <stop offset="50%" stopColor="#4b0012" />
              <stop offset="100%" stopColor="#680018" />
            </linearGradient>
          </defs>
          <path {...sharedPathProps} stroke="rgba(0,0,0,0.48)" strokeWidth="178" transform="translate(30,58)" opacity="0.82" />
          <path {...sharedPathProps} stroke="url(#dark-grad)" strokeWidth="158" transform="translate(-22,36)" opacity="0.95" />
          <path {...sharedPathProps} stroke="url(#main-grad)" strokeWidth="150" />
          <path {...sharedPathProps} stroke="rgba(255,226,214,0.34)" strokeWidth="58" transform="translate(-22,-28)" opacity="0.42" />
          <path {...sharedPathProps} stroke="rgba(255,136,82,0.30)" strokeWidth="72" transform="translate(18,-18)" opacity="0.48" />
        </svg>
      </AbsoluteFill>

      <AbsoluteFill style={{ display: 'flex', flexDirection: 'row', justifyContent: 'center', alignItems: 'center' }}>
        {words.map((word, i) => {
          const delay = 24 + i * 4;
          const wordFrame = Math.max(0, adjFrame - delay);
          const springVal = spring({
            frame: wordFrame,
            fps,
            config: { damping: 17, stiffness: 115, mass: 0.9 }
          });
          const translateY = interpolate(springVal, [0, 1], [54, 0]);
          const opacity = interpolate(springVal, [0, 1], [0, 1]);
          const scaleVal = interpolate(springVal, [0, 1], [0.92, 1]);
          return (
            <div key={i} style={{
              display: 'inline-block',
              marginRight: i === words.length - 1 ? 0 : '0.28em',
              transform: `translateY(${translateY}px) scale(${scaleVal})`,
              opacity,
              fontFamily,
              fontSize: 118,
              fontWeight: 800,
              color: textColor,
              letterSpacing: '-0.055em',
              textShadow: '0px 12px 32px rgba(0,0,0,0.4)',
              zIndex: 10
            }}>
              {word}
            </div>
          );
        })}
      </AbsoluteFill>
    </div>
  );
};

const StaggeredQuestions = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
  const props = item.props || {};

  const q1Text = props.q1Text;
  const q2Text = props.q2Text;
  const q3Text = props.q3Text;
  const q4Text = props.q4Text;
  const fontFamily = props.fontFamily;
  const textColor = props.textColor;
  const bgBaseColor = props.bgBaseColor;
  const bgAccent1 = props.bgAccent1;
  const bgAccent2 = props.bgAccent2;
  const animationSpeed = props.animationSpeed;
  const transparentBackground = props.transparentBackground;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);
  const safeFps = fps || 30;

  const sprConfig = { damping: 18, stiffness: 120 };
  const speed = Math.max(0.1, animationSpeed);
  const numberToFirstWord = Math.max(1, Math.round(6 / speed));
  const wordDelay = Math.max(1, Math.round(5 / speed));
  const interRowGap = Math.max(1, Math.round(12 / speed));

  const parseQuestion = (text) => {
    const match = text.match(/^(\d+\.)\s*([\s\S]*)/);
    if (match) return { number: match[1], words: match[2].replace(/\n/g, ' ').split(' ').filter(Boolean) };
    return { number: '', words: text.split(' ').filter(Boolean) };
  };

  const questions = [q1Text, q2Text, q3Text, q4Text];
  const parsed = questions.map(parseQuestion);

  const rowStarts = [];
  let cursor = 15;
  for (let i = 0; i < parsed.length; i++) {
    rowStarts.push(cursor);
    const lastWordOffset = numberToFirstWord + (parsed[i].words.length - 1) * wordDelay;
    cursor = cursor + lastWordOffset + interRowGap;
  }

  const rootStyle = {
    position: 'absolute',
    top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: transparentBackground ? 'transparent' : bgBaseColor,
    overflow: 'hidden',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
  };

  const textContainerStyle = {
    display: 'flex',
    flexDirection: 'column',
    width: '1000px',
    transform: 'translateX(80px)',
    zIndex: 10,
  };

  const sharedTextStyle = {
    fontFamily,
    fontSize: '60px',
    fontWeight: 800,
    color: textColor,
    lineHeight: 1.25,
    letterSpacing: '-0.02em',
    textShadow: '0px 4px 16px rgba(0,0,0,0.4)',
  };

  return (
    <div style={rootStyle}>
      {!transparentBackground && (
        <div style={{ position: 'absolute', width: '100%', height: '100%', top: 0, left: 0 }}>
          <div style={{ position: 'absolute', width: '100%', height: '100%', filter: 'blur(100px)' }}>
            <div style={{ position: 'absolute', top: '-20%', left: '-10%', width: '80%', height: '80%', backgroundColor: bgAccent1, borderRadius: '50%', opacity: 0.6 }} />
            <div style={{ position: 'absolute', top: '40%', right: '-20%', width: '70%', height: '90%', backgroundColor: bgAccent2, borderRadius: '50%', opacity: 0.6 }} />
            <div style={{ position: 'absolute', top: '10%', left: '40%', width: '60%', height: '60%', backgroundColor: bgAccent1, borderRadius: '50%', opacity: 0.4 }} />
          </div>
        </div>
      )}

      <div style={textContainerStyle}>
        {parsed.map(({ number, words }, qi) => {
          const rowStart = rowStarts[qi];

          const numSpr = spring({ frame: Math.max(0, frame - rowStart), fps: safeFps, config: sprConfig });
          const numOpacity = Math.min(1, Math.max(0, numSpr));
          const numTx = interpolate(numSpr, [0, 1], [-28, 0]);

          return (
            <div key={qi} style={{
              ...sharedTextStyle,
              display: 'flex',
              flexDirection: 'row',
              alignItems: 'flex-start',
              marginBottom: '35px',
            }}>
              {/* Number column — fixed width so words always start at same X */}
              <span style={{
                display: 'inline-block',
                flexShrink: 0,
                width: '90px',
                opacity: numOpacity,
                transform: `translateX(${numTx}px)`,
              }}>
                {number}
              </span>
              {/* Words column — wraps internally, second line aligns with first word */}
              <div style={{
                display: 'flex',
                flexWrap: 'wrap',
                alignItems: 'baseline',
                columnGap: '0.3em',
                rowGap: '0.1em',
                flex: 1,
              }}>
                {words.map((word, wi) => {
                  const wordStart = rowStart + numberToFirstWord + wi * wordDelay;
                  const wSpr = spring({ frame: Math.max(0, frame - wordStart), fps: safeFps, config: sprConfig });
                  const wOpacity = Math.min(1, Math.max(0, wSpr));
                  const wTx = interpolate(wSpr, [0, 1], [30, 0]);
                  return (
                    <span key={wi} style={{
                      display: 'inline-block',
                      opacity: wOpacity,
                      transform: `translateX(${wTx}px)`,
                    }}>
                      {word}
                    </span>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const AnimatedMenu = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const props = item.props || {};
  const text1 = props.text1;
  const text2 = props.text2;
  const text3 = props.text3;
  const iconColor = props.iconColor;
  const textColor = props.textColor;
  const bgColor = props.bgColor;
  const fontFamily = props.fontFamily;

  const DESIGN_WIDTH = 1000;
  const DESIGN_HEIGHT = 500;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const safeFps = fps || 30;

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: bgColor,
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    paddingLeft: 80,
    overflow: 'hidden'
  };

  const renderWord = (word, wordDelay) => {
    const wordMovement = spring({ frame: Math.max(0, frame - wordDelay), fps: safeFps, config: { damping: 28, stiffness: 160 } });
    const wordX = interpolate(wordMovement, [0, 1], [30, 0]);
    const wordOpacity = interpolate(frame, [wordDelay, wordDelay + 6], [0, 1], {
      extrapolateRight: 'clamp',
      extrapolateLeft: 'clamp'
    });
    return (
      <span key={word + wordDelay} style={{
        display: 'inline-block',
        transform: `translateX(${wordX}px)`,
        opacity: wordOpacity,
        marginRight: 16
      }}>
        {word}
      </span>
    );
  };

  const renderRow = (text, rowIndex) => {
    const rowDelay = rowIndex * 15;
    const iconDelay = rowDelay;
    const words = text.split(' ');

    const iconScale = spring({ frame: Math.max(0, frame - iconDelay), fps: safeFps, config: { damping: 28, stiffness: 180 } });
    const iconOpacity = interpolate(frame, [iconDelay, iconDelay + 5], [0, 1], {
      extrapolateRight: 'clamp',
      extrapolateLeft: 'clamp'
    });

    return (
      <div key={rowIndex} style={{
        display: 'flex',
        alignItems: 'center',
        marginBottom: rowIndex === 2 ? 0 : 50
      }}>
        <div style={{
          width: 50,
          height: 60,
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          transform: `scale(${iconScale})`,
          opacity: iconOpacity,
          flexShrink: 0
        }}>
          <svg width="36" height="42" viewBox="0 0 36 42" fill="none" xmlns="http://www.w3.org/2000/svg">
            <polygon points="0,0 36,21 0,42" fill={iconColor} />
          </svg>
        </div>
        <div style={{
          marginLeft: 30,
          fontFamily,
          fontSize: 84,
          fontWeight: 700,
          letterSpacing: '-0.03em',
          color: textColor,
          display: 'flex',
          alignItems: 'center',
          whiteSpace: 'nowrap'
        }}>
          {words.map((word, wi) => renderWord(word, rowDelay + 6 + wi * 6))}
        </div>
      </div>
    );
  };

  return (
    <div style={rootStyle}>
      {renderRow(text1, 0)}
      {renderRow(text2, 1)}
      {renderRow(text3, 2)}
    </div>
  );
};

const AnimatedChart = ({item}) => {
