    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
  };
  return (
    <div style={rootStyle}>
      {/* 双色光晕背景 */}
      <div style={{ position: 'absolute', left: 0, right: 0, bottom: 0, height: '80%', background: `radial-gradient(ellipse at 35% 100%, ${bgGlowColor} 0%, transparent 60%)`, opacity: 0.75 }} />
      <div style={{ position: 'absolute', left: 0, right: 0, bottom: 0, height: '70%', background: `radial-gradient(ellipse at 68% 100%, #00baa3 0%, transparent 55%)`, opacity: 0.35 }} />
