        <div style={{ color: textColor, fontSize: 48, fontWeight: 700, letterSpacing: '-0.01em', opacity: 0.75 }}>{subtitleText}</div>
      </div>
      {/* 柱状图区 */}
      <div style={{ position: 'absolute', left: 200, top: 350, width: 1520, height: 600, display: 'flex', flexDirection: 'row', justifyContent: 'space-between' }}>
        {data.map((d, i) => {
          const progress = spring({ frame: Math.max(0, frame - d.delay), fps: safeFps, config: { damping: 40, mass: 1, stiffness: 100 } });
          const currentVal = Math.round(interpolate(progress, [0, 1], [0, d.val]));
          const h = (d.val / maxVal) * maxBarHeight * Math.max(0, progress);
          const colOpacity = interpolate(progress, [0, 1], [0, 1]);
          const barGradient = `linear-gradient(to top, #4c7475, ${barColorTop})`;
          return (
            <div key={i} style={{ width: 140, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'flex-end' }}>
              <div style={{ opacity: colOpacity, marginBottom: 20, fontSize: 42, fontWeight: 800, color: textColor, letterSpacing: '-0.03em' }}>
