              </div>
              <div style={{ width: '100%', height: h, background: barGradient, borderRadius: '6px 6px 0 0', boxShadow: `0 0 24px rgba(0,186,163,${colOpacity * 0.45})` }} />
              <div style={{ opacity: colOpacity, marginTop: 24, fontSize: 36, fontWeight: 800, color: textColor, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                {d.label}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const MinimalGradientTitle = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const chapterNumber = props.chapterNumber;
  const titleLine1 = props.titleLine1;
  const titleLine2 = props.titleLine2;
  const bgColor = props.bgColor;
  const transparentBackground = props.transparentBackground;
  const blobColor1 = props.blobColor1;
  const blobColor2 = props.blobColor2;
  const textColor = props.textColor;
  const fontFamily = props.fontFamily;

  const backgroundColor = transparentBackground ? 'transparent' : bgColor;

  // --- Easing ---
  const smoothSettle = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 3.5);
  };

  // --- Exit ---
  const totalFrames = durationInFrames || 120;
  const exitStart = totalFrames - 25;
  const exitRaw = Math.max(0, Math.min(1, (frame - exitStart) / 25));
  const exitProgress = exitRaw * exitRaw;
  const exitOpacity = 1 - exitProgress;
  const exitScale = 1 - exitProgress * 0.02;

  // --- Blob: scale 1.06 → 1.0 over 45 frames, opacity fade in ---
  const blobFadeRaw = Math.min(1, Math.max(0, frame / 40));
  const blobOpacity = smoothSettle(blobFadeRaw) * 0.8;
  const blobScaleRaw = Math.min(1, Math.max(0, frame / 45));
  const blobScale = 1.06 - 0.06 * smoothSettle(blobScaleRaw);
  // Gentle sin/cos drift (amplitude ≤ 8px)
  const blobDriftX = Math.sin(frame / 50) * 8;
  const blobDriftY = Math.cos(frame / 70) * 6;

  // --- Chapter number: starts frame 10, 50 frames ---
  const chapterRaw = Math.min(1, Math.max(0, (frame - 10) / 50));
  const chapterProgress = smoothSettle(chapterRaw);
  const chapterOpacity = smoothSettle(Math.min(1, Math.max(0, (frame - 10) / 18)));
  const chapterY = (1 - chapterProgress) * 60;

  // --- Title line 1: starts frame 35, 45 frames ---
  const t1Raw = Math.min(1, Math.max(0, (frame - 35) / 45));
  const t1Progress = smoothSettle(t1Raw);
  const t1Opacity = smoothSettle(Math.min(1, Math.max(0, (frame - 35) / 15)));
  const t1Y = (1 - t1Progress) * 55;

  // --- Title line 2: starts frame 50, 45 frames ---
  const t2Raw = Math.min(1, Math.max(0, (frame - 50) / 45));
  const t2Progress = smoothSettle(t2Raw);
  const t2Opacity = smoothSettle(Math.min(1, Math.max(0, (frame - 50) / 15)));
  const t2Y = (1 - t2Progress) * 55;

  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor,
    overflow: 'hidden',
    fontFamily,
    color: textColor,
    opacity: exitOpacity,
    transform: `scale(${exitScale})`
  };

  const chapterStyle = {
    position: 'absolute',
    top: 140,
    left: 180,
    fontSize: 96,
    fontStyle: 'italic',
    fontWeight: 400,
    opacity: chapterOpacity,
    transform: `translateY(${chapterY}px)`,
    lineHeight: 1,
    letterSpacing: '-0.02em',
  };

  const titleContainerStyle = {
    position: 'absolute',
    bottom: 160,
    right: 180,
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'flex-end',
    gap: 10,
  };

  const title1Style = {
    fontSize: 120,
    fontWeight: 400,
    fontStyle: 'normal',
    textTransform: 'uppercase',
    opacity: t1Opacity,
    transform: `translateY(${t1Y}px)`,
    lineHeight: 0.9,
    letterSpacing: '0.05em',
  };

  const title2Style = {
    fontSize: 120,
    fontWeight: 400,
    fontStyle: 'italic',
    textTransform: 'uppercase',
    opacity: t2Opacity,
    transform: `translateY(${t2Y}px)`,
    lineHeight: 0.9,
    letterSpacing: '0.02em',
  };

  const blobStyle = {
    position: 'absolute',
    top: -100,
    left: 450,
    width: 1200,
    height: 1200,
    opacity: blobOpacity,
    transform: `translate(${blobDriftX}px, ${blobDriftY}px) scale(${blobScale})`,
    transformOrigin: 'center center',
    pointerEvents: 'none',
  };

  return (
    <div style={rootStyle}>
      <svg viewBox="0 0 1200 1200" style={blobStyle}>
        <defs>
          <linearGradient id="organicGrad" x1="20%" y1="10%" x2="80%" y2="90%">
            <stop offset="0%" stopColor={blobColor1} />
            <stop offset="100%" stopColor={blobColor2} />
          </linearGradient>
          <filter id="softBlur" x="-50%" y="-50%" width="200%" height="200%">
            <feGaussianBlur stdDeviation="120" />
          </filter>
        </defs>
        <ellipse cx="600" cy="600" rx="350" ry="450" fill="url(#organicGrad)" filter="url(#softBlur)" />
      </svg>

      <div style={chapterStyle}>{chapterNumber}</div>

      <div style={titleContainerStyle}>
        <div style={title1Style}>{titleLine1}</div>
        <div style={title2Style}>{titleLine2}</div>
      </div>
    </div>
  );
};

const MinimalGradientCard = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const bgColor = props.transparentBackground ? 'transparent' : props.bgColor;

  const parseHex = (hex) => {
    if (!hex) return [0, 0, 0];
    const h = hex.replace('#', '');
    const r = parseInt(h.length === 3 ? h[0]+h[0] : h.substring(0,2), 16) || 0;
    const g = parseInt(h.length === 3 ? h[1]+h[1] : h.substring(2,4), 16) || 0;
    const b = parseInt(h.length === 3 ? h[2]+h[2] : h.substring(4,6), 16) || 0;
    return [r, g, b];
  };

  const rgba = (r, g, b, a) => `rgba(${r},${g},${b},${a})`;

  const smoothSettle = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 3.5);
  };

  // Exit (last 25 frames) — NO root opacity/transform
  const totalFrames = durationInFrames || 150;
  const exitStart = totalFrames - 25;
  const exitRaw = Math.max(0, Math.min(1, (frame - exitStart) / 25));
  const exitAlpha = 1 - exitRaw * exitRaw;

  // Blob: scale settle + gentle drift
  const blobFadeRaw = Math.min(1, Math.max(0, frame / 40));
  const blobAlpha = smoothSettle(blobFadeRaw) * 0.8 * exitAlpha;
  const blobScaleRaw = Math.min(1, Math.max(0, frame / 45));
  const blobScale = 1.05 - 0.05 * smoothSettle(blobScaleRaw);
  const blobDriftX = Math.sin(frame / 55) * 8;
  const blobDriftY = Math.cos(frame / 75) * 6;

  // Title line 1: starts frame 8, 50 frames
  const t1Raw = Math.min(1, Math.max(0, (frame - 8) / 50));
  const t1Progress = smoothSettle(t1Raw);
  const t1Y = (1 - t1Progress) * 70;
  const t1Alpha = smoothSettle(Math.min(1, Math.max(0, (frame - 8) / 18))) * exitAlpha;

  // Title line 2: starts frame 22, 50 frames
  const t2Raw = Math.min(1, Math.max(0, (frame - 22) / 50));
  const t2Progress = smoothSettle(t2Raw);
  const t2Y = (1 - t2Progress) * 70;
  const t2Alpha = smoothSettle(Math.min(1, Math.max(0, (frame - 22) / 18))) * exitAlpha;

  // Body: starts frame 50, 35 frames
  const bBodyRaw = Math.min(1, Math.max(0, (frame - 50) / 35));
  const bBodyProgress = smoothSettle(bBodyRaw);
  const bBodyY = (1 - bBodyProgress) * 40;
  const bBodyAlpha = smoothSettle(Math.min(1, Math.max(0, (frame - 50) / 15))) * exitAlpha;

  const [txR, txG, txB] = parseHex(props.textColor);
  const textRgba = (a) => rgba(txR, txG, txB, a);

  // Blob gradient with alpha baked in
  const blobBg = blobAlpha > 0.01
    ? `radial-gradient(circle, ${rgba(...parseHex(props.blobColor1), blobAlpha)} 0%, ${rgba(...parseHex(props.blobColor2), blobAlpha * 0.5)} 40%, transparent 75%)`
    : 'transparent';

  return (
    <div style={{
      position: 'absolute',
      inset: 0,
      backgroundColor: bgColor,
      overflow: 'hidden',
      display: 'flex'
    }}>
      {/* Blob */}
      <div style={{
        position: 'absolute',
        right: '-15%',
        top: '-20%',
        width: '1400px',
        height: '1400px',
        borderRadius: '50%',
        background: blobBg,
        transform: `translate(${blobDriftX}px, ${blobDriftY}px) scale(${blobScale})`,
        transformOrigin: 'center center',
        pointerEvents: 'none'
      }} />

      {/* Content */}
      <div style={{
        position: 'absolute',
        left: '12%',
        top: '25%',
        width: '55%',
        display: 'flex',
        flexDirection: 'column',
        gap: '10px'
      }}>
        <div style={{
          fontFamily: props.titleFont,
          fontSize: '120px',
          fontWeight: 400,
          color: textRgba(t1Alpha),
          lineHeight: 1.05,
          letterSpacing: '0.02em',
          textTransform: 'uppercase',
          transform: `translateY(${t1Y}px)`
        }}>
          {props.titleLine1}
        </div>
        <div style={{
          fontFamily: props.titleFont,
          fontSize: '120px',
          fontWeight: 300,
          fontStyle: 'italic',
          color: textRgba(t2Alpha),
          lineHeight: 1.05,
          letterSpacing: '0.12em',
          textTransform: 'uppercase',
          transform: `translateY(${t2Y}px)`
        }}>
          {props.titleLine2}
        </div>
        <div style={{
          fontFamily: props.bodyFont,
          fontSize: '30px',
          fontWeight: 300,
          color: textRgba(bBodyAlpha),
          lineHeight: 1.5,
          marginTop: '60px',
          transform: `translateY(${bBodyY}px)`,
          whiteSpace: 'normal',
          overflowWrap: 'break-word'
        }}>
          {props.bodyText}
        </div>
      </div>
    </div>
  );
};

const ProjectAllocation = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();
  const props = item.props || {};

  const titleText = props.titleText;
  const titleFont = props.titleFont;
  const labelFont = props.labelFont;
  const titleColor = props.titleColor;
  const color1 = props.color1;
  const color2 = props.color2;
  const color3 = props.color3;
  const blobColor = props.blobColor;
  const backgroundColor = props.transparentBackground ? 'transparent' : props.bgColor;

  // --- Easing curves ---
  const smoothSettle = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 3.5);
  };
  const bellCurveLate = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return t < 0.4
      ? 0.15 * Math.pow(t / 0.4, 2.5)
      : 0.15 + 0.85 * (1 - Math.pow(1 - (t - 0.4) / 0.6, 2.8));
  };

  // --- Exit ---
  const totalFrames = durationInFrames || 180;
  const exitStart = totalFrames - 25;
  const exitRaw = Math.max(0, Math.min(1, (frame - exitStart) / 25));
  const exitProgress = exitRaw * exitRaw;
  const exitOpacity = 1 - exitProgress;
  const exitScale = 1 - exitProgress * 0.02;

  // --- Blob: opacity fade in over 40 frames, scale settle ---
  const blobFadeRaw = Math.min(1, Math.max(0, frame / 40));
  const blobOpacity = smoothSettle(blobFadeRaw) * 0.8;

  // --- Title: starts frame 5, 50 frames ---
  const titleRaw = Math.min(1, Math.max(0, (frame - 5) / 50));
  const titleProgress = smoothSettle(titleRaw);
  const titleOpacity = smoothSettle(Math.min(1, Math.max(0, (frame - 5) / 18)));
  const titleY = (1 - titleProgress) * 50;

  // --- Donut chart: bellCurveLate, staggered from frame 25 ---
  const cx = 1250;
  const cy = 540;
  const r = 260;
  const sw = 100;
  const c = 2 * Math.PI * r;

  const v1 = 0.45;
  const v2 = 0.30;
  const v3 = 0.25;

  const l1 = v1 * c;
  const l2 = v2 * c;
  const l3 = v3 * c;

  const chart1Raw = Math.min(1, Math.max(0, (frame - 25) / 65));
  const chart2Raw = Math.min(1, Math.max(0, (frame - 31) / 65));
  const chart3Raw = Math.min(1, Math.max(0, (frame - 37) / 65));

  const s1 = bellCurveLate(chart1Raw);
  const s2 = bellCurveLate(chart2Raw);
  const s3 = bellCurveLate(chart3Raw);

  // --- Labels: appear when chart segment at ~55% ---
  const labelDelay1 = 25 + 65 * 0.55;
  const labelDelay2 = 31 + 65 * 0.55;
  const labelDelay3 = 37 + 65 * 0.55;

  const labelAnim = (delay) => {
    const raw = Math.min(1, Math.max(0, (frame - delay) / 20));
    return smoothSettle(raw);
  };

  const label1Op = labelAnim(labelDelay1);
  const label2Op = labelAnim(labelDelay2);
  const label3Op = labelAnim(labelDelay3);

  const getPos = (valStart, valMid, radiusOffset) => {
    const angle = (valStart + valMid / 2) * 2 * Math.PI;
    return {
      x: cx + Math.sin(angle) * (r + radiusOffset),
      y: cy - Math.cos(angle) * (r + radiusOffset)
    };
  };

  const pos1 = getPos(0, v1, 140);
  const pos2 = getPos(v1, v2, 140);
  const pos3 = getPos(v1 + v2, v3, 140);

  return (
    <div style={{position: 'absolute', inset: 0, backgroundColor, overflow: 'hidden', opacity: exitOpacity, transform: `scale(${exitScale})`}}>
      <div style={{position: 'absolute', inset: 0, opacity: blobOpacity}}>
        <svg style={{position: 'absolute', width: '100%', height: '100%', pointerEvents: 'none'}}>
          <defs>
            <radialGradient id="blobGrad" cx="50%" cy="50%" r="50%">
              <stop offset="0%" stopColor={blobColor} stopOpacity={1} />
              <stop offset="100%" stopColor={blobColor} stopOpacity={0} />
            </radialGradient>
          </defs>
          <circle cx="1600" cy="850" r="700" fill="url(#blobGrad)" />
        </svg>
      </div>

      <svg style={{position: 'absolute', width: '100%', height: '100%', pointerEvents: 'none'}}>
        <g transform={`rotate(-90 ${cx} ${cy})`}>
          <circle cx={cx} cy={cy} r={r} fill="none" stroke={color1} strokeWidth={sw}
            strokeDasharray={`${s1 * l1} ${c}`} strokeDashoffset={0} strokeLinecap="butt" />
          <circle cx={cx} cy={cy} r={r} fill="none" stroke={color2} strokeWidth={sw}
            strokeDasharray={`${s2 * l2} ${c}`} strokeDashoffset={-l1} strokeLinecap="butt" />
          <circle cx={cx} cy={cy} r={r} fill="none" stroke={color3} strokeWidth={sw}
            strokeDasharray={`${s3 * l3} ${c}`} strokeDashoffset={-(l1 + l2)} strokeLinecap="butt" />
        </g>
      </svg>

      <div style={{
        position: 'absolute',
        left: 150,
        top: 380,
        width: 700,
        display: 'flex',
        flexDirection: 'column',
        opacity: titleOpacity,
        transform: `translateY(${titleY}px)`
      }}>
        {titleText.split('\\n').map((line, i) => (
          <h1 key={i} style={{
            margin: 0,
            fontFamily: titleFont,
            fontSize: 120,
            fontWeight: 400,
            color: titleColor,
            lineHeight: 1.05,
            letterSpacing: '-0.03em',
            textTransform: 'uppercase'
          }}>
            {line}
          </h1>
        ))}
      </div>

      <div style={{
        position: 'absolute', left: pos1.x, top: pos1.y,
        transform: 'translate(-50%, -50%)', opacity: label1Op,
        fontFamily: labelFont, fontSize: 30, fontWeight: 300, color: titleColor, textAlign: 'center'
      }}>
        <div>Lodging</div>
        <div style={{fontWeight: 400, marginTop: 4}}>45%</div>
      </div>

      <div style={{
        position: 'absolute', left: pos2.x, top: pos2.y,
        transform: 'translate(-50%, -50%)', opacity: label2Op,
        fontFamily: labelFont, fontSize: 30, fontWeight: 300, color: titleColor, textAlign: 'center'
      }}>
        <div>Transit</div>
        <div style={{fontWeight: 400, marginTop: 4}}>30%</div>
      </div>

      <div style={{
        position: 'absolute', left: pos3.x, top: pos3.y,
        transform: 'translate(-50%, -50%)', opacity: label3Op,
        fontFamily: labelFont, fontSize: 30, fontWeight: 300, color: titleColor, textAlign: 'center'
      }}>
        <div>Dining</div>
        <div style={{fontWeight: 400, marginTop: 4}}>25%</div>
      </div>
    </div>
  );
};

