  const titleFont = props.titleFont;
  const bodyFont = props.bodyFont;
  const textColor = props.textColor;
  const lineColor = props.lineColor;
  const blobColor1 = props.blobColor1;
  const blobColor2 = props.blobColor2;
  const bgColor = props.bgColor;
  const transparentBackground = props.transparentBackground === 'true' || props.transparentBackground === true;

  const backgroundColor = transparentBackground ? 'transparent' : bgColor;

  // --- Easing curves ---
  const smoothSettle = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 3.5);
  };
  const lineDraw = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 2.8);
  };

  // --- Exit ---
  const totalFrames = durationInFrames || 210;
  const exitStart = totalFrames - 25;
  const exitRaw = Math.max(0, Math.min(1, (frame - exitStart) / 25));
  const exitProgress = exitRaw * exitRaw;
  const exitOpacity = 1 - exitProgress;
  const exitScale = 1 - exitProgress * 0.02;

  // --- Blob: scale 1.04 → 1.0 over 45 frames, gentle sin/cos drift ---
  const blobFadeRaw = Math.min(1, Math.max(0, frame / 45));
  const blobOpacity = smoothSettle(blobFadeRaw);
  const blobScaleRaw = Math.min(1, Math.max(0, frame / 45));
  const blobScale = 1.04 - 0.04 * smoothSettle(blobScaleRaw);
  const blobDriftX = Math.sin(frame / 60) * 8;
  const blobDriftY = Math.cos(frame / 80) * 6;

  // --- Title: starts frame 5, 50 frames ---
  const titleRaw = Math.min(1, Math.max(0, (frame - 5) / 50));
  const titleProgress = smoothSettle(titleRaw);
  const titleOpacity = smoothSettle(Math.min(1, Math.max(0, (frame - 5) / 18)));
  const titleY = (1 - titleProgress) * 60;

  // --- Horizontal line: starts frame 20, 55 frames ---
  const lineRaw = Math.min(1, Math.max(0, (frame - 20) / 55));
  const lineProgress = lineDraw(lineRaw);
  const lineWidth = lineProgress * 1320;

  // --- Nodes: staggered from frame 45, every 20 frames apart ---
  const nodes = [
    { x: 300, year: year1, desc: desc1, delay: 45 },
    { x: 740, year: year2, desc: desc2, delay: 65 },
    { x: 1180, year: year3, desc: desc3, delay: 85 },
    { x: 1620, year: year4, desc: desc4, delay: 105 },
  ];

  return (
    <div style={{ position: 'absolute', inset: 0, backgroundColor, overflow: 'hidden', opacity: exitOpacity, transform: `scale(${exitScale})` }}>
      {/* Blob background — no translate, only scale + drift */}
      <div style={{
        position: 'absolute',
        top: '50%', left: '50%',
        width: 1400, height: 1400,
        marginLeft: -700, marginTop: -700,
        background: `radial-gradient(circle, ${blobColor1} 0%, ${blobColor2} 40%, transparent 70%)`,
        opacity: blobOpacity,
        transform: `translate(${blobDriftX}px, ${blobDriftY}px) scale(${blobScale})`,
        transformOrigin: 'center center'
      }} />

      {/* Title */}
      <div style={{
        position: 'absolute',
        top: 120, left: 160,
        fontFamily: titleFont,
        fontSize: 72,
        fontStyle: 'italic',
        color: textColor,
        opacity: titleOpacity,
        transform: `translateY(${titleY}px)`,
        letterSpacing: '-0.02em',
