        maxWidth: 800
      }}>
        {titleText}
      </div>

      {/* Horizontal line */}
      <div style={{
        position: 'absolute',
        left: 300,
        top: 540,
        width: lineWidth,
        height: 2,
        backgroundColor: lineColor,
        transformOrigin: 'left center'
      }} />

      {/* Nodes */}
      {nodes.map((node, i) => {
        const nodeRaw = Math.min(1, Math.max(0, (frame - node.delay) / 40));
        const nodeProgress = smoothSettle(nodeRaw);
        const nodeOpacity = smoothSettle(Math.min(1, Math.max(0, (frame - node.delay) / 15)));
        const textY = (1 - nodeProgress) * 30;

        return (
          <div key={i} style={{ position: 'absolute', left: node.x, top: 540, opacity: nodeOpacity }}>
            <div style={{
              position: 'absolute',
              width: 12, height: 12,
              borderRadius: '50%',
              backgroundColor: lineColor,
              left: -6, top: -5,
              transform: `scale(${nodeProgress})`
            }} />

            <div style={{
              position: 'absolute',
              bottom: 40, left: -150, width: 300,
              textAlign: 'center',
              fontFamily: titleFont,
              fontSize: 40,
              fontStyle: 'italic',
              color: textColor,
              transform: `translateY(${textY}px)`
            }}>
              {node.year}
            </div>

            <div style={{
              position: 'absolute',
              top: 40, left: -150, width: 300,
              textAlign: 'center',
