          </div>
        );
      })}
    </div>
  );
};

const MinimalGradientAnchor = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const bgColor = props.transparentBackground ? 'transparent' : props.bgColor;
  const textColor = props.textColor;
  const titleFont = props.titleFont;
  const bodyFont = props.bodyFont;
  const blobColor1 = props.blobColor1;
  const blobColor2 = props.blobColor2;
  const chartColor1 = props.chartColor1;
  const chartColor2 = props.chartColor2;
  const chartColor3 = props.chartColor3;

  const parseHex = (hex) => {
    if (!hex) return [0,0,0];
    const h = hex.replace('#','');
    return [parseInt(h.substring(0,2),16)||0, parseInt(h.substring(2,4),16)||0, parseInt(h.substring(4,6),16)||0];
  };
  const rgba = (hex, a) => { const [r,g,b] = parseHex(hex); return `rgba(${r},${g},${b},${a})`; };

  const smoothSettle = (t) => t<=0?0:t>=1?1:1-Math.pow(1-t,3.5);
  const bellCurveLate = (t) => t<=0?0:t>=1?1:t<0.4?0.15*Math.pow(t/0.4,2.5):0.15+0.85*(1-Math.pow(1-(t-0.4)/0.6,2.8));
  const lineDraw = (t) => t<=0?0:t>=1?1:1-Math.pow(1-t,2.8);

  // Exit (last 25f)
  const total = durationInFrames || 150;
  const exitRaw = Math.max(0, Math.min(1, (frame-(total-25))/25));
  const ex = 1 - exitRaw*exitRaw;

  // Stagger helper: element starts at `delay`, takes `dur` frames
  const anim = (delay, dur) => smoothSettle(Math.min(1, Math.max(0, (frame-delay)/dur)));
  const fadeIn = (delay) => smoothSettle(Math.min(1, Math.max(0, (frame-delay)/15)));

  // Blob
  const blobA = anim(0, 40) * ex;
  const blobScale = 1.05 - 0.05*anim(0,45);
  const driftX = Math.sin(frame/55)*6;
  const driftY = Math.cos(frame/70)*5;

  // Chapter + Title (delay 5)
  const ttA = fadeIn(5)*ex;
  const ttY = (1-anim(5,48))*50;

  // Body (delay 20)
  const bdA = fadeIn(20)*ex;
  const bdY = (1-anim(20,40))*35;

  // Name tag (delay 30)
  const nmA = fadeIn(30)*ex;
  const nmY = (1-anim(30,35))*25;

  // Timeline line (delay 15)
  const tlW = lineDraw(Math.min(1, Math.max(0,(frame-15)/50)))*680;
  const tlA = fadeIn(15)*ex;

  // Timeline nodes (stagger from 25, every 5f)
  const nd = [0,1,2,3].map(i => {
    const d = 25+i*5;
    return { a: fadeIn(d)*ex, y: (1-anim(d,30))*18 };
  });

  // Donut chart (delay 20, 60f)
  const chRaw = Math.min(1, Math.max(0,(frame-20)/60));
  const chP = bellCurveLate(chRaw);
  const chLblA = anim(20+60*0.55, 18)*ex;

  const cx=160, cy=160, r=110, sw=32;
  const C = 2*Math.PI*r;
  const segs = [{p:0.45,c:chartColor1},{p:0.35,c:chartColor2},{p:0.20,c:chartColor3}];
  let offset = 0;

  return (
    <div style={{position:'absolute',inset:0,backgroundColor:bgColor,overflow:'hidden',fontFamily:bodyFont}}>
      {/* Blobs */}
      <div style={{position:'absolute',top:'-12%',right:'-8%',width:1300,height:1300,
        background:`radial-gradient(circle,${rgba(blobColor1,blobA*0.55)} 0%,transparent 60%)`,
        transform:`translate(${driftX}px,${driftY}px) scale(${blobScale})`,transformOrigin:'center'}}/>
      <div style={{position:'absolute',bottom:'-18%',left:'-6%',width:1100,height:1100,
        background:`radial-gradient(circle,${rgba(blobColor2,blobA*0.4)} 0%,transparent 60%)`,
        transform:`translate(${-driftX}px,${-driftY}px) scale(${blobScale})`,transformOrigin:'center'}}/>

      {/* Chapter + Title */}
      <div style={{position:'absolute',left:140,top:100,transform:`translateY(${ttY}px)`}}>
        <div style={{fontFamily:titleFont,fontStyle:'italic',fontSize:100,color:rgba(textColor,ttA*0.7),letterSpacing:'-0.02em',lineHeight:1}}>01</div>
        <div style={{fontFamily:titleFont,fontSize:130,fontWeight:400,textTransform:'uppercase',color:rgba(textColor,ttA),lineHeight:0.9,letterSpacing:'0.05em',marginTop:10}}>JOURNEY</div>
        <div style={{fontFamily:titleFont,fontSize:130,fontWeight:400,fontStyle:'italic',textTransform:'uppercase',color:rgba(textColor,ttA),lineHeight:0.9,letterSpacing:'0.02em'}}>ROUTES</div>
      </div>

      {/* Body text */}
      <div style={{position:'absolute',left:140,top:560,width:550,transform:`translateY(${bdY}px)`}}>
        <div style={{fontSize:30,lineHeight:1.5,color:rgba(textColor,bdA*0.85),whiteSpace:'pre-wrap'}}>
          We create meaningful experiences through thoughtful design.
        </div>
      </div>

      {/* Name tag */}
      <div style={{position:'absolute',left:140,bottom:100,transform:`translateY(${nmY}px)`}}>
        <div style={{fontSize:22,fontWeight:500,color:rgba(textColor,nmA),borderLeft:`3px solid ${rgba(chartColor1,nmA)}`,paddingLeft:14}}>
          Elena Rossi — Creative Director
        </div>
      </div>

      {/* Timeline (bottom center) */}
      <div style={{position:'absolute',left:140,top:720,width:750,height:90}}>
        <div style={{position:'absolute',left:0,top:10,width:tlW,height:2,backgroundColor:rgba(textColor,tlA*0.25)}}/>
        {['2020','2021','2023','2025'].map((yr,i) => (
          <div key={i} style={{position:'absolute',left:i*200,top:0,transform:`translateY(${nd[i].y}px)`}}>
            <div style={{width:8,height:8,borderRadius:'50%',backgroundColor:rgba(blobColor2,nd[i].a),marginBottom:8}}/>
            <div style={{fontFamily:titleFont,fontStyle:'italic',fontSize:24,color:rgba(textColor,nd[i].a)}}>{yr}</div>
            <div style={{fontSize:13,color:rgba(textColor,nd[i].a*0.6),letterSpacing:'0.1em',textTransform:'uppercase',marginTop:4}}>WAYPOINT</div>
          </div>
        ))}
      </div>

      {/* Donut chart (right) */}
      <div style={{position:'absolute',right:180,top:200,width:320,height:320}}>
        <svg width={320} height={320} style={{transform:'rotate(-90deg)'}}>
          {segs.map((s,i) => {
            const len = s.p*C*chP;
            const dash = `${len} ${C}`;
            const el = <circle key={i} cx={cx} cy={cy} r={r} fill="none" stroke={rgba(s.c,ex)} strokeWidth={sw} strokeDasharray={dash} strokeDashoffset={-offset} strokeLinecap="butt"/>;
            offset += s.p*C;
            return el;
          })}
        </svg>
        {/* Labels */}
        {[{pct:'45%',ang:-45},{pct:'35%',ang:96},{pct:'20%',ang:216}].map((l,i) => {
          const lx = cx+Math.cos(l.ang*Math.PI/180)*145;
          const ly = cy+Math.sin(l.ang*Math.PI/180)*145;
          return <div key={`l${i}`} style={{position:'absolute',left:lx-20,top:ly-10,width:40,textAlign:'center',fontSize:18,fontWeight:600,color:rgba(textColor,chLblA)}}>{l.pct}</div>;
        })}
      </div>

      {/* Team circles hint (right side, below chart) */}
      <div style={{position:'absolute',right:180,bottom:160,display:'flex',gap:30}}>
        {[chartColor1,chartColor2,chartColor3].map((c,i) => {
          const cA = fadeIn(35+i*6)*ex;
          return <div key={i} style={{width:70,height:70,borderRadius:'50%',border:`2px solid ${rgba(c,cA*0.6)}`,backgroundColor:rgba(c,cA*0.08)}}/>; 
        })}
      </div>
    </div>
  );
};

const LowerThirdNameBar = ({item}) => {
