  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const qFrame = Math.floor(baseFrame / 3) * 3;

  const nameLen = nameText ? nameText.length : 0;
  const TYPE_START = 6;
  const TYPE_SPEED = 1;
  const charsToShow = Math.min(nameLen, Math.max(0, Math.floor((qFrame - TYPE_START) / TYPE_SPEED)));
  const displayedName = nameText ? nameText.substring(0, charsToShow) : '';

  const nameFinishFrame = TYPE_START + nameLen * TYPE_SPEED;
  const subStartFrame = nameFinishFrame + 4;
  const subEndFrame = subStartFrame + 12;
  const subHeight = interpolate(qFrame, [subStartFrame, subEndFrame], [0, 48], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  const BAR_HEIGHT = 140;
  const BAR_DURATION = 9;
  const yellowStart  = subEndFrame - BAR_DURATION;
  const magentaStart = yellowStart - 4;
  const cyanStart    = magentaStart - 6;

  const cyanHeight    = interpolate(qFrame, [cyanStart,    cyanStart    + BAR_DURATION], [0, BAR_HEIGHT], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const magentaHeight = interpolate(qFrame, [magentaStart, magentaStart + BAR_DURATION], [0, BAR_HEIGHT], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const yellowHeight  = interpolate(qFrame, [yellowStart,  yellowStart  + BAR_DURATION], [0, BAR_HEIGHT], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  const rootStyle = {
    position: 'absolute', top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`, transformOrigin: 'top left',
    backgroundColor: transparentBackground ? 'transparent' : '#1a1a1a',
    overflow: 'hidden'
  };

  return (
    <div style={rootStyle}>
      <div style={{ position: 'absolute', left: 80, top: 760, width: 1700, height: 200 }}>
        <div style={{ position: 'absolute', left: 0, top: 8, width: 14, height: BAR_HEIGHT }}>
          <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: cyanHeight,    backgroundColor: color3, zIndex: 1 }} />
          <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: magentaHeight, backgroundColor: color2, zIndex: 2 }} />
          <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: yellowHeight,  backgroundColor: color1, zIndex: 3 }} />
        </div>
        <div style={{
          position: 'absolute', left: 38, top: 0,
          fontFamily: 'Roboto, sans-serif',
          fontSize: 88, fontWeight: 'bold', color: '#ffffff',
          lineHeight: '92px', whiteSpace: 'nowrap', letterSpacing: '0.5px'
        }}>{displayedName}</div>
        <div style={{
          position: 'absolute', left: 40, top: 94,
          width: 1600, height: subHeight, overflow: 'hidden'
        }}>
          <div style={{
            fontFamily: 'Roboto, sans-serif',
            fontSize: 34, color: 'rgba(255,255,255,0.85)',
            lineHeight: '48px', whiteSpace: 'nowrap', fontWeight: 'normal', letterSpacing: '0.4px'
          }}>{subtitleText}</div>
        </div>
      </div>
    </div>
  );
};

const VoxNewsCard = ({item}) => {
  const baseFrame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();

  const frame = Math.floor(baseFrame / 3) * 3;

  const props = item.props || {};
  const headlineLine1 = props.headlineLine1;
  const headlineLine2 = props.headlineLine2;
  const headlineLine3 = props.headlineLine3;
  const bylineText = props.bylineText;
  const sourceName = props.sourceName;
  const sourceColor = props.sourceColor;
  const highlightColor = props.highlightColor;
  const backgroundColor = props.backgroundColor;
  const headlineFont = props.headlineFont;
  const sourceFont = props.sourceFont;
  const bylineFont = props.bylineFont;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const canvasScale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // Highlight wipe: easeOutCubic, quantized
  const highlightPct = interpolate(frame, [0, 24], [0, 100], {
    easing: Easing.out(Easing.cubic),
    extrapolateRight: 'clamp'
  });

  // Ken Burns: raw frame, GPU layer
  const kenBurns = interpolate(baseFrame, [0, durationInFrames || 150], [1.0, 1.03], {
    extrapolateRight: 'clamp'
  });

  const watermarks = React.useMemo(() => {
    const symbols = ['∑','∫','π','Δ','α','β','∞','≈','≠','≤','≥','Ω','µ','√'];
    const out = [];
    let seed = 12345;
    const rng = () => { seed = (seed * 9301 + 49297) % 233280; return seed / 233280; };
    for (let i = 0; i < 40; i++) {
      out.push({ id: i, char: symbols[Math.floor(rng() * symbols.length)],
        left: `${rng()*110-5}%`, top: `${rng()*110-5}%`,
        size: 150 + rng()*450, rot: (rng()-0.5)*120, opacity: 0.02+rng()*0.03 });
    }
    return out;
  }, []);

  // Split line1: prefix = first word, highlighted = rest
  const words = headlineLine1 ? headlineLine1.split(' ') : [];
  const prefix = words[0] ? words[0] + ' ' : '';
  const highlightedPart = words.slice(1).join(' ');

  // CSS background-size gradient highlight — zero layout impact, pure inline
  const highlightSpanStyle = {
    background: `linear-gradient(${highlightColor}, ${highlightColor}) no-repeat left center`,
    backgroundSize: `${highlightPct}% 88%`,
    paddingBottom: 4,
  };

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      transform: `scale(${canvasScale})`, transformOrigin: 'top left',
      overflow: 'hidden', backgroundColor,
    }}>

      {/* Static background grid */}
      <div style={{ position: 'absolute', inset: 0, zIndex: 1 }}>
        <svg width="100%" height="100%">
          <defs>
            <pattern id="vgrid" width="80" height="80" patternUnits="userSpaceOnUse">
              <path d="M 40 0 L 40 80 M 0 40 L 80 40" stroke="#999" strokeOpacity="0.06" strokeWidth="1.5"/>
              <path d="M 33 40 L 47 40 M 40 33 L 40 47" stroke="#999" strokeOpacity="0.15" strokeWidth="2"/>
            </pattern>
          </defs>
          <rect width="100%" height="100%" fill="url(#vgrid)"/>
        </svg>
      </div>

      {/* Static watermark symbols */}
      <div style={{ position: 'absolute', inset: 0, zIndex: 2 }}>
        {watermarks.map(wm => (
          <div key={wm.id} style={{
            position: 'absolute', left: wm.left, top: wm.top,
            fontSize: wm.size, color: '#888', opacity: wm.opacity,
            transform: `rotate(${wm.rot}deg)`, lineHeight: 1, fontFamily: 'serif',
          }}>{wm.char}</div>
        ))}
      </div>

      {/* Ken Burns content layer */}
      <div style={{
        position: 'absolute', inset: 0, zIndex: 10,
        transform: `translate3d(0,0,0) scale(${kenBurns})`,
        transformOrigin: '50% 50%',
        willChange: 'transform',
      }}>
        <div style={{
          position: 'absolute', left: 240, top: 0, width: 1440, height: '100%',
          display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'flex-start',
          fontFamily: bylineFont,
        }}>

          {/* Source badge */}
          <div style={{ backgroundColor: sourceColor, padding: '10px 24px', marginBottom: 36 }}>
            <span style={{ color: '#fff', fontFamily: sourceFont, fontSize: 44, fontWeight: 'bold', letterSpacing: '0.05em', lineHeight: 1 }}>
              {sourceName}
            </span>
          </div>

          {/* Headline — 3 lines matching reference layout */}
          <div style={{ fontSize: 78, fontWeight: 900, lineHeight: 1.18, color: '#111', letterSpacing: '-0.02em', margin: 0, fontFamily: headlineFont }}>
            {/* Line 1: prefix plain, rest highlighted */}
            <div style={{ whiteSpace: 'nowrap' }}>
              <span>{prefix}</span>
              <span style={highlightSpanStyle}>{highlightedPart}</span>
            </div>
            <div style={{ whiteSpace: 'nowrap' }}>{headlineLine2}</div>
            <div style={{ whiteSpace: 'nowrap' }}>{headlineLine3}</div>
          </div>

          {/* Byline */}
          <div style={{ fontSize: 30, fontWeight: 'normal', color: '#444', marginTop: 36, fontFamily: bylineFont }}>
            {bylineText}
          </div>
        </div>
      </div>
    </div>
  );
};

const ListOverlay = ({ item }) => {
  const frame = useCurrentFrame();
  const props = item.props || {};

  const titleText = props.titleText;
  const item1Text = props.item1Text;
  const item2Text = props.item2Text;
  const item3Text = props.item3Text;
  const item4Text = props.item4Text;
  const accentColor = props.accentColor;
  const textColor = props.textColor;
  const fontFamily = props.fontFamily;
  const transparentBackground = props.transparentBackground;

  const DESIGN_WIDTH = 1200;
  const iw = item?.width || DESIGN_WIDTH;
  const ih = item?.height || 1080;
  const scale = iw / DESIGN_WIDTH;
  const DESIGN_HEIGHT = Math.ceil(ih / scale);

  const totalFrames = 240;
  const slideInDur = 30;
  const slideOutStart = totalFrames - 30;

  // Bell-curve: slow → fast(peak late) → slow
  const enterEase = Easing.bezier(0.12, 0.0, 0.20, 1.0);
  // Exit mirror: slow → fast(peak early) → slow
  const exitEase = Easing.bezier(0.80, 0.0, 0.88, 1.0);

  const enterTx = interpolate(frame, [0, slideInDur], [DESIGN_WIDTH, 0], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: enterEase,
  });
  const exitTx = interpolate(frame, [slideOutStart, slideOutStart + 30], [0, DESIGN_WIDTH], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: exitEase,
  });
  const tx = frame < slideInDur ? enterTx : (frame >= slideOutStart ? exitTx : 0);

  const co = slideInDur;

  const titleChars = (titleText || '').split('');
  const tStagger = titleChars.length > 1 ? 22 / titleChars.length : 0;
  const titleElements = titleChars.map((char, i) => {
    const p = interpolate(frame - co - i * tStagger, [0, 15], [0, 1], {
      extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: Easing.out(Easing.quad)
    });
    return (
      <span key={`t${i}`} style={{
        display: 'inline-block', whiteSpace: 'pre',
        opacity: p, transform: `translateY(${interpolate(p,[0,1],[-18,0])}px)`
      }}>{char}</span>
    );
  });

  const r = 22;
  const circumference = 2 * Math.PI * r;
  const itemData = [
    { text: item1Text || '', start: co + 20 },
    { text: item2Text || '', start: co + 60 },
    { text: item3Text || '', start: co + 100 },
    { text: item4Text || '', start: co + 140 },
  ];

  const listElements = itemData.map((listItem, idx) => {
    const s = listItem.start;
    const strokeP = interpolate(frame - s, [0, 18], [0, 1], {
      extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: Easing.inOut(Easing.quad)
    });
    const dashOffset = circumference * (1 - strokeP);
    const numP = interpolate(frame - (s + 10), [0, 14], [0, 1], {
      extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: Easing.out(Easing.quad)
    });
    const words = listItem.text.split(' ').filter(Boolean);
    const wordElements = words.map((word, w) => {
      const wp = interpolate(frame - (s + 16 + w * 4), [0, 14], [0, 1], {
        extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: Easing.out(Easing.quad)
      });
      return (
        <span key={`w${idx}-${w}`}>
          <span style={{ display:'inline-block', opacity:wp, transform:`translateY(${interpolate(wp,[0,1],[-18,0])}px)` }}>{word}</span>{' '}
        </span>
      );
    });
    const fIdFar = `gFar${idx}`;
    const fIdNear = `gNear${idx}`;
    const cx = 40; const cy = 40;
    return (
      <div key={`li${idx}`} style={{ display:'flex', alignItems:'center', marginBottom:46 }}>
        <div style={{ position:'relative', width:60, height:60, flexShrink:0, marginRight:40 }}>
          <svg width="120" height="120" viewBox="0 0 80 80"
            style={{ position:'absolute', top:-30, left:-30, transform:'rotate(-90deg) scaleY(-1)', overflow:'visible' }}>
            <defs>
              <filter id={fIdFar} x="-200%" y="-200%" width="500%" height="500%">
                <feGaussianBlur in="SourceGraphic" stdDeviation="20" result="b1"/>
                <feGaussianBlur in="SourceGraphic" stdDeviation="9" result="b2"/>
                <feMerge><feMergeNode in="b1"/><feMergeNode in="b1"/><feMergeNode in="b2"/></feMerge>
              </filter>
              <filter id={fIdNear} x="-50%" y="-50%" width="200%" height="200%">
                <feGaussianBlur in="SourceGraphic" stdDeviation="4" result="b"/>
                <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge>
              </filter>
            </defs>
            <circle cx={cx} cy={cy} r={r} fill="transparent" stroke={accentColor} strokeWidth="3"
              strokeDasharray={circumference} strokeDashoffset={dashOffset} strokeLinecap="round"
              filter={`url(#${fIdFar})`} opacity={strokeP * 0.9}/>
            <circle cx={cx} cy={cy} r={r} fill="transparent" stroke={accentColor} strokeWidth="3"
              strokeDasharray={circumference} strokeDashoffset={dashOffset} strokeLinecap="round"
              filter={`url(#${fIdNear})`} opacity={strokeP}/>
            <circle cx={cx} cy={cy} r={r} fill="transparent" stroke={accentColor} strokeWidth="3"
              strokeDasharray={circumference} strokeDashoffset={dashOffset} strokeLinecap="round"
              opacity={strokeP}/>
          </svg>
          <div style={{
            position:'absolute', inset:0,
            display:'flex', justifyContent:'center', alignItems:'center',
            fontFamily, color:textColor, fontSize:28, fontWeight:'bold',
            opacity:numP,
            transform:`translate(${interpolate(numP,[0,1],[10,0])}px,${interpolate(numP,[0,1],[14,0])}px)`,
          }}>{idx + 1}</div>
        </div>
        <div style={{ fontFamily, color:textColor, fontSize:38, lineHeight:1.4, flex:1 }}>{wordElements}</div>
      </div>
    );
  });

  // Root div: NO overflow:hidden — the panel must be able to exist outside its own canvas bounds
  // translateX pushes the entire rendered panel: positive = off to the right, 0 = in place
  // The host canvas/compositor clips what's outside the screen — we just move the panel
  return (
    <div style={{
      position:'absolute', top:0, left:0,
      width:DESIGN_WIDTH, height:DESIGN_HEIGHT,
      transform:`scale(${scale}) translateX(${tx}px)`,
      transformOrigin:'top left',
      // NO overflow:hidden — don't clip the panel, let it slide freely
    }}>
      <div style={{
        position:'absolute', top:0, left:0,
        width:'100%', height:'100%',
        backgroundColor: transparentBackground ? 'transparent' : 'rgb(8,6,14)',
      }}>
        <div style={{
          position:'absolute', bottom:-60, right:-60,
          width:800, height:700, zIndex:0, pointerEvents:'none',
          background:`radial-gradient(ellipse at 85% 90%, ${accentColor}80 0%, ${accentColor}38 28%, ${accentColor}12 50%, transparent 68%)`,
        }}/>
        <div style={{ position:'absolute', top:0, left:0, width:8, height:'100%', backgroundColor:'rgba(255,255,255,0.50)', zIndex:2 }}/>
        <div style={{ position:'absolute', top:0, left:8, width:4, height:'100%', backgroundColor:'rgba(60,60,60,0.90)', zIndex:2 }}/>
        <div style={{ position:'relative', zIndex:1, padding:'200px 90px 60px 100px', boxSizing:'border-box' }}>
          <div style={{ fontFamily, color:textColor, fontSize:42, fontWeight:'bold', marginBottom:64, lineHeight:1.2, whiteSpace:'nowrap' }}>
            {titleElements}
          </div>
          {listElements}
        </div>
      </div>
    </div>
  );
};

const NumberedListCard = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const row1Text = props.row1Text;
  const row2Text = props.row2Text;
  const row3Text = props.row3Text;
  const badge1Color = props.badge1Color;
  const badge2Color = props.badge2Color;
  const badge3Color = props.badge3Color;
  const fontFamily = props.fontFamily;
  const textColor = props.textColor;
  const backgroundColor = props.backgroundColor;
  const bandColor = props.bandColor;
  const numberColor = props.numberColor;
  const wordDelay = props.wordDelay;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const PANEL_IN = 22;
  const BADGE_DURATION = 14;
  const WORD_ANIM_DURATION = 18;
  const ROW_GAP = 6;

  const rowsData = [
    { text: row1Text || '', badgeColor: badge1Color },
    { text: row2Text || '', badgeColor: badge2Color },
    { text: row3Text || '', badgeColor: badge3Color }
  ];

  const rowStartFrames = [];
  let cursor = PANEL_IN;
  rowsData.forEach((row) => {
    rowStartFrames.push(cursor);
    const wordCount = row.text.split(' ').filter(Boolean).length;
    const lastWordStart = cursor + BADGE_DURATION + (wordCount - 1) * wordDelay;
    cursor = lastWordStart + WORD_ANIM_DURATION + ROW_GAP;
  });

  const blobs = [
    'M62,8 C88,2 114,28 116,58 C118,92 94,118 62,112 C30,106 4,82 8,50 C12,18 36,14 62,8 Z',
    'M52,12 C82,2 116,18 112,54 C108,90 88,116 52,112 C16,108 2,84 6,50 C10,16 22,22 52,12 Z',
    'M68,8 C98,12 114,38 116,68 C118,98 88,114 56,116 C24,118 6,94 4,62 C2,30 38,4 68,8 Z'
  ];

  const panelY = interpolate(frame, [0, PANEL_IN], [1080, 0], {
    easing: Easing.bezier(0.22, 1, 0.36, 1),
    extrapolateRight: 'clamp'
  });

  // S-curve band grows slowly over 400 frames
  const bandGrow = interpolate(frame, [PANEL_IN, PANEL_IN + 400], [1, 0], {
    easing: Easing.bezier(0.4, 0, 0.2, 1),
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp'
  });

  return (
    <div style={{ position: 'absolute', top: 0, left: 0, width: DESIGN_WIDTH, height: DESIGN_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'top left', overflow: 'hidden' }}>
      <div style={{ width: DESIGN_WIDTH, height: DESIGN_HEIGHT, backgroundColor: backgroundColor, transform: `translateY(${panelY}px)`, position: 'relative', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center' }}>

        {/* S-curve band — same shape language as Principle card */}
        <svg style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none' }}>
          <path
            d="M -300 1100 C 200 1350, 700 580, 1200 380 C 1550 240, 1900 210, 2300 190"
            pathLength="1"
            stroke={bandColor}
            strokeWidth="500"
            fill="none"
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeDasharray="1"
            strokeDashoffset={bandGrow}
          />
        </svg>

        <div style={{ position: 'relative', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'flex-start', width: '1200px', gap: '80px', zIndex: 1 }}>
          {rowsData.map((row, index) => {
            const baseFrame = rowStartFrames[index];
            const badgeFade = interpolate(frame, [baseFrame, baseFrame + BADGE_DURATION], [0, 1], {
              easing: Easing.bezier(0.22, 1, 0.36, 1),
              extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
            });
            const words = row.text.split(' ').filter(Boolean);
            const wordsStartFrame = baseFrame + BADGE_DURATION;

            return (
              <div key={index} style={{ display: 'flex', flexDirection: 'row', alignItems: 'center', gap: '40px', width: '100%' }}>
                <div style={{ position: 'relative', width: '120px', height: '120px', flexShrink: 0, opacity: badgeFade }}>
                  <svg width="120" height="120" viewBox="0 0 120 120" style={{ position: 'absolute', top: 0, left: 0 }}>
                    <path d={blobs[index]} fill={row.badgeColor} />
                  </svg>
                  <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', display: 'flex', justifyContent: 'center', alignItems: 'center', color: numberColor, fontSize: '52px', fontFamily: fontFamily, fontWeight: '800', lineHeight: '1' }}>
                    {index + 1}
                  </div>
                </div>
                <div style={{ flex: 1, fontSize: '72px', fontFamily: fontFamily, color: textColor, fontWeight: 'bold', lineHeight: '1.2', paddingTop: '8px' }}>
                  {words.map((word, wIndex) => {
                    const wordStart = wordsStartFrame + wIndex * wordDelay;
                    const wordX = interpolate(frame, [wordStart, wordStart + WORD_ANIM_DURATION], [20, 0], {
                      easing: Easing.bezier(0.22, 1, 0.36, 1),
                      extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
                    });
                    const wordOp = interpolate(frame, [wordStart, wordStart + 12], [0, 1], {
                      extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
                    });
                    return (
                      <span key={wIndex} style={{ display: 'inline-block', whiteSpace: 'pre' }}>
                        <span style={{ display: 'inline-block', transform: `translateX(${wordX}px)`, opacity: wordOp }}>{word}</span>
                        {' '}
                      </span>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

const ShowcaseGraphic = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
  const props = item.props || {};

  // Theme & Colors
  const bgColor = props.transparentBackground ? 'transparent' : props.bgColor;
  const cCobalt = props.cCobalt;
  const cYellow = props.cYellow;
  const cRed = props.cRed;
  const cTeal = props.cTeal;
  const cOrange = props.cOrange;
  const textColor = props.textColor;
  const fontHeading = props.fontHeading;
  const fontAccent = props.fontAccent;

  // Safely bound springs
  const safeSpring = (delay = 0, damping = 15) => {
    return spring({ frame: Math.max(0, frame - delay), fps, config: { damping } });
  };

  // 0. Background Cubist Accents Animation
  const bgShape1Scale = safeSpring(0, 12);
  const bgShape2Scale = safeSpring(5, 12);
  const bgShape3Scale = safeSpring(10, 12);

  // 1. Title Animation
  const titleSlide = interpolate(frame, [10, 40], [40, 0], {extrapolateRight: 'clamp'});
  const titleOp = interpolate(frame, [10, 35], [0, 1], {extrapolateRight: 'clamp'});
  const titleAccentScale = safeSpring(25, 14);

  // 2. Chart Animation
  const chartTitleOp = interpolate(frame, [15, 45], [0, 1], {extrapolateRight: 'clamp'});
  const bar1Width = safeSpring(25);
  const bar2Width = safeSpring(35);
  const bar3Width = safeSpring(45);

  // 3. Name Tag Animation
  const avatarScale = safeSpring(30);
  const nameSlide = interpolate(frame, [35, 60], [-30, 0], {extrapolateRight: 'clamp'});
  const nameOp = interpolate(frame, [35, 60], [0, 1], {extrapolateRight: 'clamp'});

  // 4. Bullets Animation
  const b1Scale = safeSpring(40);
  const b1Op = interpolate(frame, [40, 60], [0, 1], {extrapolateRight: 'clamp'});
  const b2Scale = safeSpring(50);
  const b2Op = interpolate(frame, [50, 70], [0, 1], {extrapolateRight: 'clamp'});
  const b3Scale = safeSpring(60);
  const b3Op = interpolate(frame, [60, 80], [0, 1], {extrapolateRight: 'clamp'});

  // 5. Quote Animation
  const quoteOp = interpolate(frame, [55, 85], [0, 1], {extrapolateRight: 'clamp'});
  const quoteMarkScale = safeSpring(60);

  // 6. Timeline Animation
  const lineDraw = safeSpring(60);
  const t1Scale = safeSpring(70);
  const t2Scale = safeSpring(75);
  const t3Scale = safeSpring(80);
  const t4Scale = safeSpring(85);

  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor: bgColor,
    overflow: 'hidden',
    fontFamily: fontHeading,
    color: textColor
  };

  return (
    <div style={rootStyle}>
      {/* --- Background Cubist Accents --- */}
      <div style={{
        position: 'absolute', top: -100, left: 600, 
        transform: `scale(${bgShape1Scale}) rotate(15deg)`,
        opacity: 0.15
      }}>
        <svg width="600" height="800" viewBox="0 0 600 800">
          <polygon points="0,200 600,0 500,800 100,700" fill={cYellow} />
        </svg>
      </div>
      <div style={{
        position: 'absolute', top: 500, left: -200, 
        transform: `scale(${bgShape2Scale}) rotate(-10deg)`,
        opacity: 0.1
      }}>
        <svg width="800" height="600" viewBox="0 0 800 600">
          <circle cx="400" cy="300" r="350" fill={cCobalt} />
        </svg>
      </div>
      <div style={{
        position: 'absolute', top: 600, left: 1300, 
        transform: `scale(${bgShape3Scale}) rotate(45deg)`,
        opacity: 0.15
      }}>
        <svg width="500" height="500" viewBox="0 0 500 500">
          <rect x="50" y="50" width="400" height="400" fill={cRed} />
        </svg>
      </div>

      {/* --- 1. Chapter Title --- */}
      <div style={{
        position: 'absolute', top: 120, left: 120, width: 700,
        transform: `translateY(${titleSlide}px)`,
        opacity: titleOp
      }}>
        <div style={{ fontSize: 64, fontWeight: 'bold', letterSpacing: '-0.02em', zIndex: 2, position: 'relative' }}>
          {props.titleTop}
        </div>
        <div style={{
          fontFamily: fontAccent,
          fontSize: 160,
          color: cRed,
          lineHeight: 0.7,
          marginLeft: 60,
          marginTop: 10,
          transform: `scale(${titleAccentScale}) rotate(-4deg)`,
          transformOrigin: 'left center',
          zIndex: 1
        }}>
          {props.titleBottom}
        </div>
      </div>

      {/* --- 2. Data Chart --- */}
      <div style={{
        position: 'absolute', top: 120, left: 950, width: 850,
        opacity: chartTitleOp
      }}>
        <div style={{ fontSize: 22, textTransform: 'uppercase', letterSpacing: '0.15em', fontWeight: 'bold', marginBottom: 30 }}>
          {props.chartTitle}
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
          {[ 
            { label: props.chartL1, val: props.chartV1, w: bar1Width, color: cCobalt },
