};

const PieChartOverlay = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  const props = item.props || {};
  const label1 = props.label1;
  const label2 = props.label2;
  const color1 = props.color1;
  const color2 = props.color2;
  const bgColor = props.bgColor;
  const textColor = props.textColor;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // Phase 1: 白色圆盘从中心弹出 (0~20帧)
  const discScale = spring({ frame, fps, config: { damping: 10, stiffness: 160, mass: 0.8 } });

  // Phase 2: 橙色扇区 0→25% (30~55帧)
  const phase2Progress = interpolate(frame, [30, 55], [0, 1], {
    easing: Easing.out(Easing.cubic),
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });

  // Phase 3: 橙色扇区 25%→50% (70~95帧)
  const phase3Progress = interpolate(frame, [70, 95], [0, 1], {
    easing: Easing.out(Easing.cubic),
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });

  // 最终橙色扇区角度：0→180度
  const orangeDeg = (phase2Progress * 90) + (phase3Progress * 90);

  // 标注在最终状态后淡入
  const labelOpacity = interpolate(frame, [95, 110], [0, 1], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });

  // 中心文字：初始显示 100% Emergency Fund，橙色出现后隐藏
  const centerTextOpacity = interpolate(frame, [20, 30], [1, 0], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });

  const labelBaseStyle = {
    position: 'absolute',
    opacity: labelOpacity,
    fontFamily: 'Inter, system-ui, sans-serif',
    fontWeight: 800, fontSize: 34,
    color: textColor,
    whiteSpace: 'pre-line', textAlign: 'center', lineHeight: 1.25, width: 280,
  };

  // Use CSS conic-gradient instead of SVG arc path.
  // conic-gradient has no degeneracy at any angle (including 90°, 180°, 270°),
  // completely eliminating the SVG arc flip/flash bug.
  const pieStyle = {
    width: 360,
    height: 360,
    borderRadius: '50%',
    background: 'conic-gradient(from -90deg, ' + color1 + ' 0deg, ' + color1 + ' ' + orangeDeg + 'deg, ' + color2 + ' ' + orangeDeg + 'deg, ' + color2 + ' 360deg)',
    boxShadow: '0px 12px 32px rgba(0,0,0,0.18)',
    flexShrink: 0,
  };

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      transform: 'scale(' + scale + ')', transformOrigin: 'top left',
      backgroundColor: '#ffffff',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
    }}>
      <div style={{
        width: 1140, height: 800,
        backgroundColor: bgColor, borderRadius: 40,
        display: 'flex', justifyContent: 'center', alignItems: 'center',
        boxShadow: '0 25px 50px -12px rgba(0,0,0,0.1)',
        position: 'relative',
      }}>
        <div style={{
          position: 'relative', width: 400, height: 400,
          transform: 'scale(' + discScale + ')',
          transformOrigin: 'center center',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }}>
          <div style={pieStyle} />

          {/* 中心文字：100% Emergency Fund，橙色出现前显示 */}
          <div style={{
            position: 'absolute', top: 0, left: 0, width: 400, height: 400,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            opacity: centerTextOpacity,
            pointerEvents: 'none',
          }}>
            <div style={{
              fontFamily: 'Inter, system-ui, sans-serif',
              fontWeight: 800, fontSize: 32,
              color: '#111', textAlign: 'center', lineHeight: 1.3,
            }}>100%{String.fromCharCode(10)}Emergency Fund</div>
          </div>

          {/* 外部标注 */}
          <div style={{ ...labelBaseStyle, left: 420, top: 20 }}>{label1}</div>
          <div style={{ ...labelBaseStyle, right: 420, bottom: 20 }}>{label2}</div>
        </div>
      </div>
    </div>
  );
};

const DottedSlidePanel = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const backgroundColor = props.backgroundColor;
  const dotColor = props.dotColor;
  const textColor = props.textColor;
  const accentColor = props.badgeBgColor;
  const bandColor = props.badgeColor;
  const titleText = props.titleText;
  const accentLineIndex = Number(props.badgeText) || 3;
  const accentWordCount = 2;
  const fontFamily = props.fontFamily;

  const slideDuration = 18;
  const wordInterval = 4;
  const wordDelay = 28;
  const wordEase = Easing.bezier(0.22, 1, 0.36, 1);

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const PANEL_EXTRA = 300;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const bgTop = interpolate(
    frame, [0, 26], [DESIGN_HEIGHT, -PANEL_EXTRA],
    { easing: Easing.bezier(0.76, 0, 0.24, 1), extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );
  const dotOpacity = interpolate(
    frame, [26, 44], [0, 1],
    { easing: Easing.out(Easing.quad), extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );
  const bandOffset = interpolate(
    frame, [26, 80], [1, 0],
    { easing: Easing.bezier(0.25, 1, 0.4, 1), extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );

  // word animation: frame-driven x and opacity
  const makeSpan = (word, wordIndex, isLast) => {
    const start = wordDelay + wordIndex * wordInterval;
    const end = start + slideDuration;
    const x = interpolate(frame, [start, end], [180, 0], {
      easing: wordEase, extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
    });
    const op = interpolate(frame, [start, start + 10], [0, 1], {
      extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
    });
    return (
      <span key={word + wordIndex} style={{
        display: 'inline-block',
        opacity: op,
        transform: 'translateX(' + x + 'px)',
        marginRight: isLast ? 0 : '0.22em'
      }}>{word}</span>
    );
  };

  const titleLines = titleText.split(/\\n|\n/);
  let gi = 0;

  const renderedLines = titleLines.map((line, lineIdx) => {
    const words = line.trim().split(' ');
    const isAccent = (lineIdx + 1) === accentLineIndex;

    if (!isAccent) {
      const spans = words.map((word, wi) => {
        const idx = gi; gi++;
        return makeSpan(word, idx, wi === words.length - 1);
      });
      return (
        <div key={lineIdx} style={{ display: 'block', textAlign: 'center', lineHeight: 1.22 }}>
          <span style={{ display: 'inline-block' }}>{spans}</span>
        </div>
      );
    }

    const ulWords = words.slice(0, accentWordCount);
    const restWords = words.slice(accentWordCount);

    const ulSpans = ulWords.map((word, wi) => {
      const idx = gi; gi++;
      return makeSpan(word, idx, wi === ulWords.length - 1);
    });
    const ulLastIdx = gi - 1;
    const ulLandFrame = wordDelay + ulLastIdx * wordInterval + slideDuration;
    const ulW = interpolate(frame, [ulLandFrame, ulLandFrame + 20], [0, 100], {
      easing: wordEase, extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
    });
    const ulOp = interpolate(frame, [ulLandFrame, ulLandFrame + 8], [0, 1], {
      extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
    });

    const restSpans = restWords.map((word, wi) => {
      const idx = gi; gi++;
      return makeSpan(word, idx, wi === restWords.length - 1);
    });

    return (
      <div key={lineIdx} style={{ display: 'block', textAlign: 'center', lineHeight: 1.22, marginBottom: 8 }}>
        <span style={{
          display: 'inline-block', position: 'relative',
          paddingBottom: 10, marginRight: restWords.length > 0 ? '0.22em' : 0
        }}>
          {ulSpans}
          <span style={{
            position: 'absolute', bottom: 0, left: 0,
            height: 6, width: ulW + '%',
            backgroundColor: accentColor, borderRadius: 3, opacity: ulOp, display: 'block'
          }} />
        </span>
        {restWords.length > 0 && <span style={{ display: 'inline-block' }}>{restSpans}</span>}
      </div>
    );
  });

  const lastWordLand = wordDelay + (gi - 1) * wordInterval + slideDuration;
  const exitStart = Math.min(lastWordLand + 10, durationInFrames - 24);
  const exitY = interpolate(
    frame, [exitStart, exitStart + 22], [0, DESIGN_HEIGHT + PANEL_EXTRA],
    { easing: Easing.bezier(0.76, 0, 0.24, 1), extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      transform: 'scale(' + scale + ')', transformOrigin: 'top left',
      overflow: 'hidden'
    }}>
      <div style={{
        position: 'absolute', top: bgTop, left: 0,
        width: DESIGN_WIDTH, height: DESIGN_HEIGHT + PANEL_EXTRA,
        backgroundColor: backgroundColor,
        transform: 'translateY(' + exitY + 'px)'
      }}>
        <svg width="100%" height="100%" style={{ position: 'absolute', top: 0, left: 0 }}>
          <defs>
            <pattern id="mgdots2" width="30" height="30" patternUnits="userSpaceOnUse">
              <circle cx="15" cy="15" r="1.5" fill={dotColor} />
            </pattern>
          </defs>
          <rect width="100%" height="100%" fill="url(#mgdots2)" opacity={dotOpacity} />
        </svg>
        <svg width={DESIGN_WIDTH} height={DESIGN_HEIGHT + PANEL_EXTRA} style={{ position: 'absolute', top: 0, left: 0 }}>
          <path
            d={'M -300 '+(920+PANEL_EXTRA)+' C 300 '+(1100+PANEL_EXTRA)+', 900 '+(480+PANEL_EXTRA)+', 1400 '+(320+PANEL_EXTRA)+' C 1700 '+(220+PANEL_EXTRA)+', 2000 '+(200+PANEL_EXTRA)+', 2300 '+(180+PANEL_EXTRA)}
            pathLength="1" fill="none" stroke={bandColor} strokeWidth="320"
            strokeLinecap="round" strokeLinejoin="round"
            strokeDasharray="1" strokeDashoffset={bandOffset}
          />
        </svg>
        <div style={{
          position: 'absolute', top: PANEL_EXTRA, left: 0,
          width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
          display: 'flex', flexDirection: 'column',
          alignItems: 'center', justifyContent: 'center',
          zIndex: 10, padding: '0 160px', boxSizing: 'border-box'
        }}>
          <div style={{
            fontFamily: fontFamily, fontSize: 90, fontWeight: 700,
            color: textColor, textAlign: 'center',
            letterSpacing: '-0.01em', width: '100%'
          }}>
            {renderedLines}
          </div>
        </div>
      </div>
    </div>
  );
};

const PrincipleCard = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const backgroundColor = props.backgroundColor;
  const curveColor = props.curveColor;
  const cardColor = props.cardColor;
  const textColor = props.textColor;
  const badgeText = props.badgeText;
  const titleText = props.titleText;
  const fontFamily = props.fontFamily;
  const iconPrimaryColor = props.iconPrimaryColor;
  const iconSecondaryColor = props.iconSecondaryColor;
  const iconStrokeColor = props.iconStrokeColor;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const PANEL_EXTRA = 300;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);
  const safeFps = fps || 30;

  const float = (rampIn, period, amp, phase = 0) => {
    const t = Math.max(0, frame - rampIn);
    return Math.sin((t / period) * Math.PI * 2 + phase) * amp * Math.min(1, t / 24);
  };
  const iconFloatY = float(52, 110, 10, 0);
  const iconFloatR = float(52, 130, 0.8, 1.1);
  const titleFloatY = float(90, 95, 7, 2.3);
  const titleFloatR = float(90, 120, 0.4, 0.5);

  const bgTop = interpolate(
    frame, [0, 22],
    [DESIGN_HEIGHT, -PANEL_EXTRA],
    { easing: Easing.bezier(0.76, 0, 0.24, 1), extrapolateRight: 'clamp' }
  );

  const iconEntrance = spring({
    frame: Math.max(0, frame - 24), fps: safeFps,
    config: { damping: 14, stiffness: 120, mass: 0.65 }
  });

  const badgeEntrance = spring({
    frame: Math.max(0, frame - 33), fps: safeFps,
    config: { damping: 14, stiffness: 120, mass: 0.65 }
  });

  const titleLines = titleText.split(/\\n|\n/);
  let wordIndex = 0;
  const renderedTitle = titleLines.map((line, lineIdx) => {
    const words = line.trim().split(' ');
    const lineSpans = words.map((word) => {
      const delay = 42 + wordIndex * 5;
      wordIndex++;
      const wOpacity = interpolate(frame, [delay, delay + 14], [0, 1],
        { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
      const wY = interpolate(frame, [delay, delay + 14], [18, 0],
        { easing: Easing.out(Easing.quad), extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
      return (
        <span key={word + delay} style={{
          display: 'inline-block',
          opacity: wOpacity,
          // translate3d 前置，强制独立 GPU 合成层，避免 translateY 亚像素跳帧
          transform: `translate3d(0, ${wY}px, 0)`,
          willChange: 'transform',
          marginRight: '0.26em'
        }}>{word}</span>
      );
    });
    return (
      <div key={lineIdx} style={{ display: 'block', lineHeight: 1.18 }}>
        {lineSpans}
      </div>
    );
  });

  const curveOffset = interpolate(
    frame, [68, 116], [1, 0],
    { easing: Easing.bezier(0.25, 1, 0.4, 1),
      extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );

  const exitStart = durationInFrames - 22;
