const VictorianChart = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();
  const props = item.props || {};

  const title = props.title;
  const label1 = props.label1;
  const val1 = Number(props.val1);
  const color1 = props.color1;
  const label2 = props.label2;
  const val2 = Number(props.val2);
  const color2 = props.color2;
  const label3 = props.label3;
  const val3 = Number(props.val3);
  const color3 = props.color3;
  const label4 = props.label4;
  const val4 = Number(props.val4);
  const color4 = props.color4;

  const textColor = props.textColor;
  const bgColor = props.bgColor;
  const fontFamily = props.fontFamily;
  const isTransparent = props.transparentBackground;
  const backgroundColor = isTransparent ? 'transparent' : bgColor;
  const accentColorChart = '#926859';

  // Parse hex to r,g,b for rgba usage
  const parseHex = (hex) => {
    if (!hex) return [0, 0, 0];
    const h = hex.replace('#', '');
    const r = parseInt(h.length === 3 ? h[0]+h[0] : h.substring(0,2), 16) || 0;
    const g = parseInt(h.length === 3 ? h[1]+h[1] : h.substring(2,4), 16) || 0;
    const b = parseInt(h.length === 3 ? h[2]+h[2] : h.substring(4,6), 16) || 0;
    return [r, g, b];
  };

  const [tr, tg, tb] = parseHex(textColor);
  const rgba = (r, g, b, a) => `rgba(${r},${g},${b},${a})`;
  const textRgba = (a) => rgba(tr, tg, tb, a);

  const [ar, ag, ab] = parseHex('#926859');
  const accentRgba = (a) => rgba(ar, ag, ab, a);

  const smoothSettle = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 3.5);
  };
  const bellCurveLate = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return t < 0.4
      ? 0.15 * Math.pow(t / 0.4, 2.5)
      : 0.15 + 0.85 * (1 - Math.pow(1 - (t - 0.4) / 0.6, 2.8));
  };

  // Exit
  const totalFrames = durationInFrames || 180;
  const exitStart = totalFrames - 30;
  const exitRaw = Math.max(0, Math.min(1, (frame - exitStart) / (totalFrames - 1 - exitStart)));
  const exitAlpha = 1 - exitRaw * exitRaw;

  // Border fade in
  const borderAlpha = smoothSettle(Math.min(1, Math.max(0, frame / 35))) * exitAlpha;

  // Title
  const titleRaw = Math.min(1, Math.max(0, (frame - 10) / 45));
  const titleProgress = smoothSettle(titleRaw);
  const titleAlpha = smoothSettle(Math.min(1, Math.max(0, (frame - 10) / 18))) * exitAlpha;

  const titleY = (1 - titleProgress) * 30;

  // Grid
  const gridRaw = Math.min(1, Math.max(0, (frame - 15) / 40));
  const gridProgress = smoothSettle(gridRaw);
  const gridAlpha = 0.3 * gridProgress * exitAlpha;

  // Bar data
  const data = [
    { label: label1, value: val1, color: color1, delay: 30 },
    { label: label2, value: val2, color: color2, delay: 50 },
    { label: label3, value: val3, color: color3, delay: 70 },
    { label: label4, value: val4, color: color4, delay: 90 },
  ];

  const chartMax = Math.max(50, val1, val2, val3, val4);
  const xMax = Math.ceil(chartMax / 10) * 10;

  const gridLines = [];
  for (let i = 0; i <= xMax; i += 10) {
    gridLines.push(i);
  }

  const chartBorderScale = 0.95 + borderAlpha * 0.05;

  const CornerFlourishChart = ({ style, item }) => (
    <div style={{ position: 'absolute', width: 150, height: 150, ...style }}>
      <svg viewBox="0 0 150 150" width="100%" height="100%">
        <g stroke={accentColorChart} fill="none" strokeWidth="1.5" strokeLinecap="round" opacity={borderAlpha}>
          <path d="M 0,150 C 0,50 50,0 150,0" />
          <path d="M 15,150 C 15,70 70,15 150,15" />
          <path d="M 30,150 C 30,90 70,50 110,40 C 130,35 140,45 130,60 C 115,80 90,60 95,45 C 100,35 110,35 115,45" />
          <path d="M 150,30 C 90,30 50,70 40,110 C 35,130 45,140 60,130 C 80,115 60,90 45,95 C 35,100 35,110 45,115" />
          <circle cx="20" cy="20" r="2.5" fill={accentColorChart} />
          <path d="M 0,0 L 25,0 C 25,25 0,25 0,25 Z" fill={accentColorChart} stroke="none" />
        </g>
      </svg>
    </div>
  );

  return (
    <div style={{ position: 'absolute', inset: 0, backgroundColor, fontFamily, overflow: 'hidden', opacity: exitAlpha }}>
      {/* Border */}
      <div style={{
        position: 'absolute', top: 50, left: 60, right: 60, bottom: 50,
        border: `2px solid ${accentRgba(borderAlpha)}`,
