        <div style={{ width: '100%', height: '100%', border: `1px solid ${accentRgba(borderAlpha)}`, position: 'relative', boxSizing: 'border-box' }}>
          <CornerFlourishChart style={{ top: 0, left: 0 }} />
          <CornerFlourishChart style={{ top: 0, right: 0, transform: 'scaleX(-1)' }} />
          <CornerFlourishChart style={{ bottom: 0, left: 0, transform: 'scaleY(-1)' }} />
          <CornerFlourishChart style={{ bottom: 0, right: 0, transform: 'scale(-1, -1)' }} />
        </div>
      </div>

      {/* Title */}
      <div style={{
        position: 'absolute', top: 120, left: 0, width: '100%',
        textAlign: 'center', fontSize: 72, fontWeight: 'bold',
        color: textRgba(titleAlpha),
        transform: `translateY(${titleY}px)`
      }}>
        {title}
      </div>

      {/* Chart area */}
      <div style={{ position: 'absolute', top: 280, left: 400, width: 1200, height: 650 }}>
        {/* Grid lines */}
        <div style={{ position: 'absolute', inset: 0 }}>
          {gridLines.map((val, i) => {
            const xPos = (val / xMax) * 1200;
            return (
              <div key={`g${i}`} style={{
                position: 'absolute', left: xPos, top: 0, bottom: 0,
                width: 1
              }}>
                <div style={{
                  position: 'absolute', top: 0, bottom: 0, width: 1,
                  backgroundColor: textRgba(gridAlpha)
                }} />
                <div style={{
                  position: 'absolute', bottom: -40, left: -40, width: 80,
                  textAlign: 'center', fontSize: 22, color: textRgba(gridProgress * exitAlpha)
                }}>
                  {val}%
                </div>
              </div>
            );
          })}
        </div>

        {/* Bars */}
        <div style={{
          position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column',
          justifyContent: 'space-evenly'
        }}>
          {data.map((d, i) => {
            const barRaw = Math.min(1, Math.max(0, (frame - d.delay) / 55));
            const barProgress = bellCurveLate(barRaw);
            const w = (d.value / xMax) * 1200;
            const labelAlpha = smoothSettle(Math.min(1, Math.max(0, (frame - d.delay) / 20))) * exitAlpha;
            const valAlpha = barProgress > 0.6 ? smoothSettle((barProgress - 0.6) / 0.4) * exitAlpha : 0;
            const [cr, cg, cb] = parseHex(d.color);
            const barColorAlpha = barProgress * exitAlpha;
            return (
              <div key={`b${i}`} style={{
                display: 'flex', alignItems: 'center', height: 80, position: 'relative'
              }}>
                <div style={{
                  position: 'absolute', left: -340, width: 300,
                  textAlign: 'right', fontSize: 22, fontWeight: 'bold',
                  color: textRgba(labelAlpha)
                }}>
                  {d.label}
                </div>
                <div style={{
                  height: '100%', backgroundColor: rgba(cr, cg, cb, barColorAlpha),
                  width: w * barProgress,
                  display: 'flex', alignItems: 'center', paddingLeft: 24,
                  overflow: 'hidden', whiteSpace: 'nowrap'
                }}>
                  <span style={{ fontSize: 22, fontWeight: 'bold', color: rgba(255, 255, 255, valAlpha) }}>
                    {d.value}%
                  </span>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

