      {/* Bullet list (left bottom) */}
      <div style={{position:'absolute',left:120,top:560,width:450}}>
        <div style={{fontSize:24,fontWeight:'bold',color:rgba(textColor,bullets[0]),marginBottom:12}}>Solar Grid</div>
