const withAlphaRG = (color, alpha) => {
  const m = String(color).match(/rgba?\(\s*(\d+),\s*(\d+),\s*(\d+)(?:,\s*([\d.]+))?\s*\)/);
  if (m) {
    const a = parseFloat(m[4] || '1') * alpha;
    return 'rgba(' + m[1] + ',' + m[2] + ',' + m[3] + ',' + a.toFixed(4) + ')';
  }
  return color;
};

const evalBezierRG = (seg, t) => {
  const mt = 1 - t;
  return [
    mt * mt * mt * seg[0][0] + 3 * mt * mt * t * seg[1][0] + 3 * mt * t * t * seg[2][0] + t * t * t * seg[3][0],
    mt * mt * mt * seg[0][1] + 3 * mt * mt * t * seg[1][1] + 3 * mt * t * t * seg[2][1] + t * t * t * seg[3][1],
  ];
};

const getSegLenRG = (seg) => {
  let length = 0;
  let prev = evalBezierRG(seg, 0);
  for (let i = 1; i <= 48; i++) {
    const cur = evalBezierRG(seg, i / 48);
    const dx = cur[0] - prev[0];
    const dy = cur[1] - prev[1];
    length += Math.sqrt(dx * dx + dy * dy);
    prev = cur;
  }
  return length;
};

const RetentionGraph = ({ item }) => {
  const frame = useCurrentFrame();
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const SEGS = [
    [[0, 100], [30, 100], [50, 20], [80, 20]],
    [[80, 20], [120, 20], [150, 220], [200, 220]],
    [[200, 220], [240, 220], [260, 170], [300, 170]],
    [[300, 170], [350, 170], [380, 260], [420, 260]],
    [[420, 260], [450, 260], [470, 240], [500, 240]],
    [[500, 240], [550, 240], [580, 320], [650, 360]],
    [[650, 360], [750, 390], [850, 380], [950, 380]],
  ];

  const PATH_D =
    'M 0 100 C 30 100, 50 20, 80 20 ' +
    'C 120 20, 150 220, 200 220 ' +
    'C 240 220, 260 170, 300 170 ' +
    'C 350 170, 380 260, 420 260 ' +
    'C 450 260, 470 240, 500 240 ' +
    'C 550 240, 580 320, 650 360 ' +
    'C 750 390, 850 380, 950 380';

  const props = item.props || {};
  const titleText = props.titleText;
  const fontFamily = props.fontFamily;
  const accentColor = props.accentColor;
  const lineColor = props.lineColor || accentColor;
  const glowColorMain = props.glowColorMain || accentColor;
  const glowColorSoft = props.glowColorSoft || accentColor;
  const fillColorStart = props.fillColorStart;
  const fillColorEnd = props.fillColorEnd;
  const bgColorCenter = props.bgColorCenter;
  const bgColorOuter = props.bgColorOuter;
  const transparentBackground = props.transparentBackground;

  const SEG_LENS = React.useMemo(() => SEGS.map(getSegLenRG), []);
  const TOTAL_LEN = React.useMemo(() => SEG_LENS.reduce((s, l) => s + l, 0), [SEG_LENS]);

  const buildAreaPath = (progress) => {
    if (progress <= 0) return null;
    const targetLen = progress * TOTAL_LEN;
    const points = [[0, 100]];
    let accumulated = 0;
    let done = false;
    for (let si = 0; si < SEGS.length && !done; si++) {
      const seg = SEGS[si];
      const segLen = SEG_LENS[si];
      let prevPoint = evalBezierRG(seg, 0);
      let cumulativeInSegment = 0;
      for (let i = 1; i <= 32 && !done; i++) {
        const t = i / 32;
        const cur = evalBezierRG(seg, t);
        const dx = cur[0] - prevPoint[0];
        const dy = cur[1] - prevPoint[1];
        const stepLen = Math.sqrt(dx * dx + dy * dy);
        cumulativeInSegment += stepLen;
        if (accumulated + cumulativeInSegment >= targetLen) {
          const overshoot = accumulated + cumulativeInSegment - targetLen;
          const ratio = stepLen === 0 ? 0 : 1 - overshoot / stepLen;
          points.push([
            prevPoint[0] + (cur[0] - prevPoint[0]) * ratio,
            prevPoint[1] + (cur[1] - prevPoint[1]) * ratio,
          ]);
          done = true;
        } else {
          points.push([cur[0], cur[1]]);
          prevPoint = cur;
        }
      }
      if (!done) accumulated += segLen;
    }
    if (points.length < 2) return null;
    const tip = points[points.length - 1];
    return (
      'M ' + points.map((p) => p[0].toFixed(2) + ' ' + p[1].toFixed(2)).join(' L ') +
      ' L ' + tip[0].toFixed(2) + ' 400 L 0 400 Z'
    );
  };

  const introProgress = interpolate(frame, [0, 15], [0, 1], { extrapolateRight: 'clamp' });
  const cardY = interpolate(frame, [0, 20], [32, 0], {
    extrapolateRight: 'clamp',
    easing: Easing.out(Easing.quad),
  });
  const axisProgress = interpolate(frame, [10, 30], [0, 1], { extrapolateRight: 'clamp' });
  const lineProgress = interpolate(frame, [38, 110], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });
  const lineOffset = (1 - lineProgress) * 1000;
  const dotOffset = -lineProgress * 1000;
  const dotOpacity = interpolate(lineProgress, [0, 0.04], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  const areaPath = buildAreaPath(lineProgress);

  const cardLeft = 360;
  const cardTop = 190;
  const cardW = 1200;
  const cardH = 700;

  const gridOpacity = axisProgress * 0.095;
  const gridColor = 'rgba(255,255,255,' + gridOpacity.toFixed(4) + ')';

  const itemId = item && (item.id || item.name);
  const uid = 'rg-' + (itemId ? String(itemId).replace(/[^a-zA-Z0-9_-]/g, '_') : 'chart');

  const ids = {
    fillV: uid + '-fill-v',
    fillH: uid + '-fill-h',
    glowHuge: uid + '-glow-huge',
    glowMedium: uid + '-glow-medium',
    glowSmall: uid + '-glow-small',
    areaEdge: uid + '-area-edge',
  };

  const labelColor = 'rgba(197,232,225,' + (0.52 * axisProgress).toFixed(4) + ')';
  const xLabelColor = 'rgba(197,232,225,' + (0.58 * axisProgress).toFixed(4) + ')';

  const labelStyle = {
    position: 'absolute',
    width: 130,
    height: 40,
    left: 22,
    textAlign: 'right',
    color: labelColor,
    fontSize: 15,
    fontWeight: 400,
    letterSpacing: '-0.2px',
    lineHeight: 1.18,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'flex-end',
    textShadow: '0 0 14px rgba(0,186,169,0.16)',
    fontFamily: fontFamily,
  };

  const xLabelStyle = {
    position: 'absolute',
    top: 572,
    color: xLabelColor,
    fontSize: 15,
    fontWeight: 400,
    textShadow: '0 0 14px rgba(0,186,169,0.14)',
    fontFamily: fontFamily,
  };

  const glowSoftStroke = withAlphaRG(glowColorSoft, 0.28);
  const glowMainStroke = withAlphaRG(glowColorMain, 0.55);
  const whiteLineStroke = 'rgba(255,255,255,0.616)';
  const dotGlowStroke = withAlphaRG(glowColorMain, dotOpacity * 0.65);
  const dotWhiteStroke = withAlphaRG('rgba(217,250,249,0.95)', dotOpacity);

  const fillVStart88 = withAlphaRG(fillColorStart, 0.88);
  const fillVEnd88 = withAlphaRG(fillColorEnd, 0.88);

  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor: transparentBackground ? 'transparent' : bgColorOuter,
    fontFamily: fontFamily,
    overflow: 'hidden',
  };

  return (
    <div style={rootStyle}>
      {!transparentBackground && (
        <>
          <div
            style={{
              position: 'absolute',
              inset: 0,
              background:
                'radial-gradient(circle at 38% -8%, ' + bgColorCenter + ' 0%, rgba(0,104,82,0.42) 28%, transparent 55%),' +
                'radial-gradient(circle at 63% 18%, rgba(0,131,97,0.38) 0%, transparent 38%),' +
                'radial-gradient(circle at 22% 78%, rgba(0,91,71,0.22) 0%, transparent 42%),' +
                'linear-gradient(125deg, #001611 0%, #0b0a10 62%, #151515 100%)',
              filter: 'saturate(1.15)',
            }}
          />
          <div
            style={{
              position: 'absolute',
              width: 900,
              height: 520,
              left: 240,
              top: -170,
              background: 'radial-gradient(ellipse, rgba(0,123,102,0.405), transparent 65%)',
              filter: 'blur(42px)',
            }}
          />
          <div
            style={{
              position: 'absolute',
              width: 620,
              height: 460,
              right: 180,
              top: 130,
              background: 'radial-gradient(ellipse, rgba(0,90,69,0.192), transparent 70%)',
              filter: 'blur(55px)',
            }}
          />
        </>
      )}

      <div
        style={{
          position: 'absolute',
          left: cardLeft - 70,
          top: cardTop + cardY - 70,
          width: cardW + 140,
          height: cardH + 140,
          pointerEvents: 'none',
          background: 'radial-gradient(ellipse at 28% 8%, rgba(0,97,79,0.259), transparent 58%)',
          filter: 'blur(36px)',
        }}
      />

      <div
        style={{
          position: 'absolute',
          width: cardW,
          height: cardH,
          left: cardLeft,
          top: cardTop + cardY,
          opacity: introProgress,
          borderRadius: 24,
          background:
            'linear-gradient(135deg, rgba(0,113,90,0.72) 0%, rgba(0,53,47,0.82) 34%, rgba(0,21,16,0.88) 100%)',
          border: '1px solid rgba(255,255,255,0.18)',
          boxShadow:
            '0 40px 120px rgba(0,0,0,0.72),' +
            '0 0 90px rgba(0,128,98,0.16),' +
            'inset 0 1px 0 rgba(255,255,255,0.28),' +
            'inset 0 -1px 0 rgba(255,255,255,0.05),' +
            'inset 1px 0 0 rgba(255,255,255,0.08)',
          overflow: 'hidden',
        }}
      >
        <div
          style={{
            position: 'absolute',
            top: -160,
            left: -120,
            width: 720,
            height: 620,
            background:
              'radial-gradient(ellipse at 25% 25%, rgba(0,141,118,0.82) 0%, rgba(0,99,76,0.34) 36%, transparent 68%)',
            pointerEvents: 'none',
          }}
        />

        <div
          style={{
            position: 'absolute',
            inset: 0,
            pointerEvents: 'none',
            background:
              'linear-gradient(135deg, rgba(255,255,255,0.115) 0%, rgba(255,255,255,0.032) 18%, transparent 48%),' +
              'radial-gradient(circle at 18% 0%, rgba(0,180,166,0.274) 0%, rgba(0,134,101,0.13) 28%, transparent 58%)',
          }}
        />

        <div
          style={{
            position: 'absolute',
            left: 1,
            right: 1,
            top: 0,
            height: 1,
            background:
              'linear-gradient(90deg, transparent, rgba(255,255,255,0.357), rgba(103,220,206,0.238), transparent)',
          }}
        />

        <div
          style={{
            position: 'absolute',
            left: 0,
            top: 24,
            bottom: 24,
            width: 1,
            background:
              'linear-gradient(180deg, transparent, rgba(255,255,255,0.158), transparent)',
          }}
        />

        <div
          style={{
            position: 'absolute',
            right: 54,
            top: 36,
            fontSize: 50,
            fontWeight: 700,
            fontFamily: fontFamily,
            color: 'rgba(255,255,255,0.96)',
            letterSpacing: '-1.2px',
            textShadow:
              '0 1px 0 rgba(255,255,255,0.18),' +
              '0 0 24px rgba(0,186,169,0.16),' +
              '0 10px 30px rgba(0,0,0,0.35)',
          }}
        >
          {titleText}
        </div>

        <div style={{ ...labelStyle, top: 125 }}>Strong</div>
        <div style={{ ...labelStyle, top: 218 }}>Elevated<br />Baseline</div>
        <div style={{ ...labelStyle, top: 322 }}>Baseline</div>
        <div style={{ ...labelStyle, top: 416 }}>Reduced<br />Baseline</div>
        <div style={{ ...labelStyle, top: 515 }}>Weak</div>

        <div style={{ ...xLabelStyle, left: 178 }}>0:00</div>
        <div style={{ ...xLabelStyle, right: 68 }}>1:00</div>

        <div
          style={{
            position: 'absolute',
            left: 178,
            top: 145,
            width: 950,
            height: 410,
          }}
        >
          <svg
            width="950"
            height="410"
            viewBox="0 0 950 410"
            style={{ overflow: 'visible' }}
          >
            <defs>
              <linearGradient id={ids.fillV} x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor={fillVStart88} />
                <stop offset="34%" stopColor="rgba(0,152,130,0.1936)" />
                <stop offset="68%" stopColor="rgba(0,106,85,0.0704)" />
                <stop offset="100%" stopColor={fillVEnd88} />
              </linearGradient>

              <linearGradient id={ids.fillH} x1="0" y1="0" x2="1" y2="0">
                <stop offset="0%" stopColor="rgba(161,232,223,0.1875)" />
                <stop offset="16%" stopColor="rgba(86,218,206,0.0825)" />
                <stop offset="38%" stopColor="rgba(0,177,157,0.01875)" />
                <stop offset="100%" stopColor="rgba(0,177,157,0)" />
              </linearGradient>

              <filter id={ids.glowHuge} x="-55%" y="-55%" width="210%" height="210%" colorInterpolationFilters="sRGB">
                <feGaussianBlur stdDeviation="24" result="blur" />
                <feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge>
              </filter>

              <filter id={ids.glowMedium} x="-35%" y="-35%" width="170%" height="170%" colorInterpolationFilters="sRGB">
                <feGaussianBlur stdDeviation="9" result="blur" />
                <feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge>
              </filter>

              <filter id={ids.glowSmall} x="-20%" y="-20%" width="140%" height="140%" colorInterpolationFilters="sRGB">
                <feGaussianBlur stdDeviation="2" result="blur" />
                <feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge>
              </filter>

              <filter id={ids.areaEdge} x="-20%" y="-120%" width="140%" height="340%" colorInterpolationFilters="sRGB">
                <feGaussianBlur stdDeviation="13" result="blur" />
                <feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge>
              </filter>
            </defs>

            {[0, 100, 200, 300, 400].map((y) => (
              <line key={y} x1="0" y1={y} x2="950" y2={y} stroke={gridColor} strokeWidth="1" />
            ))}
            <line x1="0" y1="0" x2="0" y2="400" stroke={gridColor} strokeWidth="1" />

            {areaPath && (
              <React.Fragment>
                <path d={areaPath} fill={'url(#' + ids.fillV + ')'} />
                <path d={areaPath} fill={'url(#' + ids.fillH + ')'} />
              </React.Fragment>
            )}

            <path
              d={PATH_D}
              pathLength="1000"
              strokeDasharray="1000"
              strokeDashoffset={lineOffset}
              fill="none"
              stroke="rgba(43,213,200,0.28)"
              strokeWidth="14"
              filter={'url(#' + ids.areaEdge + ')'}
            />

            <path
              d={PATH_D}
              pathLength="1000"
              strokeDasharray="1000"
              strokeDashoffset={lineOffset}
              stroke={glowSoftStroke}
              strokeWidth="42"
              fill="none"
              filter={'url(#' + ids.glowHuge + ')'}
            />

            <path
              d={PATH_D}
              pathLength="1000"
              strokeDasharray="1000"
              strokeDashoffset={lineOffset}
              stroke={glowMainStroke}
              strokeWidth="18"
              fill="none"
              filter={'url(#' + ids.glowMedium + ')'}
            />

            <path
              d={PATH_D}
              pathLength="1000"
              strokeDasharray="1000"
              strokeDashoffset={lineOffset}
              stroke={lineColor}
              strokeWidth="3.2"
              fill="none"
              filter={'url(#' + ids.glowSmall + ')'}
            />

            <path
              d={PATH_D}
              pathLength="1000"
              strokeDasharray="1000"
              strokeDashoffset={lineOffset}
              stroke={whiteLineStroke}
              strokeWidth="1.15"
              fill="none"
            />

            <path
              d={PATH_D}
              pathLength="1000"
              strokeDasharray="0.01 1000"
              strokeDashoffset={dotOffset}
              stroke={dotGlowStroke}
              strokeWidth="30"
              strokeLinecap="round"
              fill="none"
              filter={'url(#' + ids.glowHuge + ')'}
            />

            <path
              d={PATH_D}
              pathLength="1000"
              strokeDasharray="0.01 1000"
              strokeDashoffset={dotOffset}
              stroke={dotWhiteStroke}
              strokeWidth="8"
              strokeLinecap="round"
              fill="none"
            />
          </svg>
        </div>
      </div>
    </div>
  );
};

const RetroDecodeStyleCard = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const safeFps = fps || 30;

  const props = item.props || {};
  const transparentBackground = props.transparentBackground;
  const bgColor = props.bgColor;
  const primaryColor = props.primaryColor;
  const accentColor = props.accentColor;

  const fontTitle = props.fontTitle;
  const fontBody = props.fontBody;
  const fontScript = props.fontScript;

  const backgroundColor = transparentBackground ? 'transparent' : bgColor;

  // Typewriter helper
  const TextAnim = ({ text, startFrame, item }) => {
    const safeText = text || '';
    const charCount = Math.max(0, Math.floor((frame - startFrame) * 1.5));
    return <>{safeText.substring(0, charCount)}</>;
  };

  // Burst shape generator for the badge
  const getBurstPath = (cx, cy, r1, r2, pts) => {
    let d = '';
    for (let i = 0; i < pts * 2; i++) {
      const r = i % 2 === 0 ? r1 : r2;
      const a = (i * Math.PI) / pts;
      d += (i === 0 ? 'M ' : 'L ') + (cx + r * Math.sin(a)) + ' ' + (cy - r * Math.cos(a)) + ' ';
    }
    return d + 'Z';
  };

  const starScale = spring({ frame: Math.max(0, frame - 15), fps: safeFps, config: { damping: 15 } });
  const badgeScale = spring({ frame: Math.max(0, frame - 35), fps: safeFps, config: { damping: 12 } });
  const badgeRotation = interpolate(frame, [35, 65], [-30, -10], { extrapolateRight: 'clamp' });

  return (
    <div style={{ position: 'absolute', inset: 0, backgroundColor, overflow: 'hidden' }}>
      {/* Halftone Texture Overlay */}
      {!transparentBackground && (
        <div
          style={{
            position: 'absolute',
            inset: 0,
            backgroundImage: `radial-gradient(${primaryColor}15 1.5px, transparent 1.5px)`,
            backgroundSize: '12px 12px',
            pointerEvents: 'none',
            zIndex: 0
          }}
        />
      )}

      <div style={{ position: 'absolute', inset: 0, zIndex: 1 }}>
        {/* 1. Chapter Title */}
        <div style={{ position: 'absolute', left: 120, top: 160, fontFamily: fontTitle, fontSize: 180, lineHeight: 0.9, textTransform: 'uppercase' }}>
          <div style={{ color: 'transparent', WebkitTextStroke: `4px ${accentColor}` }}>
            <TextAnim text={props.titleLine1} startFrame={5} />
          </div>
          <div style={{ color: primaryColor }}>
            <TextAnim text={props.titleLine2} startFrame={15} />
          </div>
          <div style={{ position: 'absolute', left: 470, top: -20, transform: `scale(${starScale}) rotate(${frame * 0.5}deg)` }}>
            <svg width="100" height="100" viewBox="0 0 100 100">
              <path d="M 50 0 L 60 40 L 100 50 L 60 60 L 50 100 L 40 60 L 0 50 L 40 40 Z" fill={accentColor} />
            </svg>
          </div>
        </div>

        {/* 2. Data Chart */}
        <div style={{ position: 'absolute', left: 120, top: 620, width: 420 }}>
          {[ 
            { label: props.chartT1, val: props.chartV1, color: primaryColor, start: 45 },
            { label: props.chartT2, val: props.chartV2, color: accentColor, start: 50 },
            { label: props.chartT3, val: props.chartV3, color: primaryColor, start: 55 }
          ].map((bar, i) => {
            const barWidth = spring({ frame: Math.max(0, frame - bar.start - 15), fps: safeFps, config: { damping: 15 } });
            return (
              <div key={i} style={{ marginBottom: 24 }}>
                <div style={{ fontFamily: fontBody, fontSize: 24, color: primaryColor, marginBottom: 8, fontWeight: 600 }}>
                  <TextAnim text={bar.label} startFrame={bar.start} />
                </div>
                {frame >= bar.start && <div style={{ width: '100%', height: 16, backgroundColor: `${bar.color}33`, borderRadius: 8, overflow: 'hidden' }}>
                  <div style={{ width: `${barWidth * bar.val}%`, height: '100%', backgroundColor: bar.color }} />
                </div>}
              </div>
            );
          })}
        </div>

        {/* 3. Name Tag */}
        <div style={{ position: 'absolute', left: 820, top: 160 }}>
          <div style={{ fontFamily: fontBody, fontSize: 24, fontWeight: 'bold', letterSpacing: 6, color: accentColor, textTransform: 'uppercase' }}>
            <TextAnim text={props.nameSubtitle} startFrame={15} />
          </div>
          <div style={{ fontFamily: fontTitle, fontSize: 72, color: primaryColor, marginTop: 4 }}>
            <TextAnim text={props.nameTitle} startFrame={25} />
          </div>
          {frame >= 30 && <svg width="450" height="40" style={{ marginTop: 16 }}>
            <path 
              d="M 0 20 Q 15 5 30 20 T 60 20 T 90 20 T 120 20 T 150 20 T 180 20 T 210 20 T 240 20 T 270 20 T 300 20 T 330 20 T 360 20 T 390 20 T 420 20 T 450 20" 
              fill="none" 
              stroke={accentColor} 
              strokeWidth="4" 
              strokeDasharray="500" 
              strokeDashoffset={interpolate(frame, [30, 60], [500, 0], { extrapolateRight: 'clamp' })} 
            />
          </svg>}
        </div>

        {/* 4. Bullet Points */}
        <div style={{ position: 'absolute', left: 820, top: 620 }}>
          {[
            { text: props.bullet1, start: 55 },
            { text: props.bullet2, start: 60 },
            { text: props.bullet3, start: 65 }
          ].map((item, i) => {
            const dotScale = spring({ frame: Math.max(0, frame - item.start), fps: safeFps, config: { damping: 15 } });
            return (
              <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 16, marginBottom: 20 }}>
                <div style={{ width: 16, height: 16, borderRadius: 8, backgroundColor: accentColor, transform: `scale(${dotScale})` }} />
                <div style={{ fontFamily: fontBody, fontSize: 32, color: primaryColor, fontWeight: 500 }}>
                  <TextAnim text={item.text} startFrame={item.start + 5} />
                </div>
              </div>
            );
          })}
        </div>

        {/* 5. Highlight Quote */}
        <div style={{ position: 'absolute', left: 1380, top: 620, width: 440 }}>
          <div style={{ fontFamily: fontScript, fontSize: 60, color: primaryColor, lineHeight: 1.25 }}>
            <TextAnim text={props.quoteText} startFrame={65} />
          </div>
        </div>

        {/* 6. Timeline & Badge */}
        <div style={{ position: 'absolute', left: 1380, top: 220, width: 440, height: 100 }}>
          <div style={{ 
            position: 'absolute', top: 48, left: 0, height: 4, backgroundColor: accentColor, 
            width: `${interpolate(frame, [25, 55], [0, 100], { extrapolateRight: 'clamp' })}%` 
          }} />

          {[props.timelineY1, props.timelineY2, props.timelineY3, props.timelineY4].map((yr, i) => {
            const nodeFrame = 25 + (i * 10);
            const scale = spring({ frame: Math.max(0, frame - nodeFrame), fps: safeFps, config: { damping: 15 } });
            return (
              <div key={i} style={{ position: 'absolute', left: `${(i / 3) * 100}%`, top: 0, transform: 'translateX(-50%)', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                <div style={{ width: 20, height: 20, borderRadius: 10, backgroundColor: primaryColor, marginTop: 40, transform: `scale(${scale})` }} />
                <div style={{ fontFamily: fontBody, fontSize: 20, color: primaryColor, marginTop: 16, fontWeight: 700 }}>
                  <TextAnim text={yr} startFrame={nodeFrame + 5} />
                </div>
              </div>
            );
          })}

          <div style={{ position: 'absolute', left: 340, top: -120, width: 140, height: 140, transform: `scale(${badgeScale}) rotate(${badgeRotation}deg)` }}>
            <svg width="140" height="140" viewBox="0 0 140 140" style={{ position: 'absolute', inset: 0 }}>
              <path d={getBurstPath(70, 70, 70, 58, 16)} fill={accentColor} />
            </svg>
            <div style={{ position: 'absolute', inset: 0, display: 'flex', justifyContent: 'center', alignItems: 'center', fontFamily: fontTitle, fontSize: 44, color: bgColor, paddingTop: 4 }}>
              <TextAnim text={props.badgeText} startFrame={45} />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const RevenueOverlay = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const titleText = props.titleText;
  const prefix = props.prefix;
  const targetValue = props.targetValue;
  const titleColor = props.titleColor;
  const numberColor = props.numberColor;
  const transparentBackground = props.transparentBackground;
  const fontFamily = props.fontFamily;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  // Timings: 0-24 (Title fade), 30-54 (Number fade), 30-105 (Number roll)
  const titleOpacity = interpolate(frame, [0, 24], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const titleBlur = interpolate(frame, [0, 24], [24, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  const numberOpacity = interpolate(frame, [30, 54], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const numberBlur = interpolate(frame, [30, 54], [40, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  const countProgress = interpolate(frame, [30, 105], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.bezier(0.1, 1, 0.2, 1) // Decelerates smoothly near the target
  });
  const currentValue = Math.floor(countProgress * Number(targetValue));
  const formattedValue = `${prefix}${currentValue.toLocaleString('en-US')}`;

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: transparentBackground ? 'transparent' : '#050505',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    fontFamily: fontFamily
  };

  const titleStyle = {
    fontSize: '72px',
    fontWeight: 600,
    color: titleColor,
    opacity: titleOpacity,
    filter: `blur(${titleBlur}px)`,
    textShadow: `0 0 15px ${titleColor}80, 0 0 30px ${titleColor}40`,
    margin: 0,
    marginBottom: '20px',
    lineHeight: 1,
    letterSpacing: '1px',
    textAlign: 'center'
  };

  const numberStyle = {
    fontSize: '440px',
    fontWeight: 800,
    color: numberColor,
    opacity: numberOpacity,
    filter: `blur(${numberBlur}px)`,
    textShadow: `0 0 40px ${numberColor}, 0 0 80px ${numberColor}B3, 0 0 140px ${numberColor}80`,
    margin: 0,
    lineHeight: 1,
    letterSpacing: '-6px',
    textAlign: 'center',
    marginTop: '-20px'
  };

  return (
    <div style={rootStyle}>
      <div style={titleStyle}>{titleText}</div>
      <div style={numberStyle}>{formattedValue}</div>
    </div>
  );
};

const NotebookShowcase = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
  const safeFps = fps || 30;

  const props = item.props || {};
  const bgColor = props.bgColor;
  const transparentBackground = props.transparentBackground;
  const paperColor = props.paperColor;
  const accentColor = props.accentColor;
  const textColor = props.textColor;
  const titleFontFamily = props.titleFontFamily;
  const bodyFontFamily = props.bodyFontFamily;

  const chapterTitle = props.chapterTitle;
  const nameTagTitle = props.nameTagTitle;
  const nameTagSubtitle = props.nameTagSubtitle;
  const quoteText = props.quoteText;

  const chartLabels = [props.chartLabel1, props.chartLabel2, props.chartLabel3];
  const chartVals = [parseFloat(props.chartValue1) || 85, parseFloat(props.chartValue2) || 72, parseFloat(props.chartValue3) || 90];

  const bullets = [props.bullet1, props.bullet2, props.bullet3];
  const timelines = [props.timeline1, props.timeline2, props.timeline3, props.timeline4];

  const backgroundColor = transparentBackground ? 'transparent' : bgColor;

  // Animations
  const paperScale = spring({frame, fps: safeFps, config: {damping: 20}});
  const paperOpacity = interpolate(frame, [0, 15], [0, 1], {extrapolateRight: 'clamp'});

  const titleScale = spring({frame: Math.max(0, frame - 15), fps: safeFps, config: {damping: 15}});
  const titleHighlightWidth = `${interpolate(frame, [20, 50], [0, 110], {extrapolateRight: 'clamp'})}%`;

  const chartBarStyles = chartVals.map((val, i) => {
    const w = interpolate(frame, [30 + i * 10, 60 + i * 10], [0, val], {extrapolateRight: 'clamp'});
    return { width: `${w}%` };
  });

  const nameTagScale = spring({frame: Math.max(0, frame - 40), fps: safeFps, config: {damping: 15}});

  const bulletStyles = bullets.map((_, i) => {
    const op = interpolate(frame, [50 + i * 10, 60 + i * 10], [0, 1], {extrapolateRight: 'clamp'});
    const tx = interpolate(frame, [50 + i * 10, 60 + i * 10], [-20, 0], {extrapolateRight: 'clamp'});
    return { opacity: op, transform: `translateX(${tx}px)` };
  });

  const quoteOpacity = interpolate(frame, [60, 80], [0, 1], {extrapolateRight: 'clamp'});
  const quoteHighlightWidth = `${interpolate(frame, [70, 100], [0, 110], {extrapolateRight: 'clamp'})}%`;

  const timelineLineWidth = `${interpolate(frame, [80, 110], [0, 100], {extrapolateRight: 'clamp'})}%`;
  const timelineNodeScales = timelines.map((_, i) => {
    return spring({frame: Math.max(0, frame - (90 + i * 5)), fps: safeFps, config: {damping: 15}});
  });

  const star1Scale = spring({frame: Math.max(0, frame - 60), fps: safeFps, config: {damping: 15}});
  const star2Scale = spring({frame: Math.max(0, frame - 100), fps: safeFps, config: {damping: 15}});

  // Styles
  const rootStyle = { position: 'absolute', inset: 0, backgroundColor };

  const paperStyle = {
    position: 'absolute',
    top: 90, left: 160, right: 160, bottom: 90,
    backgroundColor: paperColor,
    borderRadius: '4px',
    boxShadow: '10px 15px 30px rgba(0,0,0,0.15)',
    backgroundImage: `linear-gradient(to right, #e8e8e8 1px, transparent 1px), linear-gradient(to bottom, #e8e8e8 1px, transparent 1px)`,
    backgroundSize: '40px 40px',
    opacity: paperOpacity,
    transform: `scale(${paperScale})`
  };

  const gridContainerStyle = {
    display: 'grid',
    gridTemplateColumns: '1fr 1fr',
    gridTemplateRows: '1fr 1fr 1fr',
    gap: '60px',
    width: '100%',
    height: '100%',
    padding: '60px 80px 60px 120px',
    boxSizing: 'border-box'
  };

  const spiralContainerStyle = {
    position: 'absolute', left: -25, top: 40, bottom: 40, 
    display: 'flex', flexDirection: 'column', justifyContent: 'space-between', zIndex: 10
  };

  const titleHighlightStyle = {
    position: 'absolute', bottom: '15%', left: '-5%', height: '40%', 
    backgroundColor: accentColor, opacity: 0.7, zIndex: -1,
    width: titleHighlightWidth,
    transform: 'rotate(-1deg)',
    borderRadius: '4px'
  };

  const quoteHighlightStyle = {
    position: 'absolute', top: '40%', left: '-5%', height: '30%', 
    backgroundColor: accentColor, opacity: 0.5, zIndex: -1,
    width: quoteHighlightWidth,
    transform: 'rotate(1deg)'
  };

  return (
    <div style={rootStyle}>
      <div style={paperStyle}>

        {/* Spiral Binding Overlay */}
        <div style={spiralContainerStyle}>
