        </div>

        {/* Doodle Stars */}
        <div style={{position: 'absolute', top: 50, right: 70, transform: `scale(${star1Scale}) rotate(15deg)`, zIndex: 5}}>
          <svg width="40" height="40" viewBox="0 0 40 40">
            <path d="M20,2 L24,14 L38,14 L26,22 L30,36 L20,28 L10,36 L14,22 L2,14 L16,14 Z" stroke={textColor} strokeWidth="2" fill="none" strokeLinejoin="round" />
          </svg>
        </div>
        <div style={{position: 'absolute', bottom: 90, left: 140, transform: `scale(${star2Scale}) rotate(-10deg)`, zIndex: 5}}>
          <svg width="40" height="40" viewBox="0 0 40 40">
            <path d="M20,2 L24,14 L38,14 L26,22 L30,36 L20,28 L10,36 L14,22 L2,14 L16,14 Z" stroke={textColor} strokeWidth="2" fill="none" strokeLinejoin="round" />
          </svg>
        </div>

        <div style={gridContainerStyle}>

          {/* 1. Chapter Title */}
          <div style={{display:'flex', alignItems:'center', justifyContent:'center', height:'100%', position:'relative'}}>
