            <div style={{backgroundColor: '#fff3fc', padding: '30px 40px', boxShadow: '4px 6px 15px rgba(0,0,0,0.1)', transform: `scale(${nameTagScale}) rotate(-3deg)`, position: 'relative', display:'flex', flexDirection:'column', alignItems:'center', fontFamily: titleFontFamily, color: textColor}}>
              <div style={{position:'absolute', top: -35, left: '40%', transform:'rotate(10deg)'}}>
                <svg width="30" height="70" viewBox="0 0 24 60">
                  <path d="M12,2 L12,48 C12,53 18,53 18,48 L18,12 C18,9 14,9 14,12 L14,40 C14,42 16,42 16,40 L16,15" stroke="#777" strokeWidth="4" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
