const TakeawayOverlay = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const titleText = props.titleText;
  const bodyText = props.bodyText;
  const accentColor = props.accentColor;
  const textColor = props.textColor;
  const titleFontFamily = props.titleFontFamily;
  const bodyFontFamily = props.bodyFontFamily;
  const transparentBackground = props.transparentBackground;

  const DESIGN_WIDTH = 1200;
  const DESIGN_HEIGHT = 300;
  const scale = Math.min(
    (item?.width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const TITLE_IN_START = 0;
  const TITLE_IN_END   = 20;
  const LINE_START     = 18;
  const LINE_END       = 58;
  const LINE_MAX_W     = 270;  // 与标题文字等宽
  const BODY_START     = 34;
  const LETTER_STAGGER = 0.9;
  const LETTER_DUR     = 7;
  const FADE_OUT_START = durationInFrames - 18;
  const FADE_OUT_END   = durationInFrames - 2;

  const globalOpacity = interpolate(
    frame,
    [Math.max(0, FADE_OUT_START), Math.max(1, FADE_OUT_END)],
    [1, 0],
    { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );

  const titleProgress = interpolate(frame, [TITLE_IN_START, TITLE_IN_END], [0, 1], {
    easing: Easing.bezier(0.25, 1, 0.5, 1),
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const titleOpacity = titleProgress;
  const titleBlur    = interpolate(titleProgress, [0, 1], [14, 0]);
  const tg = titleProgress;
  const titleShadow = [
    `0 0 4px rgba(255,255,255,${0.95*tg})`,
    `0 0 12px rgba(255,255,255,${0.8*tg})`,
    `0 0 28px rgba(255,255,255,${0.55*tg})`,
    `0 0 56px rgba(255,255,255,${0.3*tg})`,
  ].join(',');

  const lineProgress = interpolate(frame, [LINE_START, LINE_END], [0, 1], {
    easing: Easing.bezier(0.16, 1, 0.3, 1),
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const lineW = lineProgress * LINE_MAX_W;
  const lineGlowPeak = interpolate(frame, [LINE_START, LINE_END, LINE_END + 15], [0, 1, 0.65], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const lineVisible = frame >= LINE_START;

  const svgH = 44;
  const cy = svgH / 2;

  // 左端宽（两点），右端尖（一点）
  const triPoints = (w, hL) => {
    if (w <= 0) return `0,${cy} 0,${cy} 0,${cy}`;
    return `0,${cy - hL} ${w},${cy} 0,${cy + hL}`;
  };

  const hexToRgb = (hex) => {
    const h = (hex || '#0087b9').replace('#', '');
    return {
      r: parseInt(h.slice(0,2),16),
      g: parseInt(h.slice(2,4),16),
      b: parseInt(h.slice(4,6),16)
    };
  };
  const {r, g: gc, b} = hexToRgb(accentColor);
  const ac = `${r},${gc},${b}`;

  const rawWords = (bodyText || '').split(' ');

  const rootStyle = {
    position: 'absolute',
    top: 0, left: 0,
    width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: transparentBackground ? 'transparent' : 'rgba(10,10,18,0.82)',
    padding: '36px 48px',
    boxSizing: 'border-box',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'flex-start',
    alignItems: 'flex-start',
    opacity: globalOpacity,
  };

  const titleStyle = {
    fontFamily: titleFontFamily, fontSize: 52, fontWeight: 700,
    color: textColor, margin: 0, letterSpacing: '0.01em',
    lineHeight: 1.15, whiteSpace: 'nowrap',
    opacity: titleOpacity,
    filter: `blur(${titleBlur}px)`,
    textShadow: titleShadow,
  };

  const lineSvgWrap = {
    marginTop: 4,
    marginBottom: 8,
    flexShrink: 0,
    opacity: lineVisible ? 1 : 0,
    display: 'block',
    overflow: 'visible',
  };

  const bodyContainerStyle = { position: 'relative', width: '100%', lineHeight: 1.55 };

  let letterIdx = 0;
  const wordNodes = rawWords.map((word, wi) => {
    const wordLetters = word.split('').map(ch => {
      const gi = letterIdx++;
      const start = BODY_START + gi * LETTER_STAGGER;
      const end   = start + LETTER_DUR;
      const lp = interpolate(frame, [start, end], [0, 1], {
        easing: Easing.bezier(0.22, 1, 0.36, 1),
        extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
      });
      const lY    = interpolate(lp, [0, 1], [-9, 0]);
      const lBlur = interpolate(lp, [0, 1], [3, 0]);
      const g = lp;
      const ls = [
        `0 0 3px rgba(255,255,255,${0.98*g})`,
        `0 0 9px rgba(255,255,255,${0.85*g})`,
        `0 0 20px rgba(255,255,255,${0.65*g})`,
        `0 0 40px rgba(255,255,255,${0.38*g})`,
        `0 0 72px rgba(255,255,255,${0.18*g})`,
      ].join(',');
      return (
        <span key={gi} style={{
          display: 'inline-block', opacity: lp,
          transform: `translateY(${lY}px)`, verticalAlign: 'baseline',
          fontFamily: bodyFontFamily, fontSize: 34, fontWeight: 300,
          color: textColor, filter: `blur(${lBlur}px)`,
          textShadow: ls, whiteSpace: 'pre',
        }}>{ch}</span>
      );
    });
    let spaceNode = null;
    if (wi < rawWords.length - 1) {
      const si = letterIdx++;
      const sp = interpolate(frame,
        [BODY_START+si*LETTER_STAGGER, BODY_START+si*LETTER_STAGGER+LETTER_DUR],
        [0,1], {extrapolateLeft:'clamp',extrapolateRight:'clamp'});
      spaceNode = <span key={'sp-'+wi} style={{display:'inline-block',width:'0.28em',opacity:sp}} />;
    }
    return (
      <span key={'w-'+wi} style={{display:'inline-block',whiteSpace:'nowrap'}}>
        {wordLetters}{spaceNode}
      </span>
    );
  });

  return (
    <div style={rootStyle}>
      <div style={titleStyle}>{titleText}</div>

      <svg
        width={LINE_MAX_W}
        height={svgH}
        viewBox={`0 0 ${LINE_MAX_W} ${svgH}`}
        style={lineSvgWrap}
        overflow="visible"
      >
        <polygon
          points={triPoints(lineW, 18)}
          fill={`rgba(${ac},${0.45 * lineGlowPeak})`}
          style={{filter: 'blur(8px)'}}
        />
        <polygon
          points={triPoints(lineW, 10)}
          fill={`rgba(${ac},${0.7 * lineGlowPeak})`}
          style={{filter: 'blur(3px)'}}
        />
        <polygon
          points={triPoints(lineW, 2.5)}
          fill={`rgba(${ac},0.95)`}
        />
        <polygon
          points={triPoints(lineW, 0.8)}
          fill={`rgba(255,255,255,${0.85 * lineProgress})`}
        />
      </svg>

      <div style={bodyContainerStyle}>
        <div style={{position:'relative',width:'100%',lineHeight:1.55,color:textColor}}>
          {wordNodes}
        </div>
      </div>
    </div>
  );
};

const EditorialTeamGrid = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();
  const props = item.props || {};

  const titleText = props.titleText;
  const m1Name = props.m1Name;
  const m1Role = props.m1Role;
  const m2Name = props.m2Name;
  const m2Role = props.m2Role;
  const m3Name = props.m3Name;
  const m3Role = props.m3Role;

  const transparentBackground = props.transparentBackground;
  const bgColor = props.bgColor;
  const boxColor = props.boxColor;
  const frameColor = props.frameColor;
  const textColor = props.textColor;
  const textSecColor = props.textSecColor;
  const serifFont = props.serifFont;
  const sansFont = props.sansFont;

  const backgroundColor = transparentBackground ? 'transparent' : bgColor;

  // --- Easing ---
  const smoothSettle = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 3.5);
  };

  // --- Exit ---
  const totalFrames = durationInFrames || 150;
  const exitStart = totalFrames - 25;
  const exitRaw = Math.max(0, Math.min(1, (frame - exitStart) / 25));
  const exitProgress = exitRaw * exitRaw;
  const exitOpacity = 1 - exitProgress;
  const exitScale = 1 - exitProgress * 0.02;

  // --- Title: starts frame 5, 50 frames ---
  const titleRaw = Math.min(1, Math.max(0, (frame - 5) / 50));
  const titleProgress = smoothSettle(titleRaw);
  const titleY = (1 - titleProgress) * 50;
  const titleOpacity = smoothSettle(Math.min(1, Math.max(0, (frame - 5) / 18)));

  // --- Cards: staggered starts at 30, 50, 70 with 45-frame duration ---
  const cardAnim = (startFrame) => {
    const raw = Math.min(1, Math.max(0, (frame - startFrame) / 45));
    const progress = smoothSettle(raw);
    const opacity = smoothSettle(Math.min(1, Math.max(0, (frame - startFrame) / 15)));
    return { progress, opacity };
  };

  const m1Anim = cardAnim(30);
  const m2Anim = cardAnim(50);
  const m3Anim = cardAnim(70);

  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor,
    display: 'flex',
    flexDirection: 'column',
    padding: '100px 140px',
    boxSizing: 'border-box',
    fontFamily: serifFont,
    color: textColor,
    opacity: exitOpacity,
    transform: `scale(${exitScale})`
  };

  const titleStyle = {
    fontSize: '72px',
    fontWeight: '400',
    marginBottom: '80px',
    letterSpacing: '-1px',
    transform: `translateY(${titleY}px)`,
    opacity: titleOpacity
  };

  const gridStyle = {
    display: 'flex',
    gap: '60px',
    flex: 1,
    justifyContent: 'space-between'
  };

  const Card = ({ name, role, anim, item }) => {
    const cardY = (1 - anim.progress) * 50;
    const cardOpacity = anim.opacity;
    const boxHeight = anim.progress * 100;

    const cardStyle = {
      flex: 1,
      display: 'flex',
      flexDirection: 'column',
      opacity: cardOpacity,
      transform: `translateY(${cardY}px)`
    };

    const portraitContainerStyle = {
      position: 'relative',
      width: '100%',
      height: '520px',
      marginBottom: '40px',
      overflow: 'visible'
    };

    const darkBoxStyle = {
      position: 'absolute',
      top: '40px',
      left: '40px',
      right: 0,
      bottom: 0,
      backgroundColor: boxColor,
      transformOrigin: 'bottom center',
      transform: `scaleY(${boxHeight / 100})`
    };

    const lineFrameStyle = {
      position: 'absolute',
      top: 0,
      left: 0,
      width: '85%',
      height: '85%',
      borderTop: `2px solid ${frameColor}`,
      borderLeft: `2px solid ${frameColor}`,
      opacity: anim.progress
    };

    const lineFrameBottomRightStyle = {
      position: 'absolute',
      bottom: '-20px',
      right: '-20px',
      width: '40%',
      height: '30%',
      borderBottom: `2px solid ${frameColor}`,
      borderRight: `2px solid ${frameColor}`,
      opacity: anim.progress
    };

    const nameStyle = {
      fontSize: '40px',
      fontWeight: '600',
      marginBottom: '16px',
      lineHeight: '1.2'
    };

    const roleStyle = {
      fontFamily: sansFont,
      fontSize: '24px',
      fontWeight: '400',
      color: textSecColor,
      textTransform: 'uppercase',
      letterSpacing: '2px',
      lineHeight: '1.5',
      whiteSpace: 'normal',
      overflowWrap: 'break-word'
    };

    return (
      <div style={cardStyle}>
        <div style={portraitContainerStyle}>
          <div style={darkBoxStyle} />
          <div style={lineFrameStyle} />
          <div style={lineFrameBottomRightStyle} />
        </div>
        <div style={nameStyle}>{name}</div>
        <div style={roleStyle}>{role}</div>
      </div>
    );
  };

  return (
    <div style={rootStyle}>
      <div style={titleStyle}>{titleText}</div>
      <div style={gridStyle}>
        <Card name={m1Name} role={m1Role} anim={m1Anim} />
        <Card name={m2Name} role={m2Role} anim={m2Anim} />
        <Card name={m3Name} role={m3Role} anim={m3Anim} />
      </div>
    </div>
  );
};

const TechTrendsSlide = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const bgColor = props.bgColor;
  const transparentBackground = props.transparentBackground;
  const numberText = props.numberText;
  const primaryText = props.primaryText;
  const subText = props.subText;
  const textColor = props.textColor;
  const blobColor1 = props.blobColor1;
  const blobColor2 = props.blobColor2;
  const numberFont = props.numberFont;
  const titleFont = props.titleFont;

  const safeFps = fps || 30;

  // Background toggling
  const backgroundColor = transparentBackground ? 'transparent' : bgColor;
  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor,
    overflow: 'hidden',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    padding: '0 300px'
  };

  // Animation springs
  const titleSlide = spring({frame: Math.max(0, frame - 10), fps: safeFps, config: {damping: 16}});
  const subSlide = spring({frame: Math.max(0, frame - 20), fps: safeFps, config: {damping: 16}});
  const topNumScale = spring({frame: Math.max(0, frame - 5), fps: safeFps, config: {damping: 15}});
  const botNumScale = spring({frame: Math.max(0, frame - 15), fps: safeFps, config: {damping: 15}});

  // Blob floating motion
  const blob1X = interpolate(frame, [0, 120], [1000, 950]);
  const blob1Y = interpolate(frame, [0, 120], [300, 400]);
  const blob2X = interpolate(frame, [0, 120], [1300, 1400]);
  const blob2Y = interpolate(frame, [0, 120], [500, 420]);

  // Split numbers to stack them
  const halfLen = Math.ceil(numberText.length / 2);
  const topNum = numberText.substring(0, halfLen);
  const botNum = numberText.substring(halfLen);

  return (
    <div style={rootStyle}>
      {/* Background Organic Gradient Blob */}
      <div style={{position: 'absolute', inset: 0, opacity: 0.6, pointerEvents: 'none'}}>
        <svg width="100%" height="100%" style={{position: 'absolute', top: 0, left: 0}}>
          <defs>
            <filter id="blobBlur" x="-50%" y="-50%" width="200%" height="200%">
              <feGaussianBlur stdDeviation="140" />
            </filter>
          </defs>
          <g filter="url(#blobBlur)">
            <circle cx={blob1X} cy={blob1Y} r="350" fill={blobColor1} />
            <circle cx={blob2X} cy={blob2Y} r="400" fill={blobColor2} />
          </g>
        </svg>
      </div>

      {/* Left Content: Title & Subtitle */}
      <div style={{
        display: 'flex',
        flexDirection: 'column',
        gap: 16,
        zIndex: 10,
        marginTop: -50
      }}>
        <div style={{
          fontFamily: titleFont,
          fontSize: 56,
          letterSpacing: '5px',
          fontWeight: 400,
          color: textColor,
          opacity: titleSlide,
          transform: `translateX(${interpolate(titleSlide, [0, 1], [-40, 0])}px)`
        }}>
          {primaryText}
        </div>
        <div style={{
          fontFamily: titleFont,
          fontSize: 20,
          lineHeight: 1.4,
          color: textColor,
          maxWidth: 320,
          whiteSpace: 'pre-wrap',
          opacity: subSlide * 0.7,
          transform: `translateX(${interpolate(subSlide, [0, 1], [-40, 0])}px)`
        }}>
          {subText}
        </div>
      </div>

      {/* Right Content: Pixel Numbers */}
      <div style={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        zIndex: 10
      }}>
        <div style={{
          fontFamily: numberFont,
          fontSize: 220,
          lineHeight: 0.85,
          color: textColor,
          fontWeight: 700,
          opacity: topNumScale,
          transform: `translateY(${interpolate(topNumScale, [0, 1], [60, 0])}px) scale(${interpolate(topNumScale, [0, 1], [0.8, 1])})`
        }}>
          {topNum}
        </div>
        <div style={{
          fontFamily: numberFont,
          fontSize: 220,
          lineHeight: 0.85,
          color: textColor,
          fontWeight: 700,
          opacity: botNumScale,
          transform: `translateY(${interpolate(botNumScale, [0, 1], [60, 0])}px) scale(${interpolate(botNumScale, [0, 1], [0.8, 1])})`
        }}>
          {botNum}
        </div>
      </div>
    </div>
  );
};

const ModernSlide = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const titleText = props.titleText;
  const bodyText = props.bodyText;
  const titleColor = props.titleColor;
  const bodyColor = props.bodyColor;
  const blobColor1 = props.blobColor1;
  const blobColor2 = props.blobColor2;
  const bgColor = props.bgColor;
  const transparentBackground = props.transparentBackground;
  const fontFamilyTitle = props.fontFamilyTitle;
  const fontFamilyBody = props.fontFamilyBody;

  const backgroundColor = transparentBackground ? 'transparent' : bgColor;
  const safeFps = fps || 30;
  const safeDuration = durationInFrames || 150;

  // Intro Springs
  const titleSpr1 = spring({ frame: Math.max(0, frame - 5), fps: safeFps, config: { damping: 16, mass: 0.8 } });
  const titleSpr2 = spring({ frame: Math.max(0, frame - 12), fps: safeFps, config: { damping: 16, mass: 0.8 } });
  const bodySpr = spring({ frame: Math.max(0, frame - 22), fps: safeFps, config: { damping: 15, mass: 1 } });

  // Outro interpolation
  const fadeOutStart = safeDuration - 20;
  const globalOpacity = interpolate(frame, [fadeOutStart, Math.max(fadeOutStart + 1, fadeOutStart + 15)], [1, 0], { extrapolateRight: 'clamp', extrapolateLeft: 'clamp' });

  // Split title lines safely
  const titleLines = titleText.split('\n');
  const line1 = titleLines[0] || "";
  const line2 = titleLines.length > 1 ? titleLines.slice(1).join(' ') : "";

  // Blob animations
  const blobIntro = interpolate(frame, [0, 45], [0, 0.85], { extrapolateRight: 'clamp' });
  const blobScale = 1 + Math.sin(frame / 40) * 0.1;
  const blobRotate = frame * 0.15;

  return (
     <div style={{ position: 'absolute', inset: 0, backgroundColor, opacity: globalOpacity, overflow: 'hidden' }}>
        {/* Blob Backgrounds using CSS radial gradients for safe WebGL capture */}
        <div style={{
            position: 'absolute',
            top: '-40%',
            right: '-10%',
            width: '1400px',
            height: '1400px',
            background: `radial-gradient(circle at center, ${blobColor1} 0%, transparent 65%)`,
            opacity: blobIntro,
            transform: `scale(${blobScale}) rotate(${blobRotate}deg)`,
            pointerEvents: 'none'
        }} />
         <div style={{
            position: 'absolute',
            top: '-20%',
            right: '-30%',
            width: '1600px',
            height: '1600px',
            background: `radial-gradient(circle at center, ${blobColor2} 0%, transparent 60%)`,
            opacity: blobIntro * 0.7,
            transform: `scale(${blobScale * 1.05}) rotate(${-blobRotate * 0.5}deg)`,
            pointerEvents: 'none'
        }} />

        {/* Content */}
        <div style={{
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'center',
            height: '100%',
            paddingLeft: '15%',
            zIndex: 10
        }}>
            <h1 style={{
                margin: 0,
                fontFamily: fontFamilyTitle,
                fontSize: '56px',
                fontWeight: '300',
                letterSpacing: '0.15em',
                color: titleColor,
                lineHeight: '1.1',
                textTransform: 'uppercase'
            }}>
                <div style={{ overflow: 'hidden', paddingBottom: '10px' }}>
                    <div style={{ transform: `translateY(${(1 - titleSpr1) * 100}%)`, opacity: titleSpr1 }}>{line1}</div>
                </div>
                {line2 && (
                  <div style={{ overflow: 'hidden', paddingBottom: '10px' }}>
                      <div style={{ transform: `translateY(${(1 - titleSpr2) * 100}%)`, opacity: titleSpr2 }}>{line2}</div>
                  </div>
                )}
            </h1>
            <div style={{
                marginTop: '50px',
                maxWidth: '750px',
                fontFamily: fontFamilyBody,
                fontSize: '28px',
                color: bodyColor,
                lineHeight: '1.6',
                fontWeight: '400',
                opacity: bodySpr,
                transform: `translateY(${(1 - bodySpr) * 30}px)`
            }}>
                {bodyText}
            </div>
        </div>
     </div>
  );
}

