  };

  const blobStyle = {
    position: 'absolute',
    top: -300,
    right: -200,
    width: 1200,
    height: 1200,
    background: `radial-gradient(circle, ${gradientStart} 0%, ${gradientEnd} 40%, transparent 70%)`,
    opacity: 0.35,
    borderRadius: '50%',
    zIndex: 0
  };

  const blob2Style = {
    position: 'absolute',
    bottom: -200,
    left: -200,
    width: 800,
