    fontSize: 56,
    fontWeight: 300,
    letterSpacing: '0.15em',
    lineHeight: 1.15,
    color: textColor,
    margin: 0,
    opacity: titleOpacity,
    transform: `translateY(${titleY}px)`,
    flex: 1
  };

  const barsContainerStyle = {
    flex: 1,
    display: 'flex',
    flexDirection: 'column',
    gap: 48,
    position: 'relative',
    padding: 40
  };

