  };

  const backgroundColor = transparentBackground ? 'transparent' : bgColor;

  const titleSpring = safeSpring(0);
  const lineProgress = interpolate(frame, [15, 60], [0, 100], { extrapolateRight: 'clamp', extrapolateLeft: 'clamp' });

