  );
};

const TechTrendsAnchor = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();
  const props = item.props || {};

  const bgColor = props.transparentBackground ? 'transparent' : props.bgColor;
  const textColor = props.textColor;
  const titleFont = props.titleFont;
  const bodyFont = props.bodyFont;
  const blobColor1 = props.blobColor1;
  const blobColor2 = props.blobColor2;
  const accentColor = props.accentColor;

  const parseHex = (hex) => {
    if (!hex) return [0,0,0];
    const h = hex.replace('#','');
    return [parseInt(h.substring(0,2),16)||0, parseInt(h.substring(2,4),16)||0, parseInt(h.substring(4,6),16)||0];
  };
  const rgba = (hex, a) => { const [r,g,b] = parseHex(hex); return `rgba(${r},${g},${b},${a})`; };

  const smoothSettle = (t) => t<=0?0:t>=1?1:1-Math.pow(1-t,3.5);
  const bellCurveLate = (t) => t<=0?0:t>=1?1:t<0.4?0.15*Math.pow(t/0.4,2.5):0.15+0.85*(1-Math.pow(1-(t-0.4)/0.6,2.8));
  const lineDraw = (t) => t<=0?0:t>=1?1:1-Math.pow(1-t,2.8);

  const total = durationInFrames || 150;
  const exitRaw = Math.max(0, Math.min(1, (frame-(total-25))/25));
  const ex = 1 - exitRaw*exitRaw;

  const anim = (delay, dur) => smoothSettle(Math.min(1, Math.max(0, (frame-delay)/dur)));
  const fadeIn = (delay) => smoothSettle(Math.min(1, Math.max(0, (frame-delay)/15)));

  // Blobs
  const blobA = anim(0,40)*ex;
  const blobScale = 1.05-0.05*anim(0,45);
  const dX = Math.sin(frame/55)*7;
  const dY = Math.cos(frame/70)*5;

  // Big number (delay 5)
  const numA = fadeIn(5)*ex;
  const numScale = 0.9 + 0.1*anim(5,45);

  // Title (delay 12)
  const ttA = fadeIn(12)*ex;

  // Subtitle (delay 22)
  const stA = fadeIn(22)*ex;
  const stY = (1-anim(22,35))*25;

  // Body (delay 28)
  const bdA = fadeIn(28)*ex;
  const bdY = (1-anim(28,35))*25;

  // Bar chart (delay 18)
  const bars = [{l:'AI/ML',v:38},{l:'Quantum',v:22},{l:'Cloud',v:20},{l:'Biotech',v:20}];
  const maxV = 38;

  // Timeline (delay 15)
  const tlW = lineDraw(Math.min(1,Math.max(0,(frame-15)/50)))*600;
  const tlA = fadeIn(15)*ex;
  const nd = [0,1,2,3].map(i => ({ a: fadeIn(25+i*5)*ex, y: (1-anim(25+i*5,30))*15 }));

  // Name tag (delay 32)
  const nmA = fadeIn(32)*ex;

  // Team blobs (delay 35)
  const tmA = [0,1,2].map(i => fadeIn(35+i*6)*ex);

  return (
    <div style={{position:'absolute',inset:0,backgroundColor:bgColor,overflow:'hidden',fontFamily:bodyFont}}>
      {/* Gradient blobs */}
      <div style={{position:'absolute',top:'-10%',right:'-8%',width:1200,height:1200,
        background:`radial-gradient(circle,${rgba(blobColor1,blobA*0.45)} 0%,transparent 60%)`,
        transform:`translate(${dX}px,${dY}px) scale(${blobScale})`,transformOrigin:'center'}}/>
      <div style={{position:'absolute',bottom:'-15%',left:'-5%',width:1000,height:1000,
        background:`radial-gradient(circle,${rgba(blobColor2,blobA*0.35)} 0%,transparent 60%)`,
        transform:`translate(${-dX}px,${-dY}px) scale(${blobScale})`,transformOrigin:'center'}}/>

      {/* Big year number (top left) */}
      <div style={{position:'absolute',left:140,top:80}}>
        <div style={{fontFamily:titleFont,fontSize:160,fontWeight:300,color:rgba(textColor,numA*0.15),lineHeight:1,transform:`scale(${numScale})`,transformOrigin:'left top'}}>
          2026
        </div>
      </div>

      {/* Title */}
      <div style={{position:'absolute',left:140,top:200}}>
        <div style={{fontFamily:bodyFont,fontSize:48,fontWeight:700,color:rgba(textColor,ttA),letterSpacing:'-0.01em'}}>
          TECH TRENDS
        </div>
      </div>

      {/* Subtitle */}
      <div style={{position:'absolute',left:140,top:280,transform:`translateY(${stY}px)`}}>
        <div style={{fontSize:26,color:rgba(textColor,stA*0.6),lineHeight:1.4,whiteSpace:'pre-wrap'}}>
          Here is where your{'\n'}presentation begins
        </div>
      </div>

      {/* Body */}
      <div style={{position:'absolute',left:140,top:420,width:550,transform:`translateY(${bdY}px)`}}>
        <div style={{fontSize:26,color:rgba(textColor,bdA*0.8),lineHeight:1.5}}>
          Technology is reshaping every industry through AI and quantum computing.
        </div>
      </div>

      {/* Horizontal bar chart (right) */}
      <div style={{position:'absolute',right:120,top:200,width:500}}>
        {bars.map((b,i) => {
          const bRaw = Math.min(1,Math.max(0,(frame-(18+i*8))/50));
          const bP = bellCurveLate(bRaw);
          const bA = fadeIn(18+i*8)*ex;
          const w = (b.v/maxV)*350;
          return (
            <div key={i} style={{display:'flex',alignItems:'center',marginBottom:20,height:36}}>
              <div style={{width:100,fontSize:16,color:rgba(textColor,bA*0.7),textAlign:'right',paddingRight:16}}>{b.l}</div>
              <div style={{height:'100%',width:w*bP,background:`linear-gradient(90deg,${rgba(blobColor1,bA)},${rgba(blobColor2,bA)})`,borderRadius:4}}/>
              <div style={{fontSize:18,fontWeight:600,color:rgba(textColor,bA),marginLeft:12}}>{b.v}%</div>
            </div>
          );
        })}
      </div>

      {/* Timeline (bottom) */}
      <div style={{position:'absolute',left:140,bottom:140,width:650,height:70}}>
        <div style={{position:'absolute',left:0,top:10,width:tlW,height:2,backgroundColor:rgba(textColor,tlA*0.2)}}/>
        {['2023','2024','2025','2026'].map((yr,i) => (
          <div key={i} style={{position:'absolute',left:i*180,top:0,transform:`translateY(${nd[i].y}px)`}}>
            <div style={{width:7,height:7,borderRadius:'50%',backgroundColor:rgba(accentColor,nd[i].a)}}/>
            <div style={{fontFamily:titleFont,fontSize:20,color:rgba(textColor,nd[i].a),marginTop:12}}>{yr}</div>
          </div>
        ))}
      </div>

      {/* Name tag */}
      <div style={{position:'absolute',left:140,bottom:80}}>
        <div style={{fontSize:20,fontWeight:500,color:rgba(textColor,nmA),borderLeft:`3px solid ${rgba(accentColor,nmA)}`,paddingLeft:12}}>
          Dr. Aisha Patel — AI Research
        </div>
      </div>

      {/* Team member blobs (right bottom) */}
      <div style={{position:'absolute',right:120,bottom:120,display:'flex',gap:24}}>
        {[blobColor1,blobColor2,accentColor].map((c,i) => (
          <div key={i} style={{width:60,height:60,borderRadius:'50%',backgroundColor:rgba(c,tmA[i]*0.12),border:`2px solid ${rgba(c,tmA[i]*0.5)}`}}/>
        ))}
      </div>
    </div>
  );
};

const Timeline = ({item}) => {
  const frame = useCurrentFrame();
  const {durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const bgColor = props.transparentBackground ? 'transparent' : props.bgColor;
  const textColor = props.textColor;
  const titleText = props.titleText;
  const titleFont = props.titleFont;
  const descFont = props.descFont;

  const m1Year = props.m1Year;
  const m1Desc = props.m1Desc;
  const m2Year = props.m2Year;
  const m2Desc = props.m2Desc;
  const m3Year = props.m3Year;
  const m3Desc = props.m3Desc;
  const m4Year = props.m4Year;
  const m4Desc = props.m4Desc;

  // --- Easing curves ---
  const smoothSettle = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 3.5);
  };
  const lineDraw = (t) => {
    if (t <= 0) return 0;
    if (t >= 1) return 1;
    return 1 - Math.pow(1 - t, 2.8);
  };

  // --- Exit ---
  const totalFrames = durationInFrames || 210;
  const exitStart = totalFrames - 25;
  const exitRaw = Math.max(0, Math.min(1, (frame - exitStart) / 25));
  const exitProgress = exitRaw * exitRaw;
  const exitOpacity = 1 - exitProgress;
  const exitScale = 1 - exitProgress * 0.02;

  // --- Title: starts frame 5, 50 frames ---
  const titleRaw = Math.min(1, Math.max(0, (frame - 5) / 50));
  const titleProgress = smoothSettle(titleRaw);
  const titleOpacity = smoothSettle(Math.min(1, Math.max(0, (frame - 5) / 18)));
  const titleY = (1 - titleProgress) * 60;

  // --- Vertical line: starts frame 20, 55 frames ---
  const lineRaw = Math.min(1, Math.max(0, (frame - 20) / 55));
  const lineProgress = lineDraw(lineRaw);
  const lineLength = lineProgress * 540;

  // --- Milestones: staggered from frame 40, every 20 frames apart ---
  const renderMilestone = (year, desc, index, startFrame, yPos) => {
    const mRaw = Math.min(1, Math.max(0, (frame - startFrame) / 40));
    const mProgress = smoothSettle(mRaw);
    const mOpacity = smoothSettle(Math.min(1, Math.max(0, (frame - startFrame) / 15)));
    const dotScale = mProgress;
    const leftX = (1 - mProgress) * -30;
    const rightX = (1 - mProgress) * 30;

    return (
      <div key={index} style={{position: 'absolute', top: yPos, left: 0, right: 0, height: 120}}>
        <div style={{
          position: 'absolute',
          left: 750 - 6,
          top: 55,
          width: 12,
          height: 12,
          borderRadius: '50%',
          backgroundColor: textColor,
          transform: `scale(${dotScale})`,
        }} />
        <div style={{
          position: 'absolute',
          right: 1920 - 710,
          top: 0,
          opacity: mOpacity,
          transform: `translateX(${leftX}px)`,
          fontFamily: titleFont,
          fontSize: '96px',
          color: textColor,
          letterSpacing: '-2px',
          lineHeight: '1.1',
        }}>
          {year}
        </div>
        <div style={{
          position: 'absolute',
          left: 790,
          top: 40,
          width: 800,
          opacity: mOpacity,
          transform: `translateX(${rightX}px)`,
          fontFamily: descFont,
          fontSize: '30px',
          color: textColor,
          lineHeight: '1.4',
        }}>
          {desc}
        </div>
      </div>
    );
  };

  return (
    <div style={{
      position: 'absolute',
      inset: 0,
      backgroundColor: bgColor,
      overflow: 'hidden',
      opacity: exitOpacity,
      transform: `scale(${exitScale})`
    }}>
      <div style={{
        position: 'absolute',
        left: 200,
        top: 150,
        opacity: titleOpacity,
        transform: `translateY(${titleY}px)`,
        fontFamily: titleFont,
        fontSize: '72px',
        color: textColor,
      }}>
        {titleText}
      </div>

      <div style={{
        position: 'absolute',
        left: 749,
        top: 355,
        width: 2,
        height: lineLength,
        backgroundColor: textColor,
      }} />

      {renderMilestone(m1Year, m1Desc, 1, 40, 300)}
      {renderMilestone(m2Year, m2Desc, 2, 60, 480)}
      {renderMilestone(m3Year, m3Desc, 3, 80, 660)}
      {renderMilestone(m4Year, m4Desc, 4, 100, 840)}
    </div>
  );
};

const TitleCard = ({item}) => {
  const frame = useCurrentFrame();
  const { durationInFrames } = useVideoConfig();

  const props = item.props || {};
  const line1Text = props.line1Text;
  const line2Text = props.line2Text;
  const line3Text = props.line3Text;
  const line4aText = props.line4aText;
  const line4bText = props.line4bText;
  const accentColor = props.accentColor;
  const textColor = props.textColor;
  const fontFamily = props.fontFamily;

  const DESIGN_WIDTH = 800;
  const DESIGN_HEIGHT = 450;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const outroStart = Math.max(1, durationInFrames - 15);
  const outroEnd = Math.max(outroStart + 1, durationInFrames);

  const easeInQuad = (t) => t * t;
  const t = interpolate(frame, [outroStart, outroEnd], [0, 1], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp'
  });
  const outTranslateX = easeInQuad(t) * -110;
  const speed = 2 * t;
  const blurAmount = speed * 4;
  const motionFilter = t > 0.02 ? 'blur(' + blurAmount + 'px)' : 'none';

  const dropShadow = '3px 4px 6px rgba(0,0,0,0.6)';

  const words1 = (line1Text || '').split(' ').filter(Boolean);
  const words2 = (line2Text || '').split(' ').filter(Boolean);
  const words3 = (line3Text || '').split(' ').filter(Boolean);
  const words4a = (line4aText || '').split(' ').filter(Boolean);
  const words4b = (line4bText || '').split(' ').filter(Boolean);

  const start2 = words1.length;
  const start3 = start2 + words2.length;
  const start4a = start3 + words3.length;
  const start4b = start4a + words4a.length;

  const INTRO_DELAY = 8;  // 开头延迟稍长
  const WORD_INTERVAL = 7; // 每词间隔7帧，更从容

  const renderWords = (wordsArray, fontSize, fontWeight, color, startIndex) => {
    return wordsArray.map((word, i) => {
      const delay = INTRO_DELAY + (startIndex + i) * WORD_INTERVAL;
      const visible = frame >= delay;
      return (
        <span key={startIndex + i} style={{
          visibility: visible ? 'visible' : 'hidden',
          fontSize, fontWeight, color,
          textShadow: dropShadow,
          lineHeight: 1.1,
          letterSpacing: fontSize === '90px' ? '-0.02em' : '-0.01em',
        }}>{word + '\u00A0'}</span>
      );
    });
  };

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      transform: 'scale(' + scale + ')', transformOrigin: 'top left',
    }}>
      <div style={{
        transform: 'translateX(' + outTranslateX + '%)',
        filter: motionFilter,
        display: 'flex', flexDirection: 'column', alignItems: 'flex-start',
        padding: '30px', fontFamily,
        willChange: 'transform, filter',
      }}>
        <div style={{ lineHeight: 1.0 }}>{renderWords(words1, '90px', 900, accentColor, 0)}</div>
        <div style={{ lineHeight: 1.1, marginTop: '4px' }}>{renderWords(words2, '45px', 600, textColor, start2)}</div>
        <div style={{ lineHeight: 1.0, marginTop: '4px' }}>{renderWords(words3, '90px', 900, accentColor, start3)}</div>
        <div style={{ lineHeight: 1.0, marginTop: '4px', display: 'flex', alignItems: 'baseline' }}>
          {renderWords(words4a, '90px', 900, accentColor, start4a)}
          {renderWords(words4b, '45px', 600, textColor, start4b)}
        </div>
      </div>
    </div>
  );
};

const VoxDefinitionCard = ({item}) => {
    const frame = useCurrentFrame();

    const props = item.props || {};
    const headlineText = props.headlineText;
    const subtitleLine1 = props.subtitleLine1;
    const subtitleLine2 = props.subtitleLine2;
    const highlightColor = props.highlightColor;
    const backgroundColor = props.backgroundColor;
    const transparentBackground = props.transparentBackground;
    const headlineFont = props.headlineFont;
    const subtitleFont = props.subtitleFont;

    const DESIGN_WIDTH = 1920;
    const DESIGN_HEIGHT = 1080;
    const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

    const pFrame = Math.floor(frame / 3) * 3;
    const easeOutCubic = t => 1 - Math.pow(1 - t, 3);
    const easeInOut = t => t < 0.5 ? 2*t*t : -1+(4-2*t)*t;
    const getP = (f, s, e) => f < s ? 0 : f >= e ? 1 : (f-s)/(e-s);

    const arrowProgress = easeInOut(getP(pFrame, 0, 20));
    const arrowDash = 300 * (1 - arrowProgress);
    const arrowHeadOpacity = getP(pFrame, 15, 21);

    const safeH = headlineText || '';
    const nChars = Math.floor(getP(pFrame, 0, 30) * safeH.length);
    const typed = safeH.slice(0, nChars);

    const l1LineH = 60;
    const gap = 16;
    const l1H = easeOutCubic(getP(pFrame, 30, 51)) * (l1LineH + gap);
    const l2H = easeOutCubic(getP(pFrame, 39, 54)) * l1LineH;
    const hlW = easeOutCubic(getP(pFrame, 54, 78)) * 100;

    const headlineStyle = {
        fontSize: 90, fontWeight: 'bold', color: 'white',
        fontFamily: headlineFont, lineHeight: 1.1, whiteSpace: 'nowrap', margin: 0
    };
    const subtitleStyle = {
        height: l1LineH, lineHeight: l1LineH + 'px', fontSize: 44,
        fontStyle: 'italic', color: '#aaaaaa', fontFamily: subtitleFont,
        whiteSpace: 'nowrap', margin: 0
    };

    return (
        <div style={{position:'absolute',top:0,left:0,width:DESIGN_WIDTH,height:DESIGN_HEIGHT,transform:'scale('+scale+')',transformOrigin:'top left',backgroundColor:transparentBackground?'transparent':backgroundColor}}>

            {/* Arrow + Headline block — centered independently */}
            <div style={{position:'absolute',top:'50%',left:'50%',transform:'translate(-50%,-50%)',display:'flex',flexDirection:'column',alignItems:'center'}}>
                <div style={{position:'relative',width:250,height:110,marginBottom:10}}>
                    <svg width="250" height="110" style={{position:'absolute',top:0,left:0,overflow:'visible'}}>
                        <path d="M 15 100 Q 30 10, 180 10" fill="none" stroke="#ffffff" strokeWidth="3.5" strokeDasharray="300" strokeDashoffset={arrowDash} strokeLinecap="round"/>
                        <polyline points="165,-2 182,12 165,24" fill="none" stroke="#ffffff" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round" opacity={arrowHeadOpacity}/>
                    </svg>
                </div>
                <div style={{position:'relative'}}>
                    <div style={{...headlineStyle,opacity:0,userSelect:'none'}}>{safeH}</div>
                    <div style={{...headlineStyle,position:'absolute',top:0,left:0}}>{typed}</div>
                </div>
            </div>

            {/* Subtitle lines — fixed position, completely independent from headline */}
            <div style={{position:'absolute',top:'65%',left:'50%',transform:'translateX(-50%)',display:'flex',flexDirection:'column',alignItems:'center'}}>
                <div style={{height:l1H,overflow:'hidden'}}>
                    <div style={subtitleStyle}>{subtitleLine1}</div>
                    <div style={{height:gap}}/>
                </div>
                <div style={{height:l2H,overflow:'hidden',display:'flex',justifyContent:'center'}}>
                    <div style={{...subtitleStyle,position:'relative',display:'inline-block',padding:'0 8px'}}>
                        <div style={{position:'absolute',left:0,top:4,bottom:4,width:hlW+'%',backgroundColor:highlightColor,opacity:0.9,zIndex:0}}/>
                        <span style={{position:'relative',zIndex:1,color:'#aaaaaa'}}>{subtitleLine2}</span>
                    </div>
                </div>
            </div>

        </div>
    );
};

const TimelineAnimation = ({ item }) => {
  const frame = useCurrentFrame();
  const { width, height } = item;
  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min(
    (width || DESIGN_WIDTH) / DESIGN_WIDTH,
    (height || DESIGN_HEIGHT) / DESIGN_HEIGHT
  );

  const props = item.props || {};
  const text1 = props.text1;
  const text2 = props.text2;
  const text3line1 = props.text3line1;
  const text3line2 = props.text3line2;
  const dotColor = props.dotColor;
  const textColor = props.textColor;
  const transparentBackground = props.transparentBackground === 'true' || props.transparentBackground === true;
  const fontFamily = props.fontFamily;

  const easeOut = Easing.out(Easing.cubic);

  const dot1Opacity = interpolate(frame, [0, 30], [0, 1], { extrapolateRight: 'clamp', easing: easeOut });
  const dot1Blur = interpolate(frame, [0, 30], [12, 0], { extrapolateRight: 'clamp', easing: easeOut });
  const text1Opacity = interpolate(frame, [8, 33], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut });
  const text1Y = interpolate(frame, [8, 33], [20, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut });
  const line1Scale = interpolate(frame, [35, 60], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut });

  const dot2Opacity = interpolate(frame, [60, 90], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut });
  const dot2Blur = interpolate(frame, [60, 90], [12, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut });
  const text2Opacity = interpolate(frame, [68, 93], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut });
  const text2Y = interpolate(frame, [68, 93], [20, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut });
  const line2Scale = interpolate(frame, [95, 120], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut });

  const dot3Opacity = interpolate(frame, [120, 150], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut });
  const dot3Blur = interpolate(frame, [120, 150], [12, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut });
  const text3Opacity = interpolate(frame, [128, 153], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut });
  const text3Y = interpolate(frame, [128, 153], [20, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: easeOut });

  const DOT_R = 12;
  const SPACING = 160;
  const TEXT_LEFT = 56;
  const FONT_SIZE = 52;
  const LINE_HEIGHT = 1.3;

  // dot center Y coords (relative to container)
  const cy1 = 0;
  const cy2 = SPACING;
  const cy3 = SPACING * 2;

  const dotEl = (cy, opacity, blur) => (
    <div style={{
      position: 'absolute',
      left: -DOT_R,
      top: cy - DOT_R,
      width: DOT_R * 2,
      height: DOT_R * 2,
      borderRadius: DOT_R,
      backgroundColor: dotColor,
      boxShadow: '0 0 10px rgba(255,255,255,0.7)',
      opacity,
      filter: `blur(${blur}px)`
    }} />
  );

  const lineEl = (cy, scaleY) => (
    <div style={{
      position: 'absolute',
      left: -1.5,
      top: cy + DOT_R,
      width: 3,
      height: SPACING - DOT_R * 2,
      backgroundColor: dotColor,
      borderRadius: 1.5,
      transformOrigin: 'top center',
      transform: `scaleY(${scaleY})`
    }} />
  );

  // text anchored to dot center: top = cy - half of single line height
  const singleLineH = FONT_SIZE * LINE_HEIGHT;
  const textEl = (cy, lines, opacity, ty) => (
    <div style={{
      position: 'absolute',
      left: TEXT_LEFT,
      top: cy - singleLineH / 2,
      opacity,
      transform: `translateY(${ty}px)`,
      fontSize: FONT_SIZE,
      fontWeight: 700,
      lineHeight: LINE_HEIGHT,
      color: textColor,
      whiteSpace: 'pre',
      pointerEvents: 'none'
    }}>
      {lines}
    </div>
  );

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0,
      width: DESIGN_WIDTH, height: DESIGN_HEIGHT,
      transform: `scale(${scale})`, transformOrigin: 'top left',
      backgroundColor: transparentBackground ? 'transparent' : '#000000',
      fontFamily
    }}>
      <div style={{ position: 'absolute', left: 180, top: 380 }}>
        {dotEl(cy1, dot1Opacity, dot1Blur)}
        {textEl(cy1, text1, text1Opacity, text1Y)}
        {lineEl(cy1, line1Scale)}

        {dotEl(cy2, dot2Opacity, dot2Blur)}
        {textEl(cy2, text2, text2Opacity, text2Y)}
        {lineEl(cy2, line2Scale)}

        {dotEl(cy3, dot3Opacity, dot3Blur)}
        {textEl(cy3, <>{text3line1}<br />{text3line2}</>, text3Opacity, text3Y)}
      </div>
    </div>
  );
};

const BezierSlidingText = ({item}) => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();

  const props = item.props || {};
  const line1Text = props.line1Text;
  const line2Text = props.line2Text;
  const fontSize = props.fontSize;
  const fontFamily = props.fontFamily;
  const textColor = props.textColor;
  const shadowColor = props.shadowColor;

  const DESIGN_WIDTH = 1920;
  const DESIGN_HEIGHT = 1080;
  const scale = Math.min((item?.width || DESIGN_WIDTH) / DESIGN_WIDTH, (item?.height || DESIGN_HEIGHT) / DESIGN_HEIGHT);

  const customEase = Easing.bezier(0.8, 0, 0.2, 1);
  const slideOffset = 45;
  const wordDuration = 18;
  const wordGap = 6; // 0.2s @ 30fps

  const line1Words = (line1Text || '').split(' ');
  const line2Words = (line2Text || '').split(' ');
  const line2StartOffset = line1Words.length * wordGap + 8;

  const renderWords = (words, lineStartFrame) => {
    return words.map((word, i) => {
      const wordStart = lineStartFrame + i * wordGap;
      const wordEnd = wordStart + wordDuration;
      const progress = interpolate(frame, [wordStart, wordEnd], [0, 1], {
        easing: customEase,
        extrapolateLeft: 'clamp',
        extrapolateRight: 'clamp',
      });
      const x = interpolate(progress, [0, 1], [slideOffset, 0]);
      const opacity = interpolate(progress, [0, 0.25], [0, 1], { extrapolateRight: 'clamp' });
      return (
        <span key={i} style={{
          display: 'inline-block',
          transform: `translateX(${x}px)`,
          opacity,
          marginRight: i < words.length - 1 ? `${fontSize * 0.22}px` : 0,
          willChange: 'transform, opacity',
        }}>
          {word}
        </span>
      );
    });
  };

  const rootStyle = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: DESIGN_WIDTH,
    height: DESIGN_HEIGHT,
    transform: `scale(${scale})`,
    transformOrigin: 'top left',
    backgroundColor: 'transparent',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    overflow: 'hidden',
  };

  const lineStyle = {
    fontFamily,
    fontSize: `${fontSize}px`,
    fontWeight: 'bold',
    color: textColor,
    textShadow: `4px 4px 12px ${shadowColor}`,
    margin: 0,
    lineHeight: 1.25,
    letterSpacing: '-0.02em',
    display: 'flex',
    flexWrap: 'nowrap',
    alignItems: 'baseline',
  };

  return (
    <div style={rootStyle}>
      <div style={lineStyle}>
        {renderWords(line1Words, 5)}
      </div>
      <div style={{ ...lineStyle, marginTop: `${fontSize * 0.08}px` }}>
        {renderWords(line2Words, line2StartOffset)}
      </div>
    </div>
  );
};

const EditorialShowcase = ({item}) => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();
  const props = item.props || {};

  const safeFps = fps || 30;
  const safeSpring = (delay = 0, config = { damping: 18, stiffness: 90, mass: 0.8 }) => {
    return spring({ frame: Math.max(0, frame - delay), fps: safeFps, config });
  };

  const backgroundColor = props.transparentBackground ? 'transparent' : props.bgColor;
  const rootStyle = {
    position: 'absolute',
    inset: 0,
    backgroundColor,
    padding: '100px',
    boxSizing: 'border-box',
    display: 'flex',
    flexDirection: 'column',
    fontFamily: props.fontSans,
    color: props.textColor,
    overflow: 'hidden'
  };

  const chapterSpring = safeSpring(5);
  const chapterOpacity = chapterSpring;
  const chapterY = (1 - chapterSpring) * 30;

  const chartElements = [
    { label: props.chartLabel1, valueText: props.chartValue1, fill: props.chartFill1, color: props.accentCopper },
    { label: props.chartLabel2, valueText: props.chartValue2, fill: props.chartFill2, color: props.accentAmber },
    { label: props.chartLabel3, valueText: props.chartValue3, fill: props.chartFill3, color: props.accentTan }
  ].map((item, idx) => {
    const s = safeSpring(15 + idx * 8);
    return (
      <div key={idx} style={{ marginBottom: 32, opacity: s, transform: `translateX(${(1 - s) * 20}px)` }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 12, fontSize: 24, fontWeight: 600 }}>
          <span>{item.label}</span>
          <span style={{ fontFamily: props.fontSerif, fontStyle: 'italic', fontWeight: 400, color: props.textSecondaryColor }}>{item.valueText}</span>
        </div>
        <div style={{ height: 6, backgroundColor: 'rgba(255,255,255,0.1)', borderRadius: 3, overflow: 'hidden' }}>
          <div style={{ height: '100%', width: `${s * item.fill}%`, backgroundColor: item.color, borderRadius: 3 }} />
        </div>
      </div>
    );
  });

  const nameSpring = safeSpring(30);
  const nameLineScale = safeSpring(35);

  const bulletElements = [
    props.bullet1, props.bullet2, props.bullet3
  ].map((text, idx) => {
    const s = safeSpring(40 + idx * 6);
    return (
      <div key={idx} style={{ display: 'flex', alignItems: 'center', gap: 20, marginBottom: 24, opacity: s, transform: `translateX(${(1 - s) * -20}px)` }}>
        <div style={{ width: 8, height: 8, borderRadius: '50%', backgroundColor: props.accentCopper, flexShrink: 0 }} />
        <div style={{ fontSize: 26, color: props.textSecondaryColor, fontWeight: 500 }}>{text}</div>
      </div>
    );
  });

  const quoteSpring = safeSpring(60);

  const tlLineSpring = safeSpring(70);
  const timelineElements = [
    { year: props.tlYear1, text: props.tlText1 },
    { year: props.tlYear2, text: props.tlText2 },
    { year: props.tlYear3, text: props.tlText3 },
    { year: props.tlYear4, text: props.tlText4 }
  ].map((item, idx) => {
    const s = safeSpring(75 + idx * 8);
    return (
      <div key={idx} style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-start', opacity: s, transform: `translateY(${(1 - s) * 15}px)`, width: '22%' }}>
        <div style={{ width: 12, height: 12, borderRadius: 6, backgroundColor: props.accentTan, marginTop: 6, marginBottom: 28, border: `4px solid ${props.bgColor}`, boxSizing: 'content-box', zIndex: 2 }} />
        <div style={{ fontSize: 32, fontWeight: 800, marginBottom: 12, letterSpacing: 1 }}>{item.year}</div>
        <div style={{ fontSize: 20, color: props.textSecondaryColor, lineHeight: 1.5, fontWeight: 500, paddingRight: 20 }}>{item.text}</div>
      </div>
    );
  });

  return (
    <div style={rootStyle}>
      <div style={{ display: 'flex', gap: '140px', flex: 1 }}>

        {/* Left Column */}
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', justifyContent: 'space-between', paddingBottom: '40px' }}>
          <div style={{ opacity: chapterOpacity, transform: `translateY(${chapterY}px)` }}>
            <div style={{ fontSize: 20, letterSpacing: 6, fontWeight: 700, color: props.textSecondaryColor, marginBottom: 32, textTransform: 'uppercase' }}>
              {props.chapterSubtitle}
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              <div style={{ display: 'flex', alignItems: 'baseline', gap: 24, flexWrap: 'wrap' }}>
                <span style={{ fontSize: 92, fontWeight: 800, letterSpacing: 1 }}>{props.chapterTitleSans1}</span>
                <span style={{ fontSize: 100, fontFamily: props.fontSerif, fontStyle: 'italic', fontWeight: 400, letterSpacing: -2 }}>{props.chapterTitleSerif}</span>
              </div>
              <div style={{ fontSize: 92, fontWeight: 800, letterSpacing: 1 }}>{props.chapterTitleSans2}</div>
            </div>
          </div>

          <div style={{ opacity: nameSpring, transform: `translateY(${(1 - nameSpring) * 20}px)` }}>
            <div style={{ width: `${nameLineScale * 80}px`, height: 4, backgroundColor: props.accentCopper, marginBottom: 24 }} />
            <div style={{ fontSize: 44, fontWeight: 800, letterSpacing: 1, marginBottom: 8 }}>{props.nameText}</div>
            <div style={{ fontSize: 26, color: props.textSecondaryColor, fontFamily: props.fontSerif, fontStyle: 'italic' }}>{props.roleText}</div>
          </div>
        </div>

        {/* Right Column */}
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', justifyContent: 'space-between', paddingBottom: '40px' }}>
          <div style={{ width: '100%', paddingRight: '40px' }}>
            {chartElements}
          </div>

          <div style={{ marginTop: 20 }}>
            {bulletElements}
          </div>

          <div style={{
            opacity: quoteSpring, 
            transform: `translateY(${(1 - quoteSpring) * 20}px)`,
            borderLeft: `4px solid ${props.accentAmber}`,
            paddingLeft: 36,
            maxWidth: '90%',
            marginTop: 20
          }}>
            <div style={{ fontSize: 38, fontFamily: props.fontSerif, fontStyle: 'italic', lineHeight: 1.4, color: props.textColor }}>
              "{props.quoteText}"
            </div>
          </div>
        </div>
      </div>

      {/* Timeline Footer */}
      <div style={{ position: 'relative', marginTop: 40, height: 160 }}>
        {frame >= 70 && <div style={{ position: 'absolute', top: 14, left: 0, right: 0, height: 4, backgroundColor: 'rgba(255,255,255,0.06)' }} />}
        <div style={{ position: 'absolute', top: 14, left: 0, height: 4, width: `${tlLineSpring * 100}%`, backgroundColor: props.accentTan }} />
        <div style={{ position: 'absolute', top: 0, left: 0, right: 0, display: 'flex', justifyContent: 'space-between' }}>
          {timelineElements}
        </div>
      </div>
    </div>
  );
};
